        // Keep mission behavior and dedicated observer on the same battle-lifecycle pipeline.
        // This shared tick owns authoritative coop runtime state and battlefield materialization.
        // Native preview visuals may still exist for compatibility, but they no longer drive
        // a separate vanilla player-spawn finalize path.
        private static void RunSharedServerBattleLifecycleTick(
            Mission mission,
            string source,
            bool applyPreMaterializationPeerNudges)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            AppendExactBattleAgentSpawnTraceLifecycleStep(
                mission,
                "shared-tick",
                "enter",
                source,
                "ApplyPreMaterializationPeerNudges=" + applyPreMaterializationPeerNudges);

            if (ShouldDeferBattleMapStartupRuntime(mission, out string deferReason))
            {
                AppendExactBattleAgentSpawnTraceLifecycleStep(
                    mission,
                    "shared-tick",
                    "deferred-startup",
                    source,
                    "Reason=" + (deferReason ?? "unknown"));
                TryConsumeSelectionRequests(mission);
                TryApplySelectionIntentToPrimaryPeer(mission, source + " deferred-startup");
                if (applyPreMaterializationPeerNudges)
                    TryBridgeAuthoritativePeerTeams(mission, source + " deferred-startup");

                TryWriteEntryStatusSnapshot(mission, source + " deferred-startup");
                LogBattleMapStartupDeferralIfNeeded(mission, source, deferReason);
                return;
            }

            if (applyPreMaterializationPeerNudges)
            {
                AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "pre-peer-nudges", source);
                TryConsumeSelectionRequests(mission);
                TryApplySelectionIntentToPrimaryPeer(mission, source);
                TryBridgeAuthoritativePeerTeams(mission, source);
                TryForceFixedMissionCultures(mission, source);
            }
            else
            {
                AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "selection-intent-only", source);
                TryConsumeSelectionRequests(mission);
                TryApplySelectionIntentToPrimaryPeer(mission, source);
            }

            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "native-bootstrap-before", source);
            TryEnsureExactCampaignNativeArmyBootstrap(mission, source);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "native-bootstrap-after", source);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "materialize-armies-before", source);
            TryEnsureBattlefieldArmiesMaterialized(mission, source);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "materialize-armies-after", source);
            TryConsumeSpawnRequests(mission);
            TryApplySpawnIntentToPrimaryPeer(mission, source);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "runtime-sync-before", source);
            TrySyncExactCampaignBattlefieldRuntimeState(mission, source);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "runtime-sync-after", source);
            TryBridgeAuthoritativePeerTeams(mission, source);
            TryForceFixedMissionCultures(mission, source);
            TryForcePreferredHeroClassForPeer(mission, source);
            TryBridgeListedShellInitialPerkInfoReadiness(mission, source);
            TryArmListedShellNativeSpawnCompatibilityState(mission, source);
            if (EnableMaterializedArmyPossessionExperiment)
            {
                AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "materialized-possession-before", source);
                TryTakeControlOfMaterializedArmyAgents(mission, source);
                AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "materialized-possession-after", source);
            }
            TryRefreshPendingSpawnRequests(mission, source);
            TryAlignControlledAgentsWithMaterializedArmy(mission, source);
            TryRefreshMaterializedCombatProfileDrivenStats(mission, source + " tick");
            LogMaterializedEquipmentCoverageSummaryIfNeeded();
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "compatibility-audit-before", source);
            TryWriteExactEntryCompatibilityAuditSafely(source + " tick");
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "compatibility-audit-after", source);
            TryWriteEntryStatusSnapshot(mission, source + " tick");
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "shared-tick", "complete", source);
        }

        private static bool ShouldDeferBattleMapStartupRuntime(Mission mission, out string reason)
        {
            reason = string.Empty;
            if (mission == null || !IsSceneAwareBattleMapRuntime(mission))
                return false;

            string missionMode = "unknown";
            float missionTime = -1f;
            int synchronizedPeerCount = 0;
            bool isExactCampaignBattleScene = false;

            try { missionMode = mission.Mode.ToString(); } catch { }
            try { missionTime = mission.CurrentTime; } catch { }
            try { isExactCampaignBattleScene = SceneRuntimeClassifier.IsCampaignBattleScene(mission.SceneName ?? string.Empty); } catch { }

            if (GameNetwork.NetworkPeers != null)
            {
                foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
                {
                    if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                        continue;

                    synchronizedPeerCount++;
                }
            }

            if (string.Equals(missionMode, "StartUp", StringComparison.OrdinalIgnoreCase))
            {
                reason =
                    "MissionMode=" + missionMode +
                    " MissionTime=" + missionTime.ToString("0.000", System.Globalization.CultureInfo.InvariantCulture) +
                    " SynchronizedPeers=" + synchronizedPeerCount;
                return true;
            }

            if (missionTime >= 0f && missionTime < 1.5f)
            {
                reason =
                    "MissionMode=" + missionMode +
                    " MissionTime=" + missionTime.ToString("0.000", System.Globalization.CultureInfo.InvariantCulture) +
                    " SynchronizedPeers=" + synchronizedPeerCount;
                return true;
            }

            if (isExactCampaignBattleScene && synchronizedPeerCount <= 0)
            {
                reason =
                    "MissionMode=" + missionMode +
                    " MissionTime=" + missionTime.ToString("0.000", System.Globalization.CultureInfo.InvariantCulture) +
                    " SynchronizedPeers=" + synchronizedPeerCount +
                    " ExactScenePeerGate=pending";
                return true;
            }

            return false;
        }

        private static bool IsSceneAwareBattleMapRuntime(Mission mission)
        {
            string sceneName = mission?.SceneName ?? string.Empty;
            return SceneRuntimeClassifier.IsSceneAwareBattleRuntimeScene(sceneName);
        }

        private static void LogBattleMapStartupDeferralIfNeeded(Mission mission, string source, string reason)
        {
            DateTime nowUtc = DateTime.UtcNow;
            if (nowUtc < _nextBattleMapStartupDeferLogUtc)
                return;

            _nextBattleMapStartupDeferLogUtc = nowUtc.AddSeconds(2);
            ModLogger.Info(
                "CoopMissionSpawnLogic: deferred risky battle-map startup runtime. " +
                "Mission=" + (mission?.SceneName ?? "null") +
                " Source=" + (source ?? "unknown") +
                " Reason=" + (reason ?? "unknown"));
        }

        public static void RunCoopBattleSpawnOwnerTick(Mission mission, string source)
        {
            string spawnSource = string.IsNullOrWhiteSpace(source) ? "CoopBattle spawn owner" : source;
            RunSharedServerBattleLifecycleTick(
                mission,
                spawnSource,
                applyPreMaterializationPeerNudges: true);
        }

        public static void RunCoopBattlePhaseOwnerTick(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            string phaseSource = string.IsNullOrWhiteSpace(source) ? "CoopBattle phase owner" : source;
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "enter", phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "update-phase-before", phaseSource);
            TryUpdateBattlePhaseState(mission, phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "update-phase-after", phaseSource);
            TryConsumeBattlePhaseRequests(mission);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "warmup-fallback-before", phaseSource);
            TryApplyNativeBattleMapWarmupFallback(mission, phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "warmup-fallback-after", phaseSource);
            TryApplyBattlePhaseAiHold(mission, phaseSource);
            TryApplyBattlePhaseFormationHold(mission, phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "native-reinforcement-sync-before", phaseSource);
            TrySyncExactCampaignNativeArmyBootstrapReinforcements(mission, phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "native-reinforcement-sync-after", phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "materialized-reinforcement-before", phaseSource);
            TrySpawnMaterializedBattlefieldReinforcements(mission, phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "materialized-reinforcement-after", phaseSource);
            TryCompleteBattleIfResolved(mission, phaseSource);
            AppendExactBattleAgentSpawnTraceLifecycleStep(mission, "phase-tick", "complete", phaseSource);
        }

        public static void TryRunClientExactCampaignVisualObserver(Mission mission)
        {
            if (mission == null || GameNetwork.IsServer || !IsClientExactCampaignVisualOverlayRuntime(mission))
                return;

            if (GameNetwork.IsClient &&
                !CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out string snapshotReadinessSummary))
            {
                string readinessSignature = snapshotReadinessSummary ?? string.Empty;
                if (!string.Equals(_lastDeferredClientExactVisualObserverSnapshotReadiness, readinessSignature, StringComparison.Ordinal))
                {
                    _lastDeferredClientExactVisualObserverSnapshotReadiness = readinessSignature;
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: deferred battle-map client exact visual observer until authoritative V2 battle snapshot is applied. " +
                        "Mission=" + (mission.SceneName ?? "null") +
                        " SnapshotReadiness=" + readinessSignature);
                }

                return;
            }

            _lastDeferredClientExactVisualObserverSnapshotReadiness = string.Empty;
            if (ShouldDeferClientExactRuntimeBootstrapForSelectionScreen(out string selectionGateReason))
            {
                string selectionGateSignature = selectionGateReason ?? string.Empty;
                if (!string.Equals(_lastDeferredClientExactVisualObserverSelectionGateReason, selectionGateSignature, StringComparison.Ordinal))
                {
                    _lastDeferredClientExactVisualObserverSelectionGateReason = selectionGateSignature;
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: deferred battle-map client exact visual observer while local peer is still in selection gate. " +
                        "Mission=" + (mission.SceneName ?? "null") +
                        " Reason=" + (selectionGateReason ?? "unknown"));
                }

                return;
            }

            _lastDeferredClientExactVisualObserverSelectionGateReason = string.Empty;
            EnsureClientBattleSnapshotFreshForMission(mission, "client-exact-visual-observer");
            TryRefreshClientPostPossessionExactVisualPauseWindow(mission, "client-exact-visual-observer");
            ExactCampaignObjectCatalogBootstrap.EnsureLoaded("client-exact-visual-observer:" + (mission.SceneName ?? "null"));
            TryProcessPendingClientExactCampaignVisualOverlays(mission);
            TryMaintainClientPeerHeroExactVisualOverlays(mission);
            TryMaintainClientBattlefieldTroopExactVisualOverlays(mission);
        }

        public static bool ShouldDeferClientExactRuntimeBootstrapForSelectionScreen(out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
                return false;

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot status = CoopBattleEntryStatusBridgeFile.ReadStatus();
            if (status == null)
            {
                reason = "status-null";
                return true;
            }

            return ShouldPausePendingClientExactVisualOverlaysForSelectionScreen(out reason);
        }

        private static bool TryQueueClientExactCampaignVisualOverlay(
            Mission mission,
            Agent agent,
            string preferredEntryId,
            string source,
            double delaySeconds,
            bool force = false,
            bool includeWeaponsForRefresh = false)
        {
            if (mission == null || agent == null || agent.IsMount || !agent.IsActive() || GameNetwork.IsServer)
                return false;

            if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                return false;

            if (!IsMissionPeerAgentEligibleForClientExactVisualOverlay(agent))
                return false;

            EnsureClientBattleSnapshotFreshForMission(mission, source ?? "client exact visual queue");

            string entryId = preferredEntryId;
            if (string.IsNullOrWhiteSpace(entryId) || BattleSnapshotRuntimeState.GetEntryState(entryId) == null)
                entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);

            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (entryState == null)
                return false;
            bool heroEntry = IsHeroEntryEligibleForExactPersonalPerks(entryState);
            if (ShouldPauseClientExactVisualOverlaysForReconnectFinalize(out _))
                return false;
            if (heroEntry)
            {
                if (ShouldSuppressClientHeroExactVisualOverlayForLocalLiveTakeover(
                        agent,
                        entryId,
                        entryState,
                        out _))
                {
                    _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                    return false;
                }

                if (ShouldSuppressClientHeroExactVisualOverlayForRemoteLiveControl(
                        agent,
                        entryId,
                        entryState,
                        out _))
                {
                    _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                    return false;
                }
            }
            else if (ShouldSuppressClientTroopExactVisualOverlayForLiveControl(agent, out _))
            {
                return false;
            }
            if (ShouldAwaitMountedHeroEquipmentSyncBeforeClientExactVisualRefresh(
                    agent,
                    entryState,
                    includeWeaponsForRefresh,
                    out string deferredHeroReason))
            {
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                ClearClientExactCampaignVisualOverlayAppliedState(agent.Index);
                TryLogDeferredHeroEquipmentSyncVisualGate(
                    agent,
                    entryId,
                    entryState,
                    includeWeaponsForRefresh,
                    source ?? "client exact visual queue",
                    deferredHeroReason);
                return false;
            }
            if (heroEntry)
                UpdateStrictExactHeroTransferEntryState(agent.Index, entryId, entryState, source ?? "client exact visual queue");

            RefreshClientExactCampaignVisualOverlayAgentIndexState(
                agent,
                source ?? "client exact visual queue",
                preferredEntryId: entryId,
                logRefresh: true);

            _exactNativeClientVisualOverlayAgentByIndex[agent.Index] = agent;
            _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = entryId;
            TryApplyEntryIdentityToAgent(agent, entryState);

            if (!force &&
                (_exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index) ||
                 _pendingExactNativeClientVisualOverlaysByAgentIndex.ContainsKey(agent.Index)))
            {
                return false;
            }

            if (force)
            {
                _exactNativeClientVisualOverlayAppliedAgentIndices.Remove(agent.Index);
                _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.Remove(agent.Index);
            }

            bool effectiveIncludeWeaponsForRefresh = includeWeaponsForRefresh;
            if (effectiveIncludeWeaponsForRefresh &&
                IsLocalPeerControlledAgent(agent))
            {
                effectiveIncludeWeaponsForRefresh = false;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: suppressed weapon-inclusive pending client exact visual overlay for locally controlled agent. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Source=" + (source ?? "unknown"));
            }
            else if (effectiveIncludeWeaponsForRefresh &&
                     ShouldDowngradeClientMountedTroopWeaponOverlayRefresh(agent, entryState, out string mountedCooldownReason))
            {
                effectiveIncludeWeaponsForRefresh = false;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: downgraded weapon-inclusive pending client exact visual overlay for mounted non-local troop during local post-possession combat stabilization. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Reason=" + (mountedCooldownReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
            }

            DateTime notBeforeUtc = DateTime.UtcNow.AddSeconds(Math.Max(0.01, delaySeconds));
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState) &&
                ShouldPauseClientPostPossessionExactVisualForAgent(agent, out string postPossessionPauseReason) &&
                _clientPostPossessionExactVisualPauseResumeUtc > notBeforeUtc)
            {
                notBeforeUtc = _clientPostPossessionExactVisualPauseResumeUtc;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred queued client exact visual overlay until local post-possession stabilization window completes. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " IncludeWeapons=" + effectiveIncludeWeaponsForRefresh +
                    " Reason=" + (postPossessionPauseReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
            }

            _pendingExactNativeClientVisualOverlaysByAgentIndex[agent.Index] = new PendingClientExactVisualOverlayState
            {
                EntryId = entryId,
                CreatedUtc = DateTime.UtcNow,
                NotBeforeUtc = notBeforeUtc,
                RetryCount = 0,
                Source = source ?? "client exact visual queue",
                IncludeWeaponsForRefresh = effectiveIncludeWeaponsForRefresh
            };
            UpdateStrictExactHeroTransferVisualQueuedState(agent.Index, entryId, source ?? "client exact visual queue");
            ModLogger.Info(
                "CoopMissionSpawnLogic: queued client exact visual overlay refresh. " +
                "AgentIndex=" + agent.Index +
                " EntryId=" + entryId +
                " IncludeWeapons=" + effectiveIncludeWeaponsForRefresh +
                " Force=" + force +
                " DelaySeconds=" + Math.Max(0.01, (notBeforeUtc - DateTime.UtcNow).TotalSeconds).ToString("0.00") +
                " Source=" + (source ?? "unknown"));
            return true;
        }

        private static void ClearClientExactCampaignVisualOverlayAgentIndexState(
            int agentIndex,
            string source,
            bool logClear = false,
            string reason = null,
            bool preserveCreateAgentRuntime = false)
        {
            if (agentIndex < 0)
                return;

            bool hadTrackedAgent = _exactNativeClientVisualOverlayAgentByIndex.Remove(agentIndex);
            bool hadApplied = _exactNativeClientVisualOverlayAppliedAgentIndices.Remove(agentIndex);
            bool hadIncludesWeapons = _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.Remove(agentIndex);
            bool hadEntryId = _exactNativeClientVisualOverlayEntryIdByAgentIndex.Remove(agentIndex);
            bool hadTrackedMount = ClearTrackedClientMountedHeroMountAgentIndexState(agentIndex);
            bool hadPending = _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agentIndex);
            bool hadCreateAgentRuntime =
                _clientCreateAgentExactVisualStateByAgentIndex.TryGetValue(agentIndex, out ClientCreateAgentExactVisualRuntimeState _) &&
                _clientCreateAgentExactVisualStateByAgentIndex[agentIndex] != null;
            if (!preserveCreateAgentRuntime)
                _clientCreateAgentExactVisualStateByAgentIndex.Remove(agentIndex);
            bool hadAuthoritativeMaterializedEntryId = _clientAuthoritativeMaterializedEntryIdByAgentIndex.Remove(agentIndex);
            bool hadAuthoritativeMaterializedObserved = _clientAuthoritativeMaterializedEntryObservedAgentIndices.Remove(agentIndex);
            bool hadWatchdogFirstSeen = _clientHeroExactVisualWatchdogFirstSeenUtcByAgentIndex.Remove(agentIndex);
            bool hadWatchdogLastAttempt = _clientHeroExactVisualWatchdogLastAttemptUtcByAgentIndex.Remove(agentIndex);
            _lastLoggedDeferredHeroEquipmentSyncVisualSignatureByAgentIndex.Remove(agentIndex);
            bool hadStrictTransferState = _strictExactHeroTransferStateByRiderAgentIndex.ContainsKey(agentIndex);
            ClearStrictExactHeroTransferState(agentIndex, source, reason, logClear: false);
            if (logClear &&
                (hadTrackedAgent || hadApplied || hadIncludesWeapons || hadEntryId || hadTrackedMount || hadPending || hadCreateAgentRuntime || hadAuthoritativeMaterializedEntryId || hadAuthoritativeMaterializedObserved || hadWatchdogFirstSeen || hadWatchdogLastAttempt || hadStrictTransferState))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: cleared client exact visual overlay agent-index state. " +
                    "AgentIndex=" + agentIndex +
                    " Reason=" + (reason ?? "unknown") +
                    " Source=" + (source ?? "unknown") +
                    " HadTrackedAgent=" + hadTrackedAgent +
                    " HadApplied=" + hadApplied +
                    " HadIncludesWeapons=" + hadIncludesWeapons +
                    " HadEntryId=" + hadEntryId +
                    " HadTrackedMount=" + hadTrackedMount +
                    " HadPending=" + hadPending +
                    " HadCreateAgentRuntime=" + hadCreateAgentRuntime +
                    " PreservedCreateAgentRuntime=" + preserveCreateAgentRuntime +
                    " HadAuthoritativeMaterializedEntryId=" + hadAuthoritativeMaterializedEntryId +
                    " HadAuthoritativeMaterializedObserved=" + hadAuthoritativeMaterializedObserved +
                    " HadStrictTransferState=" + hadStrictTransferState +
                    " HadWatchdogFirstSeen=" + hadWatchdogFirstSeen +
                    " HadWatchdogLastAttempt=" + hadWatchdogLastAttempt);
            }
        }

        private static void ClearClientExactCampaignVisualOverlayAppliedState(int agentIndex)
        {
            if (agentIndex < 0)
                return;

            _exactNativeClientVisualOverlayAppliedAgentIndices.Remove(agentIndex);
            _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.Remove(agentIndex);
        }

        private static ClientCreateAgentExactVisualRuntimeState GetOrCreateClientCreateAgentExactVisualState(int agentIndex)
        {
            if (agentIndex < 0)
                return null;

            if (_clientCreateAgentExactVisualStateByAgentIndex.TryGetValue(agentIndex, out ClientCreateAgentExactVisualRuntimeState state) &&
                state != null)
            {
                return state;
            }

            state = new ClientCreateAgentExactVisualRuntimeState
            {
                AuthoritativeMaterializedEntryObserved =
                    _clientAuthoritativeMaterializedEntryObservedAgentIndices.Contains(agentIndex),
                FirstObservedUtc = DateTime.UtcNow,
                LastObservedUtc = DateTime.UtcNow
            };
            _clientCreateAgentExactVisualStateByAgentIndex[agentIndex] = state;
            return state;
        }

        private static bool TryGetClientCreateAgentExactVisualState(int agentIndex, out ClientCreateAgentExactVisualRuntimeState state)
        {
            return _clientCreateAgentExactVisualStateByAgentIndex.TryGetValue(agentIndex, out state) && state != null;
        }

        private static void ResetClientCreateAgentExactVisualRuntimeResolutionState(
            ClientCreateAgentExactVisualRuntimeState state,
            bool clearPayloadObservation = false)
        {
            if (state == null)
                return;

            state.EntryId = null;
            state.ResolutionState = null;
            state.ResolutionSource = null;
            state.AuthoritativeMaterializedEntryObserved = false;
            state.CreateAgentPostfixObserved = false;
            state.EquipmentSyncObserved = false;
            state.OnSpawnWieldEventCount = 0;
            state.QueueFallbackSuppressedLogged = false;
            if (clearPayloadObservation)
            {
                state.CreateAgentPayloadObserved = false;
                state.PayloadCharacterId = null;
                state.PayloadSide = BattleSideEnum.None;
            }

            state.LastObservedUtc = DateTime.UtcNow;
        }

        private static void ClearClientTrackedMaterializedAgentIdentityState(
            int agentIndex,
            string source,
            string reason,
            bool preserveCreateAgentRuntime,
            bool logClear)
        {
            if (agentIndex < 0)
                return;

            _materializedArmyEntryIdByAgentIndex.Remove(agentIndex);
            _materializedArmySideByAgentIndex.Remove(agentIndex);
            _materializedAgentInstanceByIndex.Remove(agentIndex);
            _materializedCanonicalInstanceIdByAgentIndex.Remove(agentIndex);
            _pendingServerBootstrapDelayedLiveWieldAgentIndices.Remove(agentIndex);
            _clientAuthoritativeMaterializedEntryIdByAgentIndex.Remove(agentIndex);
            _clientAuthoritativeMaterializedEntryObservedAgentIndices.Remove(agentIndex);
            ClearClientExactCampaignVisualOverlayAgentIndexState(
                agentIndex,
                source,
                logClear: logClear,
                reason: reason,
                preserveCreateAgentRuntime: preserveCreateAgentRuntime);
        }

        private static bool DoesClientCreateAgentRuntimePayloadMatchEntryId(
            ClientCreateAgentExactVisualRuntimeState state,
            string entryId,
            out string mismatchReason)
        {
            mismatchReason = null;
            if (state == null || !state.CreateAgentPayloadObserved)
                return true;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (entryState == null)
            {
                mismatchReason = "entry-state-missing";
                return false;
            }

            if (state.PayloadSide != BattleSideEnum.None &&
                !DoesClientVisualOverlayEntryMatchAgentSide(entryState, state.PayloadSide))
            {
                mismatchReason =
                    "payload-side-mismatch" +
                    "|PayloadSide=" + state.PayloadSide +
                    "|EntrySideId=" + (entryState.SideId ?? "null");
                return false;
            }

            if (!string.IsNullOrWhiteSpace(state.PayloadCharacterId) &&
                !DoesClientVisualOverlayEntryMatchAgentTroop(entryState, state.PayloadCharacterId))
            {
                mismatchReason =
                    "payload-character-mismatch" +
                    "|PayloadCharacterId=" + state.PayloadCharacterId +
                    "|EntryCharacterId=" + (entryState.CharacterId ?? "null") +
                    "|EntryOriginalCharacterId=" + (entryState.OriginalCharacterId ?? "null") +
                    "|EntrySpawnTemplateId=" + (ResolveEntrySpawnTemplateId(entryState) ?? "null");
                return false;
            }

            return true;
        }

        internal static void ObserveClientCreateAgentPayloadResolvedEntry(CreateAgent createAgent, string source)
        {
            if (GameNetwork.IsServer || createAgent == null)
                return;

            ClientCreateAgentExactVisualRuntimeState state = GetOrCreateClientCreateAgentExactVisualState(createAgent.AgentIndex);
            if (state == null)
                return;

            string payloadCharacterId = createAgent.Character?.StringId ?? string.Empty;
            BattleSideEnum payloadSide = ResolveCreateAgentPayloadBattleSide(createAgent.TeamIndex);
            bool payloadSlotReused =
                state.CreateAgentPayloadObserved &&
                (!string.Equals(state.PayloadCharacterId, payloadCharacterId, StringComparison.Ordinal) ||
                 state.PayloadSide != payloadSide);
            if (payloadSlotReused)
            {
                string previousPayloadCharacterId = state.PayloadCharacterId;
                BattleSideEnum previousPayloadSide = state.PayloadSide;
                state.PayloadGeneration = Math.Max(1, state.PayloadGeneration) + 1;
                ResetClientCreateAgentExactVisualRuntimeResolutionState(state);
                ClearClientTrackedMaterializedAgentIdentityState(
                    createAgent.AgentIndex,
                    source ?? "unknown",
                    "create-agent-payload-slot-reuse",
                    preserveCreateAgentRuntime: true,
                    logClear: true);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: detected client create-agent agent-index slot reuse and invalidated stale tracked identity state. " +
                    "AgentIndex=" + createAgent.AgentIndex +
                    " PayloadGeneration=" + state.PayloadGeneration +
                    " PreviousPayloadCharacterId=" + (previousPayloadCharacterId ?? "null") +
                    " PreviousPayloadSide=" + previousPayloadSide +
                    " CurrentPayloadCharacterId=" + (payloadCharacterId ?? "null") +
                    " CurrentPayloadSide=" + payloadSide +
                    " Source=" + (source ?? "unknown"));
            }
            else if (state.PayloadGeneration <= 0)
            {
                state.PayloadGeneration = 1;
            }

            state.PayloadCharacterId = payloadCharacterId;
            state.PayloadSide = payloadSide;
            state.CreateAgentPayloadObserved = true;
            state.AuthoritativeMaterializedEntryObserved =
                _clientAuthoritativeMaterializedEntryObservedAgentIndices.Contains(createAgent.AgentIndex);
            state.LastObservedUtc = DateTime.UtcNow;

            if (TryResolveClientAuthoritativeMaterializedEntryId(createAgent.AgentIndex, out string authoritativeEntryId))
            {
                state.EntryId = authoritativeEntryId;
                state.ResolutionState = "authoritative-materialized-entry";
                state.ResolutionSource = source ?? "unknown";
                _materializedArmyEntryIdByAgentIndex[createAgent.AgentIndex] = authoritativeEntryId;
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[createAgent.AgentIndex] = authoritativeEntryId;

                BattleSideEnum authoritativeSide = ResolveCreateAgentPayloadBattleSide(createAgent.TeamIndex);
                if (authoritativeSide != BattleSideEnum.None)
                    _materializedArmySideByAgentIndex[createAgent.AgentIndex] = authoritativeSide;

                ModLogger.Info(
                    "CoopMissionSpawnLogic: registered client create-agent authoritative entry mapping. " +
                    "AgentIndex=" + createAgent.AgentIndex +
                    " EntryId=" + authoritativeEntryId +
                    " PayloadGeneration=" + state.PayloadGeneration +
                    " Source=" + (source ?? "unknown"));
                return;
            }

            if (!ExactCreateAgentCorridorDiagnostics.TryResolveClientCreateAgentPayloadEntryId(
                    createAgent,
                    out string entryId,
                    out string resolutionState,
                    out string payloadComparisonSummary))
            {
                return;
            }

            bool payloadResolutionStrongEnough =
                string.Equals(resolutionState, "resolved-strong", StringComparison.Ordinal) ||
                string.Equals(resolutionState, "resolved-layout", StringComparison.Ordinal);
            if (!payloadResolutionStrongEnough || string.IsNullOrWhiteSpace(entryId))
                return;

            if (ShouldRequireExplicitMaterializationEntryId(createAgent, out string explicitIdentityReason))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: suppressed heuristic client create-agent payload entry mapping until explicit materialization token arrives. " +
                    "AgentIndex=" + createAgent.AgentIndex +
                    " CandidateEntryId=" + entryId +
                    " ResolutionState=" + (resolutionState ?? "unknown") +
                    " PayloadGeneration=" + state.PayloadGeneration +
                    " Reason=" + (explicitIdentityReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
                return;
            }

            state.EntryId = entryId;
            state.ResolutionState = resolutionState ?? "resolved";
            state.ResolutionSource = source ?? "unknown";

            ModLogger.Info(
                "CoopMissionSpawnLogic: registered client create-agent heuristic fallback candidate. " +
                "AgentIndex=" + createAgent.AgentIndex +
                " EntryId=" + entryId +
                " ResolutionState=" + (resolutionState ?? "unknown") +
                " PayloadGeneration=" + state.PayloadGeneration +
                " PayloadCompare=" + payloadComparisonSummary +
                " Source=" + (source ?? "unknown"));
        }

        internal static void ObserveClientCreateAgentPostfix(Agent agent, string source)
        {
            if (GameNetwork.IsServer || agent == null || agent.Index < 0)
                return;

            ClientCreateAgentExactVisualRuntimeState state = GetOrCreateClientCreateAgentExactVisualState(agent.Index);
            if (state == null)
                return;

            state.CreateAgentPostfixObserved = true;
            state.LastObservedUtc = DateTime.UtcNow;
            if (string.IsNullOrWhiteSpace(state.EntryId) &&
                _materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out string trackedEntryId) &&
                !string.IsNullOrWhiteSpace(trackedEntryId))
            {
                state.EntryId = trackedEntryId;
            }

            if (string.IsNullOrWhiteSpace(state.EntryId) &&
                _exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(agent.Index, out string overlayEntryId) &&
                !string.IsNullOrWhiteSpace(overlayEntryId))
            {
                state.EntryId = overlayEntryId;
            }
        }

        internal static void ObserveClientSynchronizeAgentEquipment(int agentIndex, string source)
        {
            if (GameNetwork.IsServer || agentIndex < 0)
                return;

            ClientCreateAgentExactVisualRuntimeState state = GetOrCreateClientCreateAgentExactVisualState(agentIndex);
            if (state == null)
                return;

            state.EquipmentSyncObserved = true;
            state.LastObservedUtc = DateTime.UtcNow;
        }

        internal static void ObserveClientSetWieldedItemIndex(int agentIndex, bool isWieldedOnSpawn, string source)
        {
            if (GameNetwork.IsServer || agentIndex < 0)
                return;

            ClientCreateAgentExactVisualRuntimeState state = GetOrCreateClientCreateAgentExactVisualState(agentIndex);
            if (state == null)
                return;

            if (isWieldedOnSpawn)
                state.OnSpawnWieldEventCount++;
            state.LastObservedUtc = DateTime.UtcNow;
        }

        internal static bool ShouldAttemptUnsafeClientSetWieldedItemIndexRepairDuringCreateAgentCorridor(
            Agent agent,
            bool isWieldedOnSpawn,
            out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
            {
                reason = "server-runtime";
                return false;
            }

            if (agent == null || agent.Index < 0)
            {
                reason = "agent-null";
                return false;
            }

            if (agent.IsMount)
            {
                reason = "mount-agent";
                return false;
            }

            if (agent.MissionPeer != null || IsLocalPeerControlledAgent(agent))
            {
                reason = "peer-controlled";
                return false;
            }

            if (isWieldedOnSpawn)
            {
                reason = "payload-onspawn";
                return true;
            }

            if (!TryGetClientTroopVisualInitStateSummary(
                    agent.Index,
                    out ClientCreateAgentExactVisualRuntimeState state,
                    out double observedAgeSeconds,
                    out string stateSummary))
            {
                reason = "create-agent-runtime-unobserved";
                return false;
            }

            if (observedAgeSeconds > ClientUnsafeSetWieldRepairCreateAgentCorridorTimeout.TotalSeconds)
            {
                reason =
                    "outside-create-agent-repair-window" +
                    "|ObservedAgeMs=" + (int)Math.Round(observedAgeSeconds * 1000d) +
                    "|" + stateSummary;
                return false;
            }

            if (!state.CreateAgentPayloadObserved)
            {
                reason = "create-agent-payload-pending";
                return true;
            }

            if (!state.CreateAgentPostfixObserved)
            {
                reason = "create-agent-postfix-pending";
                return true;
            }

            if (!HasClientTroopObservedStablePostCreateSignal(state, out string stableSignalReason))
            {
                reason = stableSignalReason ?? "post-create-stage-pending";
                return true;
            }

            string entryId = null;
            if (!TryResolveAuthoritativeTrackedEntryId(agent, out entryId) &&
                !TryResolveSelectableEntryId(agent, out entryId))
            {
                reason =
                    "entry-unresolved-outside-early-startup" +
                    "|ObservedAgeMs=" + (int)Math.Round(observedAgeSeconds * 1000d) +
                    "|" + stateSummary;
                return false;
            }

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (entryState != null && !entryState.IsHero)
            {
                if (!HasClientTroopObservedAuthoritativeMaterializationStage(
                        agent,
                        entryState,
                        state,
                        out string authoritativeMaterializationReason))
                {
                    reason = authoritativeMaterializationReason ?? "authoritative-materialized-entry-pending";
                    return true;
                }

                if (entryState.IsMounted && agent.MountAgent == null)
                {
                    if (!IsClientMountedTroopBaselineReadyWithoutLiveMountLink(
                            agent,
                            state,
                            out string mountedBaselineReason))
                    {
                        reason = "mount-link-pending";
                        return true;
                    }

                    reason = mountedBaselineReason ?? "mounted-baseline-ready-without-live-link";
                    return true;
                }

                if (!IsClientTroopVisualRefreshWeaponSeedReady(agent, entryState, out string weaponSeedReason))
                {
                    reason = weaponSeedReason ?? "weapon-seed-pending";
                    return true;
                }
            }

            reason =
                "create-agent-init-ready-no-repair" +
                "|ObservedAgeMs=" + (int)Math.Round(observedAgeSeconds * 1000d) +
                "|" + stateSummary;
            return false;
        }

        private static bool TryGetClientTroopVisualInitStateSummary(
            int agentIndex,
            out ClientCreateAgentExactVisualRuntimeState state,
            out double observedAgeSeconds,
            out string stateSummary)
        {
            observedAgeSeconds = 0d;
            stateSummary = "ClientInitState={State=unobserved}";
            if (!TryGetClientCreateAgentExactVisualState(agentIndex, out state) || state == null)
                return false;

            observedAgeSeconds = Math.Max(0d, (DateTime.UtcNow - state.FirstObservedUtc).TotalSeconds);
            stateSummary =
                "ClientInitState={PayloadObserved=" + state.CreateAgentPayloadObserved +
                ",PostfixObserved=" + state.CreateAgentPostfixObserved +
                ",AuthoritativeMaterializedObserved=" + state.AuthoritativeMaterializedEntryObserved +
                ",EquipmentSyncObserved=" + state.EquipmentSyncObserved +
                ",OnSpawnWieldEventCount=" + state.OnSpawnWieldEventCount +
                ",ObservedAgeMs=" + (int)Math.Round(observedAgeSeconds * 1000d) +
                ",EntryId=" + (state.EntryId ?? "null") +
                ",ResolutionState=" + (state.ResolutionState ?? "null") +
                ",ResolutionSource=" + (state.ResolutionSource ?? "null") + "}";
            return true;
        }

        private static bool HasClientTroopObservedStablePostCreateSignal(
            ClientCreateAgentExactVisualRuntimeState state,
            out string signalReason)
        {
            signalReason = null;
            if (state == null)
            {
                signalReason = "create-agent-runtime-unobserved";
                return false;
            }

            if (state.EquipmentSyncObserved)
            {
                signalReason = "equipment-sync-observed";
                return true;
            }

            if (state.OnSpawnWieldEventCount > 0)
            {
                signalReason = "on-spawn-wield-observed";
                return true;
            }

            if (DateTime.UtcNow - state.FirstObservedUtc >= ClientTroopVisualPostCreateSettleTimeout)
            {
                signalReason = "post-create-settle-timeout";
                return true;
            }

            signalReason = "post-create-stage-pending";
            return false;
        }

        internal static void ObserveClientAuthoritativeMaterializedAgentEntrySnapshot(
            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot snapshot,
            string source)
        {
            if (GameNetwork.IsServer || snapshot == null)
                return;

            var materializedSnapshot = new CoopBattleEntryStatusBridgeFile.AuthoritativeMaterializedAgentEntrySnapshot
            {
                BattleId = BattleSnapshotRuntimeState.GetCurrent()?.BattleId ?? string.Empty,
                MissionName = snapshot.MissionName ?? string.Empty,
                Source = source ?? snapshot.Source ?? "unknown",
                EntryCount = snapshot.AuthoritativeMaterializedAgentEntryCount,
                AgentEntries = snapshot.AuthoritativeMaterializedAgentEntries ?? string.Empty,
                UpdatedUtc = snapshot.UpdatedUtc
            };
            ObserveClientAuthoritativeMaterializedAgentEntrySnapshot(materializedSnapshot, source);
        }

        internal static void ObserveClientAuthoritativeMaterializedAgentEntrySnapshot(
            CoopBattleEntryStatusBridgeFile.AuthoritativeMaterializedAgentEntrySnapshot snapshot,
            string source)
        {
            if (GameNetwork.IsServer || snapshot == null)
                return;

            _clientUseStringIdExactEquipmentPath = snapshot.UseStringIdExactEquipmentPath;
            Dictionary<int, string> mappings =
                CoopBattleEntryStatusBridgeFile.DeserializeAgentEntryMap(snapshot.AgentEntries);
            bool ignoreRegressiveEmptySnapshot =
                snapshot.EntryCount <= 0 &&
                (mappings == null || mappings.Count == 0) &&
                (_clientAuthoritativeMaterializedEntryIdByAgentIndex.Count > 0 ||
                 _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count > 0);
            if (ignoreRegressiveEmptySnapshot)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: ignored regressive empty client authoritative materialized agent snapshot because live authoritative mappings already exist. " +
                    "ObservedAgentCount=" + _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count +
                    " TrackedEntryCount=" + _clientAuthoritativeMaterializedEntryIdByAgentIndex.Count +
                    " Source=" + (source ?? snapshot.Source ?? "unknown"));
                return;
            }

            _lastClientAuthoritativeMaterializedEntrySnapshotObservedUtc = DateTime.UtcNow;
            _lastClientAuthoritativeMaterializedEntrySnapshotEntryCount = Math.Max(0, snapshot.EntryCount);
            ApplyClientAuthoritativeMaterializedAgentEntrySnapshot(
                mappings,
                snapshot.EntryCount,
                source ?? snapshot.Source ?? "unknown");

            Mission mission = Mission.Current;
            if (mission != null)
            {
                BattleMapSpawnHandoffPatch.TryProcessDeferredClientCreateAgentMessages(
                    mission,
                    (source ?? snapshot.Source ?? "unknown") + " authoritative-materialized-entry");
            }
        }

        private static void ApplyClientAuthoritativeMaterializedAgentEntrySnapshot(
            Dictionary<int, string> mappings,
            int snapshotCount,
            string source)
        {
            if (GameNetwork.IsServer || mappings == null || mappings.Count == 0)
                return;

            Mission mission = Mission.Current;
            TryRefreshClientPostPossessionExactVisualPauseWindow(
                mission,
                (source ?? "authoritative materialized agent snapshot") + " post-possession-arm");
            int appliedCount = 0;
            int updatedPendingCount = 0;
            int queuedCount = 0;
            int deferredInitCount = 0;
            int skippedQueueCount = 0;
            int reconnectFinalizeSuppressedCount = 0;
            int liveControlledSuppressedCount = 0;
            int selectionPausedCount = 0;
            int postPossessionPausedCount = 0;
            int skippedStalePayloadCount = 0;
            int reconnectFinalizeDroppedPendingCount =
                DropPendingClientExactVisualOverlaysForReconnectFinalize(
                    (source ?? "authoritative materialized agent snapshot") + " reconnect-finalize");
            int liveControlledDroppedPendingCount =
                DropPendingClientTroopExactVisualOverlaysForLiveControl(
                    (source ?? "authoritative materialized agent snapshot") + " live-control");
            bool pauseTroopFinalizesForReconnectFinalize =
                ShouldPauseClientExactVisualOverlaysForReconnectFinalize(out _);
            bool pauseTroopFinalizesForSelectionScreen =
                ShouldPausePendingClientExactVisualOverlaysForSelectionScreen(out _);
            foreach (KeyValuePair<int, string> mapping in mappings)
            {
                int agentIndex = mapping.Key;
                string entryId = mapping.Value;
                if (agentIndex < 0 || string.IsNullOrWhiteSpace(entryId))
                    continue;

                if (TryGetClientCreateAgentExactVisualState(agentIndex, out ClientCreateAgentExactVisualRuntimeState createAgentState) &&
                    createAgentState != null &&
                    createAgentState.CreateAgentPayloadObserved &&
                    !DoesClientCreateAgentRuntimePayloadMatchEntryId(createAgentState, entryId, out string payloadMismatchReason))
                {
                    skippedStalePayloadCount++;
                    ClearClientTrackedMaterializedAgentIdentityState(
                        agentIndex,
                        source ?? "unknown",
                        "stale-authoritative-materialized-agent-snapshot|" + payloadMismatchReason,
                        preserveCreateAgentRuntime: true,
                        logClear: true);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: skipped stale client authoritative materialized agent snapshot mapping because it did not match the current CreateAgent payload. " +
                        "AgentIndex=" + agentIndex +
                        " EntryId=" + entryId +
                        " PayloadCharacterId=" + (createAgentState.PayloadCharacterId ?? "null") +
                        " PayloadSide=" + createAgentState.PayloadSide +
                        " PayloadGeneration=" + createAgentState.PayloadGeneration +
                        " Reason=" + payloadMismatchReason +
                        " Source=" + (source ?? "unknown"));
                    continue;
                }

                _materializedArmyEntryIdByAgentIndex.TryGetValue(agentIndex, out string previousTrackedEntryId);
                _materializedArmyEntryIdByAgentIndex[agentIndex] = entryId;
                _clientAuthoritativeMaterializedEntryIdByAgentIndex[agentIndex] = entryId;
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agentIndex] = entryId;
                _clientAuthoritativeMaterializedEntryObservedAgentIndices.Add(agentIndex);
                if (!string.IsNullOrWhiteSpace(previousTrackedEntryId) &&
                    !string.Equals(previousTrackedEntryId, entryId, StringComparison.Ordinal))
                {
                    _exactNativeClientVisualOverlayAppliedAgentIndices.Remove(agentIndex);
                    _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.Remove(agentIndex);
                }

                RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
                if (entryState != null)
                {
                    if (string.Equals(entryState.SideId, "attacker", StringComparison.OrdinalIgnoreCase))
                        _materializedArmySideByAgentIndex[agentIndex] = BattleSideEnum.Attacker;
                    else if (string.Equals(entryState.SideId, "defender", StringComparison.OrdinalIgnoreCase))
                        _materializedArmySideByAgentIndex[agentIndex] = BattleSideEnum.Defender;
                }

                if (TryGetClientCreateAgentExactVisualState(agentIndex, out ClientCreateAgentExactVisualRuntimeState state) &&
                    state != null)
                {
                    state.EntryId = entryId;
                    state.ResolutionState = "authoritative-materialized-agent-snapshot";
                    state.ResolutionSource = source ?? "unknown";
                    state.AuthoritativeMaterializedEntryObserved = true;
                    state.LastObservedUtc = DateTime.UtcNow;
                }

                if (_pendingExactNativeClientVisualOverlaysByAgentIndex.TryGetValue(agentIndex, out PendingClientExactVisualOverlayState pendingState) &&
                    pendingState != null &&
                    !string.Equals(pendingState.EntryId, entryId, StringComparison.Ordinal))
                {
                    pendingState.EntryId = entryId;
                    updatedPendingCount++;
                }

                if (mission != null &&
                    TryGetActiveMissionAgentByIndex(mission, agentIndex, out Agent agent) &&
                    agent != null &&
                    !agent.IsMount &&
                    agent.IsHuman &&
                    agent.IsActive() &&
                    entryState != null &&
                    !IsHeroEntryEligibleForExactPersonalPerks(entryState))
                {
                    if (!IsClientTroopExactVisualInitReady(agent, entryState, out _))
                    {
                        deferredInitCount++;
                    }
                    else if (pauseTroopFinalizesForReconnectFinalize)
                    {
                        reconnectFinalizeSuppressedCount++;
                    }
                    else if (pauseTroopFinalizesForSelectionScreen)
                    {
                        selectionPausedCount++;
                    }
                    else if (ShouldSuppressClientTroopExactVisualOverlayForLiveControl(agent, out _))
                    {
                        liveControlledSuppressedCount++;
                    }
                    else if (ShouldPauseClientPostPossessionExactVisualForAgent(agent, out _))
                    {
                        postPossessionPausedCount++;
                    }
                    else
                    {
                        double delaySeconds = 0.18d + Math.Min(1.40d, queuedCount * 0.03d);
                        bool queued = TryQueueClientExactCampaignVisualOverlay(
                            mission,
                            agent,
                            entryId,
                            (source ?? "authoritative materialized agent snapshot") + " delayed troop finalize",
                            delaySeconds,
                            force: true,
                            includeWeaponsForRefresh: _clientUseStringIdExactEquipmentPath);
                        if (queued)
                        {
                            queuedCount++;
                        }
                        else
                        {
                            skippedQueueCount++;
                        }
                    }
                }

                appliedCount++;
            }

            if (appliedCount > 0)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: applied client authoritative materialized agent entry snapshot. " +
                    "EntryCount=" + appliedCount +
                    " PendingEntryUpdates=" + updatedPendingCount +
                    " QueuedTroopFinalizes=" + queuedCount +
                    " DeferredInitTroopFinalizes=" + deferredInitCount +
                    " ReconnectFinalizeSuppressedTroopFinalizes=" + reconnectFinalizeSuppressedCount +
                    " ReconnectFinalizeDroppedPendingOverlays=" + reconnectFinalizeDroppedPendingCount +
                    " LiveControlledSuppressedTroopFinalizes=" + liveControlledSuppressedCount +
                    " LiveControlledDroppedPendingOverlays=" + liveControlledDroppedPendingCount +
                    " SelectionPausedTroopFinalizes=" + selectionPausedCount +
                    " PostPossessionPausedTroopFinalizes=" + postPossessionPausedCount +
                    " SkippedQueueTroopFinalizes=" + skippedQueueCount +
                    " SkippedStalePayloadMappings=" + skippedStalePayloadCount +
                    " UseStringIdExactEquipmentPath=" + _clientUseStringIdExactEquipmentPath +
                    " SnapshotCount=" + snapshotCount +
                    " Source=" + (source ?? "unknown"));
            }
        }

        internal static bool IsClientReconnectFinalizeReady(out string readinessSummary)
        {
            readinessSummary = string.Empty;
            if (GameNetwork.IsServer)
            {
                readinessSummary = "not-client";
                return false;
            }

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot status = CoopBattleEntryStatusBridgeFile.ReadStatus();
            if (status == null)
            {
                readinessSummary = "status-null";
                return false;
            }

            string readinessStage = status.BattleDataReadinessStage?.Trim() ?? string.Empty;
            if (!string.Equals(readinessStage, "ReconnectFinalize", StringComparison.OrdinalIgnoreCase))
            {
                readinessSummary =
                    "readiness-stage-not-reconnect-finalize" +
                    " Stage=" + readinessStage +
                    " BattleDataReady=" + status.BattleDataReady +
                    " HasAgent=" + status.HasAgent;
                return false;
            }

            if (status.HasAgent)
            {
                readinessSummary = "already-has-agent";
                return false;
            }

            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out string battleSnapshotReadinessSummary))
            {
                readinessSummary = "battle-snapshot-not-applied " + (battleSnapshotReadinessSummary ?? "unknown");
                return false;
            }

            if (_lastClientAuthoritativeMaterializedEntrySnapshotObservedUtc == DateTime.MinValue)
            {
                readinessSummary =
                    "authoritative-materialized-entry-snapshot-unobserved" +
                    " ExpectedEntryCount=" + status.AuthoritativeMaterializedAgentEntryCount;
                return false;
            }

            if (_lastClientAuthoritativeMaterializedEntrySnapshotObservedUtc != DateTime.MinValue)
            {
                TimeSpan observedAge = DateTime.UtcNow - _lastClientAuthoritativeMaterializedEntrySnapshotObservedUtc;
                if (observedAge < ClientReconnectFinalizeSettleDelay)
                {
                    readinessSummary =
                        "authoritative-materialized-entry-snapshot-settle-pending" +
                        " ObservedAgeSeconds=" + observedAge.TotalSeconds.ToString("F2") +
                        " PendingSettleSeconds=" + ClientReconnectFinalizeSettleDelay.TotalSeconds.ToString("F2") +
                        " ObservedAgentCount=" + _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count +
                        " SnapshotEntryCount=" + _lastClientAuthoritativeMaterializedEntrySnapshotEntryCount;
                    return false;
                }
            }

            if (_pendingExactNativeClientVisualOverlaysByAgentIndex.Count > 0)
            {
                readinessSummary =
                    "pending-client-exact-visual-overlays" +
                    " PendingCount=" + _pendingExactNativeClientVisualOverlaysByAgentIndex.Count +
                    " ObservedAgentCount=" + _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count;
                return false;
            }

            int deferredRecoveryPendingCount =
                BattleMapSpawnHandoffPatch.GetDeferredClientRecoveryPendingCount(out string deferredRecoverySummary);
            if (deferredRecoveryPendingCount > 0)
            {
                readinessSummary =
                    "deferred-client-recovery-pending " +
                    (deferredRecoverySummary ?? "unknown");
                return false;
            }

            readinessSummary =
                "ready" +
                " ObservedAgentCount=" + _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count +
                " SnapshotEntryCount=" + _lastClientAuthoritativeMaterializedEntrySnapshotEntryCount +
                " PendingExactVisualOverlays=" + _pendingExactNativeClientVisualOverlaysByAgentIndex.Count +
                " DeferredClientRecoveryPending=" + deferredRecoveryPendingCount;
            return true;
        }

        private static bool TryGetActiveMissionAgentByIndex(Mission mission, int agentIndex, out Agent agent)
        {
            agent = null;
            if (mission?.AllAgents == null || agentIndex < 0)
                return false;

            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent candidate = mission.AllAgents[i];
                if (candidate == null || candidate.Index != agentIndex)
                    continue;

                agent = candidate;
                return true;
            }

            return false;
        }

        private static bool IsClientTroopExactVisualInitReady(
            Agent agent,
            RosterEntryState entryState,
            out string reason)
        {
            reason = null;
            if (agent == null || agent.Index < 0)
            {
                reason = "agent-null";
                return false;
            }

            if (!TryGetClientTroopVisualInitStateSummary(
                    agent.Index,
                    out ClientCreateAgentExactVisualRuntimeState state,
                    out double observedAgeSeconds,
                    out string stateSummary))
            {
                reason = "create-agent-runtime-unobserved";
                return false;
            }

            if (!state.CreateAgentPayloadObserved)
            {
                reason = "create-agent-payload-pending";
                return false;
            }

            if (!state.CreateAgentPostfixObserved)
            {
                reason = "create-agent-postfix-pending";
                return false;
            }

            if (!HasClientTroopObservedStablePostCreateSignal(state, out string stableSignalReason))
            {
                reason = stableSignalReason ?? "post-create-stage-pending";
                return false;
            }

            if (!HasClientTroopObservedAuthoritativeMaterializationStage(agent, entryState, state, out string authoritativeMaterializationReason))
            {
                reason = authoritativeMaterializationReason ?? "authoritative-materialized-entry-pending";
                return false;
            }

            if (entryState?.IsMounted == true)
            {
                bool heroMountedEntry = IsHeroEntryEligibleForExactPersonalPerks(entryState);
                if (agent.MountAgent == null)
                {
                    if (!heroMountedEntry &&
                        IsClientMountedTroopBaselineReadyWithoutLiveMountLink(agent, state, out string mountedBaselineReason))
                    {
                        reason = mountedBaselineReason;
                    }
                    else
                    {
                        if (observedAgeSeconds >= ClientMountedTroopMountLinkGracePeriod.TotalSeconds)
                        {
                            reason =
                                "mounted-entry-without-native-mount StableSignal=" +
                                (stableSignalReason ?? "unknown") +
                                " " +
                                stateSummary;
                            return false;
                        }

                        reason = "mount-link-pending";
                        return false;
                    }
                }
                else if (!agent.MountAgent.IsActive() || agent.MountAgent.Team == null || agent.MountAgent.Team.Side == BattleSideEnum.None)
                {
                    if (!heroMountedEntry &&
                        IsClientMountedTroopBaselineReadyWithoutLiveMountLink(agent, state, out string mountedBaselineReason))
                    {
                        reason = mountedBaselineReason;
                    }
                    else
                    {
                        reason = "mount-agent-not-ready";
                        return false;
                    }
                }
            }

            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState) &&
                !IsClientTroopVisualRefreshWeaponSeedReady(agent, entryState, out string weaponSeedReason))
            {
                reason = weaponSeedReason ?? "weapon-seed-pending";
                return false;
            }

            return true;
        }

        private static bool IsClientMountedTroopBaselineReadyWithoutLiveMountLink(
            Agent agent,
            ClientCreateAgentExactVisualRuntimeState state,
            out string reason)
        {
            reason = null;
            if (agent == null)
                return false;

            bool hasTrackedMountIndex = TryGetTrackedClientMountedHeroMountAgentIndex(
                agent.Index,
                out int trackedMountAgentIndex,
                out _);
            if (!hasTrackedMountIndex || trackedMountAgentIndex < 0)
                return false;

            bool hasMountedSpawnEquipment =
                agent.SpawnEquipment?[EquipmentIndex.Horse].Item != null ||
                agent.SpawnEquipment?[EquipmentIndex.HorseHarness].Item != null;
            if (!hasMountedSpawnEquipment)
                return false;

            bool hasMountedMissionState =
                state != null &&
                (state.EquipmentSyncObserved || state.OnSpawnWieldEventCount > 0);
            if (!hasMountedMissionState)
                return false;

            reason =
                "mounted-troop-baseline-ready-without-live-mount-link:" +
                "tracked=" + trackedMountAgentIndex +
                ",equipmentSyncObserved=" + (state?.EquipmentSyncObserved ?? false) +
                ",onSpawnWieldCount=" + (state?.OnSpawnWieldEventCount ?? 0);
            return true;
        }

        private static bool HasClientTroopObservedAuthoritativeMaterializationStage(
            Agent agent,
            RosterEntryState entryState,
            ClientCreateAgentExactVisualRuntimeState state,
            out string reason)
        {
            reason = null;
            if (agent == null)
            {
                reason = "agent-null";
                return false;
            }

            if (entryState == null || entryState.IsHero)
            {
                reason = "hero-or-entry-unresolved";
                return true;
            }

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            bool locallyControlled = localMissionPeer != null && ReferenceEquals(localMissionPeer.ControlledAgent, agent);
            if (agent.MissionPeer != null || locallyControlled)
            {
                reason = "peer-controlled";
                return true;
            }

            if (ExactCampaignArmyBootstrap.TryGetEntryId(agent, out string bootstrapEntryId) &&
                !string.IsNullOrWhiteSpace(bootstrapEntryId) &&
                string.Equals(bootstrapEntryId, entryState.EntryId, StringComparison.Ordinal))
            {
                reason = "native-bootstrap-origin";
                return true;
            }

            if (state?.AuthoritativeMaterializedEntryObserved == true)
            {
                reason = "authoritative-materialized-entry-observed";
                return true;
            }

            if (TryResolveClientHeuristicCreateAgentEntryId(
                    agent.Index,
                    requireSettled: true,
                    out string heuristicEntryId,
                    out string heuristicResolutionState,
                    out string heuristicResolutionSource,
                    out string heuristicReason) &&
                string.Equals(heuristicEntryId, entryState.EntryId, StringComparison.Ordinal))
            {
                reason =
                    heuristicReason +
                    "|ResolutionState=" + (heuristicResolutionState ?? "unknown") +
                    "|ResolutionSource=" + (heuristicResolutionSource ?? "unknown");
                return true;
            }

            reason = "authoritative-materialized-entry-pending";
            return false;
        }

        private static bool IsLocalPeerControlledAgent(Agent agent)
        {
            if (agent == null || GameNetwork.IsServer)
                return false;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            Agent controlledAgent = localMissionPeer?.ControlledAgent;
            return controlledAgent != null && ReferenceEquals(controlledAgent, agent);
        }

        private static Agent GetLocalPeerControlledAgent()
        {
            if (GameNetwork.IsServer)
                return null;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            return localMissionPeer?.ControlledAgent ?? Agent.Main;
        }

        private static void TryRefreshClientPostPossessionExactVisualPauseWindow(
            Mission mission,
            string source)
        {
            if (mission == null || GameNetwork.IsServer)
                return;

            if (!ReferenceEquals(_lastClientPostPossessionExactVisualPauseMission, mission))
            {
                _lastClientPostPossessionExactVisualPauseMission = mission;
                _clientPostPossessionExactVisualPauseResumeUtc = DateTime.MinValue;
                _clientPostPossessionExactVisualPauseControlledAgentIndex = -1;
                _clientPostControlLossHeroExactVisualPauseResumeUtc = DateTime.MinValue;
                _clientPostControlLossHeroExactVisualPauseLostAgentIndex = -1;
                _clientPostPossessionMountedTroopWeaponRefreshResumeUtc = DateTime.MinValue;
                _clientPostPossessionMountedTroopWeaponRefreshControlledAgentIndex = -1;
                _lastObservedClientControlledAgentIndexForExactVisualPause = int.MinValue;
            }

            Agent controlledAgent = GetLocalPeerControlledAgent();
            int currentControlledAgentIndex =
                controlledAgent != null && controlledAgent.IsActive()
                    ? controlledAgent.Index
                    : -1;
            int previousControlledAgentIndex = _lastObservedClientControlledAgentIndexForExactVisualPause;
            if (currentControlledAgentIndex == previousControlledAgentIndex)
                return;

            _lastObservedClientControlledAgentIndexForExactVisualPause = currentControlledAgentIndex;
            if (previousControlledAgentIndex == int.MinValue)
                return;

            if (currentControlledAgentIndex < 0)
            {
                if (previousControlledAgentIndex >= 0)
                    _clientLocalHeroLiveTakeoverSuppressionByAgentIndex.Remove(previousControlledAgentIndex);

                if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                    return;

                if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out _))
                    return;

                DateTime lossNowUtc = DateTime.UtcNow;
                DateTime lossResumeUtc = lossNowUtc.AddSeconds(ClientPostPossessionExactVisualPauseSeconds);
                if (lossResumeUtc <= _clientPostControlLossHeroExactVisualPauseResumeUtc &&
                    _clientPostControlLossHeroExactVisualPauseLostAgentIndex == previousControlledAgentIndex)
                {
                    return;
                }

                _clientPostControlLossHeroExactVisualPauseResumeUtc = lossResumeUtc;
                _clientPostControlLossHeroExactVisualPauseLostAgentIndex = previousControlledAgentIndex;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: armed client post-control-loss hero exact visual stabilization window. " +
                    "LostControlledAgentIndex=" + previousControlledAgentIndex +
                    " DurationSeconds=" + ClientPostPossessionExactVisualPauseSeconds.ToString("0.00") +
                    " PendingCount=" + _pendingExactNativeClientVisualOverlaysByAgentIndex.Count +
                    " Source=" + (source ?? "unknown"));
                return;
            }

            if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                return;

            if (previousControlledAgentIndex >= 0 &&
                previousControlledAgentIndex != currentControlledAgentIndex)
            {
                _clientLocalHeroLiveTakeoverSuppressionByAgentIndex.Remove(previousControlledAgentIndex);
            }

            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out _))
                return;

            _clientPostControlLossHeroExactVisualPauseResumeUtc = DateTime.MinValue;
            _clientPostControlLossHeroExactVisualPauseLostAgentIndex = -1;

            double durationSeconds =
                previousControlledAgentIndex >= 0
                    ? ClientPostPossessionExactVisualPauseSeconds
                    : ClientPostPossessionExactVisualAcquirePauseSeconds;
            DateTime nowUtc = DateTime.UtcNow;
            DateTime resumeUtc = nowUtc.AddSeconds(durationSeconds);
            if (resumeUtc <= _clientPostPossessionExactVisualPauseResumeUtc &&
                _clientPostPossessionExactVisualPauseControlledAgentIndex == currentControlledAgentIndex)
            {
                return;
            }

            _clientPostPossessionExactVisualPauseResumeUtc = resumeUtc;
            _clientPostPossessionExactVisualPauseControlledAgentIndex = currentControlledAgentIndex;
            _clientPostPossessionMountedTroopWeaponRefreshResumeUtc =
                nowUtc.AddSeconds(Math.Max(durationSeconds, ClientPostPossessionMountedTroopWeaponRefreshCooldownSeconds));
            _clientPostPossessionMountedTroopWeaponRefreshControlledAgentIndex = currentControlledAgentIndex;
            int droppedPendingTroopOverlays =
                DropPendingClientTroopExactVisualOverlaysForLiveControl(
                    (source ?? "client post-possession exact visual stabilization") + " live-control-arm");
            ModLogger.Info(
                "CoopMissionSpawnLogic: armed client post-possession exact visual stabilization window. " +
                "ControlledAgentIndex=" + currentControlledAgentIndex +
                " PreviousControlledAgentIndex=" + previousControlledAgentIndex +
                " DurationSeconds=" + durationSeconds.ToString("0.00") +
                " MountedTroopWeaponCooldownSeconds=" +
                Math.Max(durationSeconds, ClientPostPossessionMountedTroopWeaponRefreshCooldownSeconds).ToString("0.00") +
                " DroppedPendingTroopOverlays=" + droppedPendingTroopOverlays +
                " PendingCount=" + _pendingExactNativeClientVisualOverlaysByAgentIndex.Count +
                " Source=" + (source ?? "unknown"));
        }

        private static bool ShouldSuppressClientTroopExactVisualOverlaysForLiveControl(out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
                return false;

            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out _))
                return false;

            Agent controlledAgent = GetLocalPeerControlledAgent();
            if (controlledAgent == null || !controlledAgent.IsActive())
                return false;

            reason =
                "ControlledAgentIndex=" + controlledAgent.Index +
                " LocalPeerHasLiveControl=true";
            return true;
        }

        private static bool ShouldSuppressClientTroopExactVisualOverlayForLiveControl(
            Agent agent,
            out string reason)
        {
            reason = null;
            if (!ShouldSuppressClientTroopExactVisualOverlaysForLiveControl(out string baseReason))
                return false;

            if (agent != null && IsLocalPeerControlledAgent(agent))
                return false;

            reason = agent == null
                ? baseReason
                : baseReason + " TargetAgentIndex=" + agent.Index;
            return true;
        }

        private static void PurgeExpiredClientLocalHeroLiveTakeoverSuppressions()
        {
            if (_clientLocalHeroLiveTakeoverSuppressionByAgentIndex.Count == 0)
                return;

            DateTime nowUtc = DateTime.UtcNow;
            List<int> expiredAgentIndices = null;
            foreach (KeyValuePair<int, ClientLocalHeroLiveTakeoverSuppressionState> pair in _clientLocalHeroLiveTakeoverSuppressionByAgentIndex)
            {
                if (pair.Value == null || pair.Value.ResumeUtc <= nowUtc)
                {
                    if (expiredAgentIndices == null)
                        expiredAgentIndices = new List<int>();

                    expiredAgentIndices.Add(pair.Key);
                }
            }

            if (expiredAgentIndices == null)
                return;

            for (int i = 0; i < expiredAgentIndices.Count; i++)
                _clientLocalHeroLiveTakeoverSuppressionByAgentIndex.Remove(expiredAgentIndices[i]);
        }

        private static bool TryGetActiveClientLocalHeroLiveTakeoverSuppression(
            int riderAgentIndex,
            string targetEntryId,
            out ClientLocalHeroLiveTakeoverSuppressionState suppressionState)
        {
            suppressionState = null;
            if (riderAgentIndex < 0)
                return false;

            PurgeExpiredClientLocalHeroLiveTakeoverSuppressions();
            if (!_clientLocalHeroLiveTakeoverSuppressionByAgentIndex.TryGetValue(riderAgentIndex, out suppressionState) ||
                suppressionState == null)
            {
                suppressionState = null;
                return false;
            }

            if (!string.IsNullOrWhiteSpace(targetEntryId) &&
                !string.IsNullOrWhiteSpace(suppressionState.EntryId) &&
                !string.Equals(targetEntryId, suppressionState.EntryId, StringComparison.Ordinal))
            {
                suppressionState = null;
                return false;
            }

            return true;
        }

        internal static bool TryArmClientLocalHeroLiveTakeoverSuppression(
            Mission mission,
            Agent agent,
            string preferredEntryId,
            string source,
            out string reason)
        {
            reason = null;
            if (mission == null || agent == null || agent.IsMount || GameNetwork.IsServer || !GameNetwork.IsClient)
                return false;

            if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                return false;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            if (localMissionPeer == null)
                return false;

            Agent localControlledAgent = localMissionPeer.ControlledAgent;
            if (localControlledAgent != null && !ReferenceEquals(localControlledAgent, agent))
                return false;

            string entryId = preferredEntryId;
            if (string.IsNullOrWhiteSpace(entryId) || BattleSnapshotRuntimeState.GetEntryState(entryId) == null)
                entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);
            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return false;

            bool hasPreExistingClientExactVisualApply =
                _exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index) &&
                _exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(agent.Index, out string appliedEntryId) &&
                string.Equals(appliedEntryId, entryId, StringComparison.Ordinal);

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(agent.Index, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                if (!hasPreExistingClientExactVisualApply)
                    return false;
            }
            else
            {
                if (state.DeathObserved || state.PeerBound)
                    return false;

                bool staleRemoteHeroVisualState =
                    state.ExactVisualApplied ||
                    state.Stage >= StrictExactHeroTransferStage.ExactVisualApplied ||
                    hasPreExistingClientExactVisualApply;
                if (!staleRemoteHeroVisualState)
                    return false;

                if (!string.IsNullOrWhiteSpace(state.EntryId) &&
                    !string.Equals(state.EntryId, entryId, StringComparison.Ordinal))
                {
                    return false;
                }
            }

            DateTime nowUtc = DateTime.UtcNow;
            DateTime resumeUtc = nowUtc.Add(ClientLocalHeroLiveTakeoverSuppressDuration);
            _clientLocalHeroLiveTakeoverSuppressionByAgentIndex[agent.Index] = new ClientLocalHeroLiveTakeoverSuppressionState
            {
                EntryId = entryId,
                ResumeUtc = resumeUtc,
                Source = source,
                Reason = "already-live-local-hero-takeover"
            };

            reason =
                "AgentIndex=" + agent.Index +
                " EntryId=" + entryId +
                " ResumeUtc=" + resumeUtc.ToString("O") +
                " Source=" + (source ?? "unknown");
            ModLogger.Info(
                "CoopMissionSpawnLogic: armed client local hero live-takeover exact visual suppression window. " +
                reason);
            return true;
        }

        internal static bool IsClientLocalHeroLiveTakeoverSuppressionActive(
            int riderAgentIndex,
            string entryId,
            out string reason)
        {
            reason = null;
            if (!TryGetActiveClientLocalHeroLiveTakeoverSuppression(riderAgentIndex, entryId, out ClientLocalHeroLiveTakeoverSuppressionState suppressionState))
                return false;

            double remainingSeconds = (suppressionState.ResumeUtc - DateTime.UtcNow).TotalSeconds;
            if (remainingSeconds <= 0d)
                return false;

            reason =
                "AgentIndex=" + riderAgentIndex +
                " EntryId=" + (suppressionState.EntryId ?? entryId ?? "null") +
                " RemainingSeconds=" + remainingSeconds.ToString("0.00") +
                " Reason=" + (suppressionState.Reason ?? "unknown");
            return true;
        }

        private static bool ShouldSuppressClientHeroExactVisualOverlayForLocalLiveTakeover(
            Agent agent,
            string targetEntryId,
            RosterEntryState targetEntryState,
            out string reason)
        {
            reason = null;
            if (agent == null || GameNetwork.IsServer || !GameNetwork.IsClient)
                return false;

            if (!IsLocalPeerControlledAgent(agent))
                return false;

            if (targetEntryState == null || !IsHeroEntryEligibleForExactPersonalPerks(targetEntryState))
                return false;

            string effectiveTargetEntryId = string.IsNullOrWhiteSpace(targetEntryId)
                ? targetEntryState.EntryId
                : targetEntryId;
            if (string.IsNullOrWhiteSpace(effectiveTargetEntryId))
                return false;

            if (!IsClientLocalHeroLiveTakeoverSuppressionActive(agent.Index, effectiveTargetEntryId, out string suppressionReason))
                return false;

            reason =
                (suppressionReason ?? "client-local-hero-live-takeover") +
                " TargetTroopId=" + (agent.Character?.StringId ?? "null");
            return true;
        }

        private static bool ShouldSuppressClientHeroExactVisualOverlayForRemoteLiveControl(
            Agent agent,
            string targetEntryId,
            RosterEntryState targetEntryState,
            out string reason)
        {
            reason = null;
            if (agent == null || GameNetwork.IsServer || !GameNetwork.IsClient)
                return false;

            if (targetEntryState == null || !IsHeroEntryEligibleForExactPersonalPerks(targetEntryState))
                return false;

            if (agent.MissionPeer != null || IsLocalPeerControlledAgent(agent))
                return false;

            string effectiveTargetEntryId = string.IsNullOrWhiteSpace(targetEntryId)
                ? targetEntryState.EntryId
                : targetEntryId;
            if (string.IsNullOrWhiteSpace(effectiveTargetEntryId))
                return false;

            if (ShouldPauseClientExactVisualOverlaysBeforeLiveControl(out string beforeLiveControlReason))
            {
                reason =
                    "Reason=" + (beforeLiveControlReason ?? "before-live-control") +
                    " TargetAgentIndex=" + agent.Index +
                    " TargetEntryId=" + effectiveTargetEntryId +
                    " TargetTroopId=" + (agent.Character?.StringId ?? "null");
                return true;
            }

            if (ShouldPauseClientHeroExactVisualOverlaysAfterLocalControlLoss(out string controlLossReason))
            {
                reason =
                    "Reason=" + (controlLossReason ?? "post-control-loss") +
                    " TargetAgentIndex=" + agent.Index +
                    " TargetEntryId=" + effectiveTargetEntryId +
                    " TargetTroopId=" + (agent.Character?.StringId ?? "null");
                return true;
            }

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            Agent controlledAgent = localMissionPeer?.ControlledAgent;
            if (controlledAgent == null || !controlledAgent.IsActive() || ReferenceEquals(controlledAgent, agent))
                return false;

            string controlledEntryId = ResolveClientExactCampaignVisualOverlayEntryId(controlledAgent);
            if (string.IsNullOrWhiteSpace(controlledEntryId))
                return false;

            RosterEntryState controlledEntryState = BattleSnapshotRuntimeState.GetEntryState(controlledEntryId);
            if (controlledEntryState == null || IsHeroEntryEligibleForExactPersonalPerks(controlledEntryState))
                return false;

            if (string.Equals(controlledEntryId, effectiveTargetEntryId, StringComparison.Ordinal))
                return false;

            reason =
                "ControlledAgentIndex=" + controlledAgent.Index +
                " ControlledEntryId=" + controlledEntryId +
                " ControlledTroopId=" + (controlledAgent.Character?.StringId ?? "null") +
                " TargetAgentIndex=" + agent.Index +
                " TargetEntryId=" + effectiveTargetEntryId +
                " TargetTroopId=" + (agent.Character?.StringId ?? "null");
            return true;
        }

        private static bool ShouldPauseClientHeroExactVisualOverlaysAfterLocalControlLoss(out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
                return false;

            DateTime resumeUtc = _clientPostControlLossHeroExactVisualPauseResumeUtc;
            if (resumeUtc == DateTime.MinValue)
                return false;

            double remainingSeconds = (resumeUtc - DateTime.UtcNow).TotalSeconds;
            if (remainingSeconds <= 0d)
                return false;

            reason =
                "LostControlledAgentIndex=" + _clientPostControlLossHeroExactVisualPauseLostAgentIndex +
                " RemainingSeconds=" + remainingSeconds.ToString("0.00");
            return true;
        }

        private static bool ShouldPauseClientPostPossessionExactVisualForAgent(
            Agent agent,
            out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
                return false;

            DateTime resumeUtc = _clientPostPossessionExactVisualPauseResumeUtc;
            if (resumeUtc == DateTime.MinValue)
                return false;

            double remainingSeconds = (resumeUtc - DateTime.UtcNow).TotalSeconds;
            if (remainingSeconds <= 0d)
                return false;

            if (agent != null && IsLocalPeerControlledAgent(agent))
                return false;

            reason =
                "ControlledAgentIndex=" + _clientPostPossessionExactVisualPauseControlledAgentIndex +
                " RemainingSeconds=" + remainingSeconds.ToString("0.00");
            return true;
        }

        private static bool ShouldDowngradeClientMountedTroopWeaponOverlayRefresh(
            Agent agent,
            RosterEntryState entryState,
            out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer || agent == null || entryState == null || entryState.IsHero)
                return false;

            DateTime resumeUtc = _clientPostPossessionMountedTroopWeaponRefreshResumeUtc;
            if (resumeUtc == DateTime.MinValue)
                return false;

            double remainingSeconds = (resumeUtc - DateTime.UtcNow).TotalSeconds;
            if (remainingSeconds <= 0d)
                return false;

            bool mountedTroop = entryState.IsMounted || agent.MountAgent != null;
            if (!mountedTroop || IsLocalPeerControlledAgent(agent))
                return false;

            reason =
                "ControlledAgentIndex=" + _clientPostPossessionMountedTroopWeaponRefreshControlledAgentIndex +
                " RemainingSeconds=" + remainingSeconds.ToString("0.00");
            return true;
        }

        private static bool ShouldAllowClientTroopWeaponOverlayRefresh(
            Agent agent,
            RosterEntryState entryState,
            bool requestedIncludeWeapons,
            out string reason)
        {
            reason = null;
            if (!requestedIncludeWeapons)
            {
                reason = "requested-false";
                return false;
            }

            if (agent == null || entryState == null || entryState.IsHero)
            {
                reason = "agent-or-entry-invalid";
                return false;
            }

            bool locallyControlled = IsLocalPeerControlledAgent(agent);
            bool peerControlled = agent.MissionPeer != null || locallyControlled;
            if (locallyControlled)
            {
                reason = "local-controlled-live-wield-owned-by-client";
                return false;
            }

            if (!peerControlled && !_clientUseStringIdExactEquipmentPath)
            {
                reason = "generic-bulk-ai-weapons-disabled";
                return false;
            }

            if (!TryResolveAuthoritativeTrackedEntryId(agent, out string authoritativeEntryId) ||
                !string.Equals(authoritativeEntryId, entryState.EntryId, StringComparison.Ordinal))
            {
                reason = "authoritative-entry-pending";
                return false;
            }

            if (!IsClientTroopExactVisualInitReady(agent, entryState, out string initReason))
            {
                reason = initReason ?? "init-pending";
                return false;
            }

            if (ShouldDowngradeClientMountedTroopWeaponOverlayRefresh(agent, entryState, out string mountedCooldownReason))
            {
                reason = "mounted-post-possession-combat-stabilization:" + (mountedCooldownReason ?? "unknown");
                return false;
            }

            return true;
        }

        private static bool ClearTrackedClientMountedHeroMountAgentIndexState(int riderAgentIndex)
        {
            if (riderAgentIndex < 0)
                return false;

            bool hadTrackedMount =
                _clientMountedHeroMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out int trackedMountAgentIndex);
            if (!hadTrackedMount)
                return false;

            _clientMountedHeroMountAgentIndexByRiderAgentIndex.Remove(riderAgentIndex);
            if (_clientMountedHeroRiderAgentIndexByMountAgentIndex.TryGetValue(trackedMountAgentIndex, out int trackedRiderAgentIndex) &&
                trackedRiderAgentIndex == riderAgentIndex)
            {
                _clientMountedHeroRiderAgentIndexByMountAgentIndex.Remove(trackedMountAgentIndex);
                _clientMountedHeroEntryIdByMountAgentIndex.Remove(trackedMountAgentIndex);
            }

            return true;
        }

        private static bool ClearClientMountedHeroPayloadMountAgentIndexState(int riderAgentIndex)
        {
            if (riderAgentIndex < 0)
                return false;

            bool hadTrackedMount =
                _clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out int trackedMountAgentIndex);
            if (!hadTrackedMount)
                return false;

            _clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex.Remove(riderAgentIndex);
            if (_clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.TryGetValue(trackedMountAgentIndex, out int trackedRiderAgentIndex) &&
                trackedRiderAgentIndex == riderAgentIndex)
            {
                _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.Remove(trackedMountAgentIndex);
            }

            return true;
        }

        private static void RememberClientMountedHeroMountPayloadIndex(int riderAgentIndex, int mountAgentIndex)
        {
            if (riderAgentIndex < 0 || mountAgentIndex < 0)
                return;

            if (_clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out int previousMountAgentIndex) &&
                previousMountAgentIndex != mountAgentIndex &&
                _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.TryGetValue(previousMountAgentIndex, out int previousRiderAgentIndex) &&
                previousRiderAgentIndex == riderAgentIndex)
            {
                _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.Remove(previousMountAgentIndex);
            }

            _clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex[riderAgentIndex] = mountAgentIndex;
            _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex[mountAgentIndex] = riderAgentIndex;
        }

        private static void TrackClientMountedHeroMountAgentIndex(int riderAgentIndex, int mountAgentIndex, string entryId)
        {
            if (riderAgentIndex < 0 || mountAgentIndex < 0)
                return;

            RememberClientMountedHeroMountPayloadIndex(riderAgentIndex, mountAgentIndex);

            if (_clientMountedHeroMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out int previousMountAgentIndex) &&
                previousMountAgentIndex != mountAgentIndex &&
                _clientMountedHeroRiderAgentIndexByMountAgentIndex.TryGetValue(previousMountAgentIndex, out int previousRiderAgentIndex) &&
                previousRiderAgentIndex == riderAgentIndex)
            {
                _clientMountedHeroRiderAgentIndexByMountAgentIndex.Remove(previousMountAgentIndex);
                _clientMountedHeroEntryIdByMountAgentIndex.Remove(previousMountAgentIndex);
            }

            _clientMountedHeroMountAgentIndexByRiderAgentIndex[riderAgentIndex] = mountAgentIndex;
            _clientMountedHeroRiderAgentIndexByMountAgentIndex[mountAgentIndex] = riderAgentIndex;
            if (!string.IsNullOrWhiteSpace(entryId))
                _clientMountedHeroEntryIdByMountAgentIndex[mountAgentIndex] = entryId;
        }

        private static void TrackClientMountedHeroMountAgentIndex(Agent riderAgent, string entryId)
        {
            if (riderAgent == null || riderAgent.IsMount || riderAgent.Index < 0 || string.IsNullOrWhiteSpace(entryId))
                return;

            Agent mountAgent = riderAgent.MountAgent;
            if (mountAgent == null || mountAgent.Index < 0)
                return;

            TrackClientMountedHeroMountAgentIndex(riderAgent.Index, mountAgent.Index, entryId);
            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            UpdateStrictExactHeroTransferEntryState(riderAgent.Index, entryId, entryState, "track-mounted-hero-mount-live");
            UpdateStrictExactHeroTransferMountLinkState(riderAgent, entryState, "track-mounted-hero-mount-live");
        }

        internal static void TryTrackClientMountedHeroMountAgentIndex(Agent riderAgent)
        {
            if (riderAgent == null || riderAgent.IsMount || riderAgent.MountAgent == null || GameNetwork.IsServer)
                return;

            string entryId = ResolveClientExactCampaignVisualOverlayEntryId(riderAgent);
            if (string.IsNullOrWhiteSpace(entryId))
                return;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return;

            TrackClientMountedHeroMountAgentIndex(riderAgent, entryId);
        }

        internal static void TryTrackClientMountedHeroMountAgentIndex(
            Agent riderAgent,
            int mountAgentIndex,
            string preferredEntryId = null)
        {
            if (riderAgent == null || riderAgent.IsMount || riderAgent.Index < 0 || mountAgentIndex < 0 || GameNetwork.IsServer)
                return;

            string entryId = preferredEntryId;
            if (string.IsNullOrWhiteSpace(entryId))
                entryId = ResolveClientExactCampaignVisualOverlayEntryId(riderAgent);
            if (string.IsNullOrWhiteSpace(entryId))
                return;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return;

            TrackClientMountedHeroMountAgentIndex(riderAgent.Index, mountAgentIndex, entryId);
            UpdateStrictExactHeroTransferEntryState(riderAgent.Index, entryId, entryState, "track-mounted-hero-mount-index");
            UpdateStrictExactHeroTransferPayloadState(riderAgent.Index, mountAgentIndex, "track-mounted-hero-mount-index");
            UpdateStrictExactHeroTransferMountLinkState(riderAgent, entryState, "track-mounted-hero-mount-index");
        }

        internal static void TryTrackClientMountedHeroMountAgentIndexFromPayload(int riderAgentIndex, int mountAgentIndex)
        {
            if (GameNetwork.IsServer || riderAgentIndex < 0 || mountAgentIndex < 0)
                return;

            RememberClientMountedHeroMountPayloadIndex(riderAgentIndex, mountAgentIndex);
            UpdateStrictExactHeroTransferPayloadState(riderAgentIndex, mountAgentIndex, "track-mounted-hero-payload");
        }

        internal static bool HasTrackedClientMountedHeroMountAgentIndex(int riderAgentIndex)
        {
            if (riderAgentIndex < 0)
                return false;

            return (_clientMountedHeroMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out int trackedMountAgentIndex) &&
                    trackedMountAgentIndex >= 0) ||
                   (_clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out trackedMountAgentIndex) &&
                    trackedMountAgentIndex >= 0);
        }

        private static bool TryGetTrackedClientMountedHeroMountAgentIndex(
            int riderAgentIndex,
            out int mountAgentIndex,
            out string entryId)
        {
            mountAgentIndex = -1;
            entryId = null;
            if (riderAgentIndex < 0)
                return false;

            if ((!_clientMountedHeroMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out mountAgentIndex) ||
                 mountAgentIndex < 0) &&
                (!_clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex.TryGetValue(riderAgentIndex, out mountAgentIndex) ||
                 mountAgentIndex < 0))
            {
                mountAgentIndex = -1;
                return false;
            }

            if (!_clientMountedHeroEntryIdByMountAgentIndex.TryGetValue(mountAgentIndex, out entryId) ||
                string.IsNullOrWhiteSpace(entryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(riderAgentIndex, out entryId);
            }

            if (string.IsNullOrWhiteSpace(entryId))
                _materializedArmyEntryIdByAgentIndex.TryGetValue(riderAgentIndex, out entryId);

            return true;
        }

        private static bool RequiresTrackedClientMountedHeroMountLinkRepair(
            Agent riderAgent,
            RosterEntryState entryState,
            out int trackedMountAgentIndex,
            out string reason)
        {
            trackedMountAgentIndex = -1;
            reason = null;
            if (GameNetwork.IsServer ||
                riderAgent == null ||
                riderAgent.IsMount ||
                riderAgent.Index < 0 ||
                entryState == null ||
                !entryState.IsMounted ||
                riderAgent.MountAgent != null)
            {
                return false;
            }

            if (!TryGetTrackedClientMountedHeroMountAgentIndex(
                    riderAgent.Index,
                    out trackedMountAgentIndex,
                    out _))
            {
                return false;
            }

            reason = "MountLinkMissing tracked=" + trackedMountAgentIndex;
            return true;
        }

        private static bool TryRepairTrackedClientMountedHeroMountLink(
            Agent riderAgent,
            int trackedMountAgentIndex,
            string source,
            out string repairReason)
        {
            repairReason = null;
            if (riderAgent == null || riderAgent.IsMount || riderAgent.Index < 0 || trackedMountAgentIndex < 0)
            {
                repairReason = "mount-link-repair-invalid-rider";
                return false;
            }

            if (riderAgent.MountAgent != null)
            {
                repairReason = "mount-link-already-linked";
                return true;
            }

            if (AgentSetMountAgentMethod == null ||
                AgentUpdateMountAgentCacheMethod == null ||
                AgentUpdateRiderAgentCacheMethod == null)
            {
                repairReason = "mount-link-repair-reflection-unavailable";
                return false;
            }

            Agent mountAgent = Mission.MissionNetworkHelper.GetAgentFromIndex(trackedMountAgentIndex, canBeNull: true);
            if (mountAgent == null)
            {
                repairReason = "tracked-mount-agent-unavailable:" + trackedMountAgentIndex;
                return false;
            }

            if (!mountAgent.IsMount)
            {
                repairReason = "tracked-agent-not-mount:" + trackedMountAgentIndex;
                return false;
            }

            if (!mountAgent.IsActive())
            {
                repairReason = "tracked-mount-agent-inactive:" + trackedMountAgentIndex;
                return false;
            }

            if (mountAgent.Team == null || mountAgent.Team.Side == BattleSideEnum.None)
            {
                repairReason = "tracked-mount-agent-not-ready:" + trackedMountAgentIndex;
                return false;
            }

            if (mountAgent.RiderAgent != null && !ReferenceEquals(mountAgent.RiderAgent, riderAgent))
            {
                repairReason = "tracked-mount-owned-by-other-rider:" + mountAgent.RiderAgent.Index;
                return false;
            }

            try
            {
                AgentSetMountAgentMethod.Invoke(riderAgent, new object[] { mountAgent });
                AgentUpdateMountAgentCacheMethod.Invoke(riderAgent, new object[] { mountAgent });
                AgentUpdateRiderAgentCacheMethod.Invoke(mountAgent, new object[] { riderAgent });
                riderAgent.UpdateAgentStats();
                riderAgent.UpdateAgentProperties();
                mountAgent.UpdateAgentProperties();

                if (riderAgent.MountAgent == null || riderAgent.MountAgent.Index != mountAgent.Index)
                {
                    repairReason = "mount-link-cache-link-missing:" + trackedMountAgentIndex;
                    return false;
                }

                if (!TryGetTrackedClientMountedHeroMountAgentIndex(
                        riderAgent.Index,
                        out _,
                        out string entryId) ||
                    string.IsNullOrWhiteSpace(entryId))
                {
                    entryId = ResolveClientExactCampaignVisualOverlayEntryId(riderAgent);
                }

                if (!string.IsNullOrWhiteSpace(entryId))
                    TrackClientMountedHeroMountAgentIndex(riderAgent.Index, mountAgent.Index, entryId);

                repairReason = "mounted-hero-link-repaired:" + mountAgent.Index;
                RosterEntryState entryState = !string.IsNullOrWhiteSpace(entryId)
                    ? BattleSnapshotRuntimeState.GetEntryState(entryId)
                    : null;
                UpdateStrictExactHeroTransferEntryState(riderAgent.Index, entryId, entryState, source ?? "client mount-link repair");
                UpdateStrictExactHeroTransferMountLinkState(riderAgent, entryState, source ?? "client mount-link repair");
                ModLogger.Info(
                    "CoopMissionSpawnLogic: repaired tracked client mounted-hero rider-to-mount link. " +
                    "AgentIndex=" + riderAgent.Index +
                    " MountAgentIndex=" + mountAgent.Index +
                    " EntryId=" + (entryId ?? "null") +
                    " Source=" + (source ?? "unknown"));
                ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                    "client-mount-link-repair-success",
                    "AgentIndex=" + riderAgent.Index +
                    " MountAgentIndex=" + mountAgent.Index +
                    " EntryId=" + (entryId ?? "null") +
                    " Source=" + (source ?? "unknown"));
                return true;
            }
            catch (Exception ex)
            {
                Exception actual = ex is TargetInvocationException invocationEx && invocationEx.InnerException != null
                    ? invocationEx.InnerException
                    : ex;
                repairReason = "mounted-hero-link-repair-failed:" + actual.GetType().Name;
                return false;
            }
        }

        private static bool TryEnsureTrackedClientMountedHeroMountLinkReady(
            Agent riderAgent,
            RosterEntryState entryState,
            string source,
            out string reason)
        {
            reason = null;
            if (!RequiresTrackedClientMountedHeroMountLinkRepair(
                    riderAgent,
                    entryState,
                    out int trackedMountAgentIndex,
                    out string missingReason))
            {
                return true;
            }

            if (TryRepairTrackedClientMountedHeroMountLink(
                    riderAgent,
                    trackedMountAgentIndex,
                    source,
                    out string repairReason))
            {
                UpdateStrictExactHeroTransferMountLinkState(riderAgent, entryState, source, repairReason);
                reason = repairReason;
                return true;
            }

            reason = string.IsNullOrWhiteSpace(repairReason)
                ? missingReason
                : missingReason + " | " + repairReason;
            UpdateStrictExactHeroTransferMountLinkState(riderAgent, entryState, source, reason);
            return false;
        }

        internal static bool TryResolveTrackedClientMountedHeroMissingMountAgentHealth(
            int missingMountAgentIndex,
            out int riderAgentIndex,
            out string entryId)
        {
            riderAgentIndex = -1;
            entryId = null;
            if (missingMountAgentIndex < 0)
                return false;

            bool hasResolvedRider = _clientMountedHeroRiderAgentIndexByMountAgentIndex.TryGetValue(missingMountAgentIndex, out riderAgentIndex);
            bool hasPayloadRider = false;
            if (!hasResolvedRider)
                hasPayloadRider = _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.TryGetValue(missingMountAgentIndex, out riderAgentIndex);
            if (!hasResolvedRider && !hasPayloadRider)
                return false;

            Agent riderAgent = Mission.MissionNetworkHelper.GetAgentFromIndex(riderAgentIndex, canBeNull: true);
            if (riderAgent != null &&
                riderAgent.MountAgent != null &&
                riderAgent.MountAgent.Index != missingMountAgentIndex)
            {
                if (hasResolvedRider &&
                    _clientMountedHeroRiderAgentIndexByMountAgentIndex.TryGetValue(missingMountAgentIndex, out int trackedRiderAgentIndex) &&
                    trackedRiderAgentIndex == riderAgentIndex)
                {
                    _clientMountedHeroRiderAgentIndexByMountAgentIndex.Remove(missingMountAgentIndex);
                    _clientMountedHeroEntryIdByMountAgentIndex.Remove(missingMountAgentIndex);
                }

                _clientMountedHeroMountAgentIndexByRiderAgentIndex.Remove(riderAgentIndex);
                if (hasPayloadRider &&
                    _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.TryGetValue(missingMountAgentIndex, out int payloadTrackedRiderAgentIndex) &&
                    payloadTrackedRiderAgentIndex == riderAgentIndex)
                {
                    _clientMountedHeroPayloadRiderAgentIndexByMountAgentIndex.Remove(missingMountAgentIndex);
                }

                _clientMountedHeroPayloadMountAgentIndexByRiderAgentIndex.Remove(riderAgentIndex);
                riderAgentIndex = -1;
                return false;
            }

            if (!_clientMountedHeroEntryIdByMountAgentIndex.TryGetValue(missingMountAgentIndex, out entryId) ||
                string.IsNullOrWhiteSpace(entryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(riderAgentIndex, out entryId);
            }

            if (string.IsNullOrWhiteSpace(entryId))
                _materializedArmyEntryIdByAgentIndex.TryGetValue(riderAgentIndex, out entryId);

            return riderAgentIndex >= 0;
        }

        private static void RefreshClientExactCampaignVisualOverlayAgentIndexState(
            Agent agent,
            string source,
            string preferredEntryId = null,
            bool logRefresh = false)
        {
            if (agent == null)
                return;

            bool rebound =
                _exactNativeClientVisualOverlayAgentByIndex.TryGetValue(agent.Index, out Agent cachedAgent) &&
                !ReferenceEquals(cachedAgent, agent);

            string currentTroopId = agent.Character?.StringId;
            bool troopMismatch = false;
            string previousEntryId = null;
            bool exactEntryChanged = false;
            if (_exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(agent.Index, out string cachedEntryId) &&
                !string.IsNullOrWhiteSpace(cachedEntryId))
            {
                previousEntryId = cachedEntryId;
                exactEntryChanged =
                    !string.IsNullOrWhiteSpace(preferredEntryId) &&
                    !string.Equals(cachedEntryId, preferredEntryId, StringComparison.OrdinalIgnoreCase);
                RosterEntryState cachedEntryState = BattleSnapshotRuntimeState.GetEntryState(cachedEntryId);
                troopMismatch = cachedEntryState == null ||
                                !DoesClientVisualOverlayEntryMatchAgentTroop(cachedEntryState, currentTroopId);
            }

            if (!rebound && !troopMismatch && !exactEntryChanged)
            {
                _exactNativeClientVisualOverlayAgentByIndex[agent.Index] = agent;
                return;
            }

            ClearClientExactCampaignVisualOverlayAgentIndexState(
                agent.Index,
                source ?? "unknown",
                logClear: false,
                reason: "refresh-agent-index-state",
                preserveCreateAgentRuntime: true);
            _exactNativeClientVisualOverlayAgentByIndex[agent.Index] = agent;

            if (logRefresh)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: refreshed client exact visual overlay assignment cache. " +
                    "AgentIndex=" + agent.Index +
                    " PreviousEntryId=" + (previousEntryId ?? "null") +
                    " PreferredEntryId=" + (preferredEntryId ?? "null") +
                    " CurrentTroopId=" + (currentTroopId ?? "null") +
                    " Rebound=" + rebound +
                    " TroopMismatch=" + troopMismatch +
                    " ExactEntryChanged=" + exactEntryChanged +
                    " Source=" + (source ?? "unknown"));
            }
        }

        private static bool DoesClientVisualOverlayEntryMatchAgentTroop(RosterEntryState entryState, string currentTroopId)
        {
            if (entryState == null)
                return false;

            if (string.IsNullOrWhiteSpace(currentTroopId))
                return true;

            return string.Equals(entryState.CharacterId, currentTroopId, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(entryState.OriginalCharacterId, currentTroopId, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(entryState.SpawnTemplateId, currentTroopId, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(ResolveEntryMissionSafeFallbackTroopId(entryState), currentTroopId, StringComparison.OrdinalIgnoreCase) ||
                   string.Equals(ResolveEntryResolvedCharacterId(entryState), currentTroopId, StringComparison.OrdinalIgnoreCase);
        }

        private static string ResolveEntryResolvedCharacterId(RosterEntryState entryState)
        {
            if (entryState == null || string.IsNullOrWhiteSpace(entryState.EntryId))
                return null;

            return BattleSnapshotRuntimeState.TryResolveCharacterObject(entryState.EntryId)?.StringId;
        }

        private static void TryProcessPendingClientExactCampaignVisualOverlays(Mission mission)
        {
            if (mission == null || GameNetwork.IsServer || _pendingExactNativeClientVisualOverlaysByAgentIndex.Count == 0)
                return;

            DropPendingClientExactVisualOverlaysForReconnectFinalize("pending-client-exact-visual-process");
            DropPendingClientTroopExactVisualOverlaysForLiveControl("pending-client-exact-visual-process");
            if (_pendingExactNativeClientVisualOverlaysByAgentIndex.Count == 0)
                return;

            TryRefreshClientPostPossessionExactVisualPauseWindow(mission, "pending-client-exact-visual-process");
            if (ShouldPausePendingClientExactVisualOverlaysForSelectionScreen(out string pauseReason))
            {
                if (!string.Equals(_lastPendingClientExactVisualPauseReason, pauseReason, StringComparison.Ordinal))
                {
                    _lastPendingClientExactVisualPauseReason = pauseReason ?? string.Empty;
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: paused pending client exact visual overlay processing while local peer is still behind selection or reconnect-finalize gating. " +
                        "PendingCount=" + _pendingExactNativeClientVisualOverlaysByAgentIndex.Count +
                        " Reason=" + (_lastPendingClientExactVisualPauseReason ?? "unknown"));
                }

                return;
            }

            _lastPendingClientExactVisualPauseReason = string.Empty;
            DateTime nowUtc = DateTime.UtcNow;
            var completedAgentIndices = new List<int>();
            foreach (KeyValuePair<int, PendingClientExactVisualOverlayState> pendingPair in _pendingExactNativeClientVisualOverlaysByAgentIndex)
            {
                if (pendingPair.Value == null || nowUtc < pendingPair.Value.NotBeforeUtc)
                    continue;

                int agentIndex = pendingPair.Key;
                PendingClientExactVisualOverlayState pendingState = pendingPair.Value;
                Agent agent = Mission.MissionNetworkHelper.GetAgentFromIndex(agentIndex, canBeNull: true);
                bool expired = nowUtc - pendingState.CreatedUtc >= TimeSpan.FromSeconds(8.0);
                if (agent == null)
                {
                    if (expired)
                    {
                        completedAgentIndices.Add(agentIndex);
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: abandoned pending client exact visual overlay because agent never became available. " +
                            "AgentIndex=" + agentIndex +
                            " EntryId=" + (pendingState.EntryId ?? "null") +
                            " Retries=" + pendingState.RetryCount +
                            " Source=" + (pendingState.Source ?? "unknown"));
                    }
                    else
                    {
                        pendingState.RetryCount++;
                        pendingState.NotBeforeUtc = nowUtc.AddMilliseconds(150);
                }
                    continue;
                }

                if (ShouldPauseClientPostPossessionExactVisualForAgent(agent, out string postPossessionPauseReason))
                {
                    pendingState.NotBeforeUtc = _clientPostPossessionExactVisualPauseResumeUtc;
                    if (!string.Equals(_lastPendingClientExactVisualPauseReason, postPossessionPauseReason, StringComparison.Ordinal))
                    {
                        _lastPendingClientExactVisualPauseReason = postPossessionPauseReason ?? string.Empty;
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: paused pending client exact visual overlay processing during local post-possession stabilization window. " +
                            "PendingCount=" + _pendingExactNativeClientVisualOverlaysByAgentIndex.Count +
                            " Reason=" + (_lastPendingClientExactVisualPauseReason ?? "unknown"));
                    }

                    continue;
                }

                if (agent.IsMount)
                {
                    completedAgentIndices.Add(agentIndex);
                    continue;
                }

                if (!agent.IsActive() || agent.Team == null || agent.Team.Side == BattleSideEnum.None)
                {
                    if (expired)
                    {
                        completedAgentIndices.Add(agentIndex);
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: abandoned pending client exact visual overlay because agent never became ready. " +
                            "AgentIndex=" + agentIndex +
                            " EntryId=" + (pendingState.EntryId ?? "null") +
                            " Active=" + agent.IsActive() +
                            " TeamNull=" + (agent.Team == null) +
                            " TeamSide=" + (agent.Team?.Side.ToString() ?? "null") +
                            " Retries=" + pendingState.RetryCount +
                            " Source=" + (pendingState.Source ?? "unknown"));
                    }
                    else
                    {
                        pendingState.RetryCount++;
                        pendingState.NotBeforeUtc = nowUtc.AddMilliseconds(150);
                    }
                    continue;
                }

                RosterEntryState pendingEntryState =
                    !string.IsNullOrWhiteSpace(pendingState.EntryId)
                        ? BattleSnapshotRuntimeState.GetEntryState(pendingState.EntryId)
                        : null;
                if (ShouldAwaitMountedHeroEquipmentSyncBeforeClientExactVisualRefresh(
                        agent,
                        pendingEntryState,
                        pendingState.IncludeWeaponsForRefresh,
                        out string deferredHeroReason))
                {
                    completedAgentIndices.Add(agentIndex);
                    TryLogDeferredHeroEquipmentSyncVisualGate(
                        agent,
                        pendingState.EntryId,
                        pendingEntryState,
                        pendingState.IncludeWeaponsForRefresh,
                        pendingState.Source ?? "client delayed exact visual refresh",
                        deferredHeroReason);
                    continue;
                }

                if (TryApplyExactCampaignSnapshotOverlayToNativeAgent(
                        agent,
                        pendingState.EntryId,
                        pendingState.Source ?? "client delayed exact visual refresh",
                        ExactCampaignSnapshotOverlayMode.ClientVisualOnly,
                        includeWeaponsForClientRefresh: pendingState.IncludeWeaponsForRefresh))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: completed pending client exact visual refresh. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + (pendingState.EntryId ?? "null") +
                        " IncludeWeapons=" + pendingState.IncludeWeaponsForRefresh +
                        " Retries=" + pendingState.RetryCount +
                        " Source=" + (pendingState.Source ?? "unknown"));
                    ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                        "client-exact-visual-complete",
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + (pendingState.EntryId ?? "null") +
                        " IncludeWeapons=" + pendingState.IncludeWeaponsForRefresh +
                        " Retries=" + pendingState.RetryCount +
                        " Source=" + (pendingState.Source ?? "unknown"));
                    completedAgentIndices.Add(agentIndex);
                }
                else if (expired)
                {
                    completedAgentIndices.Add(agentIndex);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: abandoned pending client exact visual overlay because apply never succeeded. " +
                        "AgentIndex=" + agentIndex +
                        " EntryId=" + (pendingState.EntryId ?? "null") +
                        " Retries=" + pendingState.RetryCount +
                        " Source=" + (pendingState.Source ?? "unknown"));
                    ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                        "client-exact-visual-abandoned",
                        "AgentIndex=" + agentIndex +
                        " EntryId=" + (pendingState.EntryId ?? "null") +
                        " Retries=" + pendingState.RetryCount +
                        " Source=" + (pendingState.Source ?? "unknown"));
                }
                else
                {
                    pendingState.RetryCount++;
                    pendingState.NotBeforeUtc = nowUtc.AddMilliseconds(150);
                }
            }

            for (int i = 0; i < completedAgentIndices.Count; i++)
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(completedAgentIndices[i]);
        }

        private static bool ShouldPausePendingClientExactVisualOverlaysForSelectionScreen(out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
            {
                _pendingClientExactVisualSelectionPauseSticky = false;
                return false;
            }

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot status = CoopBattleEntryStatusBridgeFile.ReadStatus();
            if (status == null)
            {
                if (_pendingClientExactVisualSelectionPauseSticky)
                {
                    reason = string.IsNullOrWhiteSpace(_lastPendingClientExactVisualPauseReason)
                        ? "selection-pause-sticky-awaiting-status"
                        : _lastPendingClientExactVisualPauseReason;
                    return true;
                }

                return false;
            }

            string lifecycle = status.LifecycleState?.Trim() ?? string.Empty;
            string readinessStage = status.BattleDataReadinessStage?.Trim() ?? string.Empty;
            bool reconnectFinalize =
                !status.BattleDataReady &&
                !status.HasAgent &&
                string.Equals(readinessStage, "ReconnectFinalize", StringComparison.OrdinalIgnoreCase);
            bool noSide =
                string.Equals(lifecycle, "NoSide", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(lifecycle, CoopBattlePeerLifecycleStatus.NoSide.ToString(), StringComparison.OrdinalIgnoreCase);
            bool sideSelection =
                string.Equals(readinessStage, "SideSelection", StringComparison.OrdinalIgnoreCase);
            bool unitSelection =
                string.Equals(readinessStage, "UnitSelection", StringComparison.OrdinalIgnoreCase);
            bool respawnSelection =
                string.Equals(readinessStage, "RespawnSelection", StringComparison.OrdinalIgnoreCase);
            bool respawnable =
                string.Equals(lifecycle, "Respawnable", StringComparison.OrdinalIgnoreCase) ||
                respawnSelection ||
                status.CanRespawn;
            bool shouldPause =
                reconnectFinalize ||
                (!status.HasAgent &&
                 (noSide || sideSelection || unitSelection || respawnSelection || respawnable));
            if (shouldPause)
            {
                reason =
                    "Lifecycle=" + lifecycle +
                    " BattleDataReady=" + status.BattleDataReady +
                    " ReadinessStage=" + readinessStage +
                    " CanRespawn=" + status.CanRespawn +
                    " HasAgent=" + status.HasAgent;
                _pendingClientExactVisualSelectionPauseSticky = true;
                return true;
            }

            bool explicitResume =
                status.HasAgent ||
                (!noSide && !sideSelection && !unitSelection && !respawnSelection && !respawnable);
            if (_pendingClientExactVisualSelectionPauseSticky && !explicitResume)
            {
                reason = string.IsNullOrWhiteSpace(_lastPendingClientExactVisualPauseReason)
                    ? "selection-pause-sticky-awaiting-explicit-resume"
                    : _lastPendingClientExactVisualPauseReason;
                return true;
            }

            _pendingClientExactVisualSelectionPauseSticky = false;
            return false;
        }

        private static bool ShouldPauseClientExactVisualOverlaysBeforeLiveControl(out string reason)
        {
            return ShouldPausePendingClientExactVisualOverlaysForSelectionScreen(out reason);
        }

        private static bool ShouldPauseClientExactVisualOverlaysForReconnectFinalize(out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer)
                return false;

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot status = CoopBattleEntryStatusBridgeFile.ReadStatus();
            if (status == null)
                return false;

            string readinessStage = status.BattleDataReadinessStage?.Trim() ?? string.Empty;
            if (status.BattleDataReady ||
                status.HasAgent ||
                !string.Equals(readinessStage, "ReconnectFinalize", StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            reason =
                "Lifecycle=" + (status.LifecycleState?.Trim() ?? string.Empty) +
                " BattleDataReady=" + status.BattleDataReady +
                " ReadinessStage=" + readinessStage +
                " HasAgent=" + status.HasAgent;
            return true;
        }

        private static int DropPendingClientExactVisualOverlaysForReconnectFinalize(string source)
        {
            if (_pendingExactNativeClientVisualOverlaysByAgentIndex.Count == 0 ||
                !ShouldPauseClientExactVisualOverlaysForReconnectFinalize(out string pauseReason))
            {
                return 0;
            }

            var droppedAgentIndices = new List<int>();
            int droppedHeroCount = 0;
            int droppedTroopCount = 0;
            foreach (KeyValuePair<int, PendingClientExactVisualOverlayState> pendingPair in _pendingExactNativeClientVisualOverlaysByAgentIndex)
            {
                droppedAgentIndices.Add(pendingPair.Key);
                RosterEntryState entryState =
                    !string.IsNullOrWhiteSpace(pendingPair.Value?.EntryId)
                        ? BattleSnapshotRuntimeState.GetEntryState(pendingPair.Value.EntryId)
                        : null;
                if (IsHeroEntryEligibleForExactPersonalPerks(entryState))
                    droppedHeroCount++;
                else
                    droppedTroopCount++;
            }

            for (int i = 0; i < droppedAgentIndices.Count; i++)
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(droppedAgentIndices[i]);

            if (droppedAgentIndices.Count > 0)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: dropped pending client exact visual overlays during reconnect finalize gate. " +
                    "DroppedCount=" + droppedAgentIndices.Count +
                    " DroppedHeroCount=" + droppedHeroCount +
                    " DroppedTroopCount=" + droppedTroopCount +
                    " Reason=" + (pauseReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
            }

            return droppedAgentIndices.Count;
        }

        private static int DropPendingClientTroopExactVisualOverlaysForLiveControl(string source)
        {
            if (_pendingExactNativeClientVisualOverlaysByAgentIndex.Count == 0 ||
                !ShouldSuppressClientTroopExactVisualOverlaysForLiveControl(out string suppressReason))
            {
                return 0;
            }

            Agent controlledAgent = GetLocalPeerControlledAgent();
            int controlledAgentIndex =
                controlledAgent != null && controlledAgent.IsActive()
                    ? controlledAgent.Index
                    : -1;
            var droppedAgentIndices = new List<int>();
            int droppedTroopCount = 0;
            int preservedLocalControlledCount = 0;
            foreach (KeyValuePair<int, PendingClientExactVisualOverlayState> pendingPair in _pendingExactNativeClientVisualOverlaysByAgentIndex)
            {
                RosterEntryState entryState =
                    !string.IsNullOrWhiteSpace(pendingPair.Value?.EntryId)
                        ? BattleSnapshotRuntimeState.GetEntryState(pendingPair.Value.EntryId)
                        : null;
                if (IsHeroEntryEligibleForExactPersonalPerks(entryState))
                    continue;

                if (pendingPair.Key == controlledAgentIndex)
                {
                    preservedLocalControlledCount++;
                    continue;
                }

                droppedAgentIndices.Add(pendingPair.Key);
                droppedTroopCount++;
            }

            for (int i = 0; i < droppedAgentIndices.Count; i++)
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(droppedAgentIndices[i]);

            if (droppedAgentIndices.Count > 0)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: dropped pending client troop exact visual overlays while local peer already has live control. " +
                    "DroppedCount=" + droppedAgentIndices.Count +
                    " DroppedTroopCount=" + droppedTroopCount +
                    " PreservedLocalControlledCount=" + preservedLocalControlledCount +
                    " Reason=" + (suppressReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
            }

            return droppedAgentIndices.Count;
        }

        private static void TryMaintainClientPeerHeroExactVisualOverlays(Mission mission)
        {
            if (mission?.AllAgents == null || GameNetwork.IsServer)
                return;

            DropPendingClientExactVisualOverlaysForReconnectFinalize("client-hero-exact-visual-watchdog");
            if (ShouldPauseClientExactVisualOverlaysBeforeLiveControl(out _))
                return;
            if (ShouldPauseClientHeroExactVisualOverlaysAfterLocalControlLoss(out _))
                return;

            DateTime nowUtc = DateTime.UtcNow;
            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent agent = mission.AllAgents[i];
                if (agent == null ||
                    !agent.IsActive() ||
                    agent.IsMount ||
                    agent.Team == null ||
                    agent.Team.Side == BattleSideEnum.None ||
                    agent.SpawnEquipment == null ||
                    !IsMissionPeerAgentEligibleForClientExactVisualOverlay(agent))
                {
                    continue;
                }

                string entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);
                if (string.IsNullOrWhiteSpace(entryId))
                    continue;

                RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
                if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                    continue;
                MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
                bool locallyControlledHero = localMissionPeer != null && ReferenceEquals(localMissionPeer.ControlledAgent, agent);
                bool peerControlledHero = agent.MissionPeer != null || locallyControlledHero;
                double heroWatchdogSettleDelaySeconds = peerControlledHero ? 0.15d : 0.45d;
                double heroPendingEscalationDelaySeconds = peerControlledHero ? 0.18d : 0.45d;
                double heroWatchdogRetryDelaySeconds = peerControlledHero ? 0.25d : 0.6d;
                bool alreadyApplied =
                    _exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index) &&
                    _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.TryGetValue(agent.Index, out bool appliedIncludesWeapons) &&
                    appliedIncludesWeapons;

                TrackClientMountedHeroMountAgentIndex(agent, entryId);
                bool mountLinkReady = TryEnsureTrackedClientMountedHeroMountLinkReady(
                    agent,
                    entryState,
                    "client hero exact visual watchdog",
                    out _);
                if (!mountLinkReady)
                {
                    if (alreadyApplied &&
                        ShouldPreserveAppliedStrictExactHeroVisualOnTransientMountLinkLoss(
                            agent.Index,
                            entryId))
                    {
                        _clientHeroExactVisualWatchdogFirstSeenUtcByAgentIndex.Remove(agent.Index);
                        _clientHeroExactVisualWatchdogLastAttemptUtcByAgentIndex.Remove(agent.Index);
                        continue;
                    }

                    ClearClientExactCampaignVisualOverlayAppliedState(agent.Index);
                }
                if (ShouldAwaitMountedHeroEquipmentSyncBeforeClientExactVisualRefresh(
                        agent,
                        entryState,
                        includeWeaponsForClientRefresh: true,
                        out string deferredHeroReason))
                {
                    _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                    ClearClientExactCampaignVisualOverlayAppliedState(agent.Index);
                    TryLogDeferredHeroEquipmentSyncVisualGate(
                        agent,
                        entryId,
                        entryState,
                        includeWeaponsForClientRefresh: true,
                        "client hero exact visual watchdog",
                        deferredHeroReason);
                    continue;
                }

                if (alreadyApplied)
                {
                    _clientHeroExactVisualWatchdogFirstSeenUtcByAgentIndex.Remove(agent.Index);
                    _clientHeroExactVisualWatchdogLastAttemptUtcByAgentIndex.Remove(agent.Index);
                    continue;
                }

                if (!_clientHeroExactVisualWatchdogFirstSeenUtcByAgentIndex.TryGetValue(agent.Index, out DateTime firstSeenUtc))
                {
                    _clientHeroExactVisualWatchdogFirstSeenUtcByAgentIndex[agent.Index] = nowUtc;
                    continue;
                }

                double secondsSinceFirstSeen = (nowUtc - firstSeenUtc).TotalSeconds;
                if (secondsSinceFirstSeen < heroWatchdogSettleDelaySeconds)
                    continue;

                if (_pendingExactNativeClientVisualOverlaysByAgentIndex.TryGetValue(agent.Index, out PendingClientExactVisualOverlayState pendingState))
                {
                    if ((nowUtc - pendingState.CreatedUtc).TotalSeconds < heroPendingEscalationDelaySeconds)
                        continue;

                    _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: escalating stuck pending client exact hero visual refresh to watchdog immediate apply. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " Retries=" + pendingState.RetryCount +
                        " PendingSource=" + (pendingState.Source ?? "unknown"));
                    ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                        "client-exact-visual-escalate",
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " Retries=" + pendingState.RetryCount +
                        " PendingSource=" + (pendingState.Source ?? "unknown"));
                }

                if (_clientHeroExactVisualWatchdogLastAttemptUtcByAgentIndex.TryGetValue(agent.Index, out DateTime lastAttemptUtc) &&
                    (nowUtc - lastAttemptUtc).TotalSeconds < heroWatchdogRetryDelaySeconds)
                {
                    continue;
                }

                if (ShouldSuppressClientHeroExactVisualOverlayForRemoteLiveControl(
                        agent,
                        entryId,
                        entryState,
                        out _))
                {
                    _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                    _clientHeroExactVisualWatchdogLastAttemptUtcByAgentIndex[agent.Index] = nowUtc;
                    continue;
                }

                _clientHeroExactVisualWatchdogLastAttemptUtcByAgentIndex[agent.Index] = nowUtc;
                _exactNativeClientVisualOverlayAppliedAgentIndices.Remove(agent.Index);
                _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.Remove(agent.Index);
                if (TryApplyExactCampaignSnapshotOverlayToNativeAgent(
                        agent,
                        entryId,
                        "client hero exact visual watchdog",
                        ExactCampaignSnapshotOverlayMode.ClientVisualOnly,
                        includeWeaponsForClientRefresh: true))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: watchdog applied client exact hero visual overlay. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TeamSide=" + agent.Team.Side +
                        " TroopId=" + (agent.Character?.StringId ?? "null"));
                    ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                        "client-exact-visual-watchdog-applied",
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TeamSide=" + agent.Team.Side +
                        " TroopId=" + (agent.Character?.StringId ?? "null"));
                    continue;
                }

                if (TryQueueClientExactCampaignVisualOverlay(
                        mission,
                        agent,
                        entryId,
                        "client hero exact visual watchdog",
                        delaySeconds: 0.12d,
                        force: true,
                        includeWeaponsForRefresh: true))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: watchdog re-queued client exact hero visual overlay. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TeamSide=" + agent.Team.Side +
                        " TroopId=" + (agent.Character?.StringId ?? "null"));
                }
            }
        }

        private static void TryMaintainClientBattlefieldTroopExactVisualOverlays(Mission mission)
        {
            if (mission?.AllAgents == null || GameNetwork.IsServer)
                return;

            DropPendingClientExactVisualOverlaysForReconnectFinalize("client-troop-exact-visual-watchdog");
            DropPendingClientTroopExactVisualOverlaysForLiveControl("client-troop-exact-visual-watchdog");
            if (ShouldPauseClientExactVisualOverlaysForReconnectFinalize(out _))
                return;

            TryRefreshClientPostPossessionExactVisualPauseWindow(mission, "client-troop-exact-visual-watchdog");
            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out _))
                return;

            if (ShouldPausePendingClientExactVisualOverlaysForSelectionScreen(out _))
                return;

            if (ShouldSuppressClientTroopExactVisualOverlaysForLiveControl(out _))
                return;

            if (ShouldPauseClientPostPossessionExactVisualForAgent(agent: null, out _))
                return;

            DateTime nowUtc = DateTime.UtcNow;
            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent agent = mission.AllAgents[i];
                if (agent == null ||
                    !agent.IsActive() ||
                    agent.IsMount ||
                    agent.Team == null ||
                    agent.Team.Side == BattleSideEnum.None ||
                    !IsMissionPeerAgentEligibleForClientExactVisualOverlay(agent))
                {
                    continue;
                }

                string entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);
                if (string.IsNullOrWhiteSpace(entryId))
                    continue;

                RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
                if (entryState == null || IsHeroEntryEligibleForExactPersonalPerks(entryState))
                    continue;

                if (!IsClientTroopExactVisualInitReady(agent, entryState, out _))
                    continue;

                bool alreadyApplied = _exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index);
                if (alreadyApplied)
                    continue;

                if (_pendingExactNativeClientVisualOverlaysByAgentIndex.TryGetValue(agent.Index, out PendingClientExactVisualOverlayState pendingState) &&
                    (nowUtc - pendingState.CreatedUtc).TotalSeconds < 0.35d)
                {
                    continue;
                }

                if (TryQueueClientExactCampaignVisualOverlay(
                        mission,
                        agent,
                        entryId,
                        "client troop exact visual watchdog",
                        delaySeconds: 0.08d,
                        force: false,
                        includeWeaponsForRefresh: _clientUseStringIdExactEquipmentPath))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: queued battlefield troop exact visual watchdog refresh. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TroopId=" + (agent.Character?.StringId ?? "null"));
                }
            }
        }

        public static bool TryFinalizeClientExactCampaignVisualForAgent(
            Mission mission,
            Agent agent,
            string preferredEntryId,
            string source,
            bool includeWeaponsForClientRefresh = false,
            bool allowImmediateApply = true)
        {
            if (mission == null || agent == null || agent.IsMount || !agent.IsActive() || GameNetwork.IsServer)
                return false;

            if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                return false;

            if (!IsMissionPeerAgentEligibleForClientExactVisualOverlay(agent))
                return false;

            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out string snapshotReadinessSummary))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client exact visual finalize until current battle snapshot is applied. " +
                    "AgentIndex=" + agent.Index +
                    " Source=" + (source ?? "unknown") +
                    " Reason=" + snapshotReadinessSummary);
                return false;
            }

            string entryId = preferredEntryId;
            if (string.IsNullOrWhiteSpace(entryId) || BattleSnapshotRuntimeState.GetEntryState(entryId) == null)
                entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);

            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return false;
            if (ShouldSuppressClientHeroExactVisualOverlayForLocalLiveTakeover(
                    agent,
                    entryId,
                    entryState,
                    out _))
            {
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                return false;
            }

            UpdateStrictExactHeroTransferEntryState(agent.Index, entryId, entryState, source ?? "client exact-visual finalize");
            if (ShouldAwaitMountedHeroEquipmentSyncBeforeClientExactVisualRefresh(
                    agent,
                    entryState,
                    includeWeaponsForClientRefresh,
                    out string deferredHeroReason))
            {
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                ClearClientExactCampaignVisualOverlayAppliedState(agent.Index);
                TryLogDeferredHeroEquipmentSyncVisualGate(
                    agent,
                    entryId,
                    entryState,
                    includeWeaponsForClientRefresh,
                    source ?? "client exact-visual finalize",
                    deferredHeroReason);
                return false;
            }
            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            bool locallyControlledHero = localMissionPeer != null && ReferenceEquals(localMissionPeer.ControlledAgent, agent);
            bool peerControlledHero = agent.MissionPeer != null || locallyControlledHero;
            double deferredHeroApplyDelaySeconds = peerControlledHero ? 0.14d : 0.35d;
            if (ShouldSuppressClientHeroExactVisualOverlayForRemoteLiveControl(
                    agent,
                    entryId,
                    entryState,
                    out _))
            {
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                return false;
            }

            TrackClientMountedHeroMountAgentIndex(agent, entryId);
            bool mountLinkReady = TryEnsureTrackedClientMountedHeroMountLinkReady(
                agent,
                entryState,
                source ?? "client exact-visual finalize",
                out string mountLinkReason);
            if (!mountLinkReady)
            {
                ClearClientExactCampaignVisualOverlayAppliedState(agent.Index);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client exact visual finalize until tracked mount link is ready. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Reason=" + (mountLinkReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
                TryQueueClientExactCampaignVisualOverlay(
                    mission,
                    agent,
                    entryId,
                    source ?? "client exact-visual finalize",
                    delaySeconds: peerControlledHero ? 0.08d : 0.12d,
                    force: true,
                    includeWeaponsForRefresh: includeWeaponsForClientRefresh);
                return false;
            }
            UpdateStrictExactHeroTransferMountLinkState(agent, entryState, source ?? "client exact-visual finalize");

            _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = entryId;
            if (_exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index) &&
                _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.TryGetValue(agent.Index, out bool appliedIncludesWeapons) &&
                (!includeWeaponsForClientRefresh || appliedIncludesWeapons))
            {
                return true;
            }

            if (!allowImmediateApply)
            {
                TryQueueClientExactCampaignVisualOverlay(
                    mission,
                    agent,
                    entryId,
                    source ?? "client exact-visual finalize",
                    delaySeconds: deferredHeroApplyDelaySeconds,
                    force: true,
                    includeWeaponsForRefresh: includeWeaponsForClientRefresh);
                return false;
            }

            if (agent.IsActive() && agent.Team != null && agent.Team.Side != BattleSideEnum.None)
            {
                _pendingExactNativeClientVisualOverlaysByAgentIndex.Remove(agent.Index);
                _exactNativeClientVisualOverlayAppliedAgentIndices.Remove(agent.Index);
                _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.Remove(agent.Index);
                if (TryApplyExactCampaignSnapshotOverlayToNativeAgent(
                        agent,
                        entryId,
                        source ?? "client exact-visual finalize",
                        ExactCampaignSnapshotOverlayMode.ClientVisualOnly,
                        includeWeaponsForClientRefresh: includeWeaponsForClientRefresh))
                {
                    return true;
                }

                AdvanceStrictExactHeroTransferStage(
                    EnsureStrictExactHeroTransferState(agent.Index),
                    StrictExactHeroTransferStage.MountLinkVerified,
                    source ?? "client exact-visual finalize",
                    failureReason: "client-exact-visual-apply-returned-false");
            }

            TryQueueClientExactCampaignVisualOverlay(
                mission,
                agent,
                entryId,
                source ?? "client exact-visual finalize",
                delaySeconds: deferredHeroApplyDelaySeconds,
                includeWeaponsForRefresh: includeWeaponsForClientRefresh);
            return false;
        }

        public static bool TryHandleClientExactCampaignSpawnEquipmentSync(
            Mission mission,
            Agent agent,
            string source)
        {
            if (mission == null || agent == null || agent.IsMount || !agent.IsActive() || GameNetwork.IsServer)
                return false;

            if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                return false;

            if (!IsMissionPeerAgentEligibleForClientExactVisualOverlay(agent))
                return false;

            if (_exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index))
            {
                if (_exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.TryGetValue(agent.Index, out bool appliedIncludesWeapons) &&
                    appliedIncludesWeapons)
                {
                    return false;
                }
            }

            ExactCampaignObjectCatalogBootstrap.EnsureLoaded("client-exact-spawn-equipment-sync:" + (mission.SceneName ?? "null"));
            string entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);
            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return false;

            if (ShouldSuppressClientHeroExactVisualOverlayForLocalLiveTakeover(
                    agent,
                    entryId,
                    entryState,
                    out _))
            {
                return false;
            }

            bool queued = TryQueueClientExactCampaignVisualOverlay(
                mission,
                agent,
                entryId,
                source ?? "client exact equipment sync",
                delaySeconds: 0.08,
                force: true,
                includeWeaponsForRefresh: true);
            if (!queued)
                return false;

            ModLogger.Info(
                "CoopMissionSpawnLogic: queued delayed client exact visual refresh after raw spawn equipment sync. " +
                "AgentIndex=" + agent.Index +
                " EntryId=" + entryId +
                " TroopId=" + (agent.Character?.StringId ?? "null") +
                " Source=" + (source ?? "unknown"));
            return false;
        }

        public static bool TryFinalizeClientExactCampaignTroopVisualForPeerAgent(
            Mission mission,
            Agent agent,
            string source,
            bool includeWeaponsForClientRefresh = true,
            bool allowImmediateApply = true)
        {
            if (mission == null || agent == null || agent.IsMount || !agent.IsActive() || GameNetwork.IsServer)
                return false;

            if (!IsClientExactCampaignVisualOverlayRuntime(mission))
                return false;

            if (!IsMissionPeerAgentEligibleForClientExactVisualOverlay(agent))
                return false;

            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out string snapshotReadinessSummary))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client troop exact visual finalize until current battle snapshot is applied. " +
                    "AgentIndex=" + agent.Index +
                    " Source=" + (source ?? "unknown") +
                    " Reason=" + snapshotReadinessSummary);
                return false;
            }

            string entryId = ResolveClientExactCampaignVisualOverlayEntryId(agent);
            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (entryState == null || IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return false;

            bool effectiveIncludeWeaponsForClientRefresh = ShouldAllowClientTroopWeaponOverlayRefresh(
                agent,
                entryState,
                includeWeaponsForClientRefresh,
                out string weaponOverlayReason);

            if (!IsClientTroopExactVisualInitReady(agent, entryState, out string initReadinessReason))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client troop exact visual finalize until client init state is ready. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " RequestedIncludeWeapons=" + includeWeaponsForClientRefresh +
                    " EffectiveIncludeWeapons=" + effectiveIncludeWeaponsForClientRefresh +
                    " Reason=" + (initReadinessReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            if (_exactNativeClientVisualOverlayAppliedAgentIndices.Contains(agent.Index) &&
                _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex.TryGetValue(agent.Index, out bool appliedIncludesWeapons) &&
                (!effectiveIncludeWeaponsForClientRefresh || appliedIncludesWeapons == effectiveIncludeWeaponsForClientRefresh))
            {
                return true;
            }

            if (!allowImmediateApply)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred immediate client troop exact visual apply until post-create sync stage. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " RequestedIncludeWeapons=" + includeWeaponsForClientRefresh +
                    " EffectiveIncludeWeapons=" + effectiveIncludeWeaponsForClientRefresh +
                    " WeaponOverlayReason=" + (weaponOverlayReason ?? "none") +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            bool applied = TryApplyExactCampaignSnapshotOverlayToNativeAgent(
                agent,
                entryId,
                source ?? "client troop exact visual finalize",
                ExactCampaignSnapshotOverlayMode.ClientVisualOnly,
                includeWeaponsForClientRefresh: effectiveIncludeWeaponsForClientRefresh);
            if (applied)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: applied client troop exact campaign visual overlay to peer-controlled agent. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " IncludeWeapons=" + effectiveIncludeWeaponsForClientRefresh +
                    " WeaponOverlayReason=" + (weaponOverlayReason ?? "none") +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " MissionPeer=" + (agent.MissionPeer?.Peer?.UserName ?? "null") +
                    " Source=" + (source ?? "unknown"));
                return true;
            }

            bool queued = TryQueueClientExactCampaignVisualOverlay(
                mission,
                agent,
                entryId,
                source ?? "client troop exact visual finalize",
                delaySeconds: 0.08d,
                force: true,
                includeWeaponsForRefresh: effectiveIncludeWeaponsForClientRefresh);
            if (queued)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: queued delayed client troop exact visual refresh for peer-controlled agent. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " IncludeWeapons=" + effectiveIncludeWeaponsForClientRefresh +
                    " WeaponOverlayReason=" + (weaponOverlayReason ?? "none") +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " MissionPeer=" + (agent.MissionPeer?.Peer?.UserName ?? "null") +
                    " Source=" + (source ?? "unknown"));
            }

            return false;
        }

        private static void TryEnsureExactCampaignNativeArmyBootstrap(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            ExactCampaignArmyBootstrap.ResetForMission(mission);
            if (!ExperimentalFeatures.EnableExactCampaignNativeArmyBootstrap ||
                !IsSceneAwareBattleMapRuntime(mission) ||
                !SceneRuntimeClassifier.IsCampaignBattleScene(mission.SceneName ?? string.Empty))
            {
                return;
            }

            if (ExactCampaignArmyBootstrap.IsActive(mission))
            {
                ExactCampaignArmyBootstrap.TryMaintainMissionPlayerTeamContract(
                    mission,
                    source + " exact-native-bootstrap-active");
                return;
            }

            MissionPeer missionPeer = ResolveExactCampaignBootstrapPeer(mission);
            if (!TryResolveExactCampaignBootstrapSide(
                    mission,
                    missionPeer,
                    source + " exact-native-bootstrap",
                    out BattleSideEnum authoritativeSide,
                    out string bootstrapSideReason))
            {
                LogExactSceneNativeBootstrapDeferred(mission, bootstrapSideReason, source);
                return;
            }

            Team authoritativeTeam = ResolveAuthoritativeMissionTeam(mission, missionPeer, authoritativeSide);
            if (authoritativeTeam == null || ReferenceEquals(authoritativeTeam, mission.SpectatorTeam))
            {
                LogExactSceneNativeBootstrapDeferred(mission, "authoritative-team-not-ready", source);
                return;
            }

            TryBridgeMissionPlayerTeamForExactCampaignBootstrap(
                mission,
                authoritativeTeam,
                authoritativeSide,
                source);

            if (mission.PlayerTeam == null || mission.PlayerEnemyTeam == null)
            {
                LogExactSceneNativeBootstrapDeferred(mission, "mission-player-teams-not-ready", source);
                return;
            }

            if (mission.PlayerTeam.Side != authoritativeSide)
            {
                LogExactSceneNativeBootstrapDeferred(
                    mission,
                    "mission-player-team-side-mismatch PlayerTeam=" + mission.PlayerTeam.Side + " AuthoritativeSide=" + authoritativeSide,
                    source);
                return;
            }

            if (!ExactCampaignArmyBootstrap.TryInitialize(
                mission,
                authoritativeSide,
                source + " exact-native-bootstrap",
                out string initializeReason))
            {
                LogExactSceneNativeBootstrapDeferred(mission, initializeReason, source);
            }
        }

        private static void TrySyncExactCampaignNativeArmyBootstrapReinforcements(Mission mission, string source)
        {
            if (!IsUsingNativeExactCampaignArmyBootstrap(mission))
                return;

            ExactCampaignArmyBootstrap.TryMaintainMissionPlayerTeamContract(
                mission,
                source + " exact-native-bootstrap-reinforcements");

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            bool shouldEnableReinforcements =
                currentPhase >= CoopBattlePhase.BattleActive &&
                currentPhase < CoopBattlePhase.BattleEnded;
            ExactCampaignArmyBootstrap.TrySyncReinforcementState(
                mission,
                shouldEnableReinforcements,
                source + " exact-native-bootstrap");
            ExactCampaignArmyBootstrap.TryLogRuntimeDiagnostics(
                mission,
                source + " exact-native-bootstrap");
        }

        private static void TrySyncExactCampaignNativeOriginRemoval(Mission mission, Agent affectedAgent, Agent affectorAgent, AgentState agentState)
        {
            ExactCampaignArmyBootstrap.TrySyncAgentOriginRemoval(
                mission,
                affectedAgent,
                affectorAgent,
                agentState,
                "mission-behavior-onagentremoved");
        }

        private static void TrySyncExactCampaignBattlefieldRuntimeState(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || !IsUsingNativeExactCampaignArmyBootstrap(mission))
                return;

            EnsureMaterializedBattleResultMission(mission);
            int seededEntries = 0;
            seededEntries += EnsureExactCampaignBattleResultEntryStates(BattleSideEnum.Attacker);
            seededEntries += EnsureExactCampaignBattleResultEntryStates(BattleSideEnum.Defender);

            int newlyTrackedAgents = 0;
            int newlyOverlaidAgents = 0;
            int newlyInitialWieldRepairedAgents = 0;
            if (mission.AllAgents != null)
            {
                for (int i = 0; i < mission.AllAgents.Count; i++)
                {
                    Agent agent = mission.AllAgents[i];
                    if (agent == null || !agent.IsActive() || agent.IsMount)
                        continue;

                    if (!TryRefreshMaterializedAgentIdentityCache(
                            agent,
                            out string entryId,
                            out BattleSideEnum side,
                            out bool requiresRegistration,
                            source,
                            logRefresh: true) ||
                        string.IsNullOrWhiteSpace(entryId) ||
                        side == BattleSideEnum.None)
                    {
                        continue;
                    }

                    RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
                    if (requiresRegistration)
                    {
                        if (entryState != null)
                        {
                            RegisterMaterializedBattleResultEntry(agent, entryState, side);
                        }
                        else if (_materializedBattleResultEntriesByEntryId.TryGetValue(entryId, out MaterializedBattleResultEntryRuntimeState runtimeState) &&
                                 runtimeState != null)
                        {
                            runtimeState.MaterializedSpawnCount++;
                            runtimeState.ActiveCount++;
                        }

                        newlyTrackedAgents++;
                    }

                    if (entryState != null &&
                        !ShouldUseSinglePassCanonicalNativeInitialWield(entryState) &&
                        TryApplyServerBootstrapInitialWieldRepairForStrictPreSpawnExactLoadout(
                            agent,
                            entryState,
                            source,
                            out bool initialWieldRepaired) &&
                        initialWieldRepaired)
                    {
                        newlyInitialWieldRepairedAgents++;
                    }

                    if (TryApplyExactCampaignSnapshotOverlayToNativeAgent(agent, entryId, source))
                        newlyOverlaidAgents++;
                }

                for (int i = 0; i < mission.AllAgents.Count; i++)
                {
                    Agent agent = mission.AllAgents[i];
                    if (agent == null || !agent.IsActive() || agent.IsMount)
                        continue;

                    if (_exactNativeSnapshotOverlayAppliedAgentIndices.Contains(agent.Index))
                        continue;

                    if (!ExactCampaignArmyBootstrap.TryGetEntryId(agent, out string entryId) ||
                        string.IsNullOrWhiteSpace(entryId))
                    {
                        continue;
                    }

                    if (TryApplyExactCampaignSnapshotOverlayToNativeAgent(agent, entryId, source))
                        newlyOverlaidAgents++;
                }
            }

            int commanderAssignments = TryAssignExactCampaignCommanders(mission, source);
            if (seededEntries <= 0 &&
                newlyTrackedAgents <= 0 &&
                newlyOverlaidAgents <= 0 &&
                newlyInitialWieldRepairedAgents <= 0 &&
                commanderAssignments <= 0)
                return;

            int trackedAttackerAgents = _materializedArmySideByAgentIndex.Values.Count(candidate => candidate == BattleSideEnum.Attacker);
            int trackedDefenderAgents = _materializedArmySideByAgentIndex.Values.Count(candidate => candidate == BattleSideEnum.Defender);
            ModLogger.Info(
                "CoopMissionSpawnLogic: synced exact campaign bootstrap runtime state. " +
                "SeededEntries=" + seededEntries +
                " NewlyTrackedAgents=" + newlyTrackedAgents +
                " SnapshotOverlays=" + newlyOverlaidAgents +
                " InitialWieldRepairs=" + newlyInitialWieldRepairedAgents +
                " CommanderAssignments=" + commanderAssignments +
                " TrackedAttackerAgents=" + trackedAttackerAgents +
                " TrackedDefenderAgents=" + trackedDefenderAgents +
                " Source=" + (source ?? "unknown"));
        }

        private static bool IsClientExactCampaignVisualOverlayRuntime(Mission mission)
        {
            return mission != null &&
                   SceneRuntimeClassifier.IsSceneAwareBattleRuntimeScene(mission.SceneName) &&
                   BattleSnapshotRuntimeState.GetState()?.Sides != null &&
                   BattleSnapshotRuntimeState.GetState().Sides.Count > 0;
        }

        private static void EnsureClientExactCampaignVisualOverlayQueuesBuilt()
        {
            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.Sides == null || runtimeState.Sides.Count == 0)
                return;

            string snapshotKey = BuildClientExactCampaignVisualOverlayQueueSnapshotKey(runtimeState);
            if (_exactNativeClientVisualOverlayEntryQueuesByAssignmentKey.Count > 0)
            {
                if (string.Equals(_exactNativeClientVisualOverlayQueueSnapshotKey, snapshotKey, StringComparison.Ordinal))
                    return;

                ResetClientExactCampaignVisualOverlayAssignmentState(
                    "EnsureClientExactCampaignVisualOverlayQueuesBuilt snapshot-changed: " +
                    (_exactNativeClientVisualOverlayQueueSnapshotKey ?? "null") +
                    " -> " +
                    (snapshotKey ?? "null"));
            }

            foreach (BattleSideState sideState in runtimeState.Sides)
            {
                BattleSideEnum side = ResolveBattleSideFromState(sideState);
                if (side == BattleSideEnum.None || sideState?.Entries == null)
                    continue;

                RosterEntryState commanderEntryState = BattleCommanderResolver.ResolveCommanderEntry(runtimeState, side, sideState.Entries);
                string commanderEntryId = commanderEntryState?.EntryId;
                IEnumerable<RosterEntryState> orderedEntries = sideState.Entries;
                if (!string.IsNullOrWhiteSpace(commanderEntryId))
                {
                    orderedEntries = sideState.Entries
                        .OrderByDescending(entry => string.Equals(entry?.EntryId, commanderEntryId, StringComparison.Ordinal));
                }

                foreach (RosterEntryState entryState in orderedEntries)
                {
                    if (entryState == null)
                        continue;

                    int availableCount = Math.Max(0, entryState.Count - entryState.WoundedCount);
                    if (availableCount <= 0)
                        continue;

                    string spawnTemplateId = ResolveEntrySpawnTemplateId(entryState);
                    if (string.IsNullOrWhiteSpace(spawnTemplateId) || string.IsNullOrWhiteSpace(entryState.EntryId))
                        continue;

                    EnqueueClientExactCampaignVisualOverlayAssignmentEntries(
                        side,
                        spawnTemplateId,
                        entryState.EntryId,
                        availableCount);

                    string fallbackTroopId = ResolveEntryMissionSafeFallbackTroopId(entryState);
                    if (!string.IsNullOrWhiteSpace(fallbackTroopId) &&
                        !string.Equals(fallbackTroopId, spawnTemplateId, StringComparison.OrdinalIgnoreCase))
                    {
                        EnqueueClientExactCampaignVisualOverlayAssignmentEntries(
                            side,
                            fallbackTroopId,
                            entryState.EntryId,
                            availableCount);
                    }
                }
            }

            _exactNativeClientVisualOverlayQueueSnapshotKey = snapshotKey;
            ModLogger.Info(
                "CoopMissionSpawnLogic: built client exact visual overlay assignment queues. " +
                "SnapshotKey=" + (_exactNativeClientVisualOverlayQueueSnapshotKey ?? "null") +
                " QueueCount=" + _exactNativeClientVisualOverlayEntryQueuesByAssignmentKey.Count +
                " EntryCount=" + (runtimeState.EntriesById?.Count ?? 0));
        }

        private static string BuildClientExactCampaignVisualOverlayQueueSnapshotKey(BattleRuntimeState runtimeState)
        {
            BattleSnapshotMessage currentSnapshot = BattleSnapshotRuntimeState.GetCurrent();
            string battleId = currentSnapshot?.BattleId ?? "null";
            string sceneName = currentSnapshot?.MapScene ?? "null";
            string sideSignature = runtimeState?.Sides == null
                ? "none"
                : string.Join(",",
                    runtimeState.Sides.Select(sideState =>
                        (sideState?.CanonicalSideKey ?? sideState?.SideId ?? "null") + ":" +
                        (sideState?.TotalManCount ?? 0) + ":" +
                        (sideState?.Entries?.Count ?? 0)));
            return battleId + "|" + sceneName + "|" + sideSignature;
        }

        private static string ResolveClientExactCampaignVisualOverlayEntryId(Agent agent)
        {
            if (agent == null || agent.Team == null || agent.Team.Side == BattleSideEnum.None)
                return null;

            EnsureClientBattleSnapshotFreshForMission(agent.Mission ?? Mission.Current, "ResolveClientExactCampaignVisualOverlayEntryId");
            RefreshClientExactCampaignVisualOverlayAgentIndexState(agent, "ResolveClientExactCampaignVisualOverlayEntryId", logRefresh: true);

            if (TryResolveClientAuthoritativeMaterializedEntryId(agent.Index, out string authoritativeEntryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = authoritativeEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = authoritativeEntryId;
                return authoritativeEntryId;
            }

            if (_exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(agent.Index, out string cachedEntryId) &&
                !string.IsNullOrWhiteSpace(cachedEntryId))
            {
                if (BattleSnapshotRuntimeState.GetEntryState(cachedEntryId) != null)
                    return cachedEntryId;

                _exactNativeClientVisualOverlayEntryIdByAgentIndex.Remove(agent.Index);
            }

            if (ExactCampaignArmyBootstrap.TryGetEntryId(agent, out string originEntryId) &&
                !string.IsNullOrWhiteSpace(originEntryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = originEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = originEntryId;
                return originEntryId;
            }

            if (_materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out string trackedEntryId) &&
                !string.IsNullOrWhiteSpace(trackedEntryId) &&
                BattleSnapshotRuntimeState.GetEntryState(trackedEntryId) != null)
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = trackedEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = trackedEntryId;
                return trackedEntryId;
            }

            if (TryResolveUniqueHeroEntryIdForClientVisualOverlay(agent, out string uniqueHeroEntryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = uniqueHeroEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = uniqueHeroEntryId;
                return uniqueHeroEntryId;
            }

            if (TryResolveLocalPeerAuthoritativeEntryIdForClientVisualOverlay(agent, out string localAuthoritativeEntryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = localAuthoritativeEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = localAuthoritativeEntryId;
                return localAuthoritativeEntryId;
            }

            if (TryResolveQueuedClientExactCampaignVisualOverlayEntryId(agent, out string queuedEntryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = queuedEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = queuedEntryId;
                return queuedEntryId;
            }

            if (TryResolveClientHeuristicCreateAgentEntryId(
                    agent.Index,
                    requireSettled: true,
                    out string heuristicEntryId,
                    out string heuristicResolutionState,
                    out string heuristicResolutionSource,
                    out _) &&
                BattleSnapshotRuntimeState.GetEntryState(heuristicEntryId) is RosterEntryState heuristicEntryState &&
                (DoesClientVisualOverlayEntryMatchAgentTroop(heuristicEntryState, agent.Character?.StringId) ||
                 ShouldPreserveStrictExactHeroEntryMapping(agent.Index, heuristicEntryId)))
            {
                PromoteSettledClientHeuristicCreateAgentEntryId(
                    agent,
                    heuristicEntryId,
                    heuristicResolutionState,
                    heuristicResolutionSource,
                    "ResolveClientExactCampaignVisualOverlayEntryId");
                return heuristicEntryId;
            }

            return null;
        }

        internal static bool TryResolveClientAuthoritativeMaterializedEntryId(int agentIndex, out string entryId)
        {
            entryId = null;
            if (agentIndex < 0)
                return false;

            if (!_clientAuthoritativeMaterializedEntryIdByAgentIndex.TryGetValue(agentIndex, out string authoritativeEntryId) ||
                string.IsNullOrWhiteSpace(authoritativeEntryId))
            {
                return false;
            }

            if (BattleSnapshotRuntimeState.GetEntryState(authoritativeEntryId) == null)
            {
                _clientAuthoritativeMaterializedEntryIdByAgentIndex.Remove(agentIndex);
                _clientAuthoritativeMaterializedEntryObservedAgentIndices.Remove(agentIndex);
                return false;
            }

            if (TryGetClientCreateAgentExactVisualState(agentIndex, out ClientCreateAgentExactVisualRuntimeState state) &&
                state != null &&
                state.CreateAgentPayloadObserved &&
                !DoesClientCreateAgentRuntimePayloadMatchEntryId(state, authoritativeEntryId, out string payloadMismatchReason))
            {
                ResetClientCreateAgentExactVisualRuntimeResolutionState(state);
                ClearClientTrackedMaterializedAgentIdentityState(
                    agentIndex,
                    "TryResolveClientAuthoritativeMaterializedEntryId",
                    "stale-authoritative-materialized-entry|" + payloadMismatchReason,
                    preserveCreateAgentRuntime: true,
                    logClear: true);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected stale client authoritative materialized entry because it did not match the current CreateAgent payload. " +
                    "AgentIndex=" + agentIndex +
                    " EntryId=" + authoritativeEntryId +
                    " PayloadCharacterId=" + (state.PayloadCharacterId ?? "null") +
                    " PayloadSide=" + state.PayloadSide +
                    " PayloadGeneration=" + state.PayloadGeneration +
                    " Reason=" + payloadMismatchReason);
                return false;
            }

            entryId = authoritativeEntryId;
            return true;
        }

        private static bool TryResolveClientHeuristicCreateAgentEntryId(
            int agentIndex,
            bool requireSettled,
            out string entryId,
            out string resolutionState,
            out string resolutionSource,
            out string reason)
        {
            entryId = null;
            resolutionState = null;
            resolutionSource = null;
            reason = null;

            if (agentIndex < 0)
            {
                reason = "agent-index-invalid";
                return false;
            }

            if (!TryGetClientCreateAgentExactVisualState(agentIndex, out ClientCreateAgentExactVisualRuntimeState state) ||
                state == null)
            {
                reason = "create-agent-runtime-unobserved";
                return false;
            }

            if (state.AuthoritativeMaterializedEntryObserved)
            {
                reason = "authoritative-materialized-entry-observed";
                return false;
            }

            if (string.IsNullOrWhiteSpace(state.EntryId))
            {
                reason = "heuristic-entry-unobserved";
                return false;
            }

            resolutionState = state.ResolutionState ?? "unresolved";
            resolutionSource = state.ResolutionSource ?? "unknown";
            bool payloadResolutionStrongEnough =
                string.Equals(resolutionState, "resolved-strong", StringComparison.Ordinal) ||
                string.Equals(resolutionState, "resolved-layout", StringComparison.Ordinal);
            if (!payloadResolutionStrongEnough)
            {
                reason = "heuristic-resolution-weak|ResolutionState=" + resolutionState;
                return false;
            }

            if (BattleSnapshotRuntimeState.GetEntryState(state.EntryId) == null)
            {
                reason = "heuristic-entry-stale|EntryId=" + state.EntryId;
                return false;
            }

            if (requireSettled &&
                !HasClientTroopObservedStablePostCreateSignal(state, out string stableSignalReason))
            {
                reason =
                    "heuristic-create-agent-fallback-pending" +
                    "|ResolutionState=" + resolutionState +
                    "|ResolutionSource=" + resolutionSource +
                    "|StableSignal=" + stableSignalReason;
                return false;
            }

            entryId = state.EntryId;
            reason =
                (requireSettled
                    ? "heuristic-create-agent-fallback-ready"
                    : "heuristic-create-agent-fallback-available") +
                "|ResolutionState=" + resolutionState +
                "|ResolutionSource=" + resolutionSource;
            return true;
        }

        private static void PromoteSettledClientHeuristicCreateAgentEntryId(
            Agent agent,
            string entryId,
            string resolutionState,
            string resolutionSource,
            string source)
        {
            if (agent == null || agent.Index < 0 || string.IsNullOrWhiteSpace(entryId))
                return;

            bool alreadyTracked =
                _materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out string trackedEntryId) &&
                string.Equals(trackedEntryId, entryId, StringComparison.Ordinal) &&
                _exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(agent.Index, out string overlayEntryId) &&
                string.Equals(overlayEntryId, entryId, StringComparison.Ordinal);

            _materializedArmyEntryIdByAgentIndex[agent.Index] = entryId;
            _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = entryId;
            if (agent.Team?.Side != null && agent.Team.Side != BattleSideEnum.None)
                _materializedArmySideByAgentIndex[agent.Index] = agent.Team.Side;

            if (TryGetClientCreateAgentExactVisualState(agent.Index, out ClientCreateAgentExactVisualRuntimeState state) &&
                state != null)
            {
                state.LastObservedUtc = DateTime.UtcNow;
            }

            if (alreadyTracked)
                return;

            ModLogger.Info(
                "CoopMissionSpawnLogic: promoted settled heuristic client create-agent fallback. " +
                "AgentIndex=" + agent.Index +
                " EntryId=" + entryId +
                " ResolutionState=" + (resolutionState ?? "unknown") +
                " ResolutionSource=" + (resolutionSource ?? "unknown") +
                " Source=" + (source ?? "unknown"));
        }

        internal static bool ShouldRequireExplicitMaterializationEntryId(CreateAgent createAgent, out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer || createAgent == null)
                return false;

            if (TryResolveClientAuthoritativeMaterializedEntryId(createAgent.AgentIndex, out string authoritativeEntryId))
            {
                reason = "authoritative-materialized-entry-present:" + authoritativeEntryId;
                return false;
            }

            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.EntriesById == null || runtimeState.EntriesById.Count == 0)
                return false;

            BattleSideEnum payloadSide = ResolveCreateAgentPayloadBattleSide(createAgent.TeamIndex);
            if (payloadSide == BattleSideEnum.None)
                return false;

            if (ShouldGateClientOrdinaryCreateAgentUntilAuthoritativeMaterializationSnapshot(
                    createAgent,
                    payloadSide,
                    out string authoritativeSnapshotGateReason))
            {
                reason = authoritativeSnapshotGateReason;
                return true;
            }

            if (createAgent.Character == null)
            {
                if (TryResolveCharacterlessCreateAgentPayloadByUniqueLayout(
                        runtimeState,
                        payloadSide,
                        createAgent,
                        out _,
                        out string resolutionSummary))
                {
                    reason = resolutionSummary;
                    return false;
                }

                reason = resolutionSummary ?? "payload-character-null-layout-unresolved";
                return true;
            }

            string payloadCharacterId = createAgent.Character.StringId ?? string.Empty;
            if (string.IsNullOrWhiteSpace(payloadCharacterId) ||
                createAgent.Character.IsHero ||
                payloadCharacterId.EndsWith("_hero", StringComparison.Ordinal))
            {
                return false;
            }

            List<string> matchingEntryIds = runtimeState.EntriesById.Values
                .Where(entryState =>
                    entryState != null &&
                    DoesClientVisualOverlayEntryMatchAgentSide(entryState, payloadSide) &&
                    DoesClientVisualOverlayEntryMatchAgentTroop(entryState, payloadCharacterId))
                .Select(entryState => entryState.EntryId)
                .Where(candidateEntryId => !string.IsNullOrWhiteSpace(candidateEntryId))
                .Distinct(StringComparer.Ordinal)
                .ToList();
            if (matchingEntryIds.Count <= 1)
                return false;

            if (TryResolveSharedSurrogateShellByUniquePayloadLayout(
                    runtimeState,
                    matchingEntryIds,
                    createAgent,
                    out _,
                    out _))
            {
                return false;
            }

            string sample = string.Join(" | ", matchingEntryIds.Take(5));

            reason =
                "shared-surrogate-shell" +
                " PayloadCharacterId=" + payloadCharacterId +
                " PayloadSide=" + payloadSide +
                " CandidateCount=" + matchingEntryIds.Count +
                " EntrySample=[" + sample + "]";
            return true;
        }

        private static bool ShouldGateClientOrdinaryCreateAgentUntilAuthoritativeMaterializationSnapshot(
            CreateAgent createAgent,
            BattleSideEnum payloadSide,
            out string reason)
        {
            reason = null;
            if (GameNetwork.IsServer || createAgent == null || payloadSide == BattleSideEnum.None)
                return false;

            if (_lastClientAuthoritativeMaterializedEntrySnapshotEntryCount > 0 ||
                _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count > 0)
            {
                return false;
            }

            if (createAgent.IsPlayerAgent || createAgent.Peer != null)
                return false;

            string payloadCharacterId = createAgent.Character?.StringId ?? string.Empty;
            if ((createAgent.Character?.IsHero ?? false) ||
                payloadCharacterId.EndsWith("_hero", StringComparison.Ordinal))
            {
                return false;
            }

            reason =
                "authoritative-materialized-entry-snapshot-pending" +
                " PayloadCharacterId=" + (string.IsNullOrWhiteSpace(payloadCharacterId) ? "null" : payloadCharacterId) +
                " PayloadSide=" + payloadSide +
                " SnapshotEntryCount=" + _lastClientAuthoritativeMaterializedEntrySnapshotEntryCount +
                " ObservedAgentCount=" + _clientAuthoritativeMaterializedEntryObservedAgentIndices.Count;
            return true;
        }

        internal static bool TryResolveCharacterlessCreateAgentPayloadEntryIdByUniqueLayout(
            CreateAgent createAgent,
            out string entryId,
            out string resolutionSummary)
        {
            entryId = null;
            resolutionSummary = "payload-character-null-layout-unresolved";
            if (GameNetwork.IsServer || createAgent == null)
                return false;

            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.EntriesById == null || runtimeState.EntriesById.Count == 0)
                return false;

            BattleSideEnum payloadSide = ResolveCreateAgentPayloadBattleSide(createAgent.TeamIndex);
            if (payloadSide == BattleSideEnum.None)
                return false;

            return TryResolveCharacterlessCreateAgentPayloadByUniqueLayout(
                runtimeState,
                payloadSide,
                createAgent,
                out entryId,
                out resolutionSummary);
        }

        private static bool TryResolveCharacterlessCreateAgentPayloadByUniqueLayout(
            BattleRuntimeState runtimeState,
            BattleSideEnum payloadSide,
            CreateAgent createAgent,
            out string entryId,
            out string resolutionSummary)
        {
            entryId = null;
            resolutionSummary = "payload-character-null-layout-unresolved";
            if (runtimeState?.EntriesById == null ||
                payloadSide == BattleSideEnum.None ||
                createAgent == null)
            {
                return false;
            }

            string payloadMissionWeaponLayout =
                ExactCreateAgentPayloadDiagnostics.BuildMissionEquipmentWeaponLayoutSummary(createAgent.MissionEquipment);
            string payloadSpawnWeaponLayout =
                ExactCreateAgentPayloadDiagnostics.BuildEquipmentWeaponLayoutSummary(createAgent.SpawnEquipment);
            string effectivePayloadLayout =
                !string.Equals(payloadMissionWeaponLayout, "(none)", StringComparison.Ordinal) &&
                !string.Equals(payloadMissionWeaponLayout, "(empty)", StringComparison.Ordinal)
                    ? payloadMissionWeaponLayout
                    : !string.Equals(payloadSpawnWeaponLayout, "(none)", StringComparison.Ordinal) &&
                      !string.Equals(payloadSpawnWeaponLayout, "(empty)", StringComparison.Ordinal)
                        ? payloadSpawnWeaponLayout
                        : null;
            if (string.IsNullOrWhiteSpace(effectivePayloadLayout))
            {
                resolutionSummary = "payload-character-null-layout-unresolved:no-payload-weapon-layout";
                return false;
            }

            bool payloadMounted =
                createAgent.MountAgentIndex >= 0 ||
                createAgent.SpawnEquipment?[EquipmentIndex.Horse].Item != null ||
                createAgent.SpawnEquipment?[EquipmentIndex.HorseHarness].Item != null;
            List<RosterEntryState> sideEntries = runtimeState.EntriesById.Values
                .Where(entryState =>
                    entryState != null &&
                    DoesClientVisualOverlayEntryMatchAgentSide(entryState, payloadSide))
                .ToList();
            if (sideEntries.Count <= 0)
            {
                resolutionSummary = "payload-character-null-layout-unresolved:no-side-candidates";
                return false;
            }

            List<RosterEntryState> layoutMatches = sideEntries
                .Where(entryState =>
                    ExactCreateAgentCorridorDiagnostics.DoesCreateAgentPayloadWeaponLayoutMatchEntry(entryState, createAgent))
                .ToList();
            if (layoutMatches.Count <= 0)
            {
                resolutionSummary =
                    "payload-character-null-layout-unresolved:no-layout-match" +
                    " PayloadLayout={" + effectivePayloadLayout + "}";
                return false;
            }

            List<RosterEntryState> mountedMatches = layoutMatches
                .Where(entryState => entryState.IsMounted == payloadMounted)
                .ToList();
            List<RosterEntryState> narrowedMatches = mountedMatches.Count > 0
                ? mountedMatches
                : layoutMatches;
            if (narrowedMatches.Count != 1)
            {
                resolutionSummary =
                    "payload-character-null-layout-unresolved:ambiguous-layout-match" +
                    " PayloadLayout={" + effectivePayloadLayout + "}" +
                    " MatchCount=" + narrowedMatches.Count;
                return false;
            }

            entryId = narrowedMatches[0].EntryId;
            resolutionSummary =
                "payload-character-null-layout-resolved" +
                " EntryId=" + (entryId ?? "null") +
                " PayloadLayout={" + effectivePayloadLayout + "}" +
                " PayloadMounted=" + payloadMounted;
            return !string.IsNullOrWhiteSpace(entryId);
        }

        private static bool TryResolveSharedSurrogateShellByUniquePayloadLayout(
            BattleRuntimeState runtimeState,
            List<string> matchingEntryIds,
            CreateAgent createAgent,
            out string entryId,
            out string resolutionSummary)
        {
            entryId = null;
            resolutionSummary = "shared-surrogate-shell-layout-unresolved";
            if (runtimeState?.EntriesById == null ||
                matchingEntryIds == null ||
                matchingEntryIds.Count <= 1 ||
                createAgent == null)
            {
                return false;
            }

            string payloadMissionWeaponLayout =
                ExactCreateAgentPayloadDiagnostics.BuildMissionEquipmentWeaponLayoutSummary(createAgent.MissionEquipment);
            string payloadSpawnWeaponLayout =
                ExactCreateAgentPayloadDiagnostics.BuildEquipmentWeaponLayoutSummary(createAgent.SpawnEquipment);
            string effectivePayloadLayout =
                !string.Equals(payloadMissionWeaponLayout, "(none)", StringComparison.Ordinal) &&
                !string.Equals(payloadMissionWeaponLayout, "(empty)", StringComparison.Ordinal)
                    ? payloadMissionWeaponLayout
                    : !string.Equals(payloadSpawnWeaponLayout, "(none)", StringComparison.Ordinal) &&
                      !string.Equals(payloadSpawnWeaponLayout, "(empty)", StringComparison.Ordinal)
                        ? payloadSpawnWeaponLayout
                        : null;
            if (string.IsNullOrWhiteSpace(effectivePayloadLayout))
            {
                resolutionSummary = "shared-surrogate-shell-layout-unresolved:no-payload-weapon-layout";
                return false;
            }

            bool payloadMounted =
                createAgent.MountAgentIndex >= 0 ||
                createAgent.SpawnEquipment?[EquipmentIndex.Horse].Item != null ||
                createAgent.SpawnEquipment?[EquipmentIndex.HorseHarness].Item != null;
            List<RosterEntryState> layoutMatches = matchingEntryIds
                .Select(candidateEntryId =>
                    runtimeState.EntriesById.TryGetValue(candidateEntryId, out RosterEntryState entryState)
                        ? entryState
                        : null)
                .Where(entryState => entryState != null)
                .Where(entryState =>
                    ExactCreateAgentCorridorDiagnostics.DoesCreateAgentPayloadWeaponLayoutMatchEntry(entryState, createAgent))
                .ToList();
            if (layoutMatches.Count <= 0)
            {
                resolutionSummary =
                    "shared-surrogate-shell-layout-unresolved:no-layout-match" +
                    " PayloadLayout={" + effectivePayloadLayout + "}";
                return false;
            }

            List<RosterEntryState> mountedMatches = layoutMatches
                .Where(entryState => entryState.IsMounted == payloadMounted)
                .ToList();
            List<RosterEntryState> narrowedMatches = mountedMatches.Count > 0
                ? mountedMatches
                : layoutMatches;
            if (narrowedMatches.Count != 1)
            {
                resolutionSummary =
                    "shared-surrogate-shell-layout-unresolved:ambiguous-layout-match" +
                    " PayloadLayout={" + effectivePayloadLayout + "}" +
                    " MatchCount=" + narrowedMatches.Count;
                return false;
            }

            entryId = narrowedMatches[0].EntryId;
            resolutionSummary =
                "shared-surrogate-shell-layout-resolved" +
                " EntryId=" + (entryId ?? "null") +
                " PayloadLayout={" + effectivePayloadLayout + "}" +
                " PayloadMounted=" + payloadMounted;
            return !string.IsNullOrWhiteSpace(entryId);
        }

        private static bool IsMissionPeerAgentEligibleForClientExactVisualOverlay(Agent agent)
        {
            if (agent == null || GameNetwork.IsServer || !GameNetwork.IsClient)
                return false;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            if (localMissionPeer != null &&
                (ReferenceEquals(localMissionPeer.ControlledAgent, agent) ||
                 ReferenceEquals(agent.MissionPeer, localMissionPeer)))
            {
                return true;
            }

            if (agent.MissionPeer != null)
                return true;

            if (ExactCampaignArmyBootstrap.TryGetEntryId(agent, out _) ||
                _materializedArmyEntryIdByAgentIndex.ContainsKey(agent.Index))
            {
                return true;
            }

            if (HasClientExactCampaignVisualOverlayAssignmentQueueCandidate(agent))
                return true;

            return false;
        }

        private static bool HasClientExactCampaignVisualOverlayAssignmentQueueCandidate(Agent agent)
        {
            if (agent == null || agent.Team == null || agent.Team.Side == BattleSideEnum.None)
                return false;

            if (!ShouldAllowQueuedClientExactCampaignVisualOverlayResolution(agent, out _))
                return false;

            string troopId = agent.Character?.StringId;
            if (string.IsNullOrWhiteSpace(troopId))
                return false;

            EnsureClientExactCampaignVisualOverlayQueuesBuilt();
            return _exactNativeClientVisualOverlayEntryQueuesByAssignmentKey.ContainsKey(
                BuildClientExactCampaignVisualOverlayAssignmentKey(agent.Team.Side, troopId));
        }

        private static bool TryResolveQueuedClientExactCampaignVisualOverlayEntryId(Agent agent, out string entryId)
        {
            entryId = null;
            if (agent == null || agent.Team == null || agent.Team.Side == BattleSideEnum.None)
                return false;

            if (!ShouldAllowQueuedClientExactCampaignVisualOverlayResolution(agent, out string blockedReason))
            {
                TryLogSuppressedQueuedClientExactCampaignVisualOverlayResolution(agent, blockedReason);
                return false;
            }

            string troopId = agent.Character?.StringId;
            if (string.IsNullOrWhiteSpace(troopId))
                return false;

            EnsureClientExactCampaignVisualOverlayQueuesBuilt();
            string assignmentKey = BuildClientExactCampaignVisualOverlayAssignmentKey(agent.Team.Side, troopId);
            if (!_exactNativeClientVisualOverlayEntryQueuesByAssignmentKey.TryGetValue(assignmentKey, out Queue<string> entryQueue) ||
                entryQueue == null)
            {
                return false;
            }

            while (entryQueue.Count > 0)
            {
                string candidateEntryId = entryQueue.Dequeue();
                if (string.IsNullOrWhiteSpace(candidateEntryId) ||
                    BattleSnapshotRuntimeState.GetEntryState(candidateEntryId) == null)
                {
                    continue;
                }

                entryId = candidateEntryId;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: resolved client exact visual overlay entry via battlefield assignment queue. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TeamSide=" + agent.Team.Side +
                    " TroopId=" + troopId +
                    " QueueKey=" + assignmentKey +
                    " Remaining=" + entryQueue.Count);
                return true;
            }

            return false;
        }

        private static bool ShouldAllowQueuedClientExactCampaignVisualOverlayResolution(
            Agent agent,
            out string reason)
        {
            reason = null;
            if (agent == null || agent.Index < 0)
            {
                reason = "agent-null";
                return false;
            }

            if (!TryGetClientCreateAgentExactVisualState(agent.Index, out ClientCreateAgentExactVisualRuntimeState state) ||
                state == null)
            {
                return true;
            }

            if (!state.CreateAgentPayloadObserved)
                return true;

            reason =
                "create-agent-payload-observed" +
                "|ResolutionState=" + (state.ResolutionState ?? "unresolved") +
                "|ObservedEntryId=" + (state.EntryId ?? "null") +
                "|AuthoritativeMaterializedObserved=" + state.AuthoritativeMaterializedEntryObserved +
                "|CreateAgentPostfixObserved=" + state.CreateAgentPostfixObserved +
                "|EquipmentSyncObserved=" + state.EquipmentSyncObserved +
                "|OnSpawnWieldEventCount=" + state.OnSpawnWieldEventCount;
            return false;
        }

        private static void TryLogSuppressedQueuedClientExactCampaignVisualOverlayResolution(
            Agent agent,
            string reason)
        {
            if (agent == null || agent.Index < 0)
                return;

            if (!TryGetClientCreateAgentExactVisualState(agent.Index, out ClientCreateAgentExactVisualRuntimeState state) ||
                state == null ||
                state.QueueFallbackSuppressedLogged)
            {
                return;
            }

            state.QueueFallbackSuppressedLogged = true;
            ModLogger.Info(
                "CoopMissionSpawnLogic: suppressed client exact visual overlay battlefield assignment queue fallback. " +
                "AgentIndex=" + agent.Index +
                " CharacterId=" + (agent.Character?.StringId ?? "null") +
                " TeamSide=" + (agent.Team?.Side.ToString() ?? "null") +
                " ObservedEntryId=" + (state.EntryId ?? "null") +
                " ResolutionState=" + (state.ResolutionState ?? "unresolved") +
                " Reason=" + (reason ?? "unknown"));
        }

        private static string BuildClientExactCampaignVisualOverlayAssignmentKey(BattleSideEnum side, string troopId)
        {
            return side + "|" + (troopId ?? string.Empty);
        }

        private static void EnqueueClientExactCampaignVisualOverlayAssignmentEntries(
            BattleSideEnum side,
            string troopId,
            string entryId,
            int availableCount)
        {
            if (side == BattleSideEnum.None ||
                string.IsNullOrWhiteSpace(troopId) ||
                string.IsNullOrWhiteSpace(entryId) ||
                availableCount <= 0)
            {
                return;
            }

            string assignmentKey = BuildClientExactCampaignVisualOverlayAssignmentKey(side, troopId);
            if (!_exactNativeClientVisualOverlayEntryQueuesByAssignmentKey.TryGetValue(assignmentKey, out Queue<string> entryQueue))
            {
                entryQueue = new Queue<string>();
                _exactNativeClientVisualOverlayEntryQueuesByAssignmentKey[assignmentKey] = entryQueue;
            }

            for (int i = 0; i < availableCount; i++)
                entryQueue.Enqueue(entryId);
        }

        private static string ResolveEntryMissionSafeFallbackTroopId(RosterEntryState entryState)
        {
            return BattleSnapshotRuntimeState.TryResolveMissionSafeFallbackCharacterId(
                entryState,
                ResolveEntrySpawnTemplateId(entryState));
        }

        private static void EnsureClientBattleSnapshotFreshForMission(Mission mission, string source)
        {
            if (mission == null || GameNetwork.IsServer || !IsSceneAwareBattleMapRuntime(mission))
                return;

            BattleSnapshotMessage currentSnapshot = BattleSnapshotRuntimeState.GetCurrent();
            string missionSceneName = mission.SceneName ?? string.Empty;
            bool missionChanged = !ReferenceEquals(_lastClientBattleSnapshotRefreshMission, mission);
            bool sceneMismatch = !string.Equals(
                currentSnapshot?.MapScene ?? string.Empty,
                missionSceneName,
                StringComparison.OrdinalIgnoreCase);
            if (!missionChanged && !sceneMismatch)
                return;

            string previousKey = _lastClientBattleSnapshotRefreshKey;
            bool allowLocalBattleRosterFallback =
                !GameNetwork.IsClient &&
                CustomGameJoinContextState.ShouldAllowLocalBattleRosterFileFallback();
            BattleSnapshotMessage refreshedSnapshot = sceneMismatch
                ? (allowLocalBattleRosterFallback ? BattleRosterFileHelper.PeekSnapshot() : null) ?? currentSnapshot
                : (allowLocalBattleRosterFallback ? BattleRosterFileHelper.ReadSnapshot() : null) ?? BattleSnapshotRuntimeState.GetCurrent();
            bool refreshedSceneMatchesMission = string.Equals(
                refreshedSnapshot?.MapScene ?? string.Empty,
                missionSceneName,
                StringComparison.OrdinalIgnoreCase);
            if (sceneMismatch && !refreshedSceneMatchesMission)
            {
                TryLogSkippedClientBattleSnapshotRefresh(missionSceneName, refreshedSnapshot, currentSnapshot, source, previousKey);
                return;
            }

            if (!ReferenceEquals(refreshedSnapshot, currentSnapshot))
                BattleSnapshotRuntimeState.SetCurrent(refreshedSnapshot, "battle-roster-file");

            string refreshedKey = BuildClientBattleSnapshotRefreshKey(refreshedSnapshot);

            ResetClientMissionRuntimeState(
                "EnsureClientBattleSnapshotFreshForMission: " + (source ?? "unknown"));
            CoopSpectator.Patches.BattleMapSpawnHandoffPatch.ResetRuntimeState(
                "EnsureClientBattleSnapshotFreshForMission: " + (source ?? "unknown"),
                preserveCommanderOrderControlState: true);

            _lastClientBattleSnapshotRefreshMission = mission;
            _lastClientBattleSnapshotRefreshKey = refreshedKey;

            ModLogger.Info(
                "CoopMissionSpawnLogic: refreshed client battle snapshot for mission. " +
                "Mission=" + (mission.SceneName ?? "null") +
                " Source=" + (source ?? "unknown") +
                " MissionChanged=" + missionChanged +
                " SceneMismatch=" + sceneMismatch +
                " PreviousSnapshotKey=" + (previousKey ?? "null") +
                " RefreshedSnapshotKey=" + (_lastClientBattleSnapshotRefreshKey ?? "null"));
        }

        private static void TryLogSkippedClientBattleSnapshotRefresh(
            string missionSceneName,
            BattleSnapshotMessage refreshedSnapshot,
            BattleSnapshotMessage currentSnapshot,
            string source,
            string previousKey)
        {
            string signature =
                (missionSceneName ?? "null") + "|" +
                (refreshedSnapshot?.MapScene ?? "null") + "|" +
                (currentSnapshot?.MapScene ?? "null") + "|" +
                (source ?? "unknown");
            DateTime nowUtc = DateTime.UtcNow;
            if (string.Equals(_lastSkippedClientBattleSnapshotRefreshKey, signature, StringComparison.Ordinal) &&
                nowUtc < _nextSkippedClientBattleSnapshotRefreshLogUtc)
            {
                return;
            }

            _lastSkippedClientBattleSnapshotRefreshKey = signature;
            _nextSkippedClientBattleSnapshotRefreshLogUtc = nowUtc.AddSeconds(2);

            ModLogger.Info(
                "CoopMissionSpawnLogic: skipped stale client battle snapshot refresh because candidate scene does not match mission. " +
                "Mission=" + (missionSceneName ?? "null") +
                " Source=" + (source ?? "unknown") +
                " CandidateScene=" + (refreshedSnapshot?.MapScene ?? "null") +
                " CurrentScene=" + (currentSnapshot?.MapScene ?? "null") +
                " PreviousSnapshotKey=" + (previousKey ?? "null"));
        }

        private static string BuildClientBattleSnapshotRefreshKey(BattleSnapshotMessage snapshot)
        {
            if (snapshot == null)
                return "null";

            string sidesSignature = snapshot.Sides == null
                ? "none"
                : string.Join(",",
                    snapshot.Sides.Select(side =>
                        (side?.SideId ?? "null") + ":" +
                        (side?.TotalManCount ?? 0) + ":" +
                        (side?.Troops?.Count ?? 0)));
            return (snapshot.BattleId ?? "null") +
                   "|" +
                   (snapshot.MapScene ?? "null") +
                   "|" +
                   sidesSignature;
        }

        private static bool HasExactCampaignPreSpawnLoadoutInjected(Agent agent)
        {
            if (!ExperimentalFeatures.EnableExactCampaignPreSpawnLoadoutInjection ||
                !GameNetwork.IsServer ||
                !CoopSpectator.Patches.ExactCampaignPreSpawnLoadoutPatch.IsOperationalOnCurrentProcess ||
                agent == null)
            {
                return false;
            }

            string entryId = null;
            if (agent.Origin is ExactCampaignSnapshotAgentOrigin exactOrigin)
            {
                entryId = exactOrigin.EntryId;
            }

            if (string.IsNullOrWhiteSpace(entryId))
                ExactCampaignArmyBootstrap.TryGetEntryId(agent, out entryId);

            if (string.IsNullOrWhiteSpace(entryId))
                _materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out entryId);

            return CoopSpectator.Patches.ExactCampaignPreSpawnLoadoutPatch.WasEquipmentInjectedForEntry(entryId);
        }

        private static bool TryResolveStrictCanonicalOrdinaryEntryState(
            Agent agent,
            out RosterEntryState entryState,
            out string entryId)
        {
            entryState = null;
            entryId = null;

            if (agent == null || agent.IsMount)
                return false;

            if (agent.Origin is ExactCampaignSnapshotAgentOrigin exactOrigin &&
                !string.IsNullOrWhiteSpace(exactOrigin.EntryId))
            {
                entryId = exactOrigin.EntryId;
            }

            if (string.IsNullOrWhiteSpace(entryId))
                ExactCampaignArmyBootstrap.TryGetEntryId(agent, out entryId);

            if (string.IsNullOrWhiteSpace(entryId))
                _materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out entryId);

            if (string.IsNullOrWhiteSpace(entryId))
            {
                string characterId = (agent.Character as BasicCharacterObject)?.StringId;
                CanonicalTroopInstance instance =
                    BattleSnapshotRuntimeState.GetCanonicalTroopInstanceByBattleTemplateId(characterId) ??
                    BattleSnapshotRuntimeState.GetCanonicalTroopInstanceByCharacterId(characterId);
                if (!string.IsNullOrWhiteSpace(instance?.EntryId))
                    entryId = instance.EntryId;
            }

            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            return ShouldUseStrictCanonicalOrdinaryRuntimePath(entryState);
        }

        private static bool ShouldUseStrictCanonicalOrdinaryRuntimePath(RosterEntryState entryState)
        {
            if (entryState == null || entryState.IsHero)
                return false;

            if (entryState.ServerCreateContractResolved &&
                entryState.ServerCreateInjectEquipment &&
                entryState.ServerCreatePreSpawnIncludesWeapons)
            {
                return true;
            }

            return BattleSnapshotRuntimeState.UsesGeneratedRuntimeBattleTemplateMaterialization(entryState.EntryId);
        }

        private static bool TryApplyCanonicalNativeInitialWieldAtAgentBuild(Agent agent, string source)
        {
            if (agent == null ||
                agent.IsMount ||
                agent.SpawnEquipment == null ||
                !TryResolveStrictCanonicalOrdinaryEntryState(agent, out RosterEntryState entryState, out string entryId))
            {
                return false;
            }

            if (GameNetwork.IsServer &&
                (agent.MissionPeer != null || agent.Controller == AgentControllerType.Player))
            {
                return false;
            }

            EquipmentIndex preMainHandIndex = agent.GetPrimaryWieldedItemIndex();
            EquipmentIndex preOffHandIndex = agent.GetOffhandWieldedItemIndex();
            if (preMainHandIndex != EquipmentIndex.None ||
                preOffHandIndex != EquipmentIndex.None ||
                agent.WieldedWeapon.Item != null ||
                agent.WieldedOffhandWeapon.Item != null)
            {
                return false;
            }

            ResolveCanonicalBootstrapDesiredWeaponPair(
                entryState,
                agent.SpawnEquipment,
                out EquipmentIndex desiredMainHandIndex,
                out EquipmentIndex desiredOffHandIndex,
                out Equipment.InitialWeaponEquipPreference initialWeaponEquipPreference,
                out string canonicalWieldReason,
                out bool canonicalWieldResolved);

            try
            {
                agent.WieldInitialWeapons(
                    Agent.WeaponWieldActionType.Instant,
                    initialWeaponEquipPreference);

                EquipmentIndex postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                bool repaired = postMainHandIndex != EquipmentIndex.None || postOffHandIndex != EquipmentIndex.None;

                agent.UpdateAgentProperties();
                agent.MountAgent?.UpdateAgentProperties();

                ModLogger.Info(
                    "CoopMissionSpawnLogic: applied build-stage canonical native initial wield for strict ordinary exact loadout. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + (entryId ?? "null") +
                    " TroopId=" + ((agent.Character as BasicCharacterObject)?.StringId ?? "null") +
                    " PreMain=" + FormatAgentWieldedEquipmentIndex(agent, preMainHandIndex) +
                    " PreOff=" + FormatAgentWieldedEquipmentIndex(agent, preOffHandIndex) +
                    " PostMain=" + FormatAgentWieldedEquipmentIndex(agent, postMainHandIndex) +
                    " PostOff=" + FormatAgentWieldedEquipmentIndex(agent, postOffHandIndex) +
                    " PostWieldedItem=" + (agent.WieldedWeapon.Item?.StringId ?? "none") +
                    " PostOffhandItem=" + (agent.WieldedOffhandWeapon.Item?.StringId ?? "none") +
                    " InitialWeaponEquipPreference=" + initialWeaponEquipPreference +
                    " WieldStrategy=build-stage-single-native-wield{" +
                    "DesiredMain=" + FormatWeaponEquipmentIndex(agent.SpawnEquipment, desiredMainHandIndex) +
                    ",DesiredOff=" + FormatWeaponEquipmentIndex(agent.SpawnEquipment, desiredOffHandIndex) +
                    ",Reason=" + (canonicalWieldReason ?? "none") +
                    ",CanonicalResolved=" + canonicalWieldResolved + "}" +
                    " Repaired=" + repaired +
                    " Runtime=" + (GameNetwork.IsServer ? "server" : (GameNetwork.IsClientOrReplay ? "client" : "offline")) +
                    " Source=" + (source ?? "unknown"));
                return true;
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: build-stage canonical native initial wield failed for strict ordinary exact loadout. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + (entryId ?? "null") +
                    " TroopId=" + ((agent.Character as BasicCharacterObject)?.StringId ?? "null") +
                    " InitialWeaponEquipPreference=" + initialWeaponEquipPreference +
                    " Error=" + ex.GetType().Name +
                    " Message=" + ex.Message +
                    " Runtime=" + (GameNetwork.IsServer ? "server" : (GameNetwork.IsClientOrReplay ? "client" : "offline")) +
                    " Source=" + (source ?? "unknown"));
                return true;
            }
        }

        internal static bool TryApplyImmediateServerExactCampaignNativeRefreshAfterSpawn(
            Agent agent,
            string entryId,
            string source)
        {
            if (!GameNetwork.IsServer ||
                agent == null ||
                !agent.IsActive() ||
                agent.IsMount ||
                string.IsNullOrWhiteSpace(entryId))
            {
                return false;
            }

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (ShouldUseStrictCanonicalOrdinaryRuntimePath(entryState))
                return false;

            return TryApplyExactCampaignSnapshotOverlayToNativeAgent(
                agent,
                entryId,
                source ?? "server immediate post-spawn refresh",
                ExactCampaignSnapshotOverlayMode.ServerAuthoritative,
                includeWeaponsForClientRefresh: false);
        }

        internal static bool TryApplyImmediateServerBootstrapInitialWieldAfterSpawn(
            Agent agent,
            string entryId,
            string source)
        {
            if (!GameNetwork.IsServer ||
                agent == null ||
                !agent.IsActive() ||
                agent.IsMount ||
                string.IsNullOrWhiteSpace(entryId))
            {
                return false;
            }

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (entryState == null ||
                ShouldUseStrictCanonicalOrdinaryRuntimePath(entryState))
            {
                return false;
            }

            return TryApplyServerBootstrapInitialWieldRepairForStrictPreSpawnExactLoadout(
                agent,
                entryState,
                source ?? "server immediate post-spawn wield bootstrap",
                out _);
        }

        private static bool TryApplyExactCampaignSnapshotOverlayToNativeAgent(
            Agent agent,
            string entryId,
            string source,
            ExactCampaignSnapshotOverlayMode overlayMode = ExactCampaignSnapshotOverlayMode.ServerAuthoritative,
            bool includeWeaponsForClientRefresh = false)
        {
            if (agent == null || !agent.IsActive() || agent.IsMount || string.IsNullOrWhiteSpace(entryId))
                return false;

            HashSet<int> appliedAgentIndices =
                overlayMode == ExactCampaignSnapshotOverlayMode.ClientVisualOnly
                    ? _exactNativeClientVisualOverlayAppliedAgentIndices
                    : _exactNativeSnapshotOverlayAppliedAgentIndices;
            HashSet<string> loggedEntryIds =
                overlayMode == ExactCampaignSnapshotOverlayMode.ClientVisualOnly
                    ? _exactNativeClientVisualOverlayLoggedEntryIds
                    : _exactNativeSnapshotOverlayLoggedEntryIds;
            if (appliedAgentIndices.Contains(agent.Index))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (entryState == null)
                return false;

            if (GameNetwork.IsServer &&
                overlayMode == ExactCampaignSnapshotOverlayMode.ServerAuthoritative &&
                ShouldTreatCanonicalGeneratedTemplateAsFinalNativeSpawn(entryState))
            {
                if (TryRefreshCanonicalGeneratedTemplateFinalNativeSpawn(
                        agent,
                        entryState,
                        source,
                        out string generatedNativeRefreshSummary))
                {
                    appliedAgentIndices.Add(agent.Index);
                    if (loggedEntryIds.Add(entryId))
                    {
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: refreshed canonical generated template final native spawn from generated battle template equipment. " +
                            "AgentIndex=" + agent.Index +
                            " EntryId=" + entryId +
                            " TroopId=" + (agent.Character?.StringId ?? "null") +
                            " " + (generatedNativeRefreshSummary ?? "GeneratedNativeRefresh=(none)") +
                            " Source=" + (source ?? "unknown"));
                    }
                }
                else if (loggedEntryIds.Add(entryId + "|refresh-failed"))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: skipped legacy server-authoritative exact overlay because canonical generated template is treated as final native spawn, but generated native refresh was unavailable. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TroopId=" + (agent.Character?.StringId ?? "null") +
                        " " + (generatedNativeRefreshSummary ?? "GeneratedNativeRefresh=(none)") +
                        " Source=" + (source ?? "unknown"));
                }

                return appliedAgentIndices.Contains(agent.Index);
            }

            ExactEntryCompatibilityDiagnostic diagnostic = GetExactEntryCompatibilityDiagnostic(entryState);
            string appliedEquipment = "(none)";
            string equipmentMisses = "(none)";
            string clientLiveWeaponPreservationSummary = null;
            bool clientOverlayLiveWeaponsClearedByRefresh = false;
            bool runtimeExactCharacter = ExactCampaignRuntimeObjectRegistry.IsRuntimeCharacter(agent.Character as BasicCharacterObject);
            bool preSpawnExactLoadoutInjected = HasExactCampaignPreSpawnLoadoutInjected(agent);
            bool enforceServerAuthoritativeOverlayContract =
                GameNetwork.IsServer &&
                overlayMode == ExactCampaignSnapshotOverlayMode.ServerAuthoritative;
            string clientMountVisualRepairReason = null;
            if (enforceServerAuthoritativeOverlayContract &&
                !IsServerAuthoritativeNativeExactOverlaySupported(diagnostic))
            {
                string rejectionReason = BuildServerAuthoritativeNativeExactOverlayRejectionReason(diagnostic);
                appliedAgentIndices.Add(agent.Index);
                LogExactEntryCompatibilityDiagnostic(diagnostic, "native-exact-overlay-reject");
                TraceNativeExactAgentOverlayDecision(
                    "native-overlay-skip",
                    agent,
                    entryState,
                    diagnostic,
                    overlayMode,
                    runtimeExactCharacter,
                    preSpawnExactLoadoutInjected,
                    appliedEquipment,
                    equipmentMisses,
                    rejectionReason,
                    source);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: skipped exact campaign snapshot overlay to native exact agent. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " TroopName=" + (entryState.TroopName ?? "null") +
                    " OverlayMode=" + overlayMode +
                    " RuntimeExactCharacter=" + runtimeExactCharacter +
                    " PreSpawnExactLoadoutInjected=" + preSpawnExactLoadoutInjected +
                    " Reason=" + rejectionReason +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            bool clientVisualOnly = overlayMode == ExactCampaignSnapshotOverlayMode.ClientVisualOnly;
            bool clientHeroEntry = IsHeroEntryEligibleForExactPersonalPerks(entryState);
            if (clientVisualOnly &&
                ShouldPauseClientExactVisualOverlaysBeforeLiveControl(out _))
            {
                return false;
            }
            if (clientVisualOnly &&
                !clientHeroEntry &&
                ShouldPauseClientPostPossessionExactVisualForAgent(agent, out _))
            {
                return false;
            }
            if (clientVisualOnly &&
                clientHeroEntry &&
                ShouldSuppressClientHeroExactVisualOverlayForLocalLiveTakeover(
                    agent,
                    entryId,
                    entryState,
                    out _))
            {
                return false;
            }
            if (clientVisualOnly &&
                clientHeroEntry &&
                ShouldSuppressClientHeroExactVisualOverlayForRemoteLiveControl(
                    agent,
                    entryId,
                    entryState,
                    out _))
            {
                return false;
            }
            bool includeWeaponsForOverlayRefresh =
                clientVisualOnly
                    ? includeWeaponsForClientRefresh
                    : !preSpawnExactLoadoutInjected;
            if (clientVisualOnly &&
                includeWeaponsForOverlayRefresh &&
                IsLocalPeerControlledAgent(agent))
            {
                includeWeaponsForOverlayRefresh = false;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: suppressed weapon-inclusive client exact visual overlay for locally controlled agent. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Source=" + (source ?? "unknown"));
            }
            else if (clientVisualOnly &&
                     includeWeaponsForOverlayRefresh &&
                     !clientHeroEntry &&
                     ShouldDowngradeClientMountedTroopWeaponOverlayRefresh(agent, entryState, out string mountedCooldownReason))
            {
                includeWeaponsForOverlayRefresh = false;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: downgraded weapon-inclusive client exact visual overlay for mounted non-local troop during local post-possession combat stabilization. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Reason=" + (mountedCooldownReason ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
            }
            bool exactSnapshotHasWeapons = HasAnySnapshotWeapons(entryState);
            bool requiresClientVisibleWeaponProjection =
                clientVisualOnly &&
                includeWeaponsForOverlayRefresh &&
                exactSnapshotHasWeapons;
            bool useNativeMountLifecycleForMountedEntry =
                ShouldUseNativeMountLifecycleForExactEntry(entryState);
            bool includeArmorVisualsForOverlayRefresh = true;
            bool includeMountVisualsForOverlayRefresh =
                !clientVisualOnly &&
                !useNativeMountLifecycleForMountedEntry;
            bool requiresClientMountedVisualProjection = false;
            if (clientVisualOnly)
            {
                if (clientHeroEntry &&
                    !TryEnsureTrackedClientMountedHeroMountLinkReady(
                        agent,
                        entryState,
                        source ?? "client exact visual overlay",
                        out _))
                {
                    return false;
                }

                TryApplyEntryIdentityToAgent(agent, entryState);
                includeMountVisualsForOverlayRefresh =
                    !useNativeMountLifecycleForMountedEntry &&
                    clientHeroEntry &&
                    entryState.IsMounted &&
                    ShouldAttemptClientMountedHeroMountVisualRepair(
                        agent,
                        entryState,
                        out clientMountVisualRepairReason);
                requiresClientMountedVisualProjection = includeMountVisualsForOverlayRefresh;
                if (includeMountVisualsForOverlayRefresh)
                {
                    ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                        "client-mount-visual-repair-request",
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " Reason=" + (clientMountVisualRepairReason ?? "none") +
                        " Source=" + (source ?? "unknown"));
                }
            }

            Equipment seedEquipment = agent.SpawnEquipment?.Clone(false);
            string clientTroopWeaponSeedReason = "not-applicable";
            string clientVisualRefreshBypassReason = null;
            if (clientVisualOnly &&
                !clientHeroEntry &&
                !TryPrepareClientTroopVisualRefreshSeedEquipment(
                    agent,
                    entryState,
                    seedEquipment,
                    out seedEquipment,
                    out clientTroopWeaponSeedReason))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: skipped client troop exact visual refresh because weapon seed is unsafe. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " Reason=" + (clientTroopWeaponSeedReason ?? "unknown") +
                    " SpawnWeapons={" + BuildExactEntryEquipmentSummary(
                        agent.SpawnEquipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3) + "}" +
                    " MissionWeapons={" + BuildMissionEquipmentSummary(
                        agent.Equipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3) + "}" +
                    " Source=" + (source ?? "unknown"));
                return false;
            }
            bool clientVisibleWeaponProjectionApplied = !requiresClientVisibleWeaponProjection;
            bool clientMountedVisualProjectionApplied = !requiresClientMountedVisualProjection;
            bool clientVisualRefreshAlreadySatisfied =
                clientVisualOnly &&
                IsClientExactVisualRefreshAlreadySatisfied(
                    agent,
                    entryState,
                    includeWeaponsForOverlayRefresh,
                    includeArmorVisualsForOverlayRefresh,
                    includeMountVisualsForOverlayRefresh,
                    out clientVisualRefreshBypassReason);
            if (clientVisualRefreshAlreadySatisfied)
            {
                clientVisibleWeaponProjectionApplied = !requiresClientVisibleWeaponProjection;
                clientMountedVisualProjectionApplied = true;
            }
            else if (clientVisualOnly)
            {
                TryLogClientExactVisualRefreshMismatch(
                    agent,
                    entryId,
                    entryState,
                    includeWeaponsForOverlayRefresh,
                    includeArmorVisualsForOverlayRefresh,
                    includeMountVisualsForOverlayRefresh,
                    clientVisualRefreshBypassReason,
                    source);
            }
            Equipment spawnEquipment =
                runtimeExactCharacter || (preSpawnExactLoadoutInjected && !clientVisualOnly)
                ? null
                : BuildSnapshotEquipmentForReplaceBot(
                    entryState,
                    seedEquipment,
                    includeWeapons: includeWeaponsForOverlayRefresh,
                    includeArmorVisuals: includeArmorVisualsForOverlayRefresh,
                    includeMountVisuals: includeMountVisualsForOverlayRefresh);
            if (clientVisualOnly &&
                includeWeaponsForOverlayRefresh &&
                clientHeroEntry &&
                spawnEquipment != null &&
                ExactTransferContractBuilder.TryNormalizeStrictHeroWeaponLayoutInPlace(
                    spawnEquipment,
                    entryState,
                    out bool normalizedStrictHeroClientVisualLayout,
                    out string normalizedStrictHeroClientVisualLayoutSummary) &&
                normalizedStrictHeroClientVisualLayout)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: normalized strict hero client exact visual overlay weapon layout before native refresh. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Summary=" + (normalizedStrictHeroClientVisualLayoutSummary ?? "(none)") +
                    " Source=" + (source ?? "unknown"));
            }
            if (runtimeExactCharacter)
            {
                appliedEquipment = "runtime-exact-character";
                equipmentMisses = "post-spawn-refresh-skipped";
            }
            else if (preSpawnExactLoadoutInjected && !clientVisualOnly)
            {
                appliedEquipment = "pre-spawn-exact-loadout";
                equipmentMisses = "overlay-skipped";
            }
            else if (clientVisualRefreshAlreadySatisfied)
            {
                appliedEquipment = "client-refresh-skipped-already-exact";
                equipmentMisses = clientVisualRefreshBypassReason ?? "already-exact";
                if (clientVisualOnly)
                {
                    ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                        "client-exact-visual-refresh-skip-already-exact",
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " Hero=" + entryState.IsHero +
                        " IncludeWeapons=" + includeWeaponsForOverlayRefresh +
                        " IncludeMountVisuals=" + includeMountVisualsForOverlayRefresh +
                        " Reason=" + (clientVisualRefreshBypassReason ?? "already-exact") +
                        " Source=" + (source ?? "unknown"));
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: skipped destructive client exact visual refresh because agent already matches snapshot visuals. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TroopId=" + (agent.Character?.StringId ?? "null") +
                        " Hero=" + entryState.IsHero +
                        " IncludeWeapons=" + includeWeaponsForOverlayRefresh +
                        " IncludeMountVisuals=" + includeMountVisualsForOverlayRefresh +
                        " Reason=" + (clientVisualRefreshBypassReason ?? "already-exact") +
                        " Source=" + (source ?? "unknown"));
                    try
                    {
                        agent.UpdateAgentProperties();
                        agent.MountAgent?.UpdateAgentProperties();
                    }
                    catch (Exception ex)
                    {
                        equipmentMisses =
                            equipmentMisses == "(none)"
                                ? "agent-properties-refresh-failed:" + ex.GetType().Name
                                : equipmentMisses + ", agent-properties-refresh-failed:" + ex.GetType().Name;
                    }

                    if (includeWeaponsForOverlayRefresh && spawnEquipment != null)
                    {
                        string appliedInitialWieldRefresh = null;
                        string initialWieldIssue = null;
                        if (TryRefreshClientOverlayLiveWeaponWieldState(
                                agent,
                                spawnEquipment,
                                entryId,
                                source,
                                out string appliedLiveWieldRefresh,
                                out string liveWieldRefreshIssue))
                        {
                            if (!string.IsNullOrWhiteSpace(appliedLiveWieldRefresh) &&
                                !string.Equals(appliedLiveWieldRefresh, "(none)", StringComparison.Ordinal))
                            {
                                appliedEquipment += ", " + appliedLiveWieldRefresh;
                            }

                            clientVisibleWeaponProjectionApplied = true;
                        }
                        else if (!string.IsNullOrWhiteSpace(liveWieldRefreshIssue) &&
                                 !string.Equals(liveWieldRefreshIssue, "(none)", StringComparison.Ordinal))
                        {
                            equipmentMisses =
                                equipmentMisses == "(none)"
                                    ? liveWieldRefreshIssue
                                    : equipmentMisses + ", " + liveWieldRefreshIssue;

                            if (clientHeroEntry &&
                                TryApplyStrictExactHeroLocalInitialWield(
                                    agent,
                                    entryId,
                                    (source ?? "client exact visual overlay") + " strict-exact-hero-fallback",
                                    out appliedInitialWieldRefresh,
                                    out initialWieldIssue))
                            {
                                if (!string.IsNullOrWhiteSpace(appliedInitialWieldRefresh) &&
                                    !string.Equals(appliedInitialWieldRefresh, "(none)", StringComparison.Ordinal))
                                {
                                    appliedEquipment += ", " + appliedInitialWieldRefresh;
                                }

                                clientVisibleWeaponProjectionApplied = true;
                            }
                            else if (clientHeroEntry &&
                                     !string.IsNullOrWhiteSpace(initialWieldIssue) &&
                                     !string.Equals(initialWieldIssue, "(none)", StringComparison.Ordinal))
                            {
                                equipmentMisses =
                                    equipmentMisses == "(none)"
                                        ? initialWieldIssue
                                        : equipmentMisses + ", " + initialWieldIssue;
                            }
                        }
                    }
                }
            }
            else if (spawnEquipment != null)
            {
                var missedSlots = new List<string>();
                appliedEquipment = TryApplyMaterializedEquipmentOverrides(
                    spawnEquipment,
                    entryState,
                    missedSlots,
                    trackCoverage: false,
                    includeWeapons: includeWeaponsForOverlayRefresh,
                    includeArmorVisuals: includeArmorVisualsForOverlayRefresh,
                    includeMountVisuals: includeMountVisualsForOverlayRefresh);
                if (clientVisualOnly)
                {
                    appliedEquipment =
                        appliedEquipment == "(none)"
                            ? "client-rider-visual-refresh"
                            : "client-rider-visual-refresh, " + appliedEquipment;
                }
                equipmentMisses = missedSlots.Count > 0 ? string.Join(", ", missedSlots) : "(none)";
                if (clientVisualOnly && !includeMountVisualsForOverlayRefresh)
                {
                    string keptNativeSlots = includeWeaponsForOverlayRefresh
                        ? "Horse/HorseHarness=kept-native"
                        : "Weapons/Horse/HorseHarness=kept-native";
                    equipmentMisses =
                        equipmentMisses == "(none)"
                            ? keptNativeSlots
                            : equipmentMisses + ", " + keptNativeSlots;
                }

                if (clientVisualOnly &&
                    !includeWeaponsForOverlayRefresh &&
                    TryPreserveEquipmentWeaponSlotsFromMissionEquipment(
                        spawnEquipment,
                        agent.Equipment,
                        out string preservedLiveWeapons))
                {
                    clientLiveWeaponPreservationSummary = preservedLiveWeapons;
                }

                string clientOverlayPreRefreshSnapshot = null;
                string clientOverlayBeforeMissionWeapons = null;
                bool clientOverlayBeforeMissionHadWeapons = false;
                if (clientVisualOnly)
                {
                    clientOverlayPreRefreshSnapshot =
                        "SnapshotWeapons={" + Infrastructure.ExactCreateAgentPayloadDiagnostics.BuildEntryWeaponLayoutSummary(entryState) + "}" +
                        " SeedSpawnWeapons={" + BuildExactEntryEquipmentSummary(
                            seedEquipment,
                            EquipmentIndex.Weapon0,
                            EquipmentIndex.Weapon1,
                            EquipmentIndex.Weapon2,
                            EquipmentIndex.Weapon3) + "}" +
                        " BeforeSpawnWeapons={" + BuildExactEntryEquipmentSummary(
                            agent.SpawnEquipment,
                            EquipmentIndex.Weapon0,
                            EquipmentIndex.Weapon1,
                            EquipmentIndex.Weapon2,
                            EquipmentIndex.Weapon3) + "}" +
                        " BeforeMissionWeapons={" + BuildMissionEquipmentSummary(
                            agent.Equipment,
                            EquipmentIndex.Weapon0,
                            EquipmentIndex.Weapon1,
                            EquipmentIndex.Weapon2,
                            EquipmentIndex.Weapon3) + "}" +
                        " OverlaySpawnWeapons={" + BuildExactEntryEquipmentSummary(
                            spawnEquipment,
                            EquipmentIndex.Weapon0,
                            EquipmentIndex.Weapon1,
                            EquipmentIndex.Weapon2,
                            EquipmentIndex.Weapon3) + "}" +
                        " PreservedLiveWeapons={" + (clientLiveWeaponPreservationSummary ?? "(none)") + "}";
                    clientOverlayBeforeMissionWeapons = BuildMissionEquipmentSummary(
                        agent.Equipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3);
                    clientOverlayBeforeMissionHadWeapons = HasAnyMissionWeapons(
                        agent.Equipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: client exact visual overlay refresh pre-state. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TroopId=" + (agent.Character?.StringId ?? "null") +
                        " Hero=" + entryState.IsHero +
                        " IncludeWeapons=" + includeWeaponsForOverlayRefresh +
                        " WeaponSeedPolicy=" + clientTroopWeaponSeedReason +
                        " RuntimeExactCharacter=" + runtimeExactCharacter +
                        " PreSpawnExactLoadoutInjected=" + preSpawnExactLoadoutInjected +
                        " " + clientOverlayPreRefreshSnapshot +
                        " Source=" + (source ?? "unknown"));
                }

                try
                {
                    agent.UpdateSpawnEquipmentAndRefreshVisuals(spawnEquipment);
                }
                catch (Exception ex)
                {
                    equipmentMisses =
                        equipmentMisses == "(none)"
                            ? "visual-refresh-failed:" + ex.GetType().Name
                            : equipmentMisses + ", visual-refresh-failed:" + ex.GetType().Name;
                }

                if (clientVisualOnly)
                {
                    string afterSpawnWeapons = BuildExactEntryEquipmentSummary(
                        agent.SpawnEquipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3);
                    string afterMissionWeapons = BuildMissionEquipmentSummary(
                        agent.Equipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3);
                    bool afterMissionHasWeapons = HasAnyMissionWeapons(
                        agent.Equipment,
                        EquipmentIndex.Weapon0,
                        EquipmentIndex.Weapon1,
                        EquipmentIndex.Weapon2,
                        EquipmentIndex.Weapon3);
                    clientOverlayLiveWeaponsClearedByRefresh =
                        clientOverlayBeforeMissionHadWeapons &&
                        !afterMissionHasWeapons;
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: client exact visual overlay refresh post-state. " +
                        "AgentIndex=" + agent.Index +
                        " EntryId=" + entryId +
                        " TroopId=" + (agent.Character?.StringId ?? "null") +
                        " Hero=" + entryState.IsHero +
                        " IncludeWeapons=" + includeWeaponsForOverlayRefresh +
                        " BeforeMissionHadWeapons=" + clientOverlayBeforeMissionHadWeapons +
                        " AfterMissionHadWeapons=" + afterMissionHasWeapons +
                        " LiveWeaponsClearedByRefresh=" + clientOverlayLiveWeaponsClearedByRefresh +
                        " BeforeMissionWeapons={" + (clientOverlayBeforeMissionWeapons ?? "(none)") + "}" +
                        " AfterSpawnWeapons={" + afterSpawnWeapons + "}" +
                        " AfterMissionWeapons={" + afterMissionWeapons + "}" +
                        " PreservedLiveWeapons={" + (clientLiveWeaponPreservationSummary ?? "(none)") + "}" +
                        " Source=" + (source ?? "unknown"));
                }

                if (equipmentMisses.IndexOf("visual-refresh-failed:", StringComparison.Ordinal) < 0)
                {
                    bool shouldRunServerLiveWieldRefresh =
                        !clientVisualOnly &&
                        GameNetwork.IsServer &&
                        spawnEquipment != null &&
                        includeWeaponsForOverlayRefresh &&
                        !entryState.IsHero &&
                        !agent.IsMount &&
                        agent.MissionPeer == null &&
                        agent.Controller != AgentControllerType.Player;
                    if (shouldRunServerLiveWieldRefresh)
                    {
                        if (TryRefreshServerOverlayLiveWeaponWieldState(
                                agent,
                                spawnEquipment,
                                entryId,
                                source,
                                out string appliedServerLiveWieldRefresh,
                                out string serverLiveWieldRefreshIssue))
                        {
                            if (!string.IsNullOrWhiteSpace(appliedServerLiveWieldRefresh) &&
                                !string.Equals(appliedServerLiveWieldRefresh, "(none)", StringComparison.Ordinal))
                            {
                                appliedEquipment += ", " + appliedServerLiveWieldRefresh;
                            }
                        }
                        else if (!string.IsNullOrWhiteSpace(serverLiveWieldRefreshIssue) &&
                                 !string.Equals(serverLiveWieldRefreshIssue, "(none)", StringComparison.Ordinal))
                        {
                            equipmentMisses =
                                equipmentMisses == "(none)"
                                    ? serverLiveWieldRefreshIssue
                                    : equipmentMisses + ", " + serverLiveWieldRefreshIssue;
                        }
                    }

                    if (clientVisualOnly && includeWeaponsForOverlayRefresh)
                    {
                        try
                        {
                            agent.WieldInitialWeapons(
                                Agent.WeaponWieldActionType.Instant,
                                Equipment.InitialWeaponEquipPreference.Any);
                        }
                        catch (Exception ex)
                        {
                            equipmentMisses =
                                equipmentMisses == "(none)"
                                    ? "client-wield-refresh-failed:" + ex.GetType().Name
                                    : equipmentMisses + ", client-wield-refresh-failed:" + ex.GetType().Name;
                        }
                    }

                    if (clientVisualOnly && includeMountVisualsForOverlayRefresh)
                    {
                        if (TryRefreshClientMountedHeroExactMountVisuals(
                                agent,
                                entryState,
                                entryId,
                                source,
                                clientMountVisualRepairReason,
                                out string appliedMountVisuals,
                                out string mountVisualRefreshIssue))
                        {
                            if (!string.IsNullOrWhiteSpace(appliedMountVisuals) &&
                                !string.Equals(appliedMountVisuals, "(none)", StringComparison.Ordinal))
                            {
                                appliedEquipment += ", Mount=" + appliedMountVisuals;
                            }

                            clientMountedVisualProjectionApplied = true;
                        }
                        else if (!string.IsNullOrWhiteSpace(mountVisualRefreshIssue) &&
                                 !string.Equals(mountVisualRefreshIssue, "(none)", StringComparison.Ordinal))
                        {
                            equipmentMisses =
                                equipmentMisses == "(none)"
                                    ? mountVisualRefreshIssue
                                    : equipmentMisses + ", " + mountVisualRefreshIssue;
                        }
                    }
                    try
                    {
                        if (clientVisualOnly)
                            agent.UpdateAgentProperties();

                        if (includeMountVisualsForOverlayRefresh || clientVisualOnly)
                            agent.MountAgent?.UpdateAgentProperties();
                    }
                    catch (Exception ex)
                    {
                        equipmentMisses =
                            equipmentMisses == "(none)"
                                ? "agent-properties-refresh-failed:" + ex.GetType().Name
                                : equipmentMisses + ", agent-properties-refresh-failed:" + ex.GetType().Name;
                    }

                    bool shouldRunClientLiveWieldRefresh =
                        clientVisualOnly &&
                        spawnEquipment != null &&
                        (includeWeaponsForOverlayRefresh || requiresClientVisibleWeaponProjection);
                    if (shouldRunClientLiveWieldRefresh)
                    {
                        string appliedInitialWieldRefresh = null;
                        string initialWieldIssue = null;
                        if (TryRefreshClientOverlayLiveWeaponWieldState(
                                agent,
                                spawnEquipment,
                                entryId,
                                source,
                                out string appliedLiveWieldRefresh,
                                out string liveWieldRefreshIssue))
                        {
                            if (!string.IsNullOrWhiteSpace(appliedLiveWieldRefresh) &&
                                !string.Equals(appliedLiveWieldRefresh, "(none)", StringComparison.Ordinal))
                            {
                                appliedEquipment += ", " + appliedLiveWieldRefresh;
                            }

                            if (requiresClientVisibleWeaponProjection)
                                clientVisibleWeaponProjectionApplied = true;
                        }
                        else if (!string.IsNullOrWhiteSpace(liveWieldRefreshIssue) &&
                                 !string.Equals(liveWieldRefreshIssue, "(none)", StringComparison.Ordinal))
                        {
                            equipmentMisses =
                                equipmentMisses == "(none)"
                                    ? liveWieldRefreshIssue
                                    : equipmentMisses + ", " + liveWieldRefreshIssue;

                            if (clientHeroEntry &&
                                includeWeaponsForOverlayRefresh &&
                                TryApplyStrictExactHeroLocalInitialWield(
                                    agent,
                                    entryId,
                                    (source ?? "client exact visual overlay") + " strict-exact-hero-fallback",
                                    out appliedInitialWieldRefresh,
                                    out initialWieldIssue))
                            {
                                if (!string.IsNullOrWhiteSpace(appliedInitialWieldRefresh) &&
                                    !string.Equals(appliedInitialWieldRefresh, "(none)", StringComparison.Ordinal))
                                {
                                    appliedEquipment += ", " + appliedInitialWieldRefresh;
                                }

                                clientVisibleWeaponProjectionApplied = true;
                            }
                            else if (clientHeroEntry &&
                                     includeWeaponsForOverlayRefresh &&
                                     !string.IsNullOrWhiteSpace(initialWieldIssue) &&
                                     !string.Equals(initialWieldIssue, "(none)", StringComparison.Ordinal))
                            {
                                equipmentMisses =
                                    equipmentMisses == "(none)"
                                        ? initialWieldIssue
                                        : equipmentMisses + ", " + initialWieldIssue;
                            }
                        }
                    }
                }

            }
            else if (preSpawnExactLoadoutInjected)
            {
                appliedEquipment = "client-rider-visual-refresh";
                equipmentMisses = includeWeaponsForOverlayRefresh
                    ? "Horse/HorseHarness=kept-native, client-refresh-equipment-unavailable"
                    : "Weapons/Horse/HorseHarness=kept-native, client-refresh-equipment-unavailable";
            }

            if (clientVisualOnly &&
                clientOverlayLiveWeaponsClearedByRefresh)
            {
                equipmentMisses =
                    equipmentMisses == "(none)"
                        ? "live-weapons-cleared-by-refresh"
                        : equipmentMisses + ", live-weapons-cleared-by-refresh";
                ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                    "client-exact-visual-refresh-cleared-live-weapons",
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Hero=" + clientHeroEntry +
                    " IncludeWeapons=" + includeWeaponsForOverlayRefresh +
                    " PreservedLiveWeapons={" + (clientLiveWeaponPreservationSummary ?? "(none)") + "}" +
                    " Source=" + (source ?? "unknown"));
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client exact final materialization because visual refresh cleared live weapons. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " Hero=" + clientHeroEntry +
                    " IncludeWeapons=" + includeWeaponsForOverlayRefresh +
                    " AppliedEquipment=" + appliedEquipment +
                    " EquipmentMisses=" + equipmentMisses +
                    " PreservedLiveWeapons={" + (clientLiveWeaponPreservationSummary ?? "(none)") + "}" +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            if (clientVisualOnly &&
                requiresClientVisibleWeaponProjection &&
                !clientVisibleWeaponProjectionApplied)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client exact final materialization because visible weapon projection is incomplete. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " Hero=" + clientHeroEntry +
                    " AppliedEquipment=" + appliedEquipment +
                    " EquipmentMisses=" + equipmentMisses +
                    " WeaponSeedPolicy=" + clientTroopWeaponSeedReason +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            if (clientVisualOnly &&
                requiresClientMountedVisualProjection &&
                !clientMountedVisualProjectionApplied)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred client exact final materialization because mounted visual projection is incomplete. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " Hero=" + clientHeroEntry +
                    " AppliedEquipment=" + appliedEquipment +
                    " EquipmentMisses=" + equipmentMisses +
                    " MountRepairReason=" + (clientMountVisualRepairReason ?? "none") +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            if (!clientVisualOnly)
                TryApplyEntryIdentityToAgent(agent, entryState);
            string appliedCombatProfile =
                overlayMode == ExactCampaignSnapshotOverlayMode.ServerAuthoritative
                    ? TryApplyMaterializedCombatProfile(agent, entryState)
                    : TryApplyClientVisualOnlyCombatProfile(agent, entryState);
            appliedAgentIndices.Add(agent.Index);
            if (clientVisualOnly)
            {
                _exactNativeClientVisualOverlayIncludesWeaponsByAgentIndex[agent.Index] =
                    !exactSnapshotHasWeapons ||
                    (!includeWeaponsForOverlayRefresh && !requiresClientVisibleWeaponProjection) ||
                    clientVisibleWeaponProjectionApplied;
                if (clientHeroEntry)
                    UpdateStrictExactHeroTransferVisualAppliedState(agent.Index, entryId, includeWeaponsForOverlayRefresh, source ?? "client exact visual apply");
            }
            if (enforceServerAuthoritativeOverlayContract)
            {
                TraceNativeExactAgentOverlayDecision(
                    "native-overlay-apply",
                    agent,
                    entryState,
                    diagnostic,
                    overlayMode,
                    runtimeExactCharacter,
                    preSpawnExactLoadoutInjected,
                    appliedEquipment,
                    equipmentMisses,
                    "applied",
                    source);
            }

            if (loggedEntryIds.Add(entryId))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: applied " +
                    (overlayMode == ExactCampaignSnapshotOverlayMode.ClientVisualOnly
                        ? "client-local exact campaign visual overlay"
                        : "exact campaign snapshot overlay") +
                    " to native exact agent. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TroopId=" + (agent.Character?.StringId ?? "null") +
                    " TroopName=" + (entryState.TroopName ?? "null") +
                    " Hero=" + entryState.IsHero +
                    " AppliedEquipment=" + appliedEquipment +
                    " EquipmentMisses=" + equipmentMisses +
                    " " + appliedCombatProfile +
                    " Source=" + (source ?? "unknown"));
            }

            return true;
        }

        private static bool TryRefreshServerOverlayLiveWeaponWieldState(
            Agent agent,
            Equipment overlaySpawnEquipment,
            string entryId,
            string source,
            out string appliedWieldRefresh,
            out string wieldRefreshIssue)
        {
            appliedWieldRefresh = "(none)";
            wieldRefreshIssue = "(none)";
            if (!GameNetwork.IsServer ||
                agent == null ||
                overlaySpawnEquipment == null ||
                agent.IsMount ||
                agent.MissionPeer != null ||
                agent.Controller == AgentControllerType.Player)
            {
                wieldRefreshIssue = "server-live-wield-refresh-skipped:invalid-agent";
                return false;
            }

            try
            {
                EquipmentIndex preMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex preOffHandIndex = agent.GetOffhandWieldedItemIndex();
                string wieldStrategy = "initial-weapons";
                overlaySpawnEquipment.GetInitialWeaponIndicesToEquip(
                    out EquipmentIndex desiredMainHandIndex,
                    out EquipmentIndex desiredOffHandIndex,
                    out bool desiredMainNotUsableWithOneHand,
                    Equipment.InitialWeaponEquipPreference.Any);
                EquipmentIndex desiredAmmoIndex =
                    ResolveDesiredLiveAmmoEquipmentIndex(overlaySpawnEquipment, desiredMainHandIndex);
                string livePairNormalization = NormalizeDesiredLiveWeaponPairForShieldIncompatibleMain(
                    overlaySpawnEquipment,
                    ref desiredMainHandIndex,
                    ref desiredOffHandIndex,
                    desiredMainNotUsableWithOneHand);

                if (TryRefreshServerOverlayMissionWeaponRuntime(
                        agent,
                        overlaySpawnEquipment,
                        desiredMainHandIndex,
                        desiredAmmoIndex,
                        out string preWieldRuntimeRefreshSummary))
                {
                    wieldStrategy += "+" + preWieldRuntimeRefreshSummary;
                }

                agent.WieldInitialWeapons(
                    Agent.WeaponWieldActionType.Instant,
                    Equipment.InitialWeaponEquipPreference.Any);

                EquipmentIndex postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                if (postMainHandIndex == EquipmentIndex.None && postOffHandIndex == EquipmentIndex.None)
                {
                    if (TryForceServerBootstrapWeaponWieldFromEquipment(
                            agent,
                            overlaySpawnEquipment,
                            null,
                            out string explicitWieldSummary))
                    {
                        wieldStrategy += "+" + explicitWieldSummary;
                    }

                    postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                    postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                }

                if (postMainHandIndex == EquipmentIndex.None && postOffHandIndex == EquipmentIndex.None)
                {
                    agent.WieldNextWeapon(
                        Agent.HandIndex.MainHand,
                        Agent.WeaponWieldActionType.InstantAfterPickUp);
                    wieldStrategy += "+wield-next-weapon";
                    postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                    postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                }

                if (TryEnsureServerOverlayDesiredWeaponPairWield(
                        agent,
                        overlaySpawnEquipment,
                        desiredMainHandIndex,
                        desiredOffHandIndex,
                        out string desiredPairWieldSummary))
                {
                    wieldStrategy += "+" + desiredPairWieldSummary;
                    postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                    postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                }

                if (!IsDesiredLiveMainAmmoReady(agent, overlaySpawnEquipment, desiredMainHandIndex, desiredAmmoIndex) &&
                    TryRefreshServerOverlayMissionWeaponRuntime(
                        agent,
                        overlaySpawnEquipment,
                        desiredMainHandIndex,
                        desiredAmmoIndex,
                        out string rangedAmmoRuntimeRefreshSummary))
                {
                    wieldStrategy += "+" + rangedAmmoRuntimeRefreshSummary;
                    agent.WieldInitialWeapons(
                        Agent.WeaponWieldActionType.Instant,
                        Equipment.InitialWeaponEquipPreference.Any);
                    postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                    postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                }

                agent.UpdateAgentProperties();
                agent.MountAgent?.UpdateAgentProperties();

                bool success = HasDesiredLiveWeaponPair(
                    agent,
                    overlaySpawnEquipment,
                    desiredMainHandIndex,
                    desiredOffHandIndex,
                    desiredAmmoIndex);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: server live wield refresh after native exact overlay " +
                    (success ? "completed. " : "failed. ") +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + (entryId ?? "null") +
                    " TroopId=" + ((agent.Character as BasicCharacterObject)?.StringId ?? "null") +
                    " PreMain=" + FormatAgentWieldedEquipmentIndex(agent, preMainHandIndex) +
                    " PreOff=" + FormatAgentWieldedEquipmentIndex(agent, preOffHandIndex) +
                    " PostMain=" + FormatAgentWieldedEquipmentIndex(agent, postMainHandIndex) +
                    " PostOff=" + FormatAgentWieldedEquipmentIndex(agent, postOffHandIndex) +
                    " PostWieldedItem=" + (agent.WieldedWeapon.Item?.StringId ?? "none") +
                    " PostOffhandItem=" + (agent.WieldedOffhandWeapon.Item?.StringId ?? "none") +
                    " PostAmmoItem=" + (agent.WieldedWeapon.AmmoWeapon.Item?.StringId ?? "none") +
                    " DesiredMain=" + FormatWeaponEquipmentIndex(overlaySpawnEquipment, desiredMainHandIndex) +
                    " DesiredOff=" + FormatWeaponEquipmentIndex(overlaySpawnEquipment, desiredOffHandIndex) +
                    " DesiredAmmo=" + FormatWeaponEquipmentIndex(overlaySpawnEquipment, desiredAmmoIndex) +
                    " LivePairNormalization=" + livePairNormalization +
                    " MainNotUsableWithOneHand=" + desiredMainNotUsableWithOneHand +
                    " WieldStrategy=" + wieldStrategy +
                    " Source=" + (source ?? "unknown"));

                if (!success)
                {
                    wieldRefreshIssue = "server-live-wield-refresh-failed:primary-none";
                    return false;
                }

                appliedWieldRefresh = "Wield=server-live-refresh";
                return true;
            }
            catch (Exception ex)
            {
                wieldRefreshIssue = "server-live-wield-refresh-failed:" + ex.GetType().Name;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: server live wield refresh after native exact overlay failed. " +
                    "AgentIndex=" + (agent?.Index.ToString() ?? "null") +
                    " EntryId=" + (entryId ?? "null") +
                    " ExceptionType=" + ex.GetType().Name +
                    " Message=" + ex.Message +
                    " Source=" + (source ?? "unknown"));
                return false;
            }
        }

        private static bool TryRefreshServerOverlayMissionWeaponRuntime(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex,
            EquipmentIndex desiredAmmoIndex,
            out string refreshSummary)
        {
            refreshSummary = "update-weapons-skipped";
            if (agent == null || equipment == null)
                return false;

            bool needsRefresh =
                !IsDesiredLiveMainWeaponReady(agent, equipment, desiredMainHandIndex) ||
                !IsDesiredLiveMainAmmoReady(agent, equipment, desiredMainHandIndex, desiredAmmoIndex);
            if (!needsRefresh)
                return false;

            try
            {
                string ammoPrimeSummary = null;
                if (TryPrimeServerOverlayDesiredAmmoRuntime(
                        agent,
                        equipment,
                        desiredMainHandIndex,
                        desiredAmmoIndex,
                        out string ammoPrimeAttemptSummary))
                {
                    ammoPrimeSummary = ammoPrimeAttemptSummary;
                }

                agent.UpdateWeapons();
                refreshSummary =
                    (string.IsNullOrWhiteSpace(ammoPrimeSummary)
                        ? string.Empty
                        : ammoPrimeSummary + "+") +
                    "update-weapons{" +
                    "PostMain=" + FormatAgentWieldedEquipmentIndex(agent, agent.GetPrimaryWieldedItemIndex()) +
                    ",PostOff=" + FormatAgentWieldedEquipmentIndex(agent, agent.GetOffhandWieldedItemIndex()) +
                    ",PostAmmo=" + (agent.WieldedWeapon.AmmoWeapon.Item?.StringId ?? "none") + "}";
                return true;
            }
            catch (Exception ex)
            {
                refreshSummary = "update-weapons-failed:" + ex.GetType().Name;
                return false;
            }
        }

        private static bool TryPrimeServerOverlayDesiredAmmoRuntime(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex,
            EquipmentIndex desiredAmmoIndex,
            out string refreshSummary)
        {
            refreshSummary = "check-loaded-ammos-skipped";
            if (agent?.Equipment == null ||
                equipment == null ||
                !IsUsableWeaponEquipmentIndex(equipment, desiredMainHandIndex) ||
                !IsUsableWeaponEquipmentIndex(equipment, desiredAmmoIndex))
            {
                return false;
            }

            ItemObject desiredMainItem = equipment[desiredMainHandIndex].Item;
            if (desiredMainItem?.PrimaryWeapon == null ||
                !desiredMainItem.PrimaryWeapon.IsRangedWeapon ||
                desiredMainItem.PrimaryWeapon.WeaponClass != WeaponClass.Crossbow ||
                IsDesiredLiveMainAmmoReady(agent, equipment, desiredMainHandIndex, desiredAmmoIndex))
            {
                return false;
            }

            try
            {
                string beforeSummary = BuildMissionEquipmentSummary(
                    agent.Equipment,
                    desiredMainHandIndex,
                    desiredAmmoIndex);
                agent.Equipment.CheckLoadedAmmos();
                refreshSummary =
                    "check-loaded-ammos{" +
                    "Before=" + beforeSummary +
                    ",After=" + BuildMissionEquipmentSummary(
                        agent.Equipment,
                        desiredMainHandIndex,
                        desiredAmmoIndex) +
                    ",PostAmmo=" + (agent.WieldedWeapon.AmmoWeapon.Item?.StringId ?? "none") + "}";
                return true;
            }
            catch (Exception ex)
            {
                refreshSummary = "check-loaded-ammos-failed:" + ex.GetType().Name;
                return false;
            }
        }

        private static bool TryEnsureServerOverlayDesiredWeaponPairWield(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex,
            EquipmentIndex desiredOffHandIndex,
            out string wieldSummary)
        {
            wieldSummary = "desired-pair-wield-skipped";
            if (agent == null || equipment == null)
                return false;

            bool needsMainRefresh =
                !IsDesiredLiveMainWeaponReady(agent, equipment, desiredMainHandIndex);
            bool needsOffRefresh =
                !IsDesiredLiveOffhandWeaponReady(agent, equipment, desiredOffHandIndex);
            if (!needsMainRefresh && !needsOffRefresh)
                return false;

            try
            {
                bool usedImmediate = false;
                bool queuedTickWield = false;

                if (needsOffRefresh)
                {
                    agent.TryToWieldWeaponInSlot(
                        desiredOffHandIndex,
                        Agent.WeaponWieldActionType.InstantAfterPickUp,
                        false);
                    usedImmediate = true;
                }

                if (needsMainRefresh)
                {
                    agent.TryToWieldWeaponInSlot(
                        desiredMainHandIndex,
                        Agent.WeaponWieldActionType.InstantAfterPickUp,
                        false);
                    usedImmediate = true;
                }

                bool mainStillMissing =
                    !IsDesiredLiveMainWeaponReady(agent, equipment, desiredMainHandIndex);
                bool offStillMissing =
                    !IsDesiredLiveOffhandWeaponReady(agent, equipment, desiredOffHandIndex);
                if ((mainStillMissing || offStillMissing) &&
                    agent.Mission != null &&
                    _pendingServerBootstrapDelayedLiveWieldAgentIndices.Add(agent.Index))
                {
                    queuedTickWield = TryQueueServerBootstrapDelayedWeaponWield(
                        agent,
                        equipment,
                        desiredMainHandIndex,
                        desiredOffHandIndex);
                }

                wieldSummary =
                    "desired-pair-wield{" +
                    "NeedsMain=" + needsMainRefresh +
                    ",NeedsOff=" + needsOffRefresh +
                    ",UsedImmediate=" + usedImmediate +
                    ",QueuedTickWield=" + queuedTickWield +
                    ",PostMain=" + FormatAgentWieldedEquipmentIndex(agent, agent.GetPrimaryWieldedItemIndex()) +
                    ",PostOff=" + FormatAgentWieldedEquipmentIndex(agent, agent.GetOffhandWieldedItemIndex()) + "}";
                return usedImmediate || queuedTickWield;
            }
            catch (Exception ex)
            {
                wieldSummary = "desired-pair-wield-failed:" + ex.GetType().Name;
                return false;
            }
        }

        private static bool TryRefreshClientOverlayLiveWeaponWieldState(
            Agent agent,
            Equipment overlaySpawnEquipment,
            string entryId,
            string source,
            out string appliedWieldRefresh,
            out string wieldRefreshIssue)
        {
            appliedWieldRefresh = "(none)";
            wieldRefreshIssue = "(none)";
            if (agent == null || overlaySpawnEquipment == null || agent.IsMount)
                return false;

            if (IsLocalPeerControlledAgent(agent))
            {
                wieldRefreshIssue = "client-live-wield-refresh-skipped:local-controlled-agent";
                return false;
            }

            try
            {
                overlaySpawnEquipment.GetInitialWeaponIndicesToEquip(
                    out EquipmentIndex desiredMainHandIndex,
                    out EquipmentIndex desiredOffHandIndex,
                    out bool mainNotUsableWithOneHand,
                    Equipment.InitialWeaponEquipPreference.Any);

                bool hasDesiredMainHand = IsUsableWeaponEquipmentIndex(overlaySpawnEquipment, desiredMainHandIndex);
                bool hasDesiredOffHand = IsUsableWeaponEquipmentIndex(overlaySpawnEquipment, desiredOffHandIndex);
                if (!hasDesiredMainHand && !hasDesiredOffHand)
                {
                    wieldRefreshIssue = "client-live-wield-refresh-skipped:no-weapon";
                    return false;
                }

                EquipmentIndex preMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex preOffHandIndex = agent.GetOffhandWieldedItemIndex();
                int desiredMainHandUsageIndex = ResolveEquipmentCurrentUsageIndex(agent, overlaySpawnEquipment, desiredMainHandIndex);

                if (preOffHandIndex != EquipmentIndex.None)
                    agent.TryToSheathWeaponInHand(Agent.HandIndex.OffHand, Agent.WeaponWieldActionType.Instant);
                if (preMainHandIndex != EquipmentIndex.None)
                    agent.TryToSheathWeaponInHand(Agent.HandIndex.MainHand, Agent.WeaponWieldActionType.Instant);

                if (hasDesiredOffHand)
                {
                    agent.SetWieldedItemIndexAsClient(
                        Agent.HandIndex.OffHand,
                        desiredOffHandIndex,
                        isWieldedInstantly: true,
                        isWieldedOnSpawn: false,
                        desiredMainHandUsageIndex);
                    agent.TryToWieldWeaponInSlot(
                        desiredOffHandIndex,
                        Agent.WeaponWieldActionType.InstantAfterPickUp,
                        isWieldedOnSpawn: false);
                }

                if (hasDesiredMainHand)
                {
                    agent.SetWieldedItemIndexAsClient(
                        Agent.HandIndex.MainHand,
                        desiredMainHandIndex,
                        isWieldedInstantly: true,
                        isWieldedOnSpawn: false,
                        desiredMainHandUsageIndex);
                    agent.TryToWieldWeaponInSlot(
                        desiredMainHandIndex,
                        Agent.WeaponWieldActionType.InstantAfterPickUp,
                        isWieldedOnSpawn: false);
                    if (agent.GetPrimaryWieldedItemIndex() == EquipmentIndex.None)
                    {
                        agent.WieldNextWeapon(
                            Agent.HandIndex.MainHand,
                            Agent.WeaponWieldActionType.InstantAfterPickUp);
                    }
                }

                EquipmentIndex postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                string details =
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + (entryId ?? "null") +
                    " DesiredMain=" + FormatWeaponEquipmentIndex(overlaySpawnEquipment, desiredMainHandIndex) +
                    " DesiredOff=" + FormatWeaponEquipmentIndex(overlaySpawnEquipment, desiredOffHandIndex) +
                    " MainNotUsableWithOneHand=" + mainNotUsableWithOneHand +
                    " PreMain=" + FormatAgentWieldedEquipmentIndex(agent, preMainHandIndex) +
                    " PreOff=" + FormatAgentWieldedEquipmentIndex(agent, preOffHandIndex) +
                    " PostMain=" + FormatAgentWieldedEquipmentIndex(agent, postMainHandIndex) +
                    " PostOff=" + FormatAgentWieldedEquipmentIndex(agent, postOffHandIndex) +
                    " PostWieldedItem=" + (agent.WieldedWeapon.Item?.StringId ?? "none") +
                    " PostOffhandItem=" + (agent.WieldedOffhandWeapon.Item?.StringId ?? "none") +
                    " Source=" + (source ?? "unknown");
                bool success = !hasDesiredMainHand || postMainHandIndex != EquipmentIndex.None;
                ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                    success
                        ? "client-live-wield-refresh"
                        : "client-live-wield-refresh-failed",
                    details);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: client live wield refresh " +
                    (success ? "completed. " : "failed. ") +
                    details);

                if (!success)
                {
                    wieldRefreshIssue = "client-live-wield-refresh-failed:primary-none";
                    return false;
                }

                appliedWieldRefresh = "Wield=client-live-refresh";
                return true;
            }
            catch (Exception ex)
            {
                wieldRefreshIssue = "client-live-wield-refresh-failed:" + ex.GetType().Name;
                ExactBattleRuntimeBundleBridgeFile.AppendContractEvent(
                    "client-live-wield-refresh-failed",
                    "AgentIndex=" + (agent?.Index.ToString() ?? "null") +
                    " EntryId=" + (entryId ?? "null") +
                    " ExceptionType=" + ex.GetType().Name +
                    " Source=" + (source ?? "unknown"));
                ModLogger.Info(
                    "CoopMissionSpawnLogic: client live wield refresh failed. " +
                    "AgentIndex=" + (agent?.Index.ToString() ?? "null") +
                    " EntryId=" + (entryId ?? "null") +
                    " ExceptionType=" + ex.GetType().Name +
                    " Source=" + (source ?? "unknown"));
                return false;
            }
        }

        private static bool IsUsableWeaponEquipmentIndex(Equipment equipment, EquipmentIndex equipmentIndex)
        {
            if (equipment == null)
                return false;

            if (equipmentIndex < EquipmentIndex.Weapon0 || equipmentIndex > EquipmentIndex.Weapon3)
                return false;

            return !equipment[equipmentIndex].IsEmpty && equipment[equipmentIndex].Item != null;
        }

        private static bool IsShieldWeaponEquipmentIndex(Equipment equipment, EquipmentIndex equipmentIndex)
        {
            if (!IsUsableWeaponEquipmentIndex(equipment, equipmentIndex))
                return false;

            return GetMaterializedMountedWeaponRole(equipment[equipmentIndex].Item) == MaterializedMountedWeaponRole.Shield;
        }

        private static string NormalizeDesiredLiveWeaponPairForShieldIncompatibleMain(
            Equipment equipment,
            ref EquipmentIndex desiredMainHandIndex,
            ref EquipmentIndex desiredOffHandIndex,
            bool mainNotUsableWithOneHand)
        {
            if (equipment == null)
                return "none";

            if (!mainNotUsableWithOneHand ||
                !IsUsableWeaponEquipmentIndex(equipment, desiredMainHandIndex))
            {
                return "none";
            }

            ItemObject desiredMainItem = equipment[desiredMainHandIndex].Item;
            MaterializedMountedWeaponRole desiredMainRole = GetMaterializedMountedWeaponRole(desiredMainItem);
            if (desiredMainRole == MaterializedMountedWeaponRole.Ranged ||
                desiredMainRole == MaterializedMountedWeaponRole.Ammo ||
                desiredMainRole == MaterializedMountedWeaponRole.Shield)
            {
                desiredOffHandIndex = EquipmentIndex.None;
                return "suppressed-shield-offhand-for-main-incompatible";
            }

            if (!TryResolveDesiredLiveShieldOffhandIndex(
                    equipment,
                    desiredMainHandIndex,
                    desiredOffHandIndex,
                    out EquipmentIndex resolvedShieldOffHandIndex))
            {
                return "none";
            }

            if (desiredMainRole == MaterializedMountedWeaponRole.Melee &&
                TryResolveShieldCompatibleDesiredLiveMainHandIndex(
                    equipment,
                    desiredMainHandIndex,
                    resolvedShieldOffHandIndex,
                    out EquipmentIndex shieldCompatibleMainHandIndex))
            {
                desiredMainHandIndex = shieldCompatibleMainHandIndex;
                desiredOffHandIndex = resolvedShieldOffHandIndex;
                return "swapped-to-shield-compatible-main:" + GetEquipmentSlotLabel(shieldCompatibleMainHandIndex);
            }

            desiredOffHandIndex = resolvedShieldOffHandIndex;
            if (desiredMainRole != MaterializedMountedWeaponRole.Melee)
            {
                desiredOffHandIndex = EquipmentIndex.None;
                return "suppressed-shield-offhand-for-main-incompatible";
            }

            if (!IsShieldWeaponEquipmentIndex(equipment, desiredOffHandIndex))
            {
                return "none";
            }

            desiredOffHandIndex = EquipmentIndex.None;
            return "suppressed-shield-offhand-for-main-incompatible";
        }

        private static bool TryResolveDesiredLiveShieldOffhandIndex(
            Equipment equipment,
            EquipmentIndex currentMainHandIndex,
            EquipmentIndex currentOffHandIndex,
            out EquipmentIndex resolvedShieldOffHandIndex)
        {
            resolvedShieldOffHandIndex = EquipmentIndex.None;
            if (equipment == null)
                return false;

            if (IsShieldWeaponEquipmentIndex(equipment, currentOffHandIndex))
            {
                resolvedShieldOffHandIndex = currentOffHandIndex;
                return true;
            }

            EquipmentIndex[] preferredSearchOrder =
            {
                EquipmentIndex.Weapon1,
                EquipmentIndex.Weapon2,
                EquipmentIndex.Weapon3,
                EquipmentIndex.Weapon0
            };

            foreach (EquipmentIndex candidateIndex in preferredSearchOrder)
            {
                if (candidateIndex == currentMainHandIndex ||
                    !IsShieldWeaponEquipmentIndex(equipment, candidateIndex))
                {
                    continue;
                }

                resolvedShieldOffHandIndex = candidateIndex;
                return true;
            }

            return false;
        }

        private static bool TryResolveShieldCompatibleDesiredLiveMainHandIndex(
            Equipment equipment,
            EquipmentIndex currentMainHandIndex,
            EquipmentIndex currentOffHandIndex,
            out EquipmentIndex shieldCompatibleMainHandIndex)
        {
            shieldCompatibleMainHandIndex = EquipmentIndex.None;
            if (equipment == null)
                return false;

            EquipmentIndex[] preferredSearchOrder =
            {
                EquipmentIndex.Weapon2,
                EquipmentIndex.Weapon3,
                EquipmentIndex.Weapon1,
                EquipmentIndex.Weapon0
            };

            foreach (EquipmentIndex candidateIndex in preferredSearchOrder)
            {
                if (candidateIndex == currentMainHandIndex ||
                    candidateIndex == currentOffHandIndex ||
                    !IsUsableWeaponEquipmentIndex(equipment, candidateIndex) ||
                    !IsShieldCompatibleDesiredLiveMainHandIndex(equipment, candidateIndex))
                {
                    continue;
                }

                shieldCompatibleMainHandIndex = candidateIndex;
                return true;
            }

            return false;
        }

        private static bool IsShieldCompatibleDesiredLiveMainHandIndex(
            Equipment equipment,
            EquipmentIndex candidateIndex)
        {
            if (!IsUsableWeaponEquipmentIndex(equipment, candidateIndex))
                return false;

            ItemObject candidateItem = equipment[candidateIndex].Item;
            if (candidateItem == null)
                return false;

            MaterializedMountedWeaponRole role = GetMaterializedMountedWeaponRole(candidateItem);
            if (role == MaterializedMountedWeaponRole.Shield ||
                role == MaterializedMountedWeaponRole.Ammo ||
                role == MaterializedMountedWeaponRole.Ranged)
            {
                return false;
            }

            WeaponComponentData primaryWeapon = candidateItem.PrimaryWeapon;
            if (primaryWeapon != null)
            {
                return primaryWeapon.IsOneHanded;
            }

            return candidateItem.ItemType == ItemObject.ItemTypeEnum.OneHandedWeapon;
        }

        private static bool IsDesiredLiveMainWeaponReady(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex)
        {
            if (!IsUsableWeaponEquipmentIndex(equipment, desiredMainHandIndex))
                return true;

            ItemObject desiredItem = equipment[desiredMainHandIndex].Item;
            return desiredItem != null &&
                   string.Equals(agent?.WieldedWeapon.Item?.StringId, desiredItem.StringId, StringComparison.Ordinal);
        }

        private static EquipmentIndex ResolveDesiredLiveAmmoEquipmentIndex(
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex)
        {
            if (!IsUsableWeaponEquipmentIndex(equipment, desiredMainHandIndex))
                return EquipmentIndex.None;

            ItemObject mainItem = equipment[desiredMainHandIndex].Item;
            if (mainItem?.PrimaryWeapon == null || !mainItem.PrimaryWeapon.IsRangedWeapon)
                return EquipmentIndex.None;

            for (EquipmentIndex slot = EquipmentIndex.Weapon0; slot <= EquipmentIndex.Weapon3; slot++)
            {
                if (slot == desiredMainHandIndex || !IsUsableWeaponEquipmentIndex(equipment, slot))
                    continue;

                if (GetMaterializedMountedWeaponRole(equipment[slot].Item) == MaterializedMountedWeaponRole.Ammo)
                    return slot;
            }

            return EquipmentIndex.None;
        }

        private static bool IsDesiredLiveMainAmmoReady(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex,
            EquipmentIndex desiredAmmoIndex)
        {
            if (!IsUsableWeaponEquipmentIndex(equipment, desiredMainHandIndex))
                return true;

            ItemObject desiredMainItem = equipment[desiredMainHandIndex].Item;
            if (desiredMainItem?.PrimaryWeapon == null || !desiredMainItem.PrimaryWeapon.IsRangedWeapon)
                return true;

            if (!IsUsableWeaponEquipmentIndex(equipment, desiredAmmoIndex))
                return agent?.WieldedWeapon.AmmoWeapon.Item == null;

            ItemObject desiredAmmoItem = equipment[desiredAmmoIndex].Item;
            return desiredAmmoItem != null &&
                   string.Equals(agent?.WieldedWeapon.AmmoWeapon.Item?.StringId, desiredAmmoItem.StringId, StringComparison.Ordinal);
        }

        private static bool IsDesiredLiveOffhandWeaponReady(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredOffHandIndex)
        {
            if (!IsUsableWeaponEquipmentIndex(equipment, desiredOffHandIndex))
                return true;

            ItemObject desiredItem = equipment[desiredOffHandIndex].Item;
            return desiredItem != null &&
                   string.Equals(agent?.WieldedOffhandWeapon.Item?.StringId, desiredItem.StringId, StringComparison.Ordinal);
        }

        private static bool HasDesiredLiveWeaponPair(
            Agent agent,
            Equipment equipment,
            EquipmentIndex desiredMainHandIndex,
            EquipmentIndex desiredOffHandIndex,
            EquipmentIndex desiredAmmoIndex)
        {
            if (agent == null || equipment == null)
                return false;

            return IsDesiredLiveMainWeaponReady(agent, equipment, desiredMainHandIndex) &&
                   IsDesiredLiveOffhandWeaponReady(agent, equipment, desiredOffHandIndex) &&
                   IsDesiredLiveMainAmmoReady(agent, equipment, desiredMainHandIndex, desiredAmmoIndex);
        }

        private static int ResolveEquipmentCurrentUsageIndex(Agent agent, Equipment overlaySpawnEquipment, EquipmentIndex equipmentIndex)
        {
            if (equipmentIndex < EquipmentIndex.Weapon0 || equipmentIndex > EquipmentIndex.Weapon3)
                return 0;

            try
            {
                if (agent?.Equipment != null &&
                    !agent.Equipment[equipmentIndex].IsEmpty)
                {
                    return Math.Max(0, agent.Equipment[equipmentIndex].CurrentUsageIndex);
                }
            }
            catch
            {
            }

            return 0;
        }

        private static string FormatWeaponEquipmentIndex(Equipment equipment, EquipmentIndex equipmentIndex)
        {
            if (equipment == null || equipmentIndex < EquipmentIndex.Weapon0 || equipmentIndex > EquipmentIndex.Weapon3)
                return "None";

            return GetEquipmentSlotLabel(equipmentIndex) + "=" + (equipment[equipmentIndex].Item?.StringId ?? "empty");
        }

        private static string FormatAgentWieldedEquipmentIndex(Agent agent, EquipmentIndex equipmentIndex)
        {
            if (agent?.Equipment == null || equipmentIndex < EquipmentIndex.Weapon0 || equipmentIndex > EquipmentIndex.Weapon3)
                return "None";

            return GetEquipmentSlotLabel(equipmentIndex) + "=" + (agent.Equipment[equipmentIndex].Item?.StringId ?? "empty");
        }

        private static string TryApplyClientVisualOnlyCombatProfile(Agent agent, RosterEntryState entryState)
        {
            if (agent == null || entryState == null || !IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return "AppliedCombatProfile=client-visual-only";

            try
            {
                const string prefix = "AppliedCombatProfile=";
                string summary = TryApplyMaterializedCombatProfile(agent, entryState);
                if (string.IsNullOrWhiteSpace(summary))
                    return "AppliedCombatProfile=client-visual-only";

                if (summary.StartsWith(prefix, StringComparison.Ordinal))
                    return prefix + "client-local/" + summary.Substring(prefix.Length);

                return summary;
            }
            catch (Exception ex)
            {
                return "AppliedCombatProfile=client-visual-only-failed:" + ex.GetType().Name;
            }
        }

        private static int TryAssignExactCampaignCommanders(Mission mission, string source)
        {
            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (mission?.Teams == null || runtimeState == null)
                return 0;

            int assignments = 0;
            assignments += TryAssignExactCampaignCommanderForSide(mission, runtimeState, BattleSideEnum.Attacker, source);
            assignments += TryAssignExactCampaignCommanderForSide(mission, runtimeState, BattleSideEnum.Defender, source);
            return assignments;
        }

        private static int TryAssignExactCampaignCommanderForSide(
            Mission mission,
            BattleRuntimeState runtimeState,
            BattleSideEnum side,
            string source)
        {
            if (mission == null || runtimeState == null || side == BattleSideEnum.None)
                return 0;

            Team team = mission.Teams?.FirstOrDefault(candidate => candidate != null && candidate.Side == side);
            if (team == null)
                return 0;

            RosterEntryState commanderEntry = BattleCommanderResolver.ResolveCommanderEntry(runtimeState, side);
            if (commanderEntry == null || string.IsNullOrWhiteSpace(commanderEntry.EntryId))
                return 0;

            Agent commanderAgent = ResolveLiveExactCampaignCommanderAgent(mission, team, commanderEntry.EntryId);
            if (commanderAgent == null)
                return 0;

            bool changed = false;
            if (!ReferenceEquals(team.GeneralAgent, commanderAgent))
            {
                commanderAgent.SetCanLeadFormationsRemotely(value: true);
                team.GeneralAgent = commanderAgent;
                changed = true;
            }

            Formation commanderFormation = commanderAgent.Formation;
            if (commanderFormation != null &&
                ReferenceEquals(commanderFormation.Team, team) &&
                !ReferenceEquals(commanderFormation.Captain, commanderAgent))
            {
                commanderFormation.Captain = commanderAgent;
                changed = true;
            }

            if (!changed)
                return 0;

            ModLogger.Info(
                "CoopMissionSpawnLogic: assigned exact campaign commander. " +
                "Side=" + side +
                " TeamIndex=" + team.TeamIndex +
                " EntryId=" + commanderEntry.EntryId +
                " TroopId=" + (commanderEntry.CharacterId ?? "null") +
                " HeroRole=" + (commanderEntry.HeroRole ?? "none") +
                " Tier=" + commanderEntry.Tier +
                " AgentIndex=" + commanderAgent.Index +
                " PlayerControlled=" + (commanderAgent.MissionPeer != null || commanderAgent.Controller == AgentControllerType.Player) +
                " Formation=" + (commanderFormation?.FormationIndex.ToString() ?? "null") +
                " Source=" + (source ?? "unknown"));
            return 1;
        }

        private static Agent ResolveLiveExactCampaignCommanderAgent(Mission mission, Team team, string commanderEntryId)
        {
            if (mission?.AllAgents == null || team == null || string.IsNullOrWhiteSpace(commanderEntryId))
                return null;

            Agent firstMatchingAgent = null;
            Agent existingGeneralAgent = null;
            Agent controlledMatchingAgent = null;

            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent candidate = mission.AllAgents[i];
                if (candidate == null ||
                    !candidate.IsActive() ||
                    candidate.IsMount ||
                    !ReferenceEquals(candidate.Team, team) ||
                    !DoesAgentMatchAuthoritativeEntryId(candidate, commanderEntryId))
                {
                    continue;
                }

                if (firstMatchingAgent == null)
                    firstMatchingAgent = candidate;

                if (ReferenceEquals(candidate, team.GeneralAgent))
                    existingGeneralAgent = candidate;

                if (controlledMatchingAgent == null &&
                    (candidate.MissionPeer != null || candidate.Controller == AgentControllerType.Player))
                {
                    controlledMatchingAgent = candidate;
                }
            }

            return controlledMatchingAgent ?? existingGeneralAgent ?? firstMatchingAgent;
        }

        private static int EnsureExactCampaignBattleResultEntryStates(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return 0;

            int seededCount = 0;
            foreach (RosterEntryState entryState in GetAllowedControlEntryStatesSnapshot(side))
            {
                if (entryState == null || string.IsNullOrWhiteSpace(entryState.EntryId) || _materializedBattleResultEntriesByEntryId.ContainsKey(entryState.EntryId))
                    continue;

                string sideId = !string.IsNullOrWhiteSpace(entryState.SideId)
                    ? entryState.SideId
                    : side.ToString();
                _materializedBattleResultEntriesByEntryId[entryState.EntryId] = new MaterializedBattleResultEntryRuntimeState
                {
                    EntryId = entryState.EntryId,
                    SideId = sideId,
                    PartyId = entryState.PartyId,
                    CharacterId = entryState.CharacterId,
                    OriginalCharacterId = entryState.OriginalCharacterId,
                    SpawnTemplateId = entryState.SpawnTemplateId,
                    TroopName = entryState.TroopName,
                    HeroId = entryState.HeroId,
                    HeroRole = entryState.HeroRole,
                    IsHero = entryState.IsHero,
                    SnapshotCount = entryState.Count,
                    SnapshotWoundedCount = entryState.WoundedCount
                };
                seededCount++;
            }

            return seededCount;
        }

        private static bool IsUsingNativeExactCampaignArmyBootstrap(Mission mission)
        {
            return ExactCampaignArmyBootstrap.IsActive(mission);
        }

        private static void LogExactSceneNativeBootstrapDeferred(Mission mission, string reason, string source)
        {
            DateTime nowUtc = DateTime.UtcNow;
            if (nowUtc < _nextExactSceneNativeBootstrapDeferLogUtc)
                return;

            _nextExactSceneNativeBootstrapDeferLogUtc = nowUtc.AddSeconds(2);
            ExactCampaignArmyBootstrap.LogInitializationDeferred(
                mission,
                reason,
                source + " exact-native-bootstrap");
        }

        private static void TryBridgeMissionPlayerTeamForExactCampaignBootstrap(
            Mission mission,
            Team authoritativeTeam,
            BattleSideEnum authoritativeSide,
            string source)
        {
            if (mission == null || authoritativeTeam == null || authoritativeSide == BattleSideEnum.None)
                return;

            Team previousPlayerTeam = mission.PlayerTeam;
            Team previousPlayerEnemyTeam = mission.PlayerEnemyTeam;
            bool needsBridge =
                previousPlayerTeam == null ||
                previousPlayerTeam.Side != authoritativeSide ||
                !ReferenceEquals(previousPlayerTeam, authoritativeTeam);
            if (!needsBridge)
                return;

            mission.PlayerTeam = authoritativeTeam;

            string previousPlayerTeamText =
                previousPlayerTeam == null
                    ? "null"
                    : previousPlayerTeam.Side + "#" + previousPlayerTeam.TeamIndex;
            string previousPlayerEnemyTeamText =
                previousPlayerEnemyTeam == null
                    ? "null"
                    : previousPlayerEnemyTeam.Side + "#" + previousPlayerEnemyTeam.TeamIndex;
            string appliedPlayerTeamText =
                mission.PlayerTeam == null
                    ? "null"
                    : mission.PlayerTeam.Side + "#" + mission.PlayerTeam.TeamIndex;
            string appliedPlayerEnemyTeamText =
                mission.PlayerEnemyTeam == null
                    ? "null"
                    : mission.PlayerEnemyTeam.Side + "#" + mission.PlayerEnemyTeam.TeamIndex;

            ModLogger.Info(
                "CoopMissionSpawnLogic: bridged mission player teams for exact campaign bootstrap. " +
                "Scene=" + (mission.SceneName ?? "null") +
                " AuthoritativeSide=" + authoritativeSide +
                " PreviousPlayerTeam=" + previousPlayerTeamText +
                " PreviousPlayerEnemyTeam=" + previousPlayerEnemyTeamText +
                " AppliedPlayerTeam=" + appliedPlayerTeamText +
                " AppliedPlayerEnemyTeam=" + appliedPlayerEnemyTeamText +
                " Source=" + (source ?? "unknown"));
        }

        private static void TryUpdateBattlePhaseState(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            if (currentPhase >= CoopBattlePhase.BattleActive)
                return;

            int assignedPeerCount = 0;
            int controlledPeerCount = 0;

            if (GameNetwork.NetworkPeers != null)
            {
                foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
                {
                    if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                        continue;

                    MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                    if (missionPeer == null)
                        continue;

                    BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, source + " phase-update");
                    if (authoritativeSide == BattleSideEnum.None)
                        continue;

                    assignedPeerCount++;
                    if (missionPeer.ControlledAgent != null)
                        controlledPeerCount++;
                }
            }

            if (AreBattlefieldArmiesReadyForStart(mission, out _, out _, out _))
            {
                CoopBattlePhaseRuntimeState.AdvanceToAtLeast(CoopBattlePhase.PreBattleHold, source + " armies-ready", mission);
                return;
            }

            if (controlledPeerCount > 0)
            {
                CoopBattlePhaseRuntimeState.AdvanceToAtLeast(CoopBattlePhase.Deployment, source + " controlled-agent", mission);
                if (assignedPeerCount > 0 && controlledPeerCount >= assignedPeerCount)
                    CoopBattlePhaseRuntimeState.AdvanceToAtLeast(CoopBattlePhase.PreBattleHold, source + " all-peers-controlled", mission);
                return;
            }

            if (assignedPeerCount > 0)
            {
                CoopBattlePhaseRuntimeState.AdvanceToAtLeast(CoopBattlePhase.UnitSelection, source + " side-assigned", mission);
                return;
            }

            CoopBattlePhaseRuntimeState.AdvanceToAtLeast(CoopBattlePhase.SideSelection, source + " waiting-for-side", mission);
        }

        private static bool IsBattleStartReady(Mission mission, out int assignedPeerCount, out int controlledPeerCount)
        {
            assignedPeerCount = 0;
            controlledPeerCount = 0;

            if (mission == null || GameNetwork.NetworkPeers == null)
                return false;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null)
                    continue;

                BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, "battle-start-ready");
                if (authoritativeSide == BattleSideEnum.None)
                    continue;

                assignedPeerCount++;
                if (missionPeer.ControlledAgent != null && missionPeer.ControlledAgent.IsActive())
                    controlledPeerCount++;
            }

            return AreBattlefieldArmiesReadyForStart(mission, out _, out _, out _) &&
                assignedPeerCount > 0 &&
                controlledPeerCount >= assignedPeerCount;
        }

        private static bool AreBattlefieldArmiesReadyForStart(
            Mission mission,
            out string readinessSource,
            out int attackerActive,
            out int defenderActive)
        {
            attackerActive = 0;
            defenderActive = 0;

            if (_hasMaterializedBattlefieldArmies)
            {
                readinessSource = "legacy-materialized";
                return true;
            }

            if (!IsUsingNativeExactCampaignArmyBootstrap(mission))
            {
                readinessSource = "not-ready";
                return false;
            }

            attackerActive = CountActiveTeamAgents(mission, BattleSideEnum.Attacker);
            defenderActive = CountActiveTeamAgents(mission, BattleSideEnum.Defender);
            readinessSource =
                "exact-native-bootstrap" +
                " MissionTeamAttacker=" + attackerActive +
                " MissionTeamDefender=" + defenderActive;
            return attackerActive > 0 && defenderActive > 0;
        }

        private static void TryConsumeBattlePhaseRequests(Mission mission)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            if (!CoopBattlePhaseBridgeFile.ConsumeStartBattleRequest(out string requestSource))
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            bool battleStartReady = IsBattleStartReady(mission, out int assignedPeerCount, out int controlledPeerCount);
            if (currentPhase < CoopBattlePhase.PreBattleHold || !battleStartReady)
            {
                bool armiesReady = AreBattlefieldArmiesReadyForStart(mission, out string readinessSource, out int attackerActive, out int defenderActive);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: ignored start battle request because phase is not ready. " +
                    "CurrentPhase=" + currentPhase +
                    " BattleStartReady=" + battleStartReady +
                    " AssignedPeers=" + assignedPeerCount +
                    " ControlledPeers=" + controlledPeerCount +
                    " MaterializedArmies=" + _hasMaterializedBattlefieldArmies +
                    " ArmiesReady=" + armiesReady +
                    " ArmiesReadySource=" + readinessSource +
                    " AttackerActive=" + attackerActive +
                    " DefenderActive=" + defenderActive +
                    " Source=" + (requestSource ?? "unknown"));
                return;
            }

            CoopBattlePhaseRuntimeState.SetPhase(
                CoopBattlePhase.BattleActive,
                "bridge-file start battle request from " + (requestSource ?? "unknown"),
                mission,
                allowRegression: false);
        }

        private static void TryApplyBattlePhaseAiHold(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            // Keep both armies inert until the host explicitly starts the battle.
            bool shouldPauseAi = currentPhase < CoopBattlePhase.BattleActive;

            if (!ReferenceEquals(_lastBattlePhaseAiHoldMission, mission))
            {
                _lastBattlePhaseAiHoldMission = mission;
                _lastAppliedBattlePhaseAiHold = null;
            }

            bool currentPauseAi = mission.PauseAITick;
            if (_lastAppliedBattlePhaseAiHold.HasValue &&
                _lastAppliedBattlePhaseAiHold.Value == shouldPauseAi &&
                currentPauseAi == shouldPauseAi)
            {
                return;
            }

            mission.PauseAITick = shouldPauseAi;
            _lastAppliedBattlePhaseAiHold = shouldPauseAi;

            ModLogger.Info(
                "CoopMissionSpawnLogic: battle phase AI hold state applied. " +
                "Phase=" + currentPhase +
                " PauseAITick=" + shouldPauseAi +
                " Source=" + (source ?? "unknown"));
        }

        private static void TryApplyNativeBattleMapWarmupFallback(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || !IsSceneAwareBattleMapRuntime(mission))
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            if (currentPhase >= CoopBattlePhase.BattleEnded)
                return;

            if (currentPhase >= CoopBattlePhase.PreBattleHold)
                return;

            MultiplayerWarmupComponent warmupComponent = mission.GetMissionBehavior<MultiplayerWarmupComponent>();
            MultiplayerTimerComponent timerComponent = mission.GetMissionBehavior<MultiplayerTimerComponent>();
            if (warmupComponent == null || timerComponent == null)
                return;

            float remainingTimeSeconds;
            try
            {
                remainingTimeSeconds = timerComponent.GetRemainingTime(false);
            }
            catch
            {
                remainingTimeSeconds = -1f;
            }

            string warmupState = NativeWarmupStateField?.GetValue(warmupComponent)?.ToString() ?? "unknown";
            bool stateNeedsRecovery =
                string.Equals(warmupState, "WaitingForPlayers", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(warmupState, "Ending", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(warmupState, "Ended", StringComparison.OrdinalIgnoreCase);
            bool timerNeedsRefresh =
                remainingTimeSeconds < 0f ||
                remainingTimeSeconds < (NativeBattleMapWarmupFallbackDurationSeconds - 60f);
            DateTime nowUtc = DateTime.UtcNow;

            if (!stateNeedsRecovery &&
                !timerNeedsRefresh &&
                nowUtc < _nextNativeBattleMapWarmupFallbackRefreshUtc)
            {
                return;
            }

            bool refreshedTimer = false;
            try
            {
                timerComponent.StartTimerAsServer(NativeBattleMapWarmupFallbackDurationSeconds);
                refreshedTimer = true;
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: native battle-map warmup fallback failed to refresh timer: " + ex.Message);
            }

            bool forcedWarmupState = false;
            try
            {
                if (NativeWarmupStateField != null)
                {
                    object inProgressState = Enum.Parse(NativeWarmupStateField.FieldType, "InProgress");
                    NativeWarmupStateField.SetValue(warmupComponent, inProgressState);
                    forcedWarmupState = true;
                }

                if (NativeWarmupCurrentStateStartTimeField != null)
                {
                    MissionTime futureStartTime = MissionTime.SecondsFromNow(NativeBattleMapWarmupFutureStartOffsetSeconds);
                    NativeWarmupCurrentStateStartTimeField.SetValue(warmupComponent, futureStartTime);
                    forcedWarmupState = true;
                }
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: native battle-map warmup fallback failed to extend warmup state: " + ex.Message);
            }

            _nextNativeBattleMapWarmupFallbackRefreshUtc = nowUtc.AddSeconds(5);

            string logKey =
                (source ?? "unknown") + "|" +
                currentPhase + "|" +
                warmupState + "|" +
                refreshedTimer + "|" +
                forcedWarmupState;
            if (string.Equals(_lastNativeBattleMapWarmupFallbackLogKey, logKey, StringComparison.Ordinal))
                return;

            _lastNativeBattleMapWarmupFallbackLogKey = logKey;
            ModLogger.Info(
                "CoopMissionSpawnLogic: native battle-map warmup fallback applied. " +
                "Phase=" + currentPhase +
                " WarmupStateBefore=" + warmupState +
                " RemainingSecondsBefore=" + remainingTimeSeconds.ToString("0.0", System.Globalization.CultureInfo.InvariantCulture) +
                " ForcedWarmupState=" + forcedWarmupState +
                " RefreshedTimer=" + refreshedTimer +
                " TargetDurationSeconds=" + NativeBattleMapWarmupFallbackDurationSeconds.ToString("0.0", System.Globalization.CultureInfo.InvariantCulture) +
                " Source=" + (source ?? "unknown"));
        }

        private static void TryCompleteBattleIfResolved(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            if (currentPhase < CoopBattlePhase.BattleActive || currentPhase >= CoopBattlePhase.BattleEnded)
                return;

            if (_hasTriggeredAuthoritativeBattleCompletion)
                return;

            ResolveActiveBattleSideCounts(mission, out int attackerActive, out int defenderActive, out string countSource);
            TryLogBattleCompletionAudit(attackerActive, defenderActive, countSource, source);
            if (attackerActive > 0 && defenderActive > 0)
                return;

            int attackerReserve;
            int defenderReserve;
            string reserveSource;
            if (IsUsingNativeExactCampaignArmyBootstrap(mission) &&
                ExactCampaignArmyBootstrap.TryGetRemainingTroopCounts(
                    mission,
                    out attackerReserve,
                    out defenderReserve))
            {
                reserveSource = "exact-native-bootstrap";
            }
            else
            {
                attackerReserve = CountMaterializedUnspawnedReserveForSide(BattleSideEnum.Attacker);
                defenderReserve = CountMaterializedUnspawnedReserveForSide(BattleSideEnum.Defender);
                reserveSource = "materialized-runtime";
            }

            if ((attackerActive <= 0 && attackerReserve > 0) ||
                (defenderActive <= 0 && defenderReserve > 0))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: authoritative battle completion deferred because reserves remain. " +
                    "AttackerActive=" + attackerActive +
                    " DefenderActive=" + defenderActive +
                    " AttackerReserve=" + attackerReserve +
                    " DefenderReserve=" + defenderReserve +
                    " ReserveSource=" + reserveSource +
                    " CountSource=" + (countSource ?? "unknown") +
                    " Source=" + (source ?? "unknown"));
                return;
            }

            _hasTriggeredAuthoritativeBattleCompletion = true;
            _authoritativeBattleCompletionReason =
                attackerActive <= 0 && defenderActive <= 0 ? "mutual-elimination" :
                attackerActive <= 0 ? "attacker-eliminated" :
                "defender-eliminated";
            _authoritativeBattleWinnerSide =
                attackerActive > 0 && defenderActive <= 0 ? BattleSideEnum.Attacker.ToString() :
                defenderActive > 0 && attackerActive <= 0 ? BattleSideEnum.Defender.ToString() :
                string.Empty;

            CoopBattlePhaseRuntimeState.SetPhase(
                CoopBattlePhase.BattleEnded,
                "authoritative battle completion from " + (source ?? "unknown"),
                mission,
                allowRegression: false);

            TryWriteBattleResultSnapshot(
                mission,
                "authoritative battle completion | " +
                (_authoritativeBattleCompletionReason ?? "unknown") +
                " | " + (source ?? "unknown"));

            ModLogger.Info(
                "CoopMissionSpawnLogic: authoritative battle completion detected. " +
                "WinnerSide=" + (string.IsNullOrWhiteSpace(_authoritativeBattleWinnerSide) ? "none" : _authoritativeBattleWinnerSide) +
                " Reason=" + (_authoritativeBattleCompletionReason ?? "unknown") +
                " AttackerActive=" + attackerActive +
                " DefenderActive=" + defenderActive +
                " AttackerReserve=" + attackerReserve +
                " DefenderReserve=" + defenderReserve +
                " ReserveSource=" + reserveSource +
                " CountSource=" + (countSource ?? "unknown") +
                " Source=" + (source ?? "unknown") +
                " AwaitingHostEndMission=True.");
        }

        private static void TryApplyBattlePhaseFormationHold(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            bool shouldHoldFormations = currentPhase >= CoopBattlePhase.SideSelection && currentPhase < CoopBattlePhase.BattleActive;
            bool shouldReleaseAndPulse = currentPhase >= CoopBattlePhase.BattleActive;

            if (!ReferenceEquals(_lastBattlePhaseAiHoldMission, mission))
            {
                _battlePhaseHeldFormationKeys.Clear();
                _battlePhaseHeldFormationUnitCounts.Clear();
                _lastAppliedFormationHoldPhase = null;
            }

            bool phaseChanged = !_lastAppliedFormationHoldPhase.HasValue || _lastAppliedFormationHoldPhase.Value != currentPhase;
            bool shouldRunReleasePass = shouldReleaseAndPulse && phaseChanged;

            // BattleActive release is a one-shot transition step. Re-running it every tick
            // would immediately overwrite commander-issued orders with charge/fire-at-will/AI delegation.
            if (!shouldHoldFormations && !shouldRunReleasePass)
                return;

            int affectedFormationCount = 0;
            int delegatedTeamCount = 0;
            int pulsedAgentCount = 0;
            HashSet<int> currentFormationKeys = shouldHoldFormations ? new HashSet<int>() : null;
            foreach (Team team in mission.Teams)
            {
                if (team == null || team.Side == BattleSideEnum.None || ReferenceEquals(team, mission.SpectatorTeam))
                    continue;

                foreach (Formation formation in team.FormationsIncludingSpecialAndEmpty)
                {
                    if (formation == null || formation.CountOfUnits <= 0)
                        continue;

                    int formationKey = GetBattlePhaseFormationKey(team, formation);
                    if (shouldHoldFormations)
                    {
                        currentFormationKeys?.Add(formationKey);

                        int unitCount = formation.CountOfUnits;
                        bool wasHeld = _battlePhaseHeldFormationKeys.Contains(formationKey);
                        bool hadTrackedUnitCount = _battlePhaseHeldFormationUnitCounts.TryGetValue(formationKey, out int trackedUnitCount);
                        if (ShouldSkipBattlePhaseFormationHold(mission, team, formation) && wasHeld)
                            continue;

                        formation.SetMovementOrder(MovementOrder.MovementOrderStop);
                        formation.SetFiringOrder(FiringOrder.FiringOrderHoldYourFire);
                        formation.SetControlledByAI(false, false);
                        _battlePhaseHeldFormationKeys.Add(formationKey);
                        _battlePhaseHeldFormationUnitCounts[formationKey] = unitCount;
                        if (!wasHeld || !hadTrackedUnitCount || trackedUnitCount != unitCount || phaseChanged)
                            affectedFormationCount++;
                    }
                    else if (shouldRunReleasePass)
                    {
                        // Release/pulse must also cover formations that contain the player.
                        // They are intentionally skipped during PreBattleHold, so BattleActive
                        // cannot rely on the held-key set alone.
                        bool wasHeld = _battlePhaseHeldFormationKeys.Remove(formationKey);
                        _battlePhaseHeldFormationUnitCounts.Remove(formationKey);
                        formation.SetMovementOrder(MovementOrder.MovementOrderCharge);
                        formation.SetFiringOrder(FiringOrder.FiringOrderFireAtWill);
                        formation.SetControlledByAI(true, true);
                        int pulsedFormationAgents = TryPulseFormationAiEngage(formation, team);
                        pulsedAgentCount += pulsedFormationAgents;
                        affectedFormationCount++;

                        bool hasPlayerControlledTroop = (GetServerMemberValue(formation, "HasPlayerControlledTroop") as bool?) ?? false;
                        bool isPlayerTroopInFormation = (GetServerMemberValue(formation, "IsPlayerTroopInFormation") as bool?) ?? false;
                        object playerOwner = GetServerMemberValue(formation, "PlayerOwner");
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: battle phase formation release detail. " +
                            "Team=" + team.Side +
                            " Formation=" + formation.FormationIndex +
                            " UnitCount=" + formation.CountOfUnits +
                            " WasHeld=" + wasHeld +
                            " HasPlayerControlledTroop=" + hasPlayerControlledTroop +
                            " IsPlayerTroopInFormation=" + isPlayerTroopInFormation +
                            " HasPlayerOwner=" + (playerOwner != null) +
                            " PulsedAgents=" + pulsedFormationAgents +
                            " Source=" + (source ?? "unknown"));
                    }
                }

                if (shouldReleaseAndPulse &&
                    team.HasTeamAi &&
                    team.HasAnyEnemyTeamsWithAgents(false))
                {
                    team.ResetTactic();
                    team.DelegateCommandToAI();
                    delegatedTeamCount++;
                }
            }

            if (shouldHoldFormations && currentFormationKeys != null)
            {
                _battlePhaseHeldFormationKeys.RemoveWhere(key => !currentFormationKeys.Contains(key));
                foreach (int key in _battlePhaseHeldFormationUnitCounts.Keys.ToArray())
                {
                    if (!currentFormationKeys.Contains(key))
                        _battlePhaseHeldFormationUnitCounts.Remove(key);
                }
            }

            if (!phaseChanged &&
                !shouldHoldFormations)
            {
                return;
            }

            if (!phaseChanged &&
                affectedFormationCount == 0)
            {
                return;
            }

            _lastAppliedFormationHoldPhase = currentPhase;
            ModLogger.Info(
                "CoopMissionSpawnLogic: battle phase formation hold state applied. " +
                "Phase=" + currentPhase +
                " HoldApplied=" + shouldHoldFormations +
                " AffectedFormations=" + affectedFormationCount +
                " DelegatedTeams=" + delegatedTeamCount +
                " PulsedAgents=" + pulsedAgentCount +
                " Source=" + (source ?? "unknown"));
        }

        private static bool ShouldSkipBattlePhaseFormationHold(Mission mission, Team team, Formation formation)
        {
            if (formation == null)
                return true;

            if (team != null &&
                team.IsPlayerGeneral &&
                team.PlayerOrderController?.Owner != null)
            {
                return true;
            }

            return IsFormationOccupiedByControlledPeer(mission, team, formation);
        }

        private static bool IsFormationOccupiedByControlledPeer(Mission mission, Team team, Formation formation)
        {
            if (mission == null || team == null || formation == null || GameNetwork.NetworkPeers == null)
                return false;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                Agent controlledAgent = missionPeer?.ControlledAgent;
                if (controlledAgent == null || !controlledAgent.IsActive())
                    continue;

                if (!ReferenceEquals(controlledAgent.Team, team))
                    continue;

                Formation controlledFormation = controlledAgent.Formation;
                if (ReferenceEquals(controlledFormation, formation))
                    return true;
            }

            return false;
        }

        private static int GetBattlePhaseFormationKey(Team team, Formation formation)
        {
            int teamKey = ((int)team.Side + 1) * 100;
            int formationKey = formation != null ? (int)formation.FormationIndex : -1;
            return teamKey + formationKey;
        }

        private static int TryPulseFormationAiEngage(Formation formation, Team team)
        {
            if (formation == null || team == null || formation.CountOfUnits <= 0)
                return 0;

            Team enemyTeam = null;
            foreach (Team candidate in team.Mission.Teams)
            {
                if (candidate == null || ReferenceEquals(candidate, team) || ReferenceEquals(candidate, team.Mission.SpectatorTeam))
                    continue;

                if (!team.IsEnemyOf(candidate))
                    continue;

                if (!candidate.FormationsIncludingSpecialAndEmpty.Any(x => x != null && x.CountOfUnits > 0))
                    continue;

                enemyTeam = candidate;
                break;
            }

            if (enemyTeam == null)
                return 0;

            Formation enemyFormation = enemyTeam.FormationsIncludingSpecialAndEmpty.FirstOrDefault(x => x != null && x.CountOfUnits > 0);
            Agent enemyAgent = enemyFormation?.GetFirstUnit();
            int pulsedAgentCount = 0;

            formation.ApplyActionOnEachUnit(agent =>
            {
                if (agent == null || !agent.IsActive() || agent.Controller != AgentControllerType.AI)
                    return;

                agent.SetAutomaticTargetSelection(true);
                agent.SetWatchState(Agent.WatchState.Alarmed);
                agent.SetAlarmState(Agent.AIStateFlag.Alarmed);
                if (enemyFormation != null)
                    agent.SetTargetFormationIndex((int)enemyFormation.FormationIndex);
                if (enemyAgent != null && enemyAgent.IsActive())
                    agent.SetTargetAgent(enemyAgent);
                agent.ForceAiBehaviorSelection();
                pulsedAgentCount++;
            }, null);

            return pulsedAgentCount;
        }

        private static void TryEnsureBattlefieldArmiesMaterialized(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            if (!ReferenceEquals(_lastMaterializedArmyMission, mission))
            {
                _lastMaterializedArmyMission = mission;
                _hasMaterializedBattlefieldArmies = false;
                _hasLoggedMaterializedEquipmentCoverageSummary = false;
                _lastAlignedControlledAgentIndexByPeer.Clear();
                _materializedArmyEntryIdByAgentIndex.Clear();
                _materializedArmySideByAgentIndex.Clear();
                _materializedAgentInstanceByIndex.Clear();
                _materializedCanonicalInstanceIdByAgentIndex.Clear();
                _clientAuthoritativeMaterializedEntryIdByAgentIndex.Clear();
                _clientAuthoritativeMaterializedEntryObservedAgentIndices.Clear();
                _lastClientAuthoritativeMaterializedEntrySnapshotObservedUtc = DateTime.MinValue;
                _lastClientAuthoritativeMaterializedEntrySnapshotEntryCount = 0;
                _loggedAutomatedMaterializedEntrySkipIds.Clear();
                _loggedSuppressedMaterializedEquipmentKeys.Clear();
                MaterializedEquipmentResolutionSourceCounts.Clear();
                MaterializedEquipmentMissCounts.Clear();
                MaterializedEquipmentNormalizedFallbackCounts.Clear();
                ResetMaterializedCombatProfileRuntimeState();
                _nextIncompleteBattleSnapshotRefreshUtc = DateTime.MinValue;
                _nextIncompleteBattleSnapshotLogUtc = DateTime.MinValue;
                _nextExactSceneMaterializationDeferLogUtc = DateTime.MinValue;
                _exactScenePostPossessionMaterializationResumeUtc = DateTime.MinValue;
                _nextInitialMaterializedArmyPulseUtc = DateTime.MinValue;
                _nextMaterializedArmyReinforcementPulseUtc = DateTime.MinValue;
                _nextExactSceneNativeBootstrapDeferLogUtc = DateTime.MinValue;
            }

            if (_hasMaterializedBattlefieldArmies)
                return;

            if (IsUsingNativeExactCampaignArmyBootstrap(mission))
                return;

            Team attackerTeam = mission.Teams?.Attacker;
            Team defenderTeam = mission.Teams?.Defender;
            if (attackerTeam == null || defenderTeam == null)
                return;

            if (ShouldDeferExactSceneInitialBattlefieldMaterialization(mission, out string exactSceneMaterializationDeferReason))
            {
                DateTime nowUtc = DateTime.UtcNow;
                if (nowUtc >= _nextExactSceneMaterializationDeferLogUtc)
                {
                    _nextExactSceneMaterializationDeferLogUtc = nowUtc.AddSeconds(2);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: deferring initial battlefield materialization on exact campaign scene until a synchronized peer has an authoritative side. " +
                        exactSceneMaterializationDeferReason +
                        " Source=" + (source ?? "unknown"));
                }

                return;
            }

            if (ShouldDeferExactScenePostPossessionMaterialization(mission, out string exactScenePostPossessionDeferReason))
            {
                DateTime nowUtc = DateTime.UtcNow;
                if (nowUtc >= _nextExactSceneMaterializationDeferLogUtc)
                {
                    _nextExactSceneMaterializationDeferLogUtc = nowUtc.AddSeconds(2);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: deferring automated battlefield materialization on exact campaign scene after player possession to let spawn handoff settle. " +
                        exactScenePostPossessionDeferReason +
                        " Source=" + (source ?? "unknown"));
                }

                return;
            }

            if (!IsBattleSnapshotReadyForMaterialization(mission, out string readinessSummary))
            {
                DateTime nowUtc = DateTime.UtcNow;
                if (nowUtc >= _nextIncompleteBattleSnapshotRefreshUtc)
                {
                    _nextIncompleteBattleSnapshotRefreshUtc = nowUtc.AddMilliseconds(750);
                    RefreshAllowedTroopsFromRoster(source + " awaiting snapshot");
                }

                if (!IsBattleSnapshotReadyForMaterialization(mission, out readinessSummary))
                {
                    if (nowUtc >= _nextIncompleteBattleSnapshotLogUtc)
                    {
                        _nextIncompleteBattleSnapshotLogUtc = nowUtc.AddSeconds(2);
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: delaying battlefield materialization because battle snapshot is incomplete. " +
                            readinessSummary +
                            " Source=" + (source ?? "unknown"));
                    }
                    return;
                }

                _nextIncompleteBattleSnapshotLogUtc = DateTime.MinValue;
            }

            DateTime pulseNowUtc = DateTime.UtcNow;
            if (pulseNowUtc < _nextInitialMaterializedArmyPulseUtc)
                return;

            _nextInitialMaterializedArmyPulseUtc = pulseNowUtc.AddSeconds(InitialMaterializedArmyPulseIntervalSeconds);

            int attackerTargetCount = GetInitialMaterializedArmyTargetCount(BattleSideEnum.Attacker);
            int defenderTargetCount = GetInitialMaterializedArmyTargetCount(BattleSideEnum.Defender);
            int attackerCurrentCount = GetCurrentMaterializedSpawnCountForSide(BattleSideEnum.Attacker);
            int defenderCurrentCount = GetCurrentMaterializedSpawnCountForSide(BattleSideEnum.Defender);

            bool exactCampaignSceneHasControlledPeer = false;
            if (SceneRuntimeClassifier.IsCampaignBattleScene(mission.SceneName ?? string.Empty) &&
                GameNetwork.NetworkPeers != null)
            {
                foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
                {
                    if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                        continue;

                    MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                    if (HasActiveControlledAgent(missionPeer))
                    {
                        exactCampaignSceneHasControlledPeer = true;
                        break;
                    }
                }
            }

            int attackerSpawnBudget = Math.Min(
                InitialMaterializedArmySpawnPulseBudgetPerSide,
                Math.Max(0, attackerTargetCount - attackerCurrentCount));
            int defenderSpawnBudget = Math.Min(
                InitialMaterializedArmySpawnPulseBudgetPerSide,
                Math.Max(0, defenderTargetCount - defenderCurrentCount));

            if (exactCampaignSceneHasControlledPeer &&
                defenderSpawnBudget > 0 &&
                defenderCurrentCount <= 0)
            {
                attackerSpawnBudget = 0;
                if (pulseNowUtc >= _nextExactSceneMaterializationDeferLogUtc)
                {
                    _nextExactSceneMaterializationDeferLogUtc = pulseNowUtc.AddSeconds(2);
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: prioritizing defender-side initial battlefield materialization on exact campaign scene after player possession. " +
                        "Scene=" + (mission.SceneName ?? "null") +
                        " AttackerCurrent=" + attackerCurrentCount +
                        " DefenderCurrent=" + defenderCurrentCount +
                        " AttackerTarget=" + attackerTargetCount +
                        " DefenderTarget=" + defenderTargetCount +
                        " Source=" + (source ?? "unknown"));
                }
            }

            int attackerCount = attackerSpawnBudget > 0
                ? MaterializeArmyForSide(mission, attackerTeam, BattleSideEnum.Attacker, source, attackerSpawnBudget)
                : 0;
            int defenderCount = defenderSpawnBudget > 0
                ? MaterializeArmyForSide(mission, defenderTeam, BattleSideEnum.Defender, source, defenderSpawnBudget)
                : 0;

            attackerCurrentCount = GetCurrentMaterializedSpawnCountForSide(BattleSideEnum.Attacker);
            defenderCurrentCount = GetCurrentMaterializedSpawnCountForSide(BattleSideEnum.Defender);

            bool attackerReady = attackerTargetCount <= 0 || attackerCurrentCount >= attackerTargetCount;
            bool defenderReady = defenderTargetCount <= 0 || defenderCurrentCount >= defenderTargetCount;
            if (!attackerReady || !defenderReady)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: initial battlefield materialization pulse. " +
                    "AttackerSpawnedThisPulse=" + attackerCount +
                    " AttackerCurrent=" + attackerCurrentCount + "/" + attackerTargetCount +
                    " DefenderSpawnedThisPulse=" + defenderCount +
                    " DefenderCurrent=" + defenderCurrentCount + "/" + defenderTargetCount +
                    " Source=" + (source ?? "unknown"));
                return;
            }

            if (attackerCurrentCount <= 0 && defenderCurrentCount <= 0)
                return;

            _hasMaterializedBattlefieldArmies = true;
            ModLogger.Info(
                "CoopMissionSpawnLogic: battlefield armies materialized. " +
                "AttackerAgents=" + attackerCurrentCount +
                " DefenderAgents=" + defenderCurrentCount +
                " BattleSizeBudget=" + GetConfiguredBattleSizeBudget() +
                " AttackerSideCap=" + GetMaterializedArmyAgentsPerSideCap(BattleSideEnum.Attacker, GetAllowedControlEntryStatesSnapshot(BattleSideEnum.Attacker).Count) +
                " DefenderSideCap=" + GetMaterializedArmyAgentsPerSideCap(BattleSideEnum.Defender, GetAllowedControlEntryStatesSnapshot(BattleSideEnum.Defender).Count) +
                " Source=" + (source ?? "unknown"));
        }

        private static void TrySpawnMaterializedBattlefieldReinforcements(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || !_hasMaterializedBattlefieldArmies)
                return;

            if (IsUsingNativeExactCampaignArmyBootstrap(mission))
                return;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            if (currentPhase < CoopBattlePhase.BattleActive || currentPhase >= CoopBattlePhase.BattleEnded)
                return;

            DateTime nowUtc = DateTime.UtcNow;
            if (nowUtc < _nextMaterializedArmyReinforcementPulseUtc)
                return;

            _nextMaterializedArmyReinforcementPulseUtc = nowUtc.AddSeconds(MaterializedArmyReinforcementPulseIntervalSeconds);

            Team attackerTeam = mission.Teams?.Attacker;
            Team defenderTeam = mission.Teams?.Defender;
            if (attackerTeam == null || defenderTeam == null)
                return;

            int attackerSpawned = SpawnMaterializedReinforcementWaveForSide(mission, attackerTeam, BattleSideEnum.Attacker, source);
            int defenderSpawned = SpawnMaterializedReinforcementWaveForSide(mission, defenderTeam, BattleSideEnum.Defender, source);
            if (attackerSpawned <= 0 && defenderSpawned <= 0)
                return;

            int pulsedAgents = 0;
            if (attackerSpawned > 0)
                pulsedAgents += TryActivateBattleActiveReinforcementAi(attackerTeam);
            if (defenderSpawned > 0)
                pulsedAgents += TryActivateBattleActiveReinforcementAi(defenderTeam);

            ModLogger.Info(
                "CoopMissionSpawnLogic: materialized reinforcement wave spawned. " +
                "AttackerSpawned=" + attackerSpawned +
                " DefenderSpawned=" + defenderSpawned +
                " PulsedAgents=" + pulsedAgents +
                " BattleSizeBudget=" + GetConfiguredBattleSizeBudget() +
                " Source=" + (source ?? "unknown"));
        }

        private static int SpawnMaterializedReinforcementWaveForSide(Mission mission, Team team, BattleSideEnum side, string source)
        {
            if (mission == null || team == null || side == BattleSideEnum.None)
                return 0;

            IReadOnlyList<RosterEntryState> entryStates = GetAutomatedMaterializableEntryStatesSnapshot(side);
            if (entryStates == null || entryStates.Count == 0)
                return 0;

            int sideCap = GetMaterializedArmyAgentsPerSideCap(side, entryStates.Count);
            int totalAvailableForSide = 0;
            int activeForSide = 0;
            var candidates = new List<MaterializedArmyReinforcementCandidate>();

            foreach (RosterEntryState entryState in entryStates)
            {
                string spawnTemplateId = ResolveEntrySpawnTemplateId(entryState);
                if (entryState == null || string.IsNullOrWhiteSpace(spawnTemplateId))
                    continue;

                int availableCount = Math.Max(0, entryState.Count - entryState.WoundedCount);
                if (availableCount <= 0)
                    continue;

                totalAvailableForSide += availableCount;

                _materializedBattleResultEntriesByEntryId.TryGetValue(entryState.EntryId ?? string.Empty, out MaterializedBattleResultEntryRuntimeState runtimeState);
                int spawnedCount = Math.Max(0, runtimeState?.MaterializedSpawnCount ?? 0);
                int activeCount = Math.Max(0, runtimeState?.ActiveCount ?? 0);
                activeForSide += activeCount;

                int totalRemainingCount = Math.Max(0, availableCount - spawnedCount);
                int concurrentRemainingCapacity = Math.Max(0, Math.Min(availableCount, GetMaterializedAgentsPerEntryCap(side, entryStates.Count)) - activeCount);
                if (totalRemainingCount <= 0 || concurrentRemainingCapacity <= 0)
                    continue;

                string resolvedTroopSource;
                BasicCharacterObject troop = ResolveMaterializedArmyCharacter(entryState, spawnTemplateId, out resolvedTroopSource);
                if (troop == null)
                    continue;

                candidates.Add(new MaterializedArmyReinforcementCandidate
                {
                    EntryState = entryState,
                    Troop = troop,
                    ResolvedTroopSource = resolvedTroopSource,
                    AvailableCount = availableCount,
                    ActiveCount = activeCount,
                    SpawnedCount = spawnedCount,
                    TotalRemainingCount = totalRemainingCount,
                    ConcurrentRemainingCapacity = concurrentRemainingCapacity,
                });
            }

            if (candidates.Count == 0)
                return 0;

            int targetActiveForSide = Math.Min(sideCap, totalAvailableForSide);
            int remainingSideNeed = Math.Max(0, targetActiveForSide - activeForSide);
            if (remainingSideNeed <= 0)
                return 0;

            int spawnedCountForSide = 0;
            var queuedByEntryId = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

            foreach (MaterializedArmyReinforcementCandidate candidate in candidates.Where(item => item.ActiveCount <= 0))
            {
                if (remainingSideNeed <= 0)
                    break;

                int seedCount = GetReinforcementSpawnCount(candidate, queuedByEntryId, remainingSideNeed, seedOneBody: true);
                if (seedCount <= 0)
                    continue;

                int spawned = SpawnMaterializedAgentsForEntry(
                    mission,
                    team,
                    side,
                    candidate.Troop,
                    candidate.EntryState,
                    seedCount,
                    activeForSide + spawnedCountForSide,
                    source + " reinforcement character=" + candidate.ResolvedTroopSource + " pass=seed",
                    isReinforcement: true);
                if (spawned <= 0)
                    continue;

                queuedByEntryId[candidate.EntryState.EntryId ?? string.Empty] = GetQueuedReinforcementCount(queuedByEntryId, candidate.EntryState.EntryId) + spawned;
                spawnedCountForSide += spawned;
                remainingSideNeed = Math.Max(0, remainingSideNeed - spawned);
            }

            foreach (MaterializedArmyReinforcementCandidate candidate in candidates)
            {
                if (remainingSideNeed <= 0)
                    break;

                int fillCount = GetReinforcementSpawnCount(candidate, queuedByEntryId, remainingSideNeed, seedOneBody: false);
                if (fillCount <= 0)
                    continue;

                int spawned = SpawnMaterializedAgentsForEntry(
                    mission,
                    team,
                    side,
                    candidate.Troop,
                    candidate.EntryState,
                    fillCount,
                    activeForSide + spawnedCountForSide,
                    source + " reinforcement character=" + candidate.ResolvedTroopSource + " pass=fill",
                    isReinforcement: true);
                if (spawned <= 0)
                    continue;

                queuedByEntryId[candidate.EntryState.EntryId ?? string.Empty] = GetQueuedReinforcementCount(queuedByEntryId, candidate.EntryState.EntryId) + spawned;
                spawnedCountForSide += spawned;
                remainingSideNeed = Math.Max(0, remainingSideNeed - spawned);
            }

            return spawnedCountForSide;
        }

        private static int GetReinforcementSpawnCount(
            MaterializedArmyReinforcementCandidate candidate,
            IReadOnlyDictionary<string, int> queuedByEntryId,
            int remainingSideNeed,
            bool seedOneBody)
        {
            if (candidate == null || remainingSideNeed <= 0)
                return 0;

            int alreadyQueued = GetQueuedReinforcementCount(queuedByEntryId, candidate.EntryState?.EntryId);
            int remainingTotalCount = Math.Max(0, candidate.TotalRemainingCount - alreadyQueued);
            int remainingConcurrentCapacity = Math.Max(0, candidate.ConcurrentRemainingCapacity - alreadyQueued);
            int allowed = Math.Min(remainingSideNeed, Math.Min(remainingTotalCount, remainingConcurrentCapacity));
            if (allowed <= 0)
                return 0;

            return seedOneBody ? Math.Min(1, allowed) : allowed;
        }

        private static int GetQueuedReinforcementCount(IReadOnlyDictionary<string, int> queuedByEntryId, string entryId)
        {
            if (queuedByEntryId == null || string.IsNullOrWhiteSpace(entryId))
                return 0;

            return queuedByEntryId.TryGetValue(entryId, out int queuedCount)
                ? Math.Max(0, queuedCount)
                : 0;
        }

        private static int TryActivateBattleActiveReinforcementAi(Team team)
        {
            if (team == null || team.Side == BattleSideEnum.None || ReferenceEquals(team, team.Mission?.SpectatorTeam))
                return 0;

            int pulsedAgentCount = 0;
            foreach (Formation formation in team.FormationsIncludingSpecialAndEmpty)
            {
                if (formation == null || formation.CountOfUnits <= 0)
                    continue;

                formation.SetMovementOrder(MovementOrder.MovementOrderCharge);
                formation.SetFiringOrder(FiringOrder.FiringOrderFireAtWill);
                formation.SetControlledByAI(true, true);
                pulsedAgentCount += TryPulseFormationAiEngage(formation, team);
            }

            if (team.HasTeamAi && team.HasAnyEnemyTeamsWithAgents(false))
            {
                team.ResetTactic();
                team.DelegateCommandToAI();
            }

            return pulsedAgentCount;
        }

        private static int CountMaterializedUnspawnedReserveForSide(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return 0;

            int reserveCount = 0;
            IReadOnlyList<RosterEntryState> entryStates = GetAutomatedMaterializableEntryStatesSnapshot(side);
            foreach (RosterEntryState entryState in entryStates)
            {
                if (entryState == null)
                    continue;

                int availableCount = Math.Max(0, entryState.Count - entryState.WoundedCount);
                if (availableCount <= 0)
                    continue;

                _materializedBattleResultEntriesByEntryId.TryGetValue(entryState.EntryId ?? string.Empty, out MaterializedBattleResultEntryRuntimeState runtimeState);
                int spawnedCount = Math.Max(0, runtimeState?.MaterializedSpawnCount ?? 0);
                reserveCount += Math.Max(0, availableCount - spawnedCount);
            }

            return reserveCount;
        }

        private static int GetInitialMaterializedArmyTargetCount(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return 0;

            IReadOnlyList<RosterEntryState> entryStates = GetAutomatedMaterializableEntryStatesSnapshot(side);
            if (entryStates != null && entryStates.Count > 0)
            {
                int sideCap = GetMaterializedArmyAgentsPerSideCap(side, entryStates.Count);
                int totalAvailable = entryStates.Sum(entryState => Math.Max(0, (entryState?.Count ?? 0) - (entryState?.WoundedCount ?? 0)));
                return Math.Max(0, Math.Min(sideCap, totalAvailable));
            }

            IReadOnlyList<string> troopIds = GetGenericMaterializedTroopFallbackIds(side);
            if (troopIds == null || troopIds.Count <= 0)
                return 0;

            int fallbackSideCap = GetMaterializedArmyAgentsPerSideCap(side, troopIds.Count);
            int fallbackAvailable = troopIds.Count * GetFallbackMaterializedAgentsPerTroopCap(side, troopIds.Count);
            return Math.Max(0, Math.Min(fallbackSideCap, fallbackAvailable));
        }

        private static int GetCurrentMaterializedSpawnCountForSide(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None || _materializedBattleResultEntriesByEntryId.Count == 0)
                return 0;

            string sideId = side.ToString();
            int spawnedCount = 0;
            foreach (MaterializedBattleResultEntryRuntimeState entryState in _materializedBattleResultEntriesByEntryId.Values)
            {
                if (entryState == null || !string.Equals(entryState.SideId, sideId, StringComparison.OrdinalIgnoreCase))
                    continue;

                spawnedCount += Math.Max(0, entryState.MaterializedSpawnCount);
            }

            return spawnedCount;
        }

        private static IReadOnlyList<RosterEntryState> GetAutomatedMaterializableEntryStatesSnapshot(BattleSideEnum side)
        {
            IReadOnlyList<RosterEntryState> entryStates = GetAllowedControlEntryStatesSnapshot(side);
            if (entryStates == null || entryStates.Count == 0)
                return Array.Empty<RosterEntryState>();

            var filteredEntries = new List<RosterEntryState>(entryStates.Count);
            var exactPlayerPartyFallbackEntries = new List<RosterEntryState>(entryStates.Count);
            foreach (RosterEntryState entryState in entryStates)
            {
                string skipReason = GetAutomatedMaterializedSpawnEntrySkipReason(entryState);
                if (string.IsNullOrEmpty(skipReason))
                {
                    filteredEntries.Add(entryState);
                    continue;
                }

                if (string.Equals(skipReason, "player-party-entry", StringComparison.OrdinalIgnoreCase) &&
                    IsAutomatedMaterializedExactPlayerPartyFallbackCandidate(entryState))
                {
                    exactPlayerPartyFallbackEntries.Add(entryState);
                    continue;
                }

                LogAutomatedMaterializedSpawnEntrySkip(entryState, skipReason);
            }

            if (filteredEntries.Count > 0)
                return filteredEntries;

            if (exactPlayerPartyFallbackEntries.Count > 0)
            {
                string logKey = "exact-player-party-fallback:" + side;
                if (_loggedAutomatedMaterializedEntrySkipIds.Add(logKey))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: preserving non-hero player-party exact roster entries for automated materialization because filtering would otherwise leave side empty. " +
                        "Side=" + side +
                        " RawEntryCount=" + entryStates.Count +
                        " PreservedEntryCount=" + exactPlayerPartyFallbackEntries.Count);
                }

                return exactPlayerPartyFallbackEntries;
            }

            return Array.Empty<RosterEntryState>();
        }

        private static string GetAutomatedMaterializedSpawnEntrySkipReason(RosterEntryState entryState)
        {
            if (entryState == null)
                return "null-entry";

            bool isHeroEntry =
                entryState.IsHero ||
                !string.IsNullOrWhiteSpace(entryState.HeroRole) ||
                string.Equals(entryState.OriginalCharacterId, "main_hero", StringComparison.OrdinalIgnoreCase);
            if (isHeroEntry)
                return "hero-entry";

            bool isPlayerPartyEntry =
                string.Equals(entryState.PartyId, "player_party", StringComparison.OrdinalIgnoreCase);
            return isPlayerPartyEntry
                ? "player-party-entry"
                : string.Empty;
        }

        private static bool IsAutomatedMaterializedExactPlayerPartyFallbackCandidate(RosterEntryState entryState)
        {
            if (entryState == null)
                return false;

            return string.Equals(entryState.PartyId, "player_party", StringComparison.OrdinalIgnoreCase) &&
                   !entryState.IsHero &&
                   string.IsNullOrWhiteSpace(entryState.HeroRole) &&
                   !string.Equals(entryState.OriginalCharacterId, "main_hero", StringComparison.OrdinalIgnoreCase) &&
                   !string.IsNullOrWhiteSpace(ResolveEntrySpawnTemplateId(entryState));
        }

        private static void LogAutomatedMaterializedSpawnEntrySkip(RosterEntryState entryState, string reason)
        {
            string spawnTemplateId = ResolveEntrySpawnTemplateId(entryState);
            string entryKey = entryState?.EntryId ?? entryState?.OriginalCharacterId ?? spawnTemplateId ?? "(unknown)";
            if (!_loggedAutomatedMaterializedEntrySkipIds.Add(entryKey))
                return;

            ModLogger.Info(
                "CoopMissionSpawnLogic: skipping automated materialized spawn entry. " +
                "Reason=" + (reason ?? "unknown") +
                " " +
                "EntryId=" + (entryState?.EntryId ?? "null") +
                " PartyId=" + (entryState?.PartyId ?? "null") +
                " OriginalCharacterId=" + (entryState?.OriginalCharacterId ?? "null") +
                " HeroRole=" + (entryState?.HeroRole ?? "null") +
                " IsHero=" + (entryState?.IsHero ?? false) +
                " SpawnTemplateId=" + (spawnTemplateId ?? "null"));
        }

        private static IReadOnlyList<string> GetGenericMaterializedTroopFallbackIds(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return Array.Empty<string>();

            IReadOnlyList<RosterEntryState> rawEntryStates = GetAllowedControlEntryStatesSnapshot(side);
            IReadOnlyList<string> allowedTroopIds = GetAllowedControlTroopIdsSnapshot(side);
            if (allowedTroopIds == null || allowedTroopIds.Count <= 0)
                return Array.Empty<string>();

            if (rawEntryStates == null || rawEntryStates.Count <= 0)
                return allowedTroopIds;

            IReadOnlyList<RosterEntryState> automatedEntryStates = GetAutomatedMaterializableEntryStatesSnapshot(side);
            if (automatedEntryStates != null && automatedEntryStates.Count > 0)
            {
                string logKey = "generic-fallback-suppressed:" + side;
                if (_loggedAutomatedMaterializedEntrySkipIds.Add(logKey))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: suppressed generic allowed-troop fallback for automated materialization because materializable roster entries exist. " +
                        "Side=" + side +
                        " RawEntryCount=" + rawEntryStates.Count +
                        " MaterializableEntryCount=" + automatedEntryStates.Count);
                }

                return Array.Empty<string>();
            }

            var safeTroopIds = new List<string>(allowedTroopIds.Count);
            foreach (string troopId in allowedTroopIds)
            {
                if (string.IsNullOrWhiteSpace(troopId))
                    continue;

                BasicCharacterObject troop = ResolveAllowedCharacter(troopId);
                bool isHeroTroop =
                    troop?.IsHero == true ||
                    troopId.IndexOf("_hero", StringComparison.OrdinalIgnoreCase) >= 0;
                if (isHeroTroop)
                    continue;

                if (safeTroopIds.Contains(troopId, StringComparer.OrdinalIgnoreCase))
                    continue;

                safeTroopIds.Add(troopId);
            }

            if (safeTroopIds.Count > 0)
            {
                string logKey = "generic-fallback-sanitized:" + side;
                if (_loggedAutomatedMaterializedEntrySkipIds.Add(logKey))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: using sanitized generic allowed-troop fallback for automated materialization because filtered roster entries left side empty. " +
                        "Side=" + side +
                        " RawEntryCount=" + rawEntryStates.Count +
                        " SafeTroopIds=[" + string.Join(", ", safeTroopIds) + "]");
                }

                return safeTroopIds;
            }

            string emptyLogKey = "generic-fallback-empty:" + side;
            if (_loggedAutomatedMaterializedEntrySkipIds.Add(emptyLogKey))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: suppressed generic allowed-troop fallback for automated materialization because only hero-class fallback ids remained after filtering. " +
                    "Side=" + side +
                    " RawEntryCount=" + rawEntryStates.Count +
                    " AllowedTroopIds=[" + string.Join(", ", allowedTroopIds) + "]");
            }

            return Array.Empty<string>();
        }

        private static bool IsBattleSnapshotReadyForMaterialization(Mission mission, out string readinessSummary)
        {
            BattleRuntimeState rosterState = BattleSnapshotRuntimeState.GetState();
            BattleSnapshotMessage snapshot = BattleSnapshotRuntimeState.GetCurrent();
            int sideCount = 0;
            int populatedSideCount = 0;
            bool hasAttacker = false;
            bool hasDefender = false;

            if (rosterState?.Sides != null && rosterState.Sides.Count > 0)
            {
                sideCount = rosterState.Sides.Count;
                foreach (BattleSideState sideState in rosterState.Sides)
                {
                    BattleSideEnum side = ResolveBattleSideFromState(sideState);
                    int entryCount = sideState?.Entries?.Count ?? 0;
                    if (entryCount <= 0)
                        continue;

                    populatedSideCount++;
                    if (side == BattleSideEnum.Attacker)
                        hasAttacker = true;
                    else if (side == BattleSideEnum.Defender)
                        hasDefender = true;
                }
            }
            else if (snapshot?.Sides != null && snapshot.Sides.Count > 0)
            {
                sideCount = snapshot.Sides.Count;
                foreach (BattleSideSnapshotMessage sideSnapshot in snapshot.Sides)
                {
                    BattleSideEnum side = ResolveBattleSideFromSnapshot(sideSnapshot);
                    int troopCount = sideSnapshot?.Troops?.Count ?? 0;
                    if (troopCount <= 0)
                        continue;

                    populatedSideCount++;
                    if (side == BattleSideEnum.Attacker)
                        hasAttacker = true;
                    else if (side == BattleSideEnum.Defender)
                        hasDefender = true;
                }
            }

            readinessSummary =
                "BattleId=" + (snapshot?.BattleId ?? "null") +
                " SnapshotSource=" + (BattleSnapshotRuntimeState.GetSource() ?? "unknown") +
                " Sides=" + sideCount +
                " PopulatedSides=" + populatedSideCount +
                " HasAttacker=" + hasAttacker +
                " HasDefender=" + hasDefender;
            bool snapshotReady = sideCount >= 2 && populatedSideCount >= 2 && hasAttacker && hasDefender;
            bool peerSnapshotAckReady =
                CoopMissionNetworkBridge.HaveAllEligiblePeersAcknowledgedCurrentBattleSnapshot(
                    mission,
                    out string peerSnapshotAckSummary);
            readinessSummary += " PeerSnapshotAck={" + (peerSnapshotAckSummary ?? "unknown") + "}";
            return snapshotReady && peerSnapshotAckReady;
        }

        private static bool ShouldDeferExactSceneInitialBattlefieldMaterialization(Mission mission, out string reason)
        {
            reason = string.Empty;
            if (mission == null || !IsSceneAwareBattleMapRuntime(mission))
                return false;

            if (IsUsingNativeExactCampaignArmyBootstrap(mission))
            {
                reason = "native exact-scene bootstrap active";
                return true;
            }

            if (!SceneRuntimeClassifier.IsCampaignBattleScene(mission.SceneName))
                return false;

            if (IsBattleSnapshotReadyForMaterialization(mission, out _))
                return false;

            if (HasExactSceneMaterializationAuthorityAnchor(mission, out string authorityAnchorSummary))
                return false;

            reason = authorityAnchorSummary;
            return true;
        }

        private static bool HasExactSceneMaterializationAuthorityAnchor(Mission mission, out string reason)
        {
            reason = string.Empty;
            int synchronizedPeerCount = 0;
            int requestedPeerCount = 0;
            int assignedPeerCount = 0;
            int selectedPeerCount = 0;

            if (GameNetwork.NetworkPeers != null)
            {
                foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
                {
                    if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                        continue;

                    synchronizedPeerCount++;
                    MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                    if (missionPeer == null)
                        continue;

                    CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
                    if (selectionState.RequestedSide != BattleSideEnum.None)
                        requestedPeerCount++;

                    BattleSideEnum authoritativeSide = selectionState.Side;
                    if (authoritativeSide == BattleSideEnum.None)
                        authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, "initial-materialization-anchor");
                    if (authoritativeSide != BattleSideEnum.None)
                        assignedPeerCount++;

                    if (!string.IsNullOrWhiteSpace(selectionState.EntryId) ||
                        !string.IsNullOrWhiteSpace(selectionState.TroopId) ||
                        CoopBattleSpawnRequestState.HasPendingRequest(missionPeer))
                    {
                        selectedPeerCount++;
                    }
                }
            }

            if (assignedPeerCount > 0)
                return true;

            reason =
                "Scene=" + (mission?.SceneName ?? "null") +
                " SynchronizedPeers=" + synchronizedPeerCount +
                " RequestedPeers=" + requestedPeerCount +
                " AssignedPeers=" + assignedPeerCount +
                " SelectedPeers=" + selectedPeerCount;
            return false;
        }

        private static bool ShouldDeferExactScenePostPossessionMaterialization(Mission mission, out string reason)
        {
            reason = string.Empty;
            if (mission == null || _hasMaterializedBattlefieldArmies || !IsSceneAwareBattleMapRuntime(mission))
                return false;

            if (IsUsingNativeExactCampaignArmyBootstrap(mission))
            {
                reason = "native exact-scene bootstrap active";
                return true;
            }

            if (!SceneRuntimeClassifier.IsCampaignBattleScene(mission.SceneName ?? string.Empty))
                return false;

            DateTime nowUtc = DateTime.UtcNow;
            if (_exactScenePostPossessionMaterializationResumeUtc <= nowUtc)
                return false;

            int controlledPeerCount = 0;
            if (GameNetwork.NetworkPeers != null)
            {
                foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
                {
                    if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                        continue;

                    MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                    if (HasActiveControlledAgent(missionPeer))
                        controlledPeerCount++;
                }
            }

            if (controlledPeerCount <= 0)
                return false;

            reason =
                "Scene=" + (mission.SceneName ?? "null") +
                " ControlledPeers=" + controlledPeerCount +
                " RemainingSeconds=" + (_exactScenePostPossessionMaterializationResumeUtc - nowUtc)
                    .TotalSeconds
                    .ToString("0.0", System.Globalization.CultureInfo.InvariantCulture);
            return true;
        }

        private static int MaterializeArmyForSide(
            Mission mission,
            Team team,
            BattleSideEnum side,
            string source,
            int maxSpawnCount = int.MaxValue)
        {
            if (mission == null || team == null || side == BattleSideEnum.None || maxSpawnCount <= 0)
                return 0;

            int spawnedCount = 0;
            int currentSpawnedForSide = GetCurrentMaterializedSpawnCountForSide(side);
            IReadOnlyList<RosterEntryState> entryStates = GetAutomatedMaterializableEntryStatesSnapshot(side);
            int sideCap = GetMaterializedArmyAgentsPerSideCap(side, entryStates.Count);
            if (entryStates.Count > 0)
            {
                var materializableEntries = new List<(RosterEntryState EntryState, BasicCharacterObject Troop, int AvailableCount, string ResolvedTroopSource)>();
                foreach (RosterEntryState entryState in entryStates)
                {
                    string spawnTemplateId = ResolveEntrySpawnTemplateId(entryState);
                    if (entryState == null || string.IsNullOrWhiteSpace(spawnTemplateId))
                        continue;

                    int availableCount = Math.Max(0, entryState.Count - entryState.WoundedCount);
                    if (availableCount <= 0)
                        continue;

                    string resolvedTroopSource;
                    BasicCharacterObject troop = ResolveMaterializedArmyCharacter(entryState, spawnTemplateId, out resolvedTroopSource);
                    if (troop == null)
                    {
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: materialized entry character resolution failed. " +
                            "Side=" + side +
                            " EntryId=" + (entryState.EntryId ?? "null") +
                            " OriginalCharacterId=" + (entryState.OriginalCharacterId ?? "null") +
                            " SpawnTemplateId=" + (spawnTemplateId ?? "null") +
                            " Source=" + (source ?? "unknown"));
                        continue;
                    }

                    materializableEntries.Add((entryState, troop, availableCount, resolvedTroopSource));
                }

                // First pass: ensure each distinct roster entry gets at least one spawned body
                // before large stacks consume the side cap. This preserves representation for
                // hero/ranged/specialized entries such as crossbowmen under tight limits.
                foreach ((RosterEntryState entryState, BasicCharacterObject troop, int availableCount, string resolvedTroopSource) in materializableEntries)
                {
                    int remainingCapacity = sideCap - (currentSpawnedForSide + spawnedCount);
                    int remainingPulseBudget = maxSpawnCount - spawnedCount;
                    if (remainingCapacity <= 0 || remainingPulseBudget <= 0)
                        break;

                    _materializedBattleResultEntriesByEntryId.TryGetValue(entryState.EntryId ?? string.Empty, out MaterializedBattleResultEntryRuntimeState runtimeState);
                    int alreadySpawnedCount = Math.Max(0, runtimeState?.MaterializedSpawnCount ?? 0);
                    if (alreadySpawnedCount > 0)
                        continue;

                    int remainingAvailableCount = Math.Max(0, availableCount - alreadySpawnedCount);
                    int seedCount = Math.Min(1, Math.Min(remainingAvailableCount, Math.Min(remainingCapacity, remainingPulseBudget)));
                    if (seedCount <= 0)
                        continue;

                    spawnedCount += SpawnMaterializedAgentsForEntry(
                        mission,
                        team,
                        side,
                        troop,
                        entryState,
                        seedCount,
                        currentSpawnedForSide + spawnedCount,
                        source + " character=" + resolvedTroopSource + " pass=seed");
                }

                // Second pass: fill remaining side capacity up to per-entry caps.
                foreach ((RosterEntryState entryState, BasicCharacterObject troop, int availableCount, string resolvedTroopSource) in materializableEntries)
                {
                    int remainingCapacity = sideCap - (currentSpawnedForSide + spawnedCount);
                    int remainingPulseBudget = maxSpawnCount - spawnedCount;
                    if (remainingCapacity <= 0 || remainingPulseBudget <= 0)
                        break;

                    _materializedBattleResultEntriesByEntryId.TryGetValue(entryState.EntryId ?? string.Empty, out MaterializedBattleResultEntryRuntimeState runtimeState);
                    int alreadySpawnedCount = Math.Max(0, runtimeState?.MaterializedSpawnCount ?? 0);
                    int remainingEntryCapacity = Math.Min(availableCount, GetMaterializedAgentsPerEntryCap(side, entryStates.Count)) - alreadySpawnedCount;
                    if (remainingEntryCapacity <= 0)
                        continue;

                    int extraCount = Math.Min(remainingEntryCapacity, Math.Min(remainingCapacity, remainingPulseBudget));
                    if (extraCount <= 0)
                        continue;

                    spawnedCount += SpawnMaterializedAgentsForEntry(
                        mission,
                        team,
                        side,
                        troop,
                        entryState,
                        extraCount,
                        currentSpawnedForSide + spawnedCount,
                        source + " character=" + resolvedTroopSource + " pass=fill");
                }

                return spawnedCount;
            }

            IReadOnlyList<string> troopIds = GetGenericMaterializedTroopFallbackIds(side);
            sideCap = GetMaterializedArmyAgentsPerSideCap(side, troopIds.Count);
            foreach (string troopId in troopIds)
            {
                BasicCharacterObject troop = ResolveAllowedCharacter(troopId);
                if (troop == null)
                    continue;

                int remainingCapacity = sideCap - (currentSpawnedForSide + spawnedCount);
                int remainingPulseBudget = maxSpawnCount - spawnedCount;
                if (remainingCapacity <= 0 || remainingPulseBudget <= 0)
                    break;

                int spawnCount = Math.Min(
                    GetFallbackMaterializedAgentsPerTroopCap(side, troopIds.Count),
                    Math.Min(remainingCapacity, remainingPulseBudget));
                spawnedCount += SpawnMaterializedAgentsForEntry(
                    mission,
                    team,
                    side,
                    troop,
                    null,
                    spawnCount,
                    currentSpawnedForSide + spawnedCount,
                    source);
            }

            return spawnedCount;
        }

        private static bool IsSyntheticAllCampaignTroopsRuntime()
        {
            BattleSnapshotMessage snapshot = BattleSnapshotRuntimeState.GetCurrent();
            return string.Equals(snapshot?.BattleId, SyntheticAllCampaignTroopsBattleId, StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsSyntheticLiveHeroesRuntime()
        {
            BattleSnapshotMessage snapshot = BattleSnapshotRuntimeState.GetCurrent();
            return string.Equals(snapshot?.BattleId, SyntheticLiveHeroesBattleId, StringComparison.OrdinalIgnoreCase);
        }

        private static bool IsSyntheticRuntime()
        {
            return IsSyntheticAllCampaignTroopsRuntime() || IsSyntheticLiveHeroesRuntime();
        }

        private static int GetMaterializedArmyAgentsPerSideCap(BattleSideEnum side, int requestedEntryCount)
        {
            if (side == BattleSideEnum.None)
                return MaxMaterializedArmyAgentsPerSide;

            if (IsSyntheticRuntime())
                return Math.Max(MaxMaterializedArmyAgentsPerSide, Math.Max(0, requestedEntryCount));

            int totalBattleBudget = GetConfiguredBattleSizeBudget();
            int attackerAvailable = GetBattleSideAvailableCount(BattleSideEnum.Attacker);
            int defenderAvailable = GetBattleSideAvailableCount(BattleSideEnum.Defender);
            int totalAvailable = attackerAvailable + defenderAvailable;
            int sideAvailable = side == BattleSideEnum.Attacker ? attackerAvailable : defenderAvailable;

            if (totalBattleBudget <= 0 || totalAvailable <= 0 || sideAvailable <= 0)
                return MaxMaterializedArmyAgentsPerSide;

            int sideCap = (int)Math.Round((double)totalBattleBudget * sideAvailable / totalAvailable, MidpointRounding.AwayFromZero);
            sideCap = Math.Max(1, sideCap);
            sideCap = Math.Min(sideAvailable, sideCap);
            return sideCap;
        }

        private static int GetMaterializedAgentsPerEntryCap(BattleSideEnum side, int requestedEntryCount)
        {
            if (IsSyntheticRuntime())
                return 1;

            if (requestedEntryCount <= 0)
                return MaxMaterializedAgentsPerEntry;

            int sideCap = GetMaterializedArmyAgentsPerSideCap(side, requestedEntryCount);
            if (sideCap <= 0)
                return MaxMaterializedAgentsPerEntry;

            return Math.Max(1, (int)Math.Ceiling((double)sideCap / requestedEntryCount));
        }

        private static int GetFallbackMaterializedAgentsPerTroopCap(BattleSideEnum side, int requestedTroopCount)
        {
            if (IsSyntheticRuntime())
                return 1;

            if (requestedTroopCount <= 0)
                return FallbackMaterializedAgentsPerTroop;

            int sideCap = GetMaterializedArmyAgentsPerSideCap(side, requestedTroopCount);
            if (sideCap <= 0)
                return FallbackMaterializedAgentsPerTroop;

            return Math.Max(1, (int)Math.Ceiling((double)sideCap / requestedTroopCount));
        }

        private static int GetConfiguredBattleSizeBudget()
        {
            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            int snapshotBudget = runtimeState?.BattleSizeBudget ?? BattleSnapshotRuntimeState.GetCurrent()?.BattleSizeBudget ?? 0;
            if (snapshotBudget > 0)
                return snapshotBudget;

            return MaxMaterializedArmyAgentsPerSide * 2;
        }

        private static int GetBattleSideAvailableCount(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return 0;

            IReadOnlyList<RosterEntryState> entryStates = GetAllowedControlEntryStatesSnapshot(side);
            if (entryStates != null && entryStates.Count > 0)
            {
                int entryTotal = entryStates.Sum(entryState => Math.Max(0, (entryState?.Count ?? 0) - (entryState?.WoundedCount ?? 0)));
                if (entryTotal > 0)
                    return entryTotal;
            }

            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.Sides != null)
            {
                BattleSideState sideState = runtimeState.Sides.FirstOrDefault(candidate =>
                    ResolveBattleSideFromState(candidate) == side);
                int fallbackTotal = Math.Max(0, sideState?.TotalManCount ?? 0);
                if (fallbackTotal > 0)
                    return fallbackTotal;
            }

            return 0;
        }

        private static bool TryRepairMaterializedDeploymentPlan(
            Mission mission,
            Team team,
            BattleSideEnum side,
            string source)
        {
            if (mission == null || team == null || side == BattleSideEnum.None)
                return false;

            BattleMapContractDiagnostics.LogDeploymentPlanContract(
                mission,
                team,
                focusFormation: null,
                isReinforcement: false,
                source: (source ?? "unknown") + " pre-repair");

            if (!mission.GetDeploymentPlan<DefaultMissionDeploymentPlan>(out DefaultMissionDeploymentPlan deploymentPlan) || deploymentPlan == null)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: materialized deployment plan repair skipped because DefaultMissionDeploymentPlan is unavailable. " +
                    "TeamSide=" + side +
                    " TeamIndex=" + team.TeamIndex +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            if (!EnsureMaterializedDeploymentPlanHasTeamPlan(mission, deploymentPlan, team, side, source))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: materialized deployment plan repair skipped because no team plan is registered for the current mission team. " +
                    "TeamSide=" + side +
                    " TeamIndex=" + team.TeamIndex +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            Dictionary<FormationClass, (int Foot, int Mounted)> formationCounts =
                BuildMaterializedDeploymentCountsForSide(side, out int plannedAgents, out bool hasMountedUnits);
            if (formationCounts.Count == 0 || plannedAgents <= 0)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: materialized deployment plan repair skipped because no planned troop counts were resolved. " +
                    "TeamSide=" + side +
                    " TeamIndex=" + team.TeamIndex +
                    " Source=" + (source ?? "unknown"));
                return false;
            }

            try
            {
                if (deploymentPlan.IsPlanMade(team))
                {
                    deploymentPlan.ClearAddedTroops(team);
                    deploymentPlan.ClearDeploymentPlan(team);
                }

                if (deploymentPlan.IsReinforcementPlanMade(team))
                {
                    deploymentPlan.ClearAddedTroops(team, isReinforcement: true);
                    deploymentPlan.ClearReinforcementPlan(team);
                }

                deploymentPlan.SetSpawnWithHorses(team, hasMountedUnits);
                foreach (KeyValuePair<FormationClass, (int Foot, int Mounted)> formationCount in formationCounts.OrderBy(pair => (int)pair.Key))
                {
                    if (formationCount.Value.Foot <= 0 && formationCount.Value.Mounted <= 0)
                        continue;

                    deploymentPlan.AddTroops(team, formationCount.Key, formationCount.Value.Foot, formationCount.Value.Mounted);
                    deploymentPlan.AddTroops(team, formationCount.Key, formationCount.Value.Foot, formationCount.Value.Mounted, isReinforcement: true);
                }

                deploymentPlan.MakeDeploymentPlan(team);
                deploymentPlan.MakeReinforcementDeploymentPlan(team);

                bool hasSceneMapPatch = false;
                try
                {
                    hasSceneMapPatch = mission.HasSceneMapPatch();
                }
                catch
                {
                }

                bool initialPlanMade = deploymentPlan.IsPlanMade(team);
                bool reinforcementPlanMade = deploymentPlan.IsReinforcementPlanMade(team);
                BattleMapContractDiagnostics.LogDeploymentPlanContract(
                    mission,
                    team,
                    focusFormation: null,
                    isReinforcement: false,
                    source: (source ?? "unknown") + " post-repair");
                ModLogger.Info(
                    "CoopMissionSpawnLogic: repaired materialized deployment plan. " +
                    "TeamSide=" + side +
                    " TeamIndex=" + team.TeamIndex +
                    " PlannedAgents=" + plannedAgents +
                    " HasMountedUnits=" + hasMountedUnits +
                    " HasSceneMapPatch=" + hasSceneMapPatch +
                    " InitialPlanMade=" + initialPlanMade +
                    " ReinforcementPlanMade=" + reinforcementPlanMade +
                    " FormationCounts=" + BuildMaterializedDeploymentCountSummary(formationCounts) +
                    " Source=" + (source ?? "unknown"));
                return initialPlanMade;
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: materialized deployment plan repair failed. " +
                    "TeamSide=" + side +
                    " TeamIndex=" + team.TeamIndex +
                    " Source=" + (source ?? "unknown") +
                    " Message=" + ex.Message);
                return false;
            }
        }

        private static readonly FieldInfo DefaultMissionDeploymentPlanTeamDeploymentPlansField =
            typeof(DefaultMissionDeploymentPlan).GetField("_teamDeploymentPlans", BindingFlags.Instance | BindingFlags.NonPublic);

        private static bool EnsureMaterializedDeploymentPlanHasTeamPlan(
            Mission mission,
            DefaultMissionDeploymentPlan deploymentPlan,
            Team team,
            BattleSideEnum side,
            string source)
        {
            if (mission == null || deploymentPlan == null || team == null)
                return false;

            bool hasTeamPlan = TryHasMaterializedDeploymentTeamPlan(deploymentPlan, team, out int registeredPlanCountBefore);
            if (hasTeamPlan)
                return true;

            int missionTeamCount = 0;
            try
            {
                missionTeamCount = mission.Teams?.Count ?? 0;
            }
            catch
            {
            }

            ModLogger.Info(
                "CoopMissionSpawnLogic: refreshing deployment plan team snapshot for materialized spawn repair. " +
                "TeamSide=" + side +
                " TeamIndex=" + team.TeamIndex +
                " MissionTeamCount=" + missionTeamCount +
                " RegisteredPlanCountBefore=" + registeredPlanCountBefore +
                " Source=" + (source ?? "unknown"));

            try
            {
                deploymentPlan.Initialize();
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deployment plan team snapshot refresh failed. " +
                    "TeamSide=" + side +
                    " TeamIndex=" + team.TeamIndex +
                    " Source=" + (source ?? "unknown") +
                    " Message=" + ex.Message);
                return false;
            }

            bool readyAfterRefresh = TryHasMaterializedDeploymentTeamPlan(deploymentPlan, team, out int registeredPlanCountAfter);
            ModLogger.Info(
                "CoopMissionSpawnLogic: deployment plan team snapshot refresh completed. " +
                "TeamSide=" + side +
                " TeamIndex=" + team.TeamIndex +
                " RegisteredPlanCountAfter=" + registeredPlanCountAfter +
                " Ready=" + readyAfterRefresh +
                " Source=" + (source ?? "unknown"));
            return readyAfterRefresh;
        }

        private static bool TryHasMaterializedDeploymentTeamPlan(
            DefaultMissionDeploymentPlan deploymentPlan,
            Team team,
            out int registeredPlanCount)
        {
            registeredPlanCount = 0;
            if (deploymentPlan == null || team == null || DefaultMissionDeploymentPlanTeamDeploymentPlansField == null)
                return false;

            if (!(DefaultMissionDeploymentPlanTeamDeploymentPlansField.GetValue(deploymentPlan) is IEnumerable entries))
                return false;

            foreach (object entry in entries)
            {
                if (entry == null)
                    continue;

                registeredPlanCount++;
                FieldInfo item1Field = entry.GetType().GetField("Item1", BindingFlags.Instance | BindingFlags.Public);
                if (item1Field == null)
                    continue;

                if (ReferenceEquals(item1Field.GetValue(entry), team))
                    return true;
            }

            return false;
        }

        private static Dictionary<FormationClass, (int Foot, int Mounted)> BuildMaterializedDeploymentCountsForSide(
            BattleSideEnum side,
            out int plannedAgents,
            out bool hasMountedUnits)
        {
            var formationCounts = new Dictionary<FormationClass, (int Foot, int Mounted)>();
            plannedAgents = 0;
            hasMountedUnits = false;

            IReadOnlyList<RosterEntryState> entryStates = GetAutomatedMaterializableEntryStatesSnapshot(side);
            int requestedEntryCount = entryStates?.Count ?? 0;
            int sideCap = GetMaterializedArmyAgentsPerSideCap(side, requestedEntryCount);
            if (entryStates != null && entryStates.Count > 0)
            {
                var materializableEntries = new List<(RosterEntryState EntryState, BasicCharacterObject Troop, int AvailableCount)>();
                foreach (RosterEntryState entryState in entryStates)
                {
                    string spawnTemplateId = ResolveEntrySpawnTemplateId(entryState);
                    if (entryState == null || string.IsNullOrWhiteSpace(spawnTemplateId))
                        continue;

                    int availableCount = Math.Max(0, entryState.Count - entryState.WoundedCount);
                    if (availableCount <= 0)
                        continue;

                    BasicCharacterObject troop = ResolveMaterializedArmyCharacter(entryState, spawnTemplateId, out _);
                    if (troop == null)
                        continue;

                    materializableEntries.Add((entryState, troop, availableCount));
                }

                foreach ((RosterEntryState entryState, BasicCharacterObject troop, int availableCount) in materializableEntries)
                {
                    int remainingCapacity = sideCap - plannedAgents;
                    if (remainingCapacity <= 0)
                        break;

                    int seedCount = Math.Min(1, Math.Min(availableCount, remainingCapacity));
                    if (seedCount <= 0)
                        continue;

                    AccumulateMaterializedDeploymentCount(
                        formationCounts,
                        troop,
                        entryState,
                        seedCount,
                        ref plannedAgents,
                        ref hasMountedUnits);
                }

                foreach ((RosterEntryState entryState, BasicCharacterObject troop, int availableCount) in materializableEntries)
                {
                    int remainingCapacity = sideCap - plannedAgents;
                    if (remainingCapacity <= 0)
                        break;

                    int remainingEntryCapacity = Math.Min(availableCount, GetMaterializedAgentsPerEntryCap(side, entryStates.Count)) - 1;
                    if (remainingEntryCapacity <= 0)
                        continue;

                    int extraCount = Math.Min(remainingEntryCapacity, remainingCapacity);
                    if (extraCount <= 0)
                        continue;

                    AccumulateMaterializedDeploymentCount(
                        formationCounts,
                        troop,
                        entryState,
                        extraCount,
                        ref plannedAgents,
                        ref hasMountedUnits);
                }

                return formationCounts;
            }

            IReadOnlyList<string> troopIds = GetGenericMaterializedTroopFallbackIds(side);
            sideCap = GetMaterializedArmyAgentsPerSideCap(side, troopIds.Count);
            foreach (string troopId in troopIds)
            {
                BasicCharacterObject troop = ResolveAllowedCharacter(troopId);
                if (troop == null)
                    continue;

                int remainingCapacity = sideCap - plannedAgents;
                if (remainingCapacity <= 0)
                    break;

                int spawnCount = Math.Min(GetFallbackMaterializedAgentsPerTroopCap(side, troopIds.Count), remainingCapacity);
                if (spawnCount <= 0)
                    continue;

                AccumulateMaterializedDeploymentCount(
                    formationCounts,
                    troop,
                    entryState: null,
                    spawnCount,
                    ref plannedAgents,
                    ref hasMountedUnits);
            }

            return formationCounts;
        }

        private static void AccumulateMaterializedDeploymentCount(
            Dictionary<FormationClass, (int Foot, int Mounted)> formationCounts,
            BasicCharacterObject troop,
            RosterEntryState entryState,
            int count,
            ref int plannedAgents,
            ref bool hasMountedUnits)
        {
            if (formationCounts == null || troop == null || count <= 0)
                return;

            FormationClass formationClass = troop.DefaultFormationClass;
            if ((int)formationClass < 0 || (int)formationClass >= (int)FormationClass.NumberOfRegularFormations)
                formationClass = FormationClass.Infantry;

            bool isMounted = entryState?.IsMounted ?? (formationClass == FormationClass.Cavalry || formationClass == FormationClass.HorseArcher);
            if (!formationCounts.TryGetValue(formationClass, out (int Foot, int Mounted) existingCounts))
                existingCounts = (0, 0);

            existingCounts = isMounted
                ? (existingCounts.Foot, existingCounts.Mounted + count)
                : (existingCounts.Foot + count, existingCounts.Mounted);
            formationCounts[formationClass] = existingCounts;

            plannedAgents += count;
            if (isMounted)
                hasMountedUnits = true;
        }

        private static string BuildMaterializedDeploymentCountSummary(
            Dictionary<FormationClass, (int Foot, int Mounted)> formationCounts)
        {
            if (formationCounts == null || formationCounts.Count == 0)
                return "(none)";

            return string.Join(
                ",",
                formationCounts
                    .OrderBy(pair => (int)pair.Key)
                    .Select(pair => pair.Key + "(F=" + pair.Value.Foot + ",M=" + pair.Value.Mounted + ")"));
        }

        private static BasicCharacterObject ResolveMaterializedArmyCharacter(
            RosterEntryState entryState,
            string spawnTemplateId,
            out string resolvedTroopSource)
        {
            resolvedTroopSource = "spawn-template";
            if (entryState == null)
                return null;

            ExactEntryCompatibilityDiagnostic entryDiagnostic = GetExactEntryCompatibilityDiagnostic(entryState);
            if (entryDiagnostic != null)
            {
                resolvedTroopSource = entryDiagnostic.CharacterResolutionSource ?? resolvedTroopSource;
                if (!IsMaterializedExactEntryCharacterSupported(entryDiagnostic))
                {
                    string rejectionReason = BuildMaterializedExactEntryContractRejectionReason(entryDiagnostic);
                    LogExactEntryCompatibilityDiagnostic(entryDiagnostic, "materialized-character-skip");
                    TraceMaterializedEntryContractDecision(
                        "materialized-character-skip",
                        entryState,
                        spawnTemplateId,
                        entryDiagnostic,
                        rejectionReason,
                        "ResolveMaterializedArmyCharacter");
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: skipped materialized entry because exact character contract is not admissible for hosted MP materialization. " +
                        "EntryId=" + (entryState.EntryId ?? "null") +
                        " Status=" + (entryDiagnostic.Status ?? "unknown") +
                        " Reason=" + rejectionReason +
                        " CharacterSource=" + (entryDiagnostic.CharacterResolutionSource ?? "unknown") +
                        " CharacterId=" + (entryDiagnostic.ResolvedCharacter?.StringId ?? "null") +
                        " SpawnTemplateId=" + (spawnTemplateId ?? "null"));
                    return null;
                }

                LogExactEntryCompatibilityDiagnostic(entryDiagnostic, "materialized-character");
                return entryDiagnostic.ResolvedCharacter;
            }

            BasicCharacterObject templateCharacter = BattleSnapshotRuntimeState.TryResolveCharacterObject(entryState.EntryId);
            if (templateCharacter == null)
                return null;

            resolvedTroopSource = "snapshot-runtime";
            return templateCharacter;
        }

        private static int SpawnMaterializedAgentsForEntry(
            Mission mission,
            Team team,
            BattleSideEnum side,
            BasicCharacterObject troop,
            RosterEntryState entryState,
            int spawnCount,
            int sideOffset,
            string source,
            bool isReinforcement = false)
        {
            if (mission == null || team == null || troop == null || spawnCount <= 0)
                return 0;

            string entryId = entryState?.EntryId;

            FormationClass formationClass = troop.DefaultFormationClass;
            ResolveMaterializedArmySpawnFrame(
                mission,
                team,
                side,
                troop,
                formationClass,
                isReinforcement,
                out Vec3 formationSpawnPosition,
                out Vec2 formationDirection,
                out string spawnFrameSource);

            if (formationDirection.LengthSquared < 0.001f)
                formationDirection = side == BattleSideEnum.Attacker ? new Vec2(1f, 0f) : new Vec2(-1f, 0f);

            formationDirection.Normalize();
            Vec3 forward = new Vec3(formationDirection.x, formationDirection.y, 0f);
            Vec3 right = new Vec3(-formationDirection.y, formationDirection.x, 0f);
            Vec3 basePosition = formationSpawnPosition;

            ExactEntryCompatibilityDiagnostic exactEntryCompatibility = GetExactEntryCompatibilityDiagnostic(entryState);
            string exactEntryCompatibilitySummary = BuildExactEntryCompatibilityShortSummary(exactEntryCompatibility);
            string equipmentOverrideDiagnostics = BuildMaterializedEquipmentOverrideDiagnostics(entryState, troop);
            string combatProfileDiagnostics = "AppliedCombatProfile=(none)";
            string identityDiagnostics = "AppliedIdentity=(none)";
            int spawnedCount = 0;
            ModLogger.Info(
                "CoopMissionSpawnLogic: materialized battlefield entry spawn begin. " +
                "Side=" + side +
                " TroopId=" + troop.StringId +
                " EntryId=" + (entryId ?? "null") +
                " RequestedCount=" + spawnCount +
                " Reinforcement=" + isReinforcement +
                " SpawnFrameSource=" + spawnFrameSource +
                " " + exactEntryCompatibilitySummary +
                " Source=" + (source ?? "unknown"));
            for (int i = 0; i < spawnCount; i++)
            {
                int absoluteIndex = sideOffset + spawnedCount;
                int column = absoluteIndex % 4;
                int row = absoluteIndex / 4;
                float lateralOffset = (column - 1.5f) * 1.8f;
                float depthOffset = row * 2.2f * (side == BattleSideEnum.Attacker ? -1f : 1f);
                Vec3 spawnPosition = basePosition + right * lateralOffset + forward * depthOffset;

                string appliedArmorOverrides;
                string appliedCombatProfile;
                string appliedIdentity;
                Agent agent = SpawnBattlefieldArmyAgent(
                    mission,
                    team,
                    troop,
                    entryState,
                    formationClass,
                    spawnPosition,
                    formationDirection,
                    out appliedArmorOverrides,
                    out appliedCombatProfile,
                    out appliedIdentity);
                if (agent == null)
                    continue;

                _materializedArmyEntryIdByAgentIndex[agent.Index] = entryId ?? string.Empty;
                _materializedArmySideByAgentIndex[agent.Index] = side;
                RegisterMaterializedBattleResultEntry(agent, entryState, side);
                combatProfileDiagnostics = appliedCombatProfile;
                identityDiagnostics = appliedIdentity;
                spawnedCount++;
            }

            if (spawnedCount > 0)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: materialized battlefield entry. " +
                    "Side=" + side +
                    " TroopId=" + troop.StringId +
                    " EntryId=" + (entryId ?? "null") +
                    " Spawned=" + spawnedCount +
                    " Reinforcement=" + isReinforcement +
                    " SpawnFrameSource=" + spawnFrameSource +
                    " " + exactEntryCompatibilitySummary +
                    " " + equipmentOverrideDiagnostics +
                    " " + identityDiagnostics +
                    " " + combatProfileDiagnostics +
                    " Source=" + (source ?? "unknown"));
            }

            return spawnedCount;
        }

        private static void ResolveMaterializedArmySpawnFrame(
            Mission mission,
            Team team,
            BattleSideEnum side,
            BasicCharacterObject troop,
            FormationClass formationClass,
            bool isReinforcement,
            out Vec3 spawnPosition,
            out Vec2 spawnDirection,
            out string spawnFrameSource)
        {
            spawnPosition = new Vec3(0f, 0f, 0f);
            spawnDirection = side == BattleSideEnum.Attacker ? new Vec2(1f, 0f) : new Vec2(-1f, 0f);
            spawnFrameSource = "direct-fallback";

            string repairSource = (isReinforcement ? "reinforcement" : "initial") + "-formation-frame-repair:" + troop.StringId;
            if (TryRepairMaterializedDeploymentPlan(mission, team, side, repairSource))
            {
                if (TryResolveRepairedMaterializedSpawnFrame(
                    mission,
                    team,
                    formationClass,
                    isReinforcement,
                    out spawnPosition,
                    out spawnDirection,
                    out string repairedSpawnDiagnostics))
                {
                    spawnFrameSource = isReinforcement ? "formation-reinforcement-repaired" : "formation-repaired";
                    return;
                }

                ModLogger.Info(
                    "CoopMissionSpawnLogic: repaired deployment plan did not yield a safe materialized spawn frame for " +
                    troop.StringId +
                    ": " + (repairedSpawnDiagnostics ?? "unknown"));
            }

            try
            {
                var spawnFrameBehavior = new FFASpawnFrameBehavior();
                spawnFrameBehavior.Initialize();
                bool hasMount = formationClass == FormationClass.Cavalry || formationClass == FormationClass.HorseArcher;
                MatrixFrame spawnFrame = spawnFrameBehavior.GetSpawnFrame(team, hasMount: hasMount, isInitialSpawn: !isReinforcement);
                if (spawnFrame.origin != Vec3.Zero)
                {
                    spawnPosition = spawnFrame.origin;
                    Vec2 frameDirection = spawnFrame.rotation.f.AsVec2;
                    if (frameDirection.LengthSquared > 0.001f)
                    {
                        spawnDirection = frameDirection.Normalized();
                    }

                    spawnFrameSource = isReinforcement ? "ffa-scene-reinforcement" : "ffa-scene";
                    return;
                }
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: FFASpawnFrameBehavior materialized spawn fallback failed for " + troop.StringId + ": " + ex.Message);
            }

            GetDirectSpawnFrame(mission, team, out Vec3 fallbackSpawnPosition, out Vec2 fallbackSpawnDirection);
            spawnPosition = fallbackSpawnPosition;
            if (fallbackSpawnDirection.LengthSquared > 0.001f)
                spawnDirection = fallbackSpawnDirection;
        }

        private static bool TryResolveRepairedMaterializedSpawnFrame(
            Mission mission,
            Team team,
            FormationClass formationClass,
            bool isReinforcement,
            out Vec3 spawnPosition,
            out Vec2 spawnDirection,
            out string diagnostics)
        {
            spawnPosition = new Vec3(0f, 0f, 0f);
            spawnDirection = Vec2.Invalid;
            diagnostics = null;

            if (mission == null || team == null)
            {
                diagnostics = "mission-or-team-missing";
                return false;
            }

            if (!mission.GetDeploymentPlan<DefaultMissionDeploymentPlan>(out DefaultMissionDeploymentPlan deploymentPlan) || deploymentPlan == null)
            {
                diagnostics = "deployment-plan-missing";
                return false;
            }

            IFormationDeploymentPlan formationPlan;
            try
            {
                formationPlan = deploymentPlan.GetFormationPlan(team, formationClass, isReinforcement);
            }
            catch (Exception ex)
            {
                diagnostics = "get-formation-plan-failed:" + ex.Message;
                return false;
            }

            if (formationPlan == null)
            {
                diagnostics = "formation-plan-null";
                return false;
            }

            bool hasFrame;
            try
            {
                hasFrame = formationPlan.HasFrame();
            }
            catch (Exception ex)
            {
                diagnostics = "has-frame-failed:" + ex.Message;
                return false;
            }

            if (!hasFrame)
            {
                BattleMapContractDiagnostics.LogDeploymentPlanContract(
                    mission,
                    team,
                    formationClass,
                    isReinforcement,
                    "repaired-frame-missing");
                diagnostics =
                    "formation-plan-has-no-frame" +
                    " PlannedTroopCount=" + formationPlan.PlannedTroopCount +
                    " HasDimensions=" + formationPlan.HasDimensions;
                return false;
            }

            try
            {
                MatrixFrame frame = formationPlan.GetFrame();
                BattleMapContractDiagnostics.LogDeploymentPlanContract(
                    mission,
                    team,
                    formationClass,
                    isReinforcement,
                    "repaired-frame-success");
                spawnPosition = frame.origin;

                Vec2 direction = formationPlan.GetDirection();
                if (direction.LengthSquared <= 0.001f)
                    direction = frame.rotation.f.AsVec2;

                spawnDirection = direction.LengthSquared > 0.001f
                    ? direction.Normalized()
                    : (team.Side == BattleSideEnum.Attacker ? new Vec2(1f, 0f) : new Vec2(-1f, 0f));

                diagnostics =
                    "frame-ok" +
                    " PlannedTroopCount=" + formationPlan.PlannedTroopCount +
                    " HasDimensions=" + formationPlan.HasDimensions;
                return true;
            }
            catch (Exception ex)
            {
                diagnostics = "extract-frame-failed:" + ex.Message;
                return false;
            }
        }

        private static Agent SpawnBattlefieldArmyAgent(
            Mission mission,
            Team team,
            BasicCharacterObject troop,
            RosterEntryState entryState,
            FormationClass formationClass,
            Vec3 spawnPosition,
            Vec2 direction,
            out string appliedArmorOverrides,
            out string appliedCombatProfile,
            out string appliedIdentity)
        {
            appliedArmorOverrides = "(none)";
            appliedCombatProfile = "AppliedCombatProfile=(none)";
            appliedIdentity = "AppliedIdentity=(none)";
            if (mission == null || team == null || troop == null)
                return null;

            try
            {
                var origin = new BasicBattleAgentOrigin(troop);
                AgentBuildData buildData = new AgentBuildData(troop);
                Equipment snapshotEquipment = BuildSnapshotEquipmentForExactRuntime(entryState);
                Equipment spawnEquipment = snapshotEquipment ?? troop.Equipment?.Clone(false);
                string spawnEquipmentSource = snapshotEquipment != null ? "exact-snapshot" : "troop-clone";
                appliedArmorOverrides = TryApplyMaterializedEquipmentOverrides(spawnEquipment, entryState, null, trackCoverage: true);
                TextObject originalTroopName = null;
                bool hasTemporaryNameOverride =
                    TryApplyEntryNameToSpawnCharacter(troop, entryState, out originalTroopName);
                try
                {
                    buildData.Team(team);
                    buildData.Controller(AgentControllerType.AI);
                    buildData.TroopOrigin(origin);
                    buildData.InitialPosition(in spawnPosition);
                    buildData.InitialDirection(in direction);
                    buildData.SpawnsIntoOwnFormation(true);
                    buildData.SpawnsUsingOwnTroopClass(true);
                    if (spawnEquipment != null)
                        buildData.Equipment(spawnEquipment);

                    appliedIdentity = TryApplyEntryIdentityToBuildData(buildData, entryState);
                    Agent agent = mission.SpawnAgent(buildData, spawnFromAgentVisuals: false);
                    if (agent != null)
                    {
                        TryApplyEntryIdentityToAgent(agent, entryState);

                        FormationClass resolvedFormationClass = formationClass;
                        if ((int)resolvedFormationClass < 0 || (int)resolvedFormationClass >= team.FormationsIncludingSpecialAndEmpty.Count())
                            resolvedFormationClass = FormationClass.Infantry;

                        Formation targetFormation = team.GetFormation(resolvedFormationClass);
                        if (targetFormation != null && !ReferenceEquals(agent.Formation, targetFormation))
                        {
                            agent.Formation = targetFormation;
                            agent.ForceUpdateCachedAndFormationValues(updateOnlyMovement: false, arrangementChangeAllowed: false);
                        }

                        agent.SetAutomaticTargetSelection(true);
                        agent.SetFiringOrder(FiringOrder.RangedWeaponUsageOrderEnum.FireAtWill);
                        appliedCombatProfile = TryApplyMaterializedCombatProfile(agent, entryState);
                        TraceMaterializedBattlefieldAgentSpawn(
                            agent,
                            team,
                            troop,
                            entryState,
                            formationClass,
                            spawnPosition,
                            direction,
                            spawnEquipment,
                            spawnEquipmentSource,
                            appliedArmorOverrides,
                            appliedCombatProfile,
                            appliedIdentity,
                            "SpawnBattlefieldArmyAgent");
                    }
                    else
                    {
                        TraceMaterializedEntryContractDecision(
                            "materialized-spawn-null",
                            entryState,
                            entryState?.SpawnTemplateId,
                            GetExactEntryCompatibilityDiagnostic(entryState),
                            "Mission.SpawnAgent returned null",
                            "SpawnBattlefieldArmyAgent");
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: SpawnBattlefieldArmyAgent returned null. " +
                            "TroopId=" + troop.StringId +
                            " TeamSide=" + team.Side +
                            " TeamIndex=" + team.TeamIndex);
                    }

                    return agent;
                }
                finally
                {
                    RestoreSpawnCharacterName(troop, hasTemporaryNameOverride, originalTroopName);
                }
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: SpawnBattlefieldArmyAgent failed. " +
                    "TroopId=" + (troop?.StringId ?? "null") +
                    " EntryId=" + (entryState?.EntryId ?? "null") +
                    " TeamSide=" + team?.Side +
                    " TeamIndex=" + (team != null ? team.TeamIndex.ToString() : "null") +
                    " FormationClass=" + formationClass +
                    " SpawnPosition=" + spawnPosition +
                    " Direction=" + direction +
                    " Message=" + ex.Message);
                return null;
            }
        }

        private static string TryApplyEntryIdentityToBuildData(AgentBuildData buildData, RosterEntryState entryState)
        {
            if (buildData == null || !HasEntryHeroIdentity(entryState))
                return "AppliedIdentity=(none)";

            var parts = new List<string>();
            try
            {
                buildData.IsFemale(entryState.HeroIsFemale);
                parts.Add("Female=" + entryState.HeroIsFemale);
            }
            catch (Exception ex)
            {
                parts.Add("FemaleApplyFailed=" + ex.GetType().Name);
            }

            if (entryState.HeroAge > 0.01f)
            {
                try
                {
                    int roundedAge = Math.Max(1, Math.Min(120, (int)Math.Round(entryState.HeroAge)));
                    buildData.Age(roundedAge);
                    parts.Add("Age=" + entryState.HeroAge.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture));
                }
                catch (Exception ex)
                {
                    parts.Add("AgeApplyFailed=" + ex.GetType().Name);
                }
            }

            if (TryResolveEntryBodyProperties(entryState, out BodyProperties bodyProperties))
            {
                try
                {
                    buildData.BodyProperties(bodyProperties);
                    parts.Add("Body=applied");
                }
                catch (Exception ex)
                {
                    parts.Add("BodyApplyFailed=" + ex.GetType().Name);
                }
            }

            if (!string.IsNullOrWhiteSpace(entryState.TroopName))
                parts.Add("Name=" + entryState.TroopName.Replace('\r', ' ').Replace('\n', ' '));

            return parts.Count == 0
                ? "AppliedIdentity=(none)"
                : "AppliedIdentity=" + string.Join(", ", parts);
        }

        internal static void TryApplyEntryIdentityToAgent(Agent agent, RosterEntryState entryState)
        {
            if (agent == null || entryState == null)
                return;

            if (HasEntryHeroIdentity(entryState))
            {
                try
                {
                    agent.IsFemale = entryState.HeroIsFemale;
                }
                catch
                {
                }

                if (entryState.HeroAge > 0.01f)
                {
                    try
                    {
                        agent.Age = entryState.HeroAge;
                    }
                    catch
                    {
                    }
                }

                if (TryResolveEntryBodyProperties(entryState, out BodyProperties bodyProperties))
                {
                    try
                    {
                        agent.UpdateBodyProperties(bodyProperties);
                    }
                    catch
                    {
                    }
                }
            }

            if (string.IsNullOrWhiteSpace(entryState.TroopName))
                return;

            try
            {
                FieldInfo agentNameField = typeof(Agent).GetField("_name", BindingFlags.Instance | BindingFlags.NonPublic);
                if (agentNameField != null)
                    agentNameField.SetValue(agent, new TextObject(entryState.TroopName));
            }
            catch
            {
            }
        }

        internal static bool TryApplyEntryNameToSpawnCharacter(BasicCharacterObject troop, RosterEntryState entryState, out TextObject originalName)
        {
            originalName = null;
            if (troop == null || !HasEntryHeroIdentity(entryState) || string.IsNullOrWhiteSpace(entryState.TroopName))
                return false;

            string currentName = troop.Name?.ToString() ?? string.Empty;
            if (string.Equals(currentName, entryState.TroopName, StringComparison.Ordinal))
                return false;

            try
            {
                originalName = new TextObject(string.IsNullOrWhiteSpace(currentName) ? troop.StringId ?? string.Empty : currentName);
                if (!TrySetCharacterName(troop, new TextObject(entryState.TroopName)))
                    return false;
                return true;
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: failed to apply temporary spawn-character name override. " +
                    "TroopId=" + troop.StringId +
                    " EntryId=" + (entryState?.EntryId ?? "null") +
                    " Name=" + (entryState?.TroopName ?? string.Empty).Replace('\r', ' ').Replace('\n', ' ') +
                    " Message=" + ex.Message);
                return false;
            }
        }

        internal static void RestoreSpawnCharacterName(BasicCharacterObject troop, bool restore, TextObject originalName)
        {
            if (!restore || troop == null || originalName == null)
                return;

            try
            {
                TrySetCharacterName(troop, originalName);
            }
            catch
            {
            }
        }

        private static bool TrySetCharacterName(BasicCharacterObject troop, TextObject name)
        {
            if (troop == null || name == null)
                return false;

            try
            {
                MethodInfo setNameMethod = troop.GetType().GetMethod(
                    "SetName",
                    BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic,
                    null,
                    new[] { typeof(TextObject) },
                    null);
                if (setNameMethod == null)
                    return false;

                setNameMethod.Invoke(troop, new object[] { name });
                return true;
            }
            catch
            {
                return false;
            }
        }

        private static bool HasEntryHeroIdentity(RosterEntryState entryState)
        {
            return entryState != null &&
                   (entryState.IsHero ||
                    !string.IsNullOrWhiteSpace(entryState.HeroId) ||
                    !string.IsNullOrWhiteSpace(entryState.HeroRole) ||
                    !string.IsNullOrWhiteSpace(entryState.HeroTemplateId) ||
                    !string.IsNullOrWhiteSpace(entryState.HeroBodyProperties));
        }

        private static bool TryResolveEntryBodyProperties(RosterEntryState entryState, out BodyProperties bodyProperties)
        {
            bodyProperties = default;
            if (string.IsNullOrWhiteSpace(entryState?.HeroBodyProperties))
                return false;

            try
            {
                return BodyProperties.FromString(entryState.HeroBodyProperties, out bodyProperties);
            }
            catch
            {
                return false;
            }
        }

        private static string TryApplyMaterializedCombatProfile(Agent agent, RosterEntryState entryState)
        {
            if (agent == null || entryState == null)
                return "AppliedCombatProfile=(none)";

            RegisterMaterializedCombatProfile(agent, entryState);
            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            BattlePartyState partyState = null;
            if (runtimeState?.PartiesById != null && !string.IsNullOrWhiteSpace(entryState.PartyId))
                runtimeState.PartiesById.TryGetValue(entryState.PartyId, out partyState);

            var parts = new List<string>();
            if (entryState.BaseHitPoints > 0)
            {
                float targetHitPoints = Math.Max(1f, entryState.BaseHitPoints);
                try
                {
                    agent.HealthLimit = targetHitPoints;
                    agent.Health = targetHitPoints;
                    parts.Add("Hp=" + targetHitPoints.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture));
                }
                catch (Exception ex)
                {
                    parts.Add("HpApplyFailed=" + ex.GetType().Name);
                }
            }

            Agent mountAgent = agent.MountAgent;
            if (mountAgent != null && mountAgent.IsActive())
            {
                try
                {
                    float targetMountHitPoints = Math.Max(1f, mountAgent.HealthLimit);
                    mountAgent.Health = targetMountHitPoints;
                    parts.Add("MountHp=" + targetMountHitPoints.ToString("0.##", System.Globalization.CultureInfo.InvariantCulture));
                }
                catch (Exception ex)
                {
                    parts.Add("MountHpApplyFailed=" + ex.GetType().Name);
                }
            }

            if (IsHeroEntryEligibleForExactPersonalPerks(entryState))
            {
                if (TryApplyExactCampaignMissionEquipmentPerks(agent, entryState, partyState, out string equipmentSummary))
                    parts.Add(equipmentSummary);
                if (TryApplyExactCampaignHeroFlags(agent, entryState, out string flagSummary))
                    parts.Add(flagSummary);
            }

            return parts.Count == 0
                ? "AppliedCombatProfile=(none)"
                : "AppliedCombatProfile=" + string.Join(", ", parts);
        }

        private static bool TryApplyExactCampaignMissionEquipmentPerks(
            Agent agent,
            RosterEntryState entryState,
            BattlePartyState partyState,
            out string summary)
        {
            summary = null;
            if (agent == null || entryState == null || !agent.IsHuman || !IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return false;

            MissionEquipment equipment = agent.Equipment;
            if (equipment == null)
                return false;

            IEnumerable<string> personalPerkIds = entryState.PerkIds ?? Enumerable.Empty<string>();
            IEnumerable<string> partyLeaderPerkIds = partyState?.Modifiers?.PartyLeaderPerkIds ?? Enumerable.Empty<string>();
            bool isMounted = agent.HasMount || agent.MountAgent != null;
            var changes = new List<string>();

            for (EquipmentIndex index = EquipmentIndex.Weapon0; index <= EquipmentIndex.Weapon3; index++)
            {
                MissionWeapon missionWeapon = equipment[index];
                ItemObject item = missionWeapon.Item;
                WeaponComponentData currentUsageItem = missionWeapon.CurrentUsageItem;
                if (item == null || currentUsageItem == null)
                    continue;

                if (currentUsageItem.IsConsumable && currentUsageItem.RelevantSkill != null)
                {
                    float ammoBonus = 0f;
                    if (currentUsageItem.RelevantSkill == DefaultSkills.Bow)
                    {
                        if (HasPerkId(personalPerkIds, "BowDeepQuivers"))
                            ammoBonus += 3f;
                        if (HasPerkId(partyLeaderPerkIds, "BowDeepQuivers"))
                            ammoBonus += 1f;
                    }
                    else if (currentUsageItem.RelevantSkill == DefaultSkills.Crossbow)
                    {
                        if (HasPerkId(personalPerkIds, "CrossbowFletcher"))
                            ammoBonus += 4f;
                        if (HasPerkId(partyLeaderPerkIds, "CrossbowFletcher"))
                            ammoBonus += 2f;
                    }
                    else if (currentUsageItem.RelevantSkill == DefaultSkills.Throwing)
                    {
                        if (HasPerkId(personalPerkIds, "ThrowingWellPrepared"))
                            ammoBonus += 1f;
                        if (HasPerkId(personalPerkIds, "ThrowingResourceful"))
                            ammoBonus += 2f;
                        if (isMounted && HasPerkId(personalPerkIds, "ThrowingSaddlebags"))
                            ammoBonus += 2f;
                        if (HasPerkId(partyLeaderPerkIds, "ThrowingWellPrepared"))
                            ammoBonus += 1f;
                    }

                    int currentAmount = missionWeapon.Amount;
                    int roundedAmmoBonus = Math.Max(0, MathF.Round(ammoBonus));
                    int? snapshotBaseAmount = GetSnapshotCombatItemBaseAmount(entryState, index, item.StringId);
                    int targetAmount = snapshotBaseAmount.HasValue && snapshotBaseAmount.Value > 0
                        ? Math.Max(0, snapshotBaseAmount.Value + roundedAmmoBonus)
                        : Math.Max(0, currentAmount + roundedAmmoBonus);
                    if (targetAmount != currentAmount)
                    {
                        if (GameNetwork.IsServerOrRecorder)
                        {
                            agent.SetWeaponAmountInSlot(index, (short)targetAmount, enforcePrimaryItem: true);
                        }
                        else
                        {
                            equipment.SetAmountOfSlot(index, (short)targetAmount, true);
                        }
                        changes.Add(
                            snapshotBaseAmount.HasValue && snapshotBaseAmount.Value > 0
                                ? index + "Ammo=" + currentAmount + "->" + targetAmount + "(base:" + snapshotBaseAmount.Value + ",+" + roundedAmmoBonus + ")"
                                : index + "Ammo=" + currentAmount + "->" + targetAmount + "(" + (roundedAmmoBonus >= 0 ? "+" : string.Empty) + roundedAmmoBonus + ")");
                    }
                }
                else if (currentUsageItem.IsShield)
                {
                    int currentHitPoints = missionWeapon.HitPoints;
                    float targetHitPointsValue = currentHitPoints;
                    if (HasPerkId(personalPerkIds, "EngineeringScaffolds"))
                        targetHitPointsValue *= 1.3f;
                    int targetHitPoints = Math.Max(1, MathF.Round(targetHitPointsValue));
                    if (targetHitPoints != currentHitPoints)
                    {
                        equipment.SetHitPointsOfSlot(index, (short)targetHitPoints, true);
                        int delta = targetHitPoints - currentHitPoints;
                        changes.Add(index + "Shield=" + (delta >= 0 ? "+" : string.Empty) + delta);
                    }
                }
            }

            if (changes.Count == 0)
                return false;

            try
            {
                agent.UpdateWeapons();
            }
            catch (Exception ex)
            {
                changes.Add("WeaponRefreshFailed=" + ex.GetType().Name);
            }

            summary = "ExactPerks=" + string.Join("/", changes);
            return true;
        }

        private static int? GetSnapshotCombatItemBaseAmount(
            RosterEntryState entryState,
            EquipmentIndex index,
            string currentItemId = null)
        {
            if (entryState == null)
                return null;

            if (!string.IsNullOrWhiteSpace(currentItemId))
            {
                string directItemId = GetSnapshotCombatItemId(entryState, index);
                int? directAmount = GetSnapshotCombatItemBaseAmountByIndex(entryState, index);
                if (string.Equals(directItemId, currentItemId, StringComparison.OrdinalIgnoreCase))
                    return directAmount;

                int? matchedAmount = GetSnapshotCombatItemBaseAmountByItemId(entryState, currentItemId);
                if (matchedAmount.HasValue)
                    return matchedAmount;
            }

            return GetSnapshotCombatItemBaseAmountByIndex(entryState, index);
        }

        private static int? GetSnapshotCombatItemBaseAmountByIndex(RosterEntryState entryState, EquipmentIndex index)
        {
            if (entryState == null)
                return null;

            switch (index)
            {
                case EquipmentIndex.Weapon0:
                    return entryState.CombatItem0Amount;
                case EquipmentIndex.Weapon1:
                    return entryState.CombatItem1Amount;
                case EquipmentIndex.Weapon2:
                    return entryState.CombatItem2Amount;
                case EquipmentIndex.Weapon3:
                    return entryState.CombatItem3Amount;
                default:
                    return null;
            }
        }

        private static string GetSnapshotCombatItemId(RosterEntryState entryState, EquipmentIndex index)
        {
            if (entryState == null)
                return null;

            switch (index)
            {
                case EquipmentIndex.Weapon0:
                    return entryState.CombatItem0Id;
                case EquipmentIndex.Weapon1:
                    return entryState.CombatItem1Id;
                case EquipmentIndex.Weapon2:
                    return entryState.CombatItem2Id;
                case EquipmentIndex.Weapon3:
                    return entryState.CombatItem3Id;
                default:
                    return null;
            }
        }

        private static int? GetSnapshotCombatItemBaseAmountByItemId(RosterEntryState entryState, string itemId)
        {
            if (entryState == null || string.IsNullOrWhiteSpace(itemId))
                return null;

            if (string.Equals(entryState.CombatItem0Id, itemId, StringComparison.OrdinalIgnoreCase))
                return entryState.CombatItem0Amount;
            if (string.Equals(entryState.CombatItem1Id, itemId, StringComparison.OrdinalIgnoreCase))
                return entryState.CombatItem1Amount;
            if (string.Equals(entryState.CombatItem2Id, itemId, StringComparison.OrdinalIgnoreCase))
                return entryState.CombatItem2Amount;
            if (string.Equals(entryState.CombatItem3Id, itemId, StringComparison.OrdinalIgnoreCase))
                return entryState.CombatItem3Amount;

            return null;
        }

        private static bool TryApplyExactCampaignHeroFlags(Agent agent, RosterEntryState entryState, out string summary)
        {
            summary = null;
            if (agent == null || entryState?.PerkIds == null || entryState.PerkIds.Count == 0 || !agent.IsHuman || !IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return false;

            int desiredFlagBits = 0;
            if (HasPerkId(entryState.PerkIds, "BowHorseMaster"))
                desiredFlagBits |= AgentFlagHorseMasterBit;
            if (HasPerkId(entryState.PerkIds, "CrossbowMountedCrossbowman"))
                desiredFlagBits |= AgentFlagMountedCrossbowmanBit;
            if (HasPerkId(entryState.PerkIds, "TwoHandedProjectileDeflection"))
                desiredFlagBits |= AgentFlagProjectileDeflectionBit;

            if (desiredFlagBits == 0)
                return false;

            AgentFlag currentFlags = agent.GetAgentFlags();
            int currentFlagBits = (int)currentFlags;
            int updatedFlagBits = currentFlagBits | desiredFlagBits;
            if (updatedFlagBits == currentFlagBits)
                return false;

            agent.SetAgentFlags((AgentFlag)updatedFlagBits);

            var appliedFlags = new List<string>();
            if ((desiredFlagBits & AgentFlagHorseMasterBit) != 0 && (currentFlagBits & AgentFlagHorseMasterBit) == 0)
                appliedFlags.Add("HorseMaster");
            if ((desiredFlagBits & AgentFlagMountedCrossbowmanBit) != 0 && (currentFlagBits & AgentFlagMountedCrossbowmanBit) == 0)
                appliedFlags.Add("MountedCrossbowman");
            if ((desiredFlagBits & AgentFlagProjectileDeflectionBit) != 0 && (currentFlagBits & AgentFlagProjectileDeflectionBit) == 0)
                appliedFlags.Add("ProjectileDeflection");

            if (appliedFlags.Count == 0)
                return false;

            summary = "HeroFlags=" + string.Join("/", appliedFlags);
            return true;
        }

        private static bool IsHeroEntryEligibleForExactPersonalPerks(RosterEntryState entryState)
        {
            return HasEntryExactPersonalPerkHeroIdentity(entryState);
        }

        private static bool IsHeroProfileEligibleForExactPersonalPerks(MaterializedCombatProfileRuntimeState profile)
        {
            return profile != null &&
                   (profile.IsHero ||
                   string.Equals(profile.OriginalCharacterId, "main_hero", StringComparison.OrdinalIgnoreCase));
        }

        private static bool HasEntryExactPersonalPerkHeroIdentity(RosterEntryState entryState)
        {
            return entryState != null &&
                   (entryState.IsHero ||
                    !string.IsNullOrWhiteSpace(entryState.HeroId) ||
                    string.Equals(entryState.OriginalCharacterId, "main_hero", StringComparison.OrdinalIgnoreCase));
        }

        private static bool HasPerkId(IEnumerable<string> perkIds, string perkId)
        {
            if (perkIds == null || string.IsNullOrWhiteSpace(perkId))
                return false;

            foreach (string candidate in perkIds)
            {
                if (string.Equals(candidate, perkId, StringComparison.OrdinalIgnoreCase))
                    return true;
            }

            return false;
        }

        private static void ResetMaterializedCombatProfileRuntimeState()
        {
            _materializedCombatProfilesByAgentIndex.Clear();
            MaterializedCombatProfileApplyCounts.Clear();
            _lastMaterializedCombatProfileMission = null;
            _lastCombatProfileDrivenRefreshMission = null;
            _lastCombatProfileDrivenRefreshMissionTime = -1f;
            _hasLoggedManualCombatProfileRefreshForMission = false;
        }

        private static void ResetMaterializedBattleResultRuntimeState()
        {
            _materializedBattleResultEntriesByEntryId.Clear();
            _materializedBattleResultInstancesByInstanceId.Clear();
            _materializedBattleResultRemovedAgentIndices.Clear();
            _materializedBattleResultLastHitDebugByVictimAgentIndex.Clear();
            _materializedBattleResultCombatEvents.Clear();
            _materializedCanonicalInstanceIdByAgentIndex.Clear();
            _materializedBattleResultRawOnScoreHitCount = 0;
            _materializedBattleResultRawOnAgentRemovedCount = 0;
            _materializedBattleResultOnScoreHitCount = 0;
            _materializedBattleResultOnAgentRemovedCount = 0;
            _materializedBattleResultRemovalDebugLogCount = 0;
            _materializedBattleResultOnScoreHitSamples.Clear();
            _materializedBattleResultOnAgentRemovedSamples.Clear();
            _materializedBattleResultReconcileRemovedSamples.Clear();
