        private static void LogExactEntryCompatibilityDiagnostic(
            ExactEntryCompatibilityDiagnostic diagnostic,
            string source)
        {
            if (diagnostic == null)
                return;

            EnsureExactEntryCompatibilityCacheCurrent();

            string logKey =
                (_exactEntryCompatibilityCacheKey ?? string.Empty) + "|" +
                (diagnostic.EntryId ?? "null") + "|" +
                (source ?? "unknown") + "|" +
                (diagnostic.Status ?? "unknown");
            if (!_loggedExactEntryCompatibilityKeys.Add(logKey))
                return;

            ModLogger.Info(
                "CoopMissionSpawnLogic: exact entry compatibility. " +
                "Source=" + (source ?? "unknown") +
                " " + BuildExactEntryCompatibilityReportLine(diagnostic));
        }

        private static bool IsStrictExactEntryContractSupported(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return false;

            return string.Equals(diagnostic.Status, "exact-supported", StringComparison.Ordinal);
        }

        private static bool IsExactWeaponContractSupported(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null ||
                diagnostic.ResolvedCharacter == null ||
                !diagnostic.ExactEquipmentBuilt ||
                (diagnostic.UsesMissionSafeCharacterFallback &&
                 !CanTreatMissionSafeCharacterFallbackAsExactForCurrentRuntime(diagnostic)) ||
                diagnostic.MountedEntryMissingHorse ||
                string.IsNullOrWhiteSpace(diagnostic.HeroClassId) ||
                diagnostic.UsesSurrogateMpHeroClass ||
                diagnostic.HasWeaponFallback ||
                diagnostic.HasWeaponMisses ||
                diagnostic.HasWeapon2WieldReplicationRisk)
            {
                return false;
            }

            return true;
        }

        private static bool IsExactVisualContractSupported(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null ||
                diagnostic.ResolvedCharacter == null ||
                !diagnostic.ExactEquipmentBuilt ||
                (diagnostic.UsesMissionSafeCharacterFallback &&
                 !CanTreatMissionSafeCharacterFallbackAsExactForCurrentRuntime(diagnostic)) ||
                diagnostic.MountedEntryMissingHorse ||
                string.IsNullOrWhiteSpace(diagnostic.HeroClassId) ||
                diagnostic.UsesSurrogateMpHeroClass ||
                diagnostic.HasVisualFallback ||
                diagnostic.HasVisualMisses ||
                diagnostic.HasMountFallback ||
                diagnostic.HasMountMisses)
            {
                return false;
            }

            return true;
        }

        private static bool IsMaterializedExactEntryCharacterSupported(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return false;

            return IsExactWeaponContractSupported(diagnostic) &&
                   (diagnostic.CurrentRuntimePreSpawnIncludesWeapons ||
                    UseDedicatedSafeStringIdExactEquipmentPathForCurrentRuntime());
        }

        private static bool IsServerAuthoritativeNativeExactOverlaySupported(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            return IsMaterializedExactEntryCharacterSupported(diagnostic);
        }

        private static string BuildExactEntryContractRejectionReason(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return "exact entry contract unresolved";

            string warning = diagnostic.Warnings.Count > 0 ? diagnostic.Warnings[0] : "unknown exact-entry incompatibility";
            return
                "exact entry contract " + (diagnostic.Status ?? "unknown") +
                " for entry '" + (diagnostic.EntryId ?? "null") + "': " + warning;
        }

        private static string BuildExactWeaponContractRejectionReason(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return "exact weapon contract unresolved";

            if (diagnostic.UsesMissionSafeCharacterFallback)
            {
                return
                    "exact weapon contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because character resolution fell back to mission-safe character '" +
                    (diagnostic.MissionSafeFallbackCharacterId ?? "null") + "'";
            }

            if (diagnostic.HasWeaponMisses)
            {
                return
                    "exact weapon contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because one or more weapon slots did not resolve";
            }

            if (diagnostic.HasWeaponFallback)
            {
                return
                    "exact weapon contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because one or more weapon slots use substitution ids";
            }

            if (diagnostic.HasWeapon2WieldReplicationRisk)
            {
                return
                    "exact weapon contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because the exact loadout still carries a Weapon2 wield replication risk";
            }

            if (string.IsNullOrWhiteSpace(diagnostic.HeroClassId))
            {
                return
                    "exact weapon contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because no multiplayer hero-class bridge resolved";
            }

            if (diagnostic.UsesSurrogateMpHeroClass)
            {
                return
                    "exact weapon contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because it still depends on surrogate MPHeroClass '" +
                    (diagnostic.HeroClassId ?? "null") + "'";
            }

            return BuildExactEntryContractRejectionReason(diagnostic);
        }

        private static string BuildExactVisualContractRejectionReason(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return "exact visual contract unresolved";

            if (diagnostic.UsesMissionSafeCharacterFallback)
            {
                return
                    "exact visual contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because character resolution fell back to mission-safe character '" +
                    (diagnostic.MissionSafeFallbackCharacterId ?? "null") + "'";
            }

            if (diagnostic.HasVisualMisses || diagnostic.HasMountMisses)
            {
                return
                    "exact visual contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because one or more visual or mount slots did not resolve";
            }

            if (diagnostic.HasVisualFallback || diagnostic.HasMountFallback)
            {
                return
                    "exact visual contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because one or more visual or mount slots use substitution ids";
            }

            if (string.IsNullOrWhiteSpace(diagnostic.HeroClassId))
            {
                return
                    "exact visual contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because no multiplayer hero-class bridge resolved";
            }

            if (diagnostic.UsesSurrogateMpHeroClass)
            {
                return
                    "exact visual contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' is degraded because it still depends on surrogate MPHeroClass '" +
                    (diagnostic.HeroClassId ?? "null") + "'";
            }

            return BuildExactEntryContractRejectionReason(diagnostic);
        }

        private static string BuildMaterializedExactEntryContractRejectionReason(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return "materialized exact entry contract unresolved";

            if (!IsExactWeaponContractSupported(diagnostic) || !diagnostic.CurrentRuntimePreSpawnIncludesWeapons)
            {
                if (UseDedicatedSafeStringIdExactEquipmentPathForCurrentRuntime() &&
                    IsExactWeaponContractSupported(diagnostic))
                {
                    return
                        "materialized exact entry contract for entry '" + (diagnostic.EntryId ?? "null") +
                        "' applies exact weapons post-create by StringId because native pre-spawn item ids are unsafe on the current runtime";
                }

                return
                    "materialized exact entry contract for entry '" + (diagnostic.EntryId ?? "null") +
                    "' falls back to native template spawn equipment because " +
                    BuildExactWeaponContractRejectionReason(diagnostic);
            }

            return BuildExactEntryContractRejectionReason(diagnostic);
        }

        private static string BuildServerAuthoritativeNativeExactOverlayRejectionReason(ExactEntryCompatibilityDiagnostic diagnostic)
        {
            if (diagnostic == null)
                return "server-authoritative native exact overlay contract unresolved";

            if (!IsExactWeaponContractSupported(diagnostic) || !diagnostic.CurrentRuntimePreSpawnIncludesWeapons)
            {
                if (UseDedicatedSafeStringIdExactEquipmentPathForCurrentRuntime() &&
                    IsExactWeaponContractSupported(diagnostic))
                {
                    return
                        "server-authoritative native exact overlay for entry '" + (diagnostic.EntryId ?? "null") +
                        "' keeps native CreateAgent baseline and reapplies exact weapons post-create by StringId";
                }

                return
                    "server-authoritative native exact overlay for entry '" + (diagnostic.EntryId ?? "null") +
                    "' keeps native template spawn equipment because " +
                    BuildExactWeaponContractRejectionReason(diagnostic);
            }

            return BuildExactEntryContractRejectionReason(diagnostic);
        }

        private static string BuildHeroEquipmentResolutionAuditForSlot(
            RosterEntryState entryState,
            string slotLabel,
            string itemId)
        {
            if (string.IsNullOrWhiteSpace(itemId))
                return (slotLabel ?? "slot") + "=(none)";

            string normalizedItemId = null;
            bool normalizedCandidate =
                TryNormalizeCampaignEquipmentToMpItemId(itemId, entryState, slotLabel, out normalizedItemId) &&
                !string.IsNullOrWhiteSpace(normalizedItemId);
            string aliasItemId =
                ExactEquipmentCompatibilityCatalog.TryGetAliasItemId(itemId, out string aliasCandidate) &&
                !string.IsNullOrWhiteSpace(aliasCandidate)
                    ? aliasCandidate
                    : null;
            string standInItemId =
                ExactEquipmentCompatibilityStandInItemIds.TryGetValue(itemId, out string standInCandidate) &&
                !string.IsNullOrWhiteSpace(standInCandidate)
                    ? standInCandidate
                    : null;
            string mpPrefixedItemId = itemId.StartsWith("mp_", StringComparison.Ordinal)
                ? null
                : "mp_" + itemId;

            bool direct = TryGetMaterializedEquipmentItem(itemId) != null;
            bool alias = !string.IsNullOrWhiteSpace(aliasItemId) && TryGetMaterializedEquipmentItem(aliasItemId) != null;
            bool standIn = !string.IsNullOrWhiteSpace(standInItemId) && TryGetMaterializedEquipmentItem(standInItemId) != null;
            bool mpPrefix = !string.IsNullOrWhiteSpace(mpPrefixedItemId) && TryGetMaterializedEquipmentItem(mpPrefixedItemId) != null;
            bool normalized = normalizedCandidate && TryGetMaterializedEquipmentItem(normalizedItemId) != null;

            string resolvedItemId;
            string resolutionSource;
            ItemObject resolvedItem = ResolveMaterializedEquipmentItem(
                itemId,
                entryState,
                slotLabel,
                out resolvedItemId,
                out resolutionSource,
                trackCoverage: false);

            return
                (slotLabel ?? "slot") + "=" + itemId +
                " -> " + (resolvedItem?.StringId ?? "unresolved") +
                "(via:" + (resolutionSource ?? "null") +
                ", direct=" + direct +
                ", alias=" + alias +
                ", standin=" + standIn +
                ", mpPrefix=" + mpPrefix +
                ", normalized=" + normalized +
                ", aliasId=" + (aliasItemId ?? "(none)") +
                ", standinId=" + (standInItemId ?? "(none)") +
                ", normalizedId=" + (normalizedItemId ?? "(none)") +
                ")";
        }

        private static void RecordMaterializedEquipmentResolution(string sourceItemId, string resolutionSource, bool trackCoverage)
        {
            if (!trackCoverage || string.IsNullOrWhiteSpace(resolutionSource))
                return;

            IncrementMaterializedEquipmentCounter(MaterializedEquipmentResolutionSourceCounts, resolutionSource);
            if (string.Equals(resolutionSource, "normalized", StringComparison.OrdinalIgnoreCase) &&
                !string.IsNullOrWhiteSpace(sourceItemId))
            {
                IncrementMaterializedEquipmentCounter(MaterializedEquipmentNormalizedFallbackCounts, sourceItemId);
            }
        }

        private static void RecordMaterializedEquipmentMiss(string sourceItemId, bool trackCoverage)
        {
            if (!trackCoverage)
                return;

            IncrementMaterializedEquipmentCounter(MaterializedEquipmentResolutionSourceCounts, "miss");
            if (!string.IsNullOrWhiteSpace(sourceItemId))
                IncrementMaterializedEquipmentCounter(MaterializedEquipmentMissCounts, sourceItemId);
        }

        private static void IncrementMaterializedEquipmentCounter(Dictionary<string, int> counters, string key)
        {
            if (counters == null || string.IsNullOrWhiteSpace(key))
                return;

            if (counters.TryGetValue(key, out int currentCount))
                counters[key] = currentCount + 1;
            else
                counters[key] = 1;
        }

        private static void LogMaterializedEquipmentCoverageSummaryIfNeeded()
        {
            if (_hasLoggedMaterializedEquipmentCoverageSummary)
                return;

            if (!IsSyntheticRuntime() && !HasLiveCombatProfileCoverageSignal())
                return;

            bool hasCoverageData =
                (MaterializedEquipmentResolutionSourceCounts != null && MaterializedEquipmentResolutionSourceCounts.Count > 0) ||
                (MaterializedEquipmentMissCounts != null && MaterializedEquipmentMissCounts.Count > 0) ||
                (MaterializedEquipmentNormalizedFallbackCounts != null && MaterializedEquipmentNormalizedFallbackCounts.Count > 0) ||
                (MaterializedCombatProfileApplyCounts != null && MaterializedCombatProfileApplyCounts.Count > 0);
            if (!hasCoverageData)
                return;

            _hasLoggedMaterializedEquipmentCoverageSummary = true;

            string resolutionCounts = FormatMaterializedEquipmentCounterSummary(MaterializedEquipmentResolutionSourceCounts, 8);
            string topMisses = FormatMaterializedEquipmentCounterSummary(MaterializedEquipmentMissCounts, 20);
            string topNormalizedFallbacks = FormatMaterializedEquipmentCounterSummary(MaterializedEquipmentNormalizedFallbackCounts, 20);
            string combatProfileCounts = FormatMaterializedEquipmentCounterSummary(MaterializedCombatProfileApplyCounts, 20);
            string modeLabel = IsSyntheticRuntime() ? "synthetic" : "live";

            ModLogger.Info(
                "CoopMissionSpawnLogic: " + modeLabel + " equipment coverage summary. " +
                "ResolutionCounts=[" + resolutionCounts + "] " +
                "CombatProfileCounts=[" + combatProfileCounts + "] " +
                "TopMisses=[" + topMisses + "] " +
                "TopNormalizedFallbacks=[" + topNormalizedFallbacks + "]");
        }

        private static bool HasLiveCombatProfileCoverageSignal()
        {
            if (MaterializedCombatProfileApplyCounts == null || MaterializedCombatProfileApplyCounts.Count == 0)
                return false;

            foreach (KeyValuePair<string, int> entry in MaterializedCombatProfileApplyCounts)
            {
                if (entry.Value <= 0 || string.IsNullOrWhiteSpace(entry.Key))
                    continue;

                if (!string.Equals(entry.Key, "registered", StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(entry.Key, "perks", StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(entry.Key, "mount", StringComparison.OrdinalIgnoreCase) &&
                    !string.Equals(entry.Key, "perk-mount", StringComparison.OrdinalIgnoreCase))
                {
                    return true;
                }
            }

            return false;
        }

        private static bool ShouldTreatCanonicalGeneratedTemplateAsFinalNativeSpawn(RosterEntryState entryState)
        {
            if (entryState == null ||
                entryState.IsHero ||
                !UseDedicatedSafeStringIdExactEquipmentPathForCurrentRuntime())
            {
                return false;
            }

            BattleSnapshotMessage snapshot = BattleSnapshotRuntimeState.GetCurrent();
            if (snapshot?.CanonicalBattle == null ||
                !string.Equals(
                    snapshot.CanonicalBattle.Context?.MultiplayerGameType,
                    "Battle",
                    StringComparison.OrdinalIgnoreCase))
            {
                return false;
            }

            if (entryState.ServerCreateContractResolved &&
                entryState.ServerCreateInjectEquipment &&
                entryState.ServerCreatePreSpawnIncludesWeapons)
            {
                return false;
            }

            return BattleSnapshotRuntimeState.UsesGeneratedRuntimeBattleTemplateMaterialization(entryState.EntryId);
        }

        private static bool TryRefreshCanonicalGeneratedTemplateFinalNativeSpawn(
            Agent agent,
            RosterEntryState entryState,
            string source,
            out string refreshSummary)
        {
            refreshSummary = "GeneratedNativeRefresh=not-applicable";
            if (agent == null ||
                entryState == null ||
                !GameNetwork.IsServer ||
                agent.IsMount)
            {
                return false;
            }

            BasicCharacterObject generatedCharacter = agent.Character as BasicCharacterObject;
            Equipment generatedBattleEquipment = null;
            Equipment snapshotBattleEquipment = null;
            try
            {
                generatedBattleEquipment =
                    generatedCharacter?.FirstBattleEquipment?.Clone(false) ??
                    generatedCharacter?.Equipment?.Clone(false);
                snapshotBattleEquipment = BuildSnapshotEquipmentForExactRuntime(entryState);
            }
            catch (Exception ex)
            {
                refreshSummary =
                    "GeneratedNativeRefresh=clone-failed:" + ex.GetType().Name +
                    " Character=" + (generatedCharacter?.StringId ?? "null");
                return false;
            }

            if (generatedBattleEquipment == null)
            {
                refreshSummary =
                    "GeneratedNativeRefresh=missing-battle-equipment Character=" +
                    (generatedCharacter?.StringId ?? "null");
                return false;
            }

            string beforeSpawnWeapons = BuildExactEntryEquipmentSummary(
                agent.SpawnEquipment,
                EquipmentIndex.Weapon0,
                EquipmentIndex.Weapon1,
                EquipmentIndex.Weapon2,
                EquipmentIndex.Weapon3);
            string beforeMissionWeapons = BuildMissionEquipmentSummary(
                agent.Equipment,
                EquipmentIndex.Weapon0,
                EquipmentIndex.Weapon1,
                EquipmentIndex.Weapon2,
                EquipmentIndex.Weapon3);
            if (HasExactCampaignPreSpawnLoadoutInjected(agent) &&
                DoesCurrentGeneratedTemplateNativeSpawnAlreadyMatchSnapshotWeapons(
                    agent,
                    snapshotBattleEquipment,
                    out string skipReason))
            {
                refreshSummary =
                    "GeneratedNativeRefresh=skipped " +
                    "RefreshEquipmentSource=none " +
                    "RefreshSelectionReason=" + (skipReason ?? "snapshot-already-materialized") +
                    " BeforeSpawnWeapons={" + beforeSpawnWeapons + "}" +
                    " BeforeMissionWeapons={" + beforeMissionWeapons + "}";
                return true;
            }

            Equipment refreshBattleEquipment = generatedBattleEquipment;
            string refreshEquipmentSource = "generated-battle-template";
            string refreshSelectionReason = "generated-template-kept";
            if (ShouldPreferSnapshotEquipmentForCanonicalGeneratedTemplateNativeRefresh(
                    entryState,
                    generatedBattleEquipment,
                    snapshotBattleEquipment,
                    out string snapshotPreferenceReason))
            {
                refreshBattleEquipment = snapshotBattleEquipment;
                refreshEquipmentSource = "snapshot-exact-runtime";
                refreshSelectionReason = snapshotPreferenceReason ?? "snapshot-preferred";
            }

            try
            {
                agent.UpdateSpawnEquipmentAndRefreshVisuals(refreshBattleEquipment);
            }
            catch (Exception ex)
            {
                refreshSummary =
                    "GeneratedNativeRefresh=refresh-failed:" + ex.GetType().Name +
                    " Character=" + (generatedCharacter?.StringId ?? "null") +
                    " RefreshEquipmentSource=" + refreshEquipmentSource +
                    " RefreshSelectionReason=" + refreshSelectionReason +
                    " BeforeSpawnWeapons={" + beforeSpawnWeapons + "}" +
                    " BeforeMissionWeapons={" + beforeMissionWeapons + "}";
                return false;
            }

            string afterSpawnWeapons = BuildExactEntryEquipmentSummary(
                agent.SpawnEquipment,
                EquipmentIndex.Weapon0,
                EquipmentIndex.Weapon1,
                EquipmentIndex.Weapon2,
                EquipmentIndex.Weapon3);
            string afterMissionWeapons = BuildMissionEquipmentSummary(
                agent.Equipment,
                EquipmentIndex.Weapon0,
                EquipmentIndex.Weapon1,
                EquipmentIndex.Weapon2,
                EquipmentIndex.Weapon3);
            refreshSummary =
                "GeneratedNativeRefresh=applied Character=" + (generatedCharacter?.StringId ?? "null") +
                " RefreshEquipmentSource=" + refreshEquipmentSource +
                " RefreshSelectionReason=" + refreshSelectionReason +
                " BeforeSpawnWeapons={" + beforeSpawnWeapons + "}" +
                " BeforeMissionWeapons={" + beforeMissionWeapons + "}" +
                " AfterSpawnWeapons={" + afterSpawnWeapons + "}" +
                " AfterMissionWeapons={" + afterMissionWeapons + "}";
            return true;
        }

        private static bool DoesCurrentGeneratedTemplateNativeSpawnAlreadyMatchSnapshotWeapons(
            Agent agent,
            Equipment snapshotBattleEquipment,
            out string reason)
        {
            reason = null;
            if (agent == null || snapshotBattleEquipment == null)
                return false;

            bool spawnMatches =
                DoesEquipmentMatchSnapshotWeaponSlots(
                    agent.SpawnEquipment,
                    snapshotBattleEquipment,
                    useMissionEquipment: false);
            bool missionMatches =
                DoesMissionEquipmentMatchSnapshotWeaponSlots(
                    agent.Equipment,
                    snapshotBattleEquipment);
            if (!spawnMatches || !missionMatches)
                return false;

            reason = "snapshot-weapon-slots-already-materialized";
            return true;
        }

        private static bool DoesEquipmentMatchSnapshotWeaponSlots(
            Equipment currentEquipment,
            Equipment expectedSnapshotEquipment,
            bool useMissionEquipment)
        {
            if (currentEquipment == null || expectedSnapshotEquipment == null)
                return false;

            for (EquipmentIndex slot = EquipmentIndex.Weapon0; slot <= EquipmentIndex.Weapon3; slot++)
            {
                string currentItemId = currentEquipment[slot].Item?.StringId;
                string expectedItemId = expectedSnapshotEquipment[slot].Item?.StringId;
                if (!string.Equals(currentItemId, expectedItemId, StringComparison.OrdinalIgnoreCase))
                    return false;
            }

            return true;
        }

        private static bool DoesMissionEquipmentMatchSnapshotWeaponSlots(
            MissionEquipment currentEquipment,
            Equipment expectedSnapshotEquipment)
        {
            if (currentEquipment == null || expectedSnapshotEquipment == null)
                return false;

            for (EquipmentIndex slot = EquipmentIndex.Weapon0; slot <= EquipmentIndex.Weapon3; slot++)
            {
                string currentItemId = currentEquipment[slot].Item?.StringId;
                string expectedItemId = expectedSnapshotEquipment[slot].Item?.StringId;
                if (!string.Equals(currentItemId, expectedItemId, StringComparison.OrdinalIgnoreCase))
                    return false;
            }

            return true;
        }

        private static bool ShouldPreferSnapshotEquipmentForCanonicalGeneratedTemplateNativeRefresh(
            RosterEntryState entryState,
            Equipment generatedBattleEquipment,
            Equipment snapshotBattleEquipment,
            out string reason)
        {
            reason = null;
            if (entryState == null ||
                entryState.IsHero ||
                entryState.IsMounted ||
                generatedBattleEquipment == null ||
                snapshotBattleEquipment == null)
            {
                return false;
            }

            bool snapshotHasRangedWeapon =
                HasCanonicalGeneratedTemplateNativeRefreshWeaponType(
                    snapshotBattleEquipment,
                    ItemObject.ItemTypeEnum.Bow,
                    ItemObject.ItemTypeEnum.Crossbow,
                    ItemObject.ItemTypeEnum.Thrown);
            bool snapshotHasAmmo =
                HasCanonicalGeneratedTemplateNativeRefreshWeaponType(
                    snapshotBattleEquipment,
                    ItemObject.ItemTypeEnum.Arrows,
                    ItemObject.ItemTypeEnum.Bolts);
            if (!snapshotHasRangedWeapon && !snapshotHasAmmo)
                return false;

            bool generatedHasRangedWeapon =
                HasCanonicalGeneratedTemplateNativeRefreshWeaponType(
                    generatedBattleEquipment,
                    ItemObject.ItemTypeEnum.Bow,
                    ItemObject.ItemTypeEnum.Crossbow,
                    ItemObject.ItemTypeEnum.Thrown);
            bool generatedHasAmmo =
                HasCanonicalGeneratedTemplateNativeRefreshWeaponType(
                    generatedBattleEquipment,
                    ItemObject.ItemTypeEnum.Arrows,
                    ItemObject.ItemTypeEnum.Bolts);
            if (snapshotHasRangedWeapon && !generatedHasRangedWeapon)
            {
                reason = "snapshot-has-ranged-weapon-generated-missing";
                return true;
            }

            if (snapshotHasAmmo && !generatedHasAmmo)
            {
                reason = "snapshot-has-ammo-generated-missing";
                return true;
            }

            int generatedWeaponCount = CountCanonicalGeneratedTemplateNativeRefreshOccupiedWeaponSlots(generatedBattleEquipment);
            int snapshotWeaponCount = CountCanonicalGeneratedTemplateNativeRefreshOccupiedWeaponSlots(snapshotBattleEquipment);
            if (snapshotHasRangedWeapon && snapshotWeaponCount > generatedWeaponCount)
            {
                reason =
                    "snapshot-ranged-layout-has-more-occupied-slots:" +
                    generatedWeaponCount + "->" + snapshotWeaponCount;
                return true;
            }

            bool snapshotHasShield =
                HasCanonicalGeneratedTemplateNativeRefreshWeaponType(
                    snapshotBattleEquipment,
                    ItemObject.ItemTypeEnum.Shield);
            if (snapshotHasShield)
            {
                int generatedCombatWeaponCount =
                    CountCanonicalGeneratedTemplateNativeRefreshCombatWeaponSlots(generatedBattleEquipment);
                int snapshotCombatWeaponCount =
                    CountCanonicalGeneratedTemplateNativeRefreshCombatWeaponSlots(snapshotBattleEquipment);
                if (snapshotCombatWeaponCount > generatedCombatWeaponCount)
                {
                    reason =
                        "snapshot-shield-combat-layout-has-more-combat-slots:" +
                        generatedCombatWeaponCount + "->" + snapshotCombatWeaponCount;
                    return true;
                }
            }

            return false;
        }

        private static bool HasCanonicalGeneratedTemplateNativeRefreshWeaponType(
            Equipment equipment,
            params ItemObject.ItemTypeEnum[] weaponTypes)
        {
            if (equipment == null || weaponTypes == null || weaponTypes.Length == 0)
                return false;

            for (EquipmentIndex slot = EquipmentIndex.Weapon0; slot <= EquipmentIndex.Weapon3; slot++)
            {
                ItemObject item = equipment[slot].Item;
                if (item == null)
                    continue;

                for (int i = 0; i < weaponTypes.Length; i++)
                {
                    if (item.ItemType == weaponTypes[i])
                        return true;
                }
            }

            return false;
        }

        private static int CountCanonicalGeneratedTemplateNativeRefreshOccupiedWeaponSlots(Equipment equipment)
        {
            if (equipment == null)
                return 0;

            int count = 0;
            for (EquipmentIndex slot = EquipmentIndex.Weapon0; slot <= EquipmentIndex.Weapon3; slot++)
            {
                if (equipment[slot].Item != null)
                    count++;
            }

            return count;
        }

        private static int CountCanonicalGeneratedTemplateNativeRefreshCombatWeaponSlots(Equipment equipment)
        {
            if (equipment == null)
                return 0;

            int count = 0;
            for (EquipmentIndex slot = EquipmentIndex.Weapon0; slot <= EquipmentIndex.Weapon3; slot++)
            {
                ItemObject item = equipment[slot].Item;
                if (item == null)
                    continue;

                if (item.ItemType == ItemObject.ItemTypeEnum.Shield ||
                    item.ItemType == ItemObject.ItemTypeEnum.Arrows ||
                    item.ItemType == ItemObject.ItemTypeEnum.Bolts)
                {
                    continue;
                }

                count++;
            }

            return count;
        }

        private static string FormatMaterializedEquipmentCounterSummary(Dictionary<string, int> counters, int take)
        {
            if (counters == null || counters.Count == 0)
                return "(none)";

            return string.Join(
                ", ",
                counters
                    .OrderByDescending(pair => pair.Value)
                    .ThenBy(pair => pair.Key, StringComparer.OrdinalIgnoreCase)
                    .Take(Math.Max(1, take))
                    .Select(pair => pair.Key + "=" + pair.Value));
        }

        private static ItemObject TryGetMaterializedEquipmentItem(string itemId)
        {
            if (string.IsNullOrWhiteSpace(itemId))
                return null;

            try
            {
                return MBObjectManager.Instance?.GetObject<ItemObject>(itemId);
            }
            catch
            {
                return null;
            }
        }

