        public static BattleSideEnum ResolveAuthoritativeSide(MissionPeer missionPeer, Mission mission, string source)
        {
            if (missionPeer == null)
                return BattleSideEnum.None;

            BattleSideEnum requestedSide = CoopBattleAuthorityState.GetRequestedSide(missionPeer);
            BattleSideEnum assignedSide = CoopBattleAuthorityState.GetAssignedSide(missionPeer);
            if (HasAllowedRosterForSide(assignedSide))
                return assignedSide;

            BattleSideEnum runtimeSide =
                missionPeer.Team != null && !ReferenceEquals(missionPeer.Team, mission?.SpectatorTeam)
                    ? missionPeer.Team.Side
                    : BattleSideEnum.None;
            if (runtimeSide != BattleSideEnum.None)
                CoopBattleAuthorityState.TryRequestSide(missionPeer, runtimeSide, source + " runtime-team");

            BattleSideEnum requestedOrRuntimeSide = requestedSide != BattleSideEnum.None ? requestedSide : runtimeSide;
            if (!HasAllowedRosterForSide(requestedOrRuntimeSide))
                return BattleSideEnum.None;

            CoopBattleAuthorityState.TryAssignSide(missionPeer, requestedOrRuntimeSide, source);
            return requestedOrRuntimeSide;
        }

        private static bool HasAllowedRosterForSide(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return false;

            if (AllowedControlEntryStatesBySide.TryGetValue(side, out List<RosterEntryState> sideEntryStates) && sideEntryStates.Count > 0)
                return true;

            if (AllowedControlTroopIdsBySide.TryGetValue(side, out List<string> sideTroopIds) && sideTroopIds.Count > 0)
                return true;

            string canonicalSideKey = side == BattleSideEnum.Attacker
                ? "attacker"
                : side == BattleSideEnum.Defender
                    ? "defender"
                    : null;
            if (string.IsNullOrWhiteSpace(canonicalSideKey))
                return false;

            BattleSideState sideState = BattleSnapshotRuntimeState.GetSideState(canonicalSideKey);
            return sideState?.Entries != null && sideState.Entries.Count > 0;
        }

        private static IReadOnlyList<string> GetFixedTestAllowedControlTroopIdsForSide(BattleSideEnum side)
        {
            if (!EnableFixedMissionCulturesExperiment)
                return Array.Empty<string>();

            if (side == BattleSideEnum.Attacker)
            {
                return new[]
                {
                    "mp_coop_light_cavalry_empire_troop",
                    "mp_coop_heavy_infantry_empire_troop",
                };
            }

            if (side == BattleSideEnum.Defender)
            {
                return new[]
                {
                    "mp_coop_light_cavalry_vlandia_troop",
                    "mp_coop_heavy_infantry_vlandia_troop",
                };
            }

            return Array.Empty<string>();
        }

        public static IReadOnlyList<string> GetFixedTestAllowedControlTroopIdsForSidePublic(BattleSideEnum side)
        {
            return GetFixedTestAllowedControlTroopIdsForSide(side);
        }

        private static void TryRefreshPendingSpawnRequests(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || GameNetwork.NetworkPeers == null)
                return;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null)
                    continue;

                Agent controlledAgent = missionPeer.ControlledAgent;
                bool hasActiveControlledAgent = HasActiveControlledAgent(missionPeer);
                bool hadActiveCoopLifeRuntime = IsPeerOccupyingActiveCoopLife(missionPeer);
                bool lostControlledAgent =
                    hadActiveCoopLifeRuntime &&
                    (!hasActiveControlledAgent ||
                     missionPeer.Team == null ||
                     ReferenceEquals(missionPeer.Team, mission.SpectatorTeam));
                if (lostControlledAgent)
                {
                    Team previousTeam = missionPeer.Team ?? controlledAgent?.Team;
                    if (controlledAgent != null && !controlledAgent.IsActive())
                    {
                        missionPeer.ControlledAgent = null;
                        missionPeer.FollowedAgent = null;
                        if (ReferenceEquals(peer.ControlledAgent, controlledAgent))
                            peer.ControlledAgent = null;
                    }

                    string lastTroopId = (controlledAgent?.Character as BasicCharacterObject)?.StringId ?? CoopBattleAuthorityState.GetSelectedTroopId(missionPeer);
                    string lastEntryId = CoopBattleAuthorityState.GetSelectedEntryId(missionPeer);
                    _spawnedCoopPeerIndices.Remove(peer.Index);
                    CoopBattleSelectionRequestState.Clear(missionPeer, source + " lost-controlled-agent");
                    CoopBattleSpawnRequestState.Clear(missionPeer, source + " lost-controlled-agent");
                    ExpireMissionPeerNativeVisualCompatibilityState(missionPeer);
                    CoopBattleSpawnRuntimeState.Clear(missionPeer, source + " lost-controlled-agent");
                    TryReleasePeerOrderOwnershipAfterLeavingActiveLife(
                        mission,
                        missionPeer,
                        peer,
                        previousTeam,
                        controlledAgent,
                        source + " lost-controlled-agent");
                    MovePeerToSpectatorHoldingState(mission, missionPeer, peer, source + " lost-controlled-agent");
                    CoopBattlePeerLifecycleRuntimeState.MarkDeadAwaitingRespawn(missionPeer, lastTroopId, lastEntryId, source + " lost-controlled-agent");
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: peer returned to respawnable state (" + source + "). " +
                        "Peer=" + (peer.UserName ?? peer.Index.ToString()));
                }

                if (HasActiveControlledAgent(missionPeer))
                {
                    CoopBattleSelectionRequestState.Clear(missionPeer, source + " controlled-agent");
                    CoopBattleSpawnRequestState.Clear(missionPeer, source + " controlled-agent");
                    CoopBattlePeerReconnectState.ClearActiveBattleReconnectFinalizeGate(
                        peer,
                        source + " controlled-agent");
                    CoopBattleSpawnRuntimeState.MarkSpawned(
                        missionPeer,
                        (missionPeer.ControlledAgent.Character as BasicCharacterObject)?.StringId,
                        CoopBattleAuthorityState.GetSelectedEntryId(missionPeer),
                        source + " controlled-agent");
                    CoopBattlePeerLifecycleRuntimeState.MarkAlive(
                        missionPeer,
                        (missionPeer.ControlledAgent.Character as BasicCharacterObject)?.StringId,
                        CoopBattleAuthorityState.GetSelectedEntryId(missionPeer),
                        source + " controlled-agent");
                    continue;
                }

                if (missionPeer.Team == null || ReferenceEquals(missionPeer.Team, mission.SpectatorTeam))
                {
                    BattleSideEnum spectatorAuthoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, source + " spectator-pending-request");
                    if (spectatorAuthoritativeSide == BattleSideEnum.None)
                    {
                        CoopBattleSelectionRequestState.Clear(missionPeer, source + " spectator");
                        CoopBattleSpawnRequestState.Clear(missionPeer, source + " spectator");
                        CoopBattlePeerReconnectState.ClearActiveBattleReconnectFinalizeGate(
                            peer,
                            source + " spectator");
                        CoopBattleSpawnRuntimeState.Clear(missionPeer, source + " spectator");
                        CoopBattlePeerLifecycleRuntimeState.MarkNoSide(missionPeer, BattleSideEnum.None, source + " spectator");
                        continue;
                    }
                }

                BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, source + " pending-request");
                if (authoritativeSide == BattleSideEnum.None)
                {
                    CoopBattleSelectionRequestState.Clear(missionPeer, source + " no-side");
                    CoopBattleSpawnRequestState.Clear(missionPeer, source + " no-side");
                    CoopBattlePeerReconnectState.ClearActiveBattleReconnectFinalizeGate(
                        peer,
                        source + " no-side");
                    CoopBattleSpawnRuntimeState.Clear(missionPeer, source + " no-side");
                    CoopBattlePeerLifecycleRuntimeState.MarkNoSide(missionPeer, BattleSideEnum.None, source + " no-side");
                    continue;
                }

                CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
                bool hasMeaningfulSelection =
                    !string.IsNullOrWhiteSpace(selectionState.EntryId) ||
                    !string.IsNullOrWhiteSpace(selectionState.TroopId);
                if (!hasMeaningfulSelection)
                {
                    CoopBattleSelectionRequestState.Clear(missionPeer, source + " no-selection");
                    CoopBattleSpawnRequestState.Clear(missionPeer, source + " no-selection");
                    CoopBattleSpawnRuntimeState.Clear(missionPeer, source + " no-selection");
                    ApplyDerivedPeerLifecycleState(
                        mission,
                        missionPeer,
                        preferSpawnQueued: false,
                        preserveDeadAwaitingRespawn: true,
                        source + " no-selection");
                    continue;
                }

                if (CoopBattleSpawnRequestState.TryGetPendingRequest(missionPeer, out CoopBattleSpawnRequestState.PeerSpawnRequestState existingPendingRequest))
                {
                    CoopBattleSpawnRuntimeState.MarkPending(existingPendingRequest);
                    ApplyDerivedPeerLifecycleState(
                        mission,
                        missionPeer,
                        preferSpawnQueued: true,
                        preserveDeadAwaitingRespawn: true,
                        source + " existing-pending-request");
                    continue;
                }

                if (!ShouldAutoQueueSelectionFromAuthority(missionPeer))
                {
                    CoopBattleSelectionRequestState.Clear(missionPeer, source + " explicit-spawn-required");
                    CoopBattleSpawnRequestState.Clear(missionPeer, source + " explicit-spawn-required");
                    if (!CoopBattlePeerLifecycleRuntimeState.TryGetState(missionPeer, out PeerLifecycleRuntimeState lifecycleState) ||
                        (lifecycleState.Status != CoopBattlePeerLifecycleStatus.Respawnable &&
                         lifecycleState.Status != CoopBattlePeerLifecycleStatus.DeadAwaitingRespawn))
                    {
                        ApplyDerivedPeerLifecycleState(
                            mission,
                            missionPeer,
                            preferSpawnQueued: false,
                            preserveDeadAwaitingRespawn: true,
                            source + " waiting-explicit-spawn");
                    }

                    continue;
                }

                CoopBattleSelectionRequestState.TryQueueFromAuthoritySelection(missionPeer, source);
                if (CoopBattleSelectionRequestState.TryGetRequest(missionPeer, out CoopBattleSelectionRequestState.PeerSelectionRequestState selectionRequest) &&
                    CoopBattleSpawnRequestState.TryQueueFromSelectionRequest(selectionRequest, source) &&
                    CoopBattleSpawnRequestState.TryGetPendingRequest(missionPeer, out CoopBattleSpawnRequestState.PeerSpawnRequestState pendingRequest))
                {
                    CoopBattleSpawnRuntimeState.MarkPending(pendingRequest);
                    ApplyDerivedPeerLifecycleState(
                        mission,
                        missionPeer,
                        preferSpawnQueued: true,
                        preserveDeadAwaitingRespawn: true,
                        source + " pending-request");
                }
                else
                {
                    ApplyDerivedPeerLifecycleState(
                        mission,
                        missionPeer,
                        preferSpawnQueued: false,
                        preserveDeadAwaitingRespawn: true,
                        source + " waiting");
                }
            }
        }

        private static bool HasActiveControlledAgent(MissionPeer missionPeer)
        {
            Agent controlledAgent = missionPeer?.ControlledAgent;
            return controlledAgent != null && controlledAgent.IsActive();
        }

        private static bool IsPeerOccupyingActiveCoopLife(MissionPeer missionPeer)
        {
            if (missionPeer == null)
                return false;

            if (CoopBattlePeerSessionState.TryBuild(null, missionPeer, "active-life-check", out CoopBattlePeerSessionSnapshot sessionSnapshot))
                return sessionSnapshot.OccupiesActiveCoopLife;

            return HasActiveControlledAgent(missionPeer);
        }

        private static bool IsPeerHoldingQueuedSpawnInCoopRuntime(MissionPeer missionPeer)
        {
            if (missionPeer == null)
                return false;

            if (CoopBattlePeerSessionState.TryBuild(null, missionPeer, "queued-spawn-check", out CoopBattlePeerSessionSnapshot sessionSnapshot))
                return sessionSnapshot.HasQueuedSpawnRuntime;

            return CoopBattleSpawnRequestState.HasPendingRequest(missionPeer);
        }

        private static void ApplyDerivedPeerLifecycleState(
            Mission mission,
            MissionPeer missionPeer,
            bool preferSpawnQueued,
            bool preserveDeadAwaitingRespawn,
            string source)
        {
            if (missionPeer == null)
                return;

            if (!CoopBattlePeerSessionState.TryBuild(mission, missionPeer, source, out CoopBattlePeerSessionSnapshot sessionSnapshot) ||
                sessionSnapshot == null)
            {
                return;
            }

            BattleSideEnum authoritativeSide = sessionSnapshot.CommittedSide != BattleSideEnum.None
                ? sessionSnapshot.CommittedSide
                : ResolveAuthoritativeSide(missionPeer, mission, source + " authoritative-side");
            bool canRespawn = CanPeerRespawn(mission, missionPeer);
            CoopBattlePeerLifecycleStatus status = CoopBattlePeerSessionState.ResolvePassiveLifecycleStatus(
                sessionSnapshot,
                authoritativeSide,
                canRespawn,
                preferSpawnQueued,
                preserveDeadAwaitingRespawn);

            BattleSideEnum side = status == CoopBattlePeerLifecycleStatus.NoSide || status == CoopBattlePeerLifecycleStatus.NoPeer
                ? BattleSideEnum.None
                : authoritativeSide;
            string troopId = status == CoopBattlePeerLifecycleStatus.NoSide ||
                             status == CoopBattlePeerLifecycleStatus.NoPeer ||
                             status == CoopBattlePeerLifecycleStatus.AwaitingSelection
                ? null
                : sessionSnapshot.PreferredTroopId;
            string entryId = status == CoopBattlePeerLifecycleStatus.NoSide ||
                             status == CoopBattlePeerLifecycleStatus.NoPeer ||
                             status == CoopBattlePeerLifecycleStatus.AwaitingSelection
                ? null
                : sessionSnapshot.PreferredEntryId;

            CoopBattlePeerLifecycleRuntimeState.Apply(
                missionPeer,
                side,
                troopId,
                entryId,
                status,
                source,
                incrementDeathCount: false);
        }

        private static bool ShouldAutoQueueSelectionFromAuthority(MissionPeer missionPeer)
        {
            return false;
        }

        private static void TryConsumeSelectionRequests(Mission mission)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            if (CoopBattleSelectionBridgeFile.ConsumeSelectSideRequest(out string requestedSideRaw, out string sideSource))
                StoreSelectionSideIntent(requestedSideRaw, sideSource ?? "bridge side request");

            if (CoopBattleSelectionBridgeFile.ConsumeSelectTroopRequest(out string troopOrEntryId, out string troopSource))
                StoreSelectionTroopIntent(troopOrEntryId, troopSource ?? "bridge troop request");

            if (CoopBattleSelectionBridgeFile.ConsumeSpectatorRequest(out string spectatorSource))
                TryApplySpectatorSelectionToPrimaryPeer(mission, spectatorSource ?? "bridge spectator request");
        }

        private static void TryConsumeSpawnRequests(Mission mission)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            if (CoopBattleSpawnBridgeFile.ConsumeSpawnNowRequest(out string source))
                CoopBattleSpawnIntentState.RequestSpawn(source ?? "bridge spawn request");

            if (CoopBattleSpawnBridgeFile.ConsumeForceRespawnableRequest(out string respawnableSource))
                TryForcePrimaryPeerRespawnable(mission, respawnableSource ?? "bridge force-respawnable request");
        }

        private static void TryForcePrimaryPeerRespawnable(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            MissionPeer missionPeer = ResolvePrimaryControllablePeer(mission);
            if (missionPeer == null)
            {
                ModLogger.Info("CoopMissionSpawnLogic: force-respawnable ignored (" + source + "). Peer=none");
                return;
            }

            TryForcePeerRespawnable(mission, missionPeer, source);
        }

        private static bool TryForcePeerRespawnable(Mission mission, MissionPeer missionPeer, string source)
        {
            if (mission == null || missionPeer == null || !GameNetwork.IsServer)
                return false;

            NetworkCommunicator peer = missionPeer.GetNetworkPeer();
            Agent controlledAgent = missionPeer.ControlledAgent;
            Team previousTeam = missionPeer.Team ?? controlledAgent?.Team;
            bool triggeredVanillaRemoval = false;
            bool returnedMaterializedAgentToAi = false;
            if (controlledAgent != null && controlledAgent.IsActive())
            {
                if (IsMaterializedArmyAgent(controlledAgent))
                {
                    returnedMaterializedAgentToAi = TryReturnMaterializedAgentControlToAi(missionPeer, peer, controlledAgent, source);
                }
                else
                {
                    try
                    {
                        mission.KillAgentCheat(controlledAgent);
                        triggeredVanillaRemoval = true;
                    }
                    catch (Exception ex)
                    {
                        ModLogger.Info("CoopMissionSpawnLogic: failed to kill controlled agent during force-respawnable: " + ex.Message);
                    }
                }
            }

            bool resetSucceeded =
                controlledAgent == null ||
                !controlledAgent.IsActive() ||
                triggeredVanillaRemoval ||
                returnedMaterializedAgentToAi;
            if (!resetSucceeded)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: force-respawnable ignored because controlled agent is still active. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " AgentIndex=" + controlledAgent.Index +
                    " Source=" + source);
                return false;
            }

            TryReleasePeerOrderOwnershipAfterLeavingActiveLife(
                mission,
                missionPeer,
                peer,
                previousTeam,
                controlledAgent,
                source + " forced-respawnable");

            missionPeer.ControlledAgent = null;
            missionPeer.FollowedAgent = null;
            if (peer != null && ReferenceEquals(peer.ControlledAgent, controlledAgent))
                peer.ControlledAgent = null;
            if (peer != null)
                _spawnedCoopPeerIndices.Remove(peer.Index);

            ExpireMissionPeerNativeVisualCompatibilityState(missionPeer);
            ResetMissionPeerSpawnTimerForImmediateRespawn(mission, missionPeer);
            missionPeer.WantsToSpawnAsBot = false;
            MovePeerToSpectatorHoldingState(mission, missionPeer, peer, source + " forced-respawnable");
            CoopBattleSelectionRequestState.Clear(missionPeer, source + " forced-respawnable");
            CoopBattleSpawnRequestState.Clear(missionPeer, source + " forced-respawnable");
            CoopBattleSpawnRuntimeState.Clear(missionPeer, source + " forced-respawnable");
            CoopBattlePeerLifecycleRuntimeState.MarkRespawnable(
                missionPeer,
                CoopBattleAuthorityState.GetSelectedTroopId(missionPeer),
                CoopBattleAuthorityState.GetSelectedEntryId(missionPeer),
                source + " forced-respawnable");

            ModLogger.Info(
                "CoopMissionSpawnLogic: forced peer into respawnable state. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " TriggeredVanillaRemoval=" + triggeredVanillaRemoval +
                " ReturnedMaterializedAgentToAi=" + returnedMaterializedAgentToAi +
                " Source=" + source);
            return true;
        }

        private static void TryReleasePeerOrderOwnershipAfterLeavingActiveLife(
            Mission mission,
            MissionPeer missionPeer,
            NetworkCommunicator peer,
            Team previousTeam,
            Agent controlledAgent,
            string source)
        {
            if (mission == null || missionPeer == null || previousTeam == null || controlledAgent == null)
                return;

            if (ReferenceEquals(previousTeam, mission.SpectatorTeam) || previousTeam.Side == BattleSideEnum.None)
                return;

            bool releasedGeneralOwnership =
                ReferenceEquals(previousTeam.GeneralAgent, controlledAgent) ||
                ReferenceEquals(previousTeam.PlayerOrderController?.Owner, controlledAgent);
            int releasedFormationCount = 0;
            int chargedFormationCount = 0;

            foreach (Formation formation in previousTeam.FormationsIncludingSpecialAndEmpty)
            {
                if (formation == null || !ReferenceEquals(formation.Team, previousTeam))
                    continue;

                bool ownedByDeadPeer = ReferenceEquals(GetServerMemberValue(formation, "PlayerOwner"), controlledAgent);
                bool shouldReleaseFormation =
                    ownedByDeadPeer ||
                    (releasedGeneralOwnership && formation.CountOfUnits > 0);
                if (!shouldReleaseFormation)
                    continue;

                SetServerMemberValue(formation, "PlayerOwner", null);
                SetServerMemberValue(formation, "HasPlayerControlledTroop", false);
                SetServerMemberValue(formation, "IsPlayerTroopInFormation", false);
                formation.SetControlledByAI(true, true);
                formation.SetFiringOrder(FiringOrder.FiringOrderFireAtWill);
                if (formation.CountOfUnits > 0)
                {
                    formation.SetMovementOrder(MovementOrder.MovementOrderCharge);
                    chargedFormationCount++;
                }

                releasedFormationCount++;
            }

            int clearedOrderControllers = TryClearDeadPeerOrderControllerOwnership(previousTeam, controlledAgent, source);
            if (ReferenceEquals(previousTeam.PlayerOrderController?.Owner, controlledAgent))
            {
                previousTeam.PlayerOrderController.ClearSelectedFormations();
                previousTeam.PlayerOrderController.Owner = null;
            }

            int pulsedAgents = 0;
            if (releasedGeneralOwnership)
            {
                previousTeam.SetPlayerRole(isPlayerGeneral: false, isPlayerSergeant: false);
                if (ReferenceEquals(previousTeam.GeneralAgent, controlledAgent))
                    previousTeam.GeneralAgent = null;

                previousTeam.ResetTactic();
                previousTeam.DelegateCommandToAI();
                pulsedAgents = TryActivateBattleActiveReinforcementAi(previousTeam);
            }

            try
            {
                controlledAgent.SetCanLeadFormationsRemotely(value: false);
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: failed to clear remote commander flag after leaving active life. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " Source=" + (source ?? "unknown") +
                    " Error=" + ex.Message);
            }
            if (releasedFormationCount <= 0 && clearedOrderControllers <= 0 && !releasedGeneralOwnership)
                return;

            if (peer != null && peer.IsConnectionActive)
            {
                try
                {
                    GameNetwork.BeginBroadcastModuleEvent();
                    WriteBotsControlledChangeClamped(peer, 0, 0, source + " post-life-clear");
                    GameNetwork.EndBroadcastModuleEvent(GameNetwork.EventBroadcastFlags.None);
                }
                catch (Exception ex)
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: failed to broadcast cleared post-life order ownership. " +
                        "Peer=" + (peer.UserName ?? peer.Index.ToString()) +
                        " Source=" + (source ?? "unknown") +
                        " Error=" + ex.Message);
                }
            }

            ModLogger.Info(
                "CoopMissionSpawnLogic: released post-life commander ownership back to AI. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " TeamSide=" + previousTeam.Side +
                " ReleasedGeneralOwnership=" + releasedGeneralOwnership +
                " ReleasedFormations=" + releasedFormationCount +
                " ChargedFormations=" + chargedFormationCount +
                " ClearedOrderControllers=" + clearedOrderControllers +
                " PulsedAgents=" + pulsedAgents +
                " Source=" + (source ?? "unknown"));
        }

        private static int TryClearDeadPeerOrderControllerOwnership(Team team, Agent controlledAgent, string source)
        {
            if (team == null || controlledAgent == null)
                return 0;

            try
            {
                if (!(GetServerMemberValue(team, "_orderControllers") is System.Collections.IEnumerable orderControllers))
                    return 0;

                int clearedCount = 0;
                foreach (object orderControllerObject in orderControllers)
                {
                    OrderController orderController = orderControllerObject as OrderController;
                    if (orderController == null ||
                        !ReferenceEquals(orderController.Owner, controlledAgent))
                    {
                        continue;
                    }

                    orderController.ClearSelectedFormations();
                    orderController.Owner = null;
                    clearedCount++;
                }

                return clearedCount;
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: failed to clear dead peer order controller ownership. " +
                    "TeamSide=" + team.Side +
                    " Source=" + (source ?? "unknown") +
                    " Error=" + ex.Message);
                return 0;
            }
        }

        private static bool IsMaterializedArmyAgent(Agent agent)
        {
            return agent != null &&
                (_materializedArmySideByAgentIndex.ContainsKey(agent.Index) ||
                 ExactCampaignArmyBootstrap.TryGetEntryId(agent, out _));
        }

        private static void ExpireMissionPeerNativeVisualCompatibilityState(MissionPeer missionPeer)
        {
            if (missionPeer == null)
                return;

            ClearSelectedTroopIndexBridgeCompatibilityState(missionPeer);
            missionPeer.HasSpawnedAgentVisuals = false;
            missionPeer.EquipmentUpdatingExpired = true;
        }

        private static void ClearSelectedTroopIndexBridgeCompatibilityState(MissionPeer missionPeer)
        {
            NetworkCommunicator peer = missionPeer?.GetNetworkPeer();
            if (peer == null)
                return;

            _lastBridgedSelectedTroopIndexByPeer.Remove(peer.Index);
        }

        private static bool ClearMissionPeerPendingNativeSpawnVisualCompatibility(Mission mission, MissionPeer missionPeer)
        {
            bool removedPendingVisuals = TryRemovePendingAgentVisuals(mission, missionPeer);
            ExpireMissionPeerNativeVisualCompatibilityState(missionPeer);
            return removedPendingVisuals;
        }

        private static void ResetMissionPeerSpawnTimerForImmediateRespawn(Mission mission, MissionPeer missionPeer)
        {
            if (mission == null || missionPeer == null)
                return;

            if (missionPeer.SpawnTimer != null)
                missionPeer.SpawnTimer.Reset(mission.CurrentTime, 0f);
            missionPeer.HasSpawnTimerExpired = true;
        }

        private static void MovePeerToSpectatorHoldingState(
            Mission mission,
            MissionPeer missionPeer,
            NetworkCommunicator peer,
            string source)
        {
            if (mission == null || missionPeer == null)
                return;

            Team spectatorTeam = mission.SpectatorTeam;
            if (spectatorTeam == null)
                return;

            Team previousTeam = missionPeer.Team;
            bool alreadySpectator = ReferenceEquals(previousTeam, spectatorTeam);

            missionPeer.ControlledFormation = null;
            ApplyBotsUnderControlCounts(
                missionPeer,
                0,
                0,
                peer,
                source + " spectator-holding",
                out _,
                out _);
            missionPeer.WantsToSpawnAsBot = false;
            ExpireMissionPeerNativeVisualCompatibilityState(missionPeer);

            if (!alreadySpectator)
            {
                SetServerMemberValue(missionPeer, "Team", spectatorTeam);
                if (!ReferenceEquals(GetServerMemberValue(missionPeer, "Team"), spectatorTeam))
                    SetServerMemberValue(missionPeer, "_team", spectatorTeam);
                if (!ReferenceEquals(GetServerMemberValue(missionPeer, "Team"), spectatorTeam))
                    SetServerMemberValue(missionPeer, "<Team>k__BackingField", spectatorTeam);

                Team appliedTeam = GetServerMemberValue(missionPeer, "Team") as Team;
                if (!ReferenceEquals(appliedTeam, spectatorTeam))
                    appliedTeam = GetServerMemberValue(missionPeer, "_team") as Team;

                if (ReferenceEquals(appliedTeam, spectatorTeam))
                {
                    if (peer != null)
                        _lastBridgedPeerTeamIndexByPeer.Remove(peer.Index);

                    try
                    {
                        if (peer != null)
                        {
                            GameNetwork.BeginBroadcastModuleEvent();
                            GameNetwork.WriteMessage(new NetworkMessages.FromServer.SetPeerTeam(peer, spectatorTeam.TeamIndex));
                            GameNetwork.EndBroadcastModuleEvent(GameNetwork.EventBroadcastFlags.None);
                        }
                    }
                    catch (Exception ex)
                    {
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: rebroadcast spectator holding team failed. " +
                            "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                            " Source=" + (source ?? "unknown") +
                            " Error=" + ex.Message);
                    }
                }
            }

            ModLogger.Info(
                "CoopMissionSpawnLogic: moved peer to spectator holding state. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " PreviousTeamIndex=" + (previousTeam?.TeamIndex ?? -1) +
                " AppliedTeamIndex=" + (missionPeer.Team?.TeamIndex ?? -1) +
                " AppliedIsSpectator=" + ReferenceEquals(missionPeer.Team, spectatorTeam) +
                " Source=" + (source ?? "unknown"));
        }

        private static bool TryReturnMaterializedAgentControlToAi(
            MissionPeer missionPeer,
            NetworkCommunicator peer,
            Agent controlledAgent,
            string source)
        {
            if (missionPeer == null || controlledAgent == null || !controlledAgent.IsActive())
                return false;

            try
            {
                Formation controlledFormation = controlledAgent.Formation;
                controlledAgent.SetOwningAgentMissionPeer(null);
                controlledAgent.MissionPeer = null;
                controlledAgent.Controller = AgentControllerType.AI;
                controlledAgent.SetAutomaticTargetSelection(true);
                controlledAgent.SetFiringOrder(FiringOrder.RangedWeaponUsageOrderEnum.FireAtWill);
                controlledAgent.WieldInitialWeapons(
                    Agent.WeaponWieldActionType.Instant,
                    Equipment.InitialWeaponEquipPreference.Any);

                if (peer != null)
                {
                    GameNetwork.BeginModuleEventAsServer(peer.VirtualPlayer);
                    GameNetwork.WriteMessage(new NetworkMessages.FromServer.SetAgentIsPlayer(controlledAgent.Index, false));
                    GameNetwork.WriteMessage(new NetworkMessages.FromServer.SetAgentOwningMissionPeer(controlledAgent.Index, null));
                    GameNetwork.EndModuleEventAsServer();
                }

                bool resetFormationPlayerState = TryResetMaterializedFormationPlayerState(
                    missionPeer,
                    controlledFormation,
                    controlledAgent,
                    source);

                missionPeer.ControlledAgent = null;
                missionPeer.FollowedAgent = null;
                missionPeer.ControlledFormation = null;
                ApplyBotsUnderControlCounts(
                    missionPeer,
                    0,
                    0,
                    peer,
                    source + " return-control-to-ai",
                    out _,
                    out _);
                if (peer != null && ReferenceEquals(peer.ControlledAgent, controlledAgent))
                    peer.ControlledAgent = null;

                ModLogger.Info(
                    "CoopMissionSpawnLogic: returned materialized agent control to AI for respawn. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " AgentIndex=" + controlledAgent.Index +
                    " Formation=" + (controlledFormation?.FormationIndex.ToString() ?? "none") +
                    " ResetFormationPlayerState=" + resetFormationPlayerState +
                    " Source=" + (source ?? "unknown"));
                return true;
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: failed to return materialized agent control to AI during force-respawnable: " + ex.Message);
                return false;
            }
        }

        private static bool TryResetMaterializedFormationPlayerState(
            MissionPeer missionPeer,
            Formation formation,
            Agent controlledAgent,
            string source)
        {
            if (formation == null)
                return false;

            bool changed = false;
            try
            {
                object playerOwner = GetServerMemberValue(formation, "PlayerOwner");
                if (ReferenceEquals(playerOwner, controlledAgent))
                {
                    SetServerMemberValue(formation, "PlayerOwner", null);
                    changed = true;
                }

                bool hadPlayerControlledTroop = (GetServerMemberValue(formation, "HasPlayerControlledTroop") as bool?) ?? false;
                SetServerMemberValue(formation, "HasPlayerControlledTroop", false);
                if (hadPlayerControlledTroop && !((GetServerMemberValue(formation, "HasPlayerControlledTroop") as bool?) ?? true))
                    changed = true;

                bool hadPlayerTroopInFormation = (GetServerMemberValue(formation, "IsPlayerTroopInFormation") as bool?) ?? false;
                SetServerMemberValue(formation, "IsPlayerTroopInFormation", false);
                if (hadPlayerTroopInFormation && !((GetServerMemberValue(formation, "IsPlayerTroopInFormation") as bool?) ?? true))
                    changed = true;

                bool wasAiControlled = (GetServerMemberValue(formation, "IsAIControlled") as bool?) ?? false;
                SetServerMemberValue(formation, "IsAIControlled", true);
                if (!wasAiControlled && ((GetServerMemberValue(formation, "IsAIControlled") as bool?) ?? false))
                    changed = true;

                MethodInfo setControlledByAiMethod = formation.GetType().GetMethod(
                    "SetControlledByAI",
                    BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic,
                    null,
                    new[] { typeof(bool), typeof(bool) },
                    null);
                if (setControlledByAiMethod != null)
                {
                    setControlledByAiMethod.Invoke(formation, new object[] { true, true });
                    changed = true;
                }

                MethodInfo onAgentControllerChangedMethod = formation.GetType().GetMethod(
                    "OnAgentControllerChanged",
                    BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic,
                    null,
                    new[] { typeof(Agent), typeof(AgentControllerType) },
                    null);
                if (onAgentControllerChangedMethod != null)
                {
                    onAgentControllerChangedMethod.Invoke(formation, new object[] { controlledAgent, AgentControllerType.AI });
                    changed = true;
                }
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: failed to reset materialized formation player state. " +
                    "Formation=" + formation.FormationIndex +
                    " Source=" + (source ?? "unknown") +
                    " Error=" + ex.Message);
            }

            if (changed)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: reset materialized formation player state. " +
                    "Formation=" + formation.FormationIndex +
                    " MissionPeer=" + (missionPeer?.GetNetworkPeer()?.UserName ?? missionPeer?.GetNetworkPeer()?.Index.ToString() ?? "none") +
                    " AgentIndex=" + controlledAgent.Index +
                    " Source=" + (source ?? "unknown"));
            }

            return changed;
        }

        private static void StoreSelectionSideIntent(string requestedSideRaw, string source)
        {
            if (!TryParseBattleSide(requestedSideRaw, out BattleSideEnum requestedSide))
            {
                ModLogger.Info("CoopMissionSpawnLogic: ignored invalid side selection request. Value=" + (requestedSideRaw ?? "null"));
                return;
            }

            CoopBattleSelectionIntentState.UpdateSide(requestedSide, source + " side-intent");
        }

        private static void StoreSelectionTroopIntent(string troopOrEntryId, string source)
        {
            if (string.IsNullOrWhiteSpace(troopOrEntryId))
                return;

            CoopBattleSelectionIntentState.UpdateTroopOrEntry(troopOrEntryId, source + " troop-intent");
        }

        private static void TryApplySpectatorSelectionToPrimaryPeer(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            MissionPeer missionPeer = ResolvePrimaryControllablePeer(mission);
            if (missionPeer == null)
            {
                ModLogger.Info("CoopMissionSpawnLogic: spectator selection ignored (" + source + "). Peer=none");
                return;
            }

            TryApplySpectatorSelectionToPeer(mission, missionPeer, source);
        }

        internal static bool TryReturnPeerToReconnectSideSelection(
            Mission mission,
            NetworkCommunicator peer,
            string source)
        {
            if (mission == null || peer == null || peer.IsServerPeer || !GameNetwork.IsServer)
                return false;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            if (currentPhase < CoopBattlePhase.BattleActive || currentPhase >= CoopBattlePhase.BattleEnded)
                return false;

            MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
            if (missionPeer == null)
                return false;

            Agent controlledAgent = missionPeer.ControlledAgent;
            if (controlledAgent != null && controlledAgent.IsActive())
                return false;

            BattleSideEnum assignedSide = CoopBattleAuthorityState.GetAssignedSide(missionPeer);
            string selectedEntryId = CoopBattleAuthorityState.GetSelectedEntryId(missionPeer);
            string selectedTroopId = CoopBattleAuthorityState.GetSelectedTroopId(missionPeer);
            bool resetApplied = TryApplySpectatorSelectionToPeer(
                mission,
                missionPeer,
                source + " reconnect-return-to-side-selection");
            if (!resetApplied)
                return false;

            ModLogger.Info(
                "CoopMissionSpawnLogic: returned reconnecting peer to authoritative side-selection shell. " +
                "Peer=" + (peer.UserName ?? peer.Index.ToString()) +
                " PreviousAssignedSide=" + assignedSide +
                " PreviousSelectedEntryId=" + (selectedEntryId ?? "null") +
                " PreviousSelectedTroopId=" + (selectedTroopId ?? "null") +
                " Phase=" + currentPhase +
                " Source=" + (source ?? "unknown"));
            return true;
        }

        private static void TryApplySelectionIntentToPrimaryPeer(Mission mission, string source)
        {
            MissionPeer missionPeer = ResolvePrimaryControllablePeer(mission);
            if (missionPeer == null)
                return;

            CoopBattleSelectionIntentSnapshot intent = CoopBattleSelectionIntentState.GetCurrent();
            TryApplySelectionIntentToPeer(mission, missionPeer, intent.Side, intent.TroopOrEntryId, source);
        }

        private static void TryApplySpawnIntentToPrimaryPeer(Mission mission, string source)
        {
            CoopBattleSpawnIntentSnapshot intent = CoopBattleSpawnIntentState.GetCurrent();
            if (intent == null || !intent.IsRequested)
                return;

            MissionPeer missionPeer = ResolvePrimaryControllablePeer(mission);
            if (missionPeer == null)
                return;

            if (missionPeer.ControlledAgent != null)
            {
                CoopBattleSpawnIntentState.Clear(source + " already-controlled");
                return;
            }

            if (TryQueueSpawnIntentForPeer(mission, missionPeer, source + " spawn-intent"))
                CoopBattleSpawnIntentState.Clear(source + " queued");
        }

        private static bool IsPeerSelectionOrSpawnTransitionInFlight(
            MissionPeer missionPeer,
            out string reason)
        {
            reason = null;
            if (missionPeer == null)
                return false;

            if (CoopBattleSpawnRequestState.HasPendingRequest(missionPeer))
            {
                reason = "pending-spawn-request";
                return true;
            }

            if (!CoopBattleSpawnRuntimeState.TryGetState(missionPeer, out PeerSpawnRuntimeState spawnState))
                return false;

            if (spawnState.Status == CoopBattleSpawnStatus.Pending ||
                spawnState.Status == CoopBattleSpawnStatus.Validating ||
                spawnState.Status == CoopBattleSpawnStatus.Validated)
            {
                reason = "spawn-runtime-" + spawnState.Status;
                return true;
            }

            if (spawnState.Status != CoopBattleSpawnStatus.Spawned)
                return false;

            bool hasLifecycleState = CoopBattlePeerLifecycleRuntimeState.TryGetState(
                missionPeer,
                out PeerLifecycleRuntimeState lifecycleState);
            bool controlledAgentActive = HasActiveControlledAgent(missionPeer);
            bool hasControlledFormation = missionPeer.ControlledFormation != null;
            bool hasLiveControlledBots = missionPeer.BotsUnderControlAlive > 0;
            bool hasMaterializedControlledFormation = missionPeer.BotsUnderControlTotal > 1;
            bool isLateSpawnHandshake =
                (!controlledAgentActive || !hasControlledFormation || !hasLiveControlledBots || !hasMaterializedControlledFormation) &&
                (!hasLifecycleState || lifecycleState.Status == CoopBattlePeerLifecycleStatus.Alive);
            if (!isLateSpawnHandshake)
                return false;

            reason =
                "late-spawn-handshake" +
                " Lifecycle=" + (hasLifecycleState ? lifecycleState.Status.ToString() : "none") +
                " ControlledAgentActive=" + controlledAgentActive +
                " ControlledFormation=" + hasControlledFormation +
                " BotsAlive=" + missionPeer.BotsUnderControlAlive +
                " BotsTotal=" + missionPeer.BotsUnderControlTotal;
            return true;
        }

        internal static bool TryHandleNetworkSelectionRequest(
            Mission mission,
            NetworkCommunicator peer,
            CoopBattleSelectionRequestKind requestKind,
            BattleSideEnum requestedSide,
            string troopOrEntryId,
            string source)
        {
            if (mission == null || !GameNetwork.IsServer || peer == null)
                return false;

            MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
            if (missionPeer == null)
                return false;

            if (!IsBattleDataReadinessBypassRequest(requestKind) &&
                !TryValidateBattleDataReadinessForNetworkRequest(
                    mission,
                    missionPeer,
                    requestKind,
                    requestedSide,
                    source,
                    out string readinessStage,
                    out string readinessReason))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected network selection request while battle data is still loading. " +
                    "Peer=" + (peer.UserName ?? peer.Index.ToString()) +
                    " Kind=" + requestKind +
                    " RequestedSide=" + requestedSide +
                    " Stage=" + (readinessStage ?? string.Empty) +
                    " Reason=" + (readinessReason ?? string.Empty) +
                    " Source=" + source);
                return false;
            }

            string inFlightReason = null;
            bool overlapsSelectionOrSpawnLifecycle =
                requestKind == CoopBattleSelectionRequestKind.SelectEntry ||
                requestKind == CoopBattleSelectionRequestKind.SpawnNow;
            bool peerOccupiesActiveCoopLifeForRequest = overlapsSelectionOrSpawnLifecycle &&
                IsPeerOccupyingActiveCoopLife(missionPeer);
            bool peerHasSpawnTransitionInFlight = overlapsSelectionOrSpawnLifecycle &&
                IsPeerSelectionOrSpawnTransitionInFlight(missionPeer, out inFlightReason);
            if (peerOccupiesActiveCoopLifeForRequest || peerHasSpawnTransitionInFlight)
            {
                string reason =
                    peerOccupiesActiveCoopLifeForRequest
                        ? "peer-still-occupies-active-coop-life"
                        : inFlightReason;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected overlapping selection/spawn request while previous coop life or spawn handoff is still active. " +
                    "Peer=" + (peer.UserName ?? peer.Index.ToString()) +
                    " Kind=" + requestKind +
                    " RequestedSide=" + requestedSide +
                    " Target=" + (troopOrEntryId ?? string.Empty) +
                    " Reason=" + (reason ?? "unknown") +
                    " Source=" + source);
                return false;
            }

            switch (requestKind)
            {
                case CoopBattleSelectionRequestKind.SelectSide:
                    return TryApplySelectionIntentToPeer(
                        mission,
                        missionPeer,
                        requestedSide,
                        null,
                        source + " select-side");
                case CoopBattleSelectionRequestKind.SelectEntry:
                    return TryApplySelectionIntentToPeer(
                        mission,
                        missionPeer,
                        requestedSide,
                        troopOrEntryId,
                        source + " select-entry");
                case CoopBattleSelectionRequestKind.Spectate:
                    return TryApplySpectatorSelectionToPeer(mission, missionPeer, source + " spectate");
                case CoopBattleSelectionRequestKind.SpawnNow:
                    return TryQueueSpawnIntentForPeer(mission, missionPeer, source + " spawn");
                case CoopBattleSelectionRequestKind.ForceRespawnable:
                    return TryForcePeerRespawnable(mission, missionPeer, source + " force-respawnable");
                default:
                    return false;
            }
        }

        private static bool IsBattleDataReadinessBypassRequest(CoopBattleSelectionRequestKind requestKind)
        {
            return requestKind == CoopBattleSelectionRequestKind.Spectate ||
                requestKind == CoopBattleSelectionRequestKind.ForceRespawnable;
        }

        private static bool TryValidateBattleDataReadinessForNetworkRequest(
            Mission mission,
            MissionPeer missionPeer,
            CoopBattleSelectionRequestKind requestKind,
            BattleSideEnum requestedSide,
            string source,
            out string readinessStage,
            out string readinessReason)
        {
            readinessStage = "Loading";
            readinessReason = "Loading battle data...";

            if (mission == null || missionPeer == null)
                return false;

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            BattleSideEnum readinessSide = requestedSide;
            if (readinessSide == BattleSideEnum.None &&
                (requestKind == CoopBattleSelectionRequestKind.SelectEntry || requestKind == CoopBattleSelectionRequestKind.SpawnNow))
            {
                readinessSide = ResolveAuthoritativeSide(missionPeer, mission, source + " battle-data-ready");
            }

            if ((requestKind == CoopBattleSelectionRequestKind.SelectEntry || requestKind == CoopBattleSelectionRequestKind.SpawnNow) &&
                readinessSide == BattleSideEnum.None)
            {
                readinessReason = "Peer side not assigned yet.";
                return false;
            }

            return TryResolveBattleDataReadinessForPeer(
                mission,
                missionPeer,
                currentPhase,
                readinessSide,
                out readinessStage,
                out readinessReason);
        }

        private static bool TryApplySpectatorSelectionToPeer(Mission mission, MissionPeer missionPeer, string source)
        {
            if (mission == null || missionPeer == null || !GameNetwork.IsServer)
                return false;

            NetworkCommunicator peer = missionPeer.GetNetworkPeer();
            if (HasActiveControlledAgent(missionPeer))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: spectator selection ignored because peer still controls an active agent. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " Source=" + source);
                return false;
            }

            CoopBattleSelectionIntentState.Reset();
            CoopBattleAuthorityState.ClearPeerSelectionAndSide(missionPeer, source + " spectator-request");
            CoopBattleSelectionRequestState.Clear(missionPeer, source + " spectator-request");
            CoopBattleSpawnRequestState.Clear(missionPeer, source + " spectator-request");
            CoopBattlePeerReconnectState.ClearActiveBattleReconnectFinalizeGate(
                peer,
                source + " spectator-request");
            CoopBattleSpawnRuntimeState.Clear(missionPeer, source + " spectator-request");
            missionPeer.WantsToSpawnAsBot = false;
            MovePeerToSpectatorHoldingState(mission, missionPeer, peer, source + " spectator-request");
            CoopBattlePeerLifecycleRuntimeState.MarkNoSide(missionPeer, BattleSideEnum.None, source + " spectator-request");

            ModLogger.Info(
                "CoopMissionSpawnLogic: applied spectator selection request. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " TeamIndex=" + (missionPeer.Team?.TeamIndex ?? -1) +
                " Source=" + source);
            return true;
        }

        private static bool TryApplySelectionIntentToPeer(
            Mission mission,
            MissionPeer missionPeer,
            BattleSideEnum requestedSide,
            string troopOrEntryId,
            string source)
        {
            if (mission == null || missionPeer == null || !GameNetwork.IsServer)
                return false;

            bool applied = false;
            bool peerOccupiesActiveCoopLife = IsPeerOccupyingActiveCoopLife(missionPeer);
            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            BattleSideEnum assignedSide = CoopBattleAuthorityState.GetAssignedSide(missionPeer);
            BattleSideEnum runtimeSide =
                missionPeer.Team != null && !ReferenceEquals(missionPeer.Team, mission.SpectatorTeam)
                    ? missionPeer.Team.Side
                    : BattleSideEnum.None;
            BattleSideEnum committedSide = assignedSide != BattleSideEnum.None ? assignedSide : runtimeSide;
            if (requestedSide != BattleSideEnum.None &&
                currentPhase >= CoopBattlePhase.BattleActive &&
                currentPhase < CoopBattlePhase.BattleEnded &&
                committedSide != BattleSideEnum.None &&
                committedSide != requestedSide &&
                peerOccupiesActiveCoopLife)
            {
                NetworkCommunicator peer = missionPeer.GetNetworkPeer();
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred cross-side selection until peer leaves active coop life. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " CurrentSide=" + committedSide +
                    " RequestedSide=" + requestedSide +
                    " Phase=" + currentPhase +
                    " Source=" + source);
            }

            bool deferCrossSideSelectionWhileActive =
                peerOccupiesActiveCoopLife &&
                requestedSide != BattleSideEnum.None &&
                runtimeSide != BattleSideEnum.None &&
                runtimeSide != requestedSide;
            if (requestedSide != BattleSideEnum.None)
            {
                applied |= CoopBattleAuthorityState.TryRequestSide(missionPeer, requestedSide, source + " side-intent");
                if (deferCrossSideSelectionWhileActive)
                {
                    NetworkCommunicator peer = missionPeer.GetNetworkPeer();
                    if (TryForcePeerRespawnable(mission, missionPeer, source + " cross-side active-life"))
                    {
                        applied |= CoopBattleAuthorityState.TryAssignSide(missionPeer, requestedSide, source + " cross-side forced-respawnable");
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: applied cross-side selection by forcing peer out of active coop life. " +
                            "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                            " PreviousSide=" + runtimeSide +
                            " RequestedSide=" + requestedSide +
                            " Phase=" + currentPhase +
                            " Source=" + source);
                        deferCrossSideSelectionWhileActive = false;
                    }
                    else
                    {
                        CoopBattleSelectionRequestState.Clear(missionPeer, source + " deferred-side-change");
                        CoopBattleSpawnRequestState.Clear(missionPeer, source + " deferred-side-change");
                        return applied;
                    }
                }

                if (HasAllowedRosterForSide(requestedSide))
                    applied |= CoopBattleAuthorityState.TryAssignSide(missionPeer, requestedSide, source + " side-intent");
            }

            if (string.IsNullOrWhiteSpace(troopOrEntryId) || deferCrossSideSelectionWhileActive)
            {
                if (applied)
                {
                    ApplyDerivedPeerLifecycleState(
                        mission,
                        missionPeer,
                        preferSpawnQueued: false,
                        preserveDeadAwaitingRespawn: true,
                        source + " side-intent");
                }

                return applied;
            }

            BattleSideEnum selectionValidationSide = requestedSide != BattleSideEnum.None
                ? requestedSide
                : (committedSide != BattleSideEnum.None
                    ? committedSide
                    : ResolveAuthoritativeSide(missionPeer, mission, source + " select-entry-validation"));
            if (!TryValidateRequestedSelectionTargetIsSelectable(
                    mission,
                    missionPeer,
                    selectionValidationSide,
                    troopOrEntryId,
                    source,
                    out string selectionValidationReason))
            {
                NetworkCommunicator peer = missionPeer.GetNetworkPeer();
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected selection request because target is not currently selectable. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " RequestedTarget=" + troopOrEntryId +
                    " Side=" + selectionValidationSide +
                    " Reason=" + selectionValidationReason +
                    " Source=" + source);
                CoopBattleSelectionRequestState.Clear(missionPeer, source + " invalid-selection-target");
                CoopBattleSpawnRequestState.Clear(missionPeer, source + " invalid-selection-target");
                return applied;
            }

            if (LooksLikeEntryId(troopOrEntryId) && IsEntryClaimedByAnotherPeer(troopOrEntryId, missionPeer))
            {
                NetworkCommunicator peer = missionPeer.GetNetworkPeer();
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected selection request because entry is already claimed by another peer. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " RequestedEntryId=" + troopOrEntryId +
                    " Side=" + requestedSide +
                    " Source=" + source);
                return applied;
            }

            if (CoopBattleAuthorityState.TrySetSelectedEntryId(missionPeer, troopOrEntryId, source + " intent entry"))
            {
                if (ShouldAutoQueueSelectionFromAuthority(missionPeer))
                    CoopBattleSelectionRequestState.TryQueueFromAuthoritySelection(missionPeer, source + " selection-request");
                ApplyDerivedPeerLifecycleState(
                    mission,
                    missionPeer,
                    preferSpawnQueued: false,
                    preserveDeadAwaitingRespawn: true,
                    source + " intent entry");
                return true;
            }

            if (CoopBattleAuthorityState.TrySetSelectedTroopId(missionPeer, troopOrEntryId, source + " intent troop"))
            {
                if (ShouldAutoQueueSelectionFromAuthority(missionPeer))
                    CoopBattleSelectionRequestState.TryQueueFromAuthoritySelection(missionPeer, source + " selection-request");
                ApplyDerivedPeerLifecycleState(
                    mission,
                    missionPeer,
                    preferSpawnQueued: false,
                    preserveDeadAwaitingRespawn: true,
                    source + " intent troop");
                return true;
            }

            return applied;
        }

        private static bool TryValidateRequestedSelectionTargetIsSelectable(
            Mission mission,
            MissionPeer missionPeer,
            BattleSideEnum side,
            string troopOrEntryId,
            string source,
            out string reason)
        {
            reason = string.Empty;
            if (mission == null || missionPeer == null || string.IsNullOrWhiteSpace(troopOrEntryId))
                return false;

            if (!LooksLikeEntryId(troopOrEntryId))
            {
                reason = "non-entry-target";
                return true;
            }

            if (side == BattleSideEnum.None)
            {
                reason = "peer side not assigned";
                return false;
            }

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            IReadOnlyList<string> selectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                side,
                currentPhase,
                missionPeer,
                out string selectableSource);
            if (selectableEntryIds == null || selectableEntryIds.Count == 0)
            {
                reason =
                    "no selectable entries available" +
                    " | selectableSource=" + selectableSource +
                    " | phase=" + currentPhase;
                return false;
            }

            if (!IsExplicitSelectableSourceReady(currentPhase, selectableSource))
            {
                reason =
                    "selectable source not ready" +
                    " | selectableSource=" + selectableSource +
                    " | phase=" + currentPhase;
                return false;
            }

            if (!selectableEntryIds.Contains(troopOrEntryId, StringComparer.Ordinal))
            {
                reason =
                    "entry not present in live selectable set" +
                    " | selectableSource=" + selectableSource +
                    " | phase=" + currentPhase +
                    " | selectableCount=" + selectableEntryIds.Count;
                return false;
            }

            return true;
        }

        private static bool TryQueueSpawnIntentForPeer(Mission mission, MissionPeer missionPeer, string source)
        {
            if (mission == null || missionPeer == null || !GameNetwork.IsServer)
                return false;

            if (missionPeer.ControlledAgent != null)
                return false;

            CoopBattleSelectionRequestState.TryQueueFromAuthoritySelection(missionPeer, source + " selection-request");
            if (!CoopBattleSelectionRequestState.TryGetRequest(missionPeer, out CoopBattleSelectionRequestState.PeerSelectionRequestState selectionRequest))
                return false;

            BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, source + " spawn-ready");
            if (!TryResolvePeerSpawnAvailability(
                    mission,
                    missionPeer,
                    authoritativeSide,
                    out CoopBattlePhase currentPhase,
                    out IReadOnlyList<string> selectableEntryIds,
                    out string selectableSource,
                    out string readinessSource,
                    out int attackerActive,
                    out int defenderActive,
                    out string spawnAvailabilityReason))
            {
                NetworkCommunicator peer = missionPeer.GetNetworkPeer();
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected spawn request because peer is not spawn-ready. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " Side=" + authoritativeSide +
                    " Phase=" + currentPhase +
                    " Reason=" + spawnAvailabilityReason +
                    " SelectableSource=" + selectableSource +
                    " SelectableCount=" + (selectableEntryIds?.Count ?? 0) +
                    " ArmiesReadySource=" + readinessSource +
                    " AttackerActive=" + attackerActive +
                    " DefenderActive=" + defenderActive +
                    " Source=" + source);
                return false;
            }

            if (!string.IsNullOrWhiteSpace(selectionRequest.EntryId) &&
                !selectableEntryIds.Contains(selectionRequest.EntryId, StringComparer.Ordinal))
            {
                NetworkCommunicator peer = missionPeer.GetNetworkPeer();
                ModLogger.Info(
                    "CoopMissionSpawnLogic: rejected spawn request because current entry is not selectable. " +
                    "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                    " Side=" + authoritativeSide +
                    " EntryId=" + selectionRequest.EntryId +
                    " SelectableSource=" + selectableSource +
                    " SelectableCount=" + selectableEntryIds.Count +
                    " Phase=" + currentPhase +
                    " Source=" + source);
                return false;
            }

            if (!CoopBattleSpawnRequestState.TryQueueFromSelectionRequest(selectionRequest, source))
                return false;

            if (!CoopBattleSpawnRequestState.TryGetPendingRequest(missionPeer, out CoopBattleSpawnRequestState.PeerSpawnRequestState pendingRequest))
                return false;

            CoopBattleSpawnRuntimeState.MarkPending(pendingRequest);
            ApplyDerivedPeerLifecycleState(
                mission,
                missionPeer,
                preferSpawnQueued: true,
                preserveDeadAwaitingRespawn: true,
                source + " pending-request");
            return true;
        }

        private static MissionPeer ResolveExactCampaignBootstrapPeer(Mission mission)
        {
            if (mission == null || GameNetwork.NetworkPeers == null)
                return null;

            MissionPeer hostedLocalPeer = ResolveHostedLocalMissionPeer(mission);
            if (hostedLocalPeer != null && HasBootstrapReadySide(hostedLocalPeer, mission, "exact-native-bootstrap-hosted-local"))
                return hostedLocalPeer;

            MissionPeer fallbackPeer = null;
            MissionPeer sideAssignedPeer = null;
            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null)
                    continue;

                if (fallbackPeer == null)
                    fallbackPeer = missionPeer;

                CoopBattleAuthorityState.PeerSelectionState selectionState =
                    CoopBattleAuthorityState.GetSelectionState(missionPeer);
                bool hasCommittedSelection =
                    !string.IsNullOrWhiteSpace(selectionState.EntryId) ||
                    !string.IsNullOrWhiteSpace(selectionState.TroopId) ||
                    CoopBattleSpawnRequestState.HasPendingRequest(missionPeer);

                BattleSideEnum authoritativeSide = selectionState.Side != BattleSideEnum.None
                    ? selectionState.Side
                    : selectionState.RequestedSide;
                if (authoritativeSide == BattleSideEnum.None)
                    authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, "exact-native-bootstrap-peer-candidate");

                if (!HasAllowedRosterForSide(authoritativeSide))
                    continue;

                if (hasCommittedSelection)
                    return missionPeer;

                if (sideAssignedPeer == null)
                    sideAssignedPeer = missionPeer;
            }

            return sideAssignedPeer ?? fallbackPeer;
        }

        private static bool TryResolveExactCampaignBootstrapSide(
            Mission mission,
            MissionPeer missionPeer,
            string source,
            out BattleSideEnum bootstrapSide,
            out string reason)
        {
            bootstrapSide = BattleSideEnum.None;
            reason = "bootstrap-side-unresolved";

            if (!IsBattleSnapshotReadyForMaterialization(mission, out string readinessSummary))
            {
                reason = "battle-snapshot-not-ready " + readinessSummary;
                return false;
            }

            if (mission != null && missionPeer != null)
            {
                BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, source + " peer");
                if (HasAllowedRosterForSide(authoritativeSide))
                {
                    bootstrapSide = authoritativeSide;
                    reason = "peer-authoritative-side";
                    return true;
                }
            }

            bootstrapSide = ResolveDeterministicBootstrapSide(mission);
            if (bootstrapSide != BattleSideEnum.None)
            {
                reason = "deterministic-side";
                return true;
            }

            reason = "bootstrap-side-none";
            return false;
        }

        private static BattleSideEnum ResolveDeterministicBootstrapSide(Mission mission)
        {
            BattleSideEnum missionPlayerTeamSide =
                mission?.PlayerTeam != null && !ReferenceEquals(mission.PlayerTeam, mission.SpectatorTeam)
                    ? mission.PlayerTeam.Side
                    : BattleSideEnum.None;
            if (HasAllowedRosterForSide(missionPlayerTeamSide))
                return missionPlayerTeamSide;

            bool hasAttackerRoster = HasAllowedRosterForSide(BattleSideEnum.Attacker);
            bool hasDefenderRoster = HasAllowedRosterForSide(BattleSideEnum.Defender);
            if (hasAttackerRoster)
                return BattleSideEnum.Attacker;

            if (hasDefenderRoster)
                return BattleSideEnum.Defender;

            return BattleSideEnum.None;
        }

        private static MissionPeer ResolvePrimaryControllablePeer(Mission mission)
        {
            if (mission == null || GameNetwork.NetworkPeers == null)
                return null;

            MissionPeer hostedLocalPeer = ResolveHostedLocalMissionPeer(mission);
            if (hostedLocalPeer != null)
                return hostedLocalPeer;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null)
                    continue;

                return missionPeer;
            }

            return null;
        }

        private static bool TryResolveLocalPeerAuthoritativeEntryIdForClientVisualOverlay(Agent agent, out string entryId)
        {
            entryId = null;
            if (agent == null || GameNetwork.IsServer || !GameNetwork.IsClient)
                return false;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            if (localMissionPeer == null)
                return false;

            bool belongsToLocalPeer =
                ReferenceEquals(localMissionPeer.ControlledAgent, agent) ||
                ReferenceEquals(agent.MissionPeer, localMissionPeer);
            if (!belongsToLocalPeer)
                return false;

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot status = CoopBattleEntryStatusBridgeFile.ReadStatus();
            if (TryResolveKnownEntryIdForClientVisualOverlay(status?.SpawnRequestEntryId, out entryId) ||
                TryResolveKnownEntryIdForClientVisualOverlay(status?.SelectionRequestEntryId, out entryId) ||
                TryResolveKnownEntryIdForClientVisualOverlay(status?.SelectedEntryId, out entryId) ||
                TryResolveKnownEntryIdForClientVisualOverlay(status?.IntentTroopOrEntryId, out entryId))
            {
                return true;
            }

            CoopBattleSelectionBridgeFile.SelectionBridgeSnapshot currentSelection =
                CoopBattleSelectionBridgeFile.ReadCurrentSelection();
            return TryResolveKnownEntryIdForClientVisualOverlay(currentSelection?.TroopOrEntryId, out entryId);
        }

        private static bool TryResolveUniqueHeroEntryIdForClientVisualOverlay(Agent agent, out string entryId)
        {
            entryId = null;
            if (agent == null || agent.Team == null || agent.Team.Side == BattleSideEnum.None)
                return false;

            string troopId = agent.Character?.StringId;
            if (string.IsNullOrWhiteSpace(troopId))
                return false;

            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.EntriesById == null || runtimeState.EntriesById.Count == 0)
                return false;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            bool isLocalPeerAgent =
                localMissionPeer != null &&
                (ReferenceEquals(localMissionPeer.ControlledAgent, agent) ||
                 ReferenceEquals(agent.MissionPeer, localMissionPeer));
            if (isLocalPeerAgent)
                return false;

            List<RosterEntryState> heroCandidates = runtimeState.EntriesById.Values
                .Where(entryState =>
                    entryState != null &&
                    IsHeroEntryEligibleForExactPersonalPerks(entryState) &&
                    DoesClientVisualOverlayEntryMatchAgentSide(entryState, agent.Team.Side) &&
                    DoesClientVisualOverlayEntryMatchAgentTroop(entryState, troopId))
                .ToList();
            if (heroCandidates.Count == 0)
                return false;

            List<RosterEntryState> exactSupportedCandidates = heroCandidates
                .Where(entryState =>
                {
                    ExactEntryCompatibilityDiagnostic diagnostic = GetExactEntryCompatibilityDiagnostic(entryState);
                    return IsMaterializedExactEntryCharacterSupported(diagnostic);
                })
                .ToList();
            if (exactSupportedCandidates.Count == 1)
            {
                entryId = exactSupportedCandidates[0].EntryId;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: resolved remote client exact visual overlay entry via unique exact hero match. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TeamSide=" + agent.Team.Side +
                    " TroopId=" + troopId);
                return true;
            }

            if (heroCandidates.Count == 1)
            {
                entryId = heroCandidates[0].EntryId;
                ModLogger.Info(
                    "CoopMissionSpawnLogic: resolved remote client exact visual overlay entry via unique hero match. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " TeamSide=" + agent.Team.Side +
                    " TroopId=" + troopId);
                return true;
            }

            ModLogger.Info(
                "CoopMissionSpawnLogic: skipped remote client exact visual overlay hero match because it was ambiguous. " +
                "AgentIndex=" + agent.Index +
                " TeamSide=" + agent.Team.Side +
                " TroopId=" + troopId +
                " HeroCandidateCount=" + heroCandidates.Count +
                " ExactSupportedCandidateCount=" + exactSupportedCandidates.Count);
            return false;
        }

        internal static bool TryResolveClientStrictExactHeroCreateAgentContract(
            CreateAgent createAgent,
            out string entryId,
            out RosterEntryState entryState,
            out ExactTransferSpawnContract contract,
            out ExactTransferValidationResult validation,
            out string resolutionSource)
        {
            entryId = null;
            entryState = null;
            contract = null;
            validation = null;
            resolutionSource = null;

            if (GameNetwork.IsServer ||
                createAgent == null ||
                createAgent.MountAgentIndex < 0)
            {
                return false;
            }

            if (!CoopMissionNetworkBridge.IsClientCurrentBattleSnapshotApplied(out string snapshotReadinessSummary))
            {
                resolutionSource = "battle-snapshot-not-applied";
                ModLogger.Info(
                    "CoopMissionSpawnLogic: deferred strict client exact CreateAgent contract resolution until current battle snapshot is applied. " +
                    "AgentIndex=" + createAgent.AgentIndex +
                    " MountAgentIndex=" + createAgent.MountAgentIndex +
                    " Reason=" + snapshotReadinessSummary);
                return false;
            }

            if (TryResolveClientAuthoritativeMaterializedEntryId(createAgent.AgentIndex, out string authoritativeEntryId))
            {
                RosterEntryState authoritativeEntryState = BattleSnapshotRuntimeState.GetEntryState(authoritativeEntryId);
                if (authoritativeEntryState != null && authoritativeEntryState.IsHero && authoritativeEntryState.IsMounted)
                {
                    entryState = authoritativeEntryState;
                    entryId = authoritativeEntryId;
                    resolutionSource = "authoritative-materialized-entry";
                    contract = ExactTransferContractBuilder.Build(
                        entryState,
                        isPlayerControlledOrigin: false,
                        teamIndex: createAgent.TeamIndex,
                        formationIndex: createAgent.FormationIndex);
                    validation = ExactTransferContractValidator.Validate(contract);
                    ExactTransferContractRuntimeCache.RegisterClientObservedContract(
                        contract,
                        validation,
                        createAgent.AgentIndex,
                        createAgent.MountAgentIndex,
                        "client strict CreateAgent contract resolve: " + resolutionSource);
                    return true;
                }
            }

            string payloadCharacterId = createAgent.Character?.StringId;
            if (TryResolveClientStrictExactHeroCreateAgentEntryFromPayloadDiagnostics(
                    createAgent,
                    payloadCharacterId,
                    out entryState,
                    out resolutionSource))
            {
                entryId = entryState.EntryId;
                contract = ExactTransferContractBuilder.Build(
                    entryState,
                    isPlayerControlledOrigin: false,
                    teamIndex: createAgent.TeamIndex,
                    formationIndex: createAgent.FormationIndex);
                validation = ExactTransferContractValidator.Validate(contract);
                ExactTransferContractRuntimeCache.RegisterClientObservedContract(
                    contract,
                    validation,
                    createAgent.AgentIndex,
                    createAgent.MountAgentIndex,
                    "client strict CreateAgent contract resolve: " + (resolutionSource ?? "unknown"));

                ModLogger.Info(
                    "CoopMissionSpawnLogic: resolved strict client exact CreateAgent contract via payload diagnostics. " +
                    "AgentIndex=" + createAgent.AgentIndex +
                    " MountAgentIndex=" + createAgent.MountAgentIndex +
                    " EntryId=" + (entryId ?? "null") +
                    " PayloadCharacterId=" + (payloadCharacterId ?? "null") +
                    " ResolutionSource=" + (resolutionSource ?? "null") +
                    " " + ExactTransferContractRuntimeCache.BuildContractSummary(entryId) +
                    " " + ExactTransferContractRuntimeCache.BuildValidationSummary(entryId) +
                    " " + ExactTransferContractRuntimeCache.BuildRuntimeStateSummary(entryId));
                return true;
            }

            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.EntriesById == null || runtimeState.EntriesById.Count == 0)
                return false;

            BattleSideEnum payloadSide = ResolveCreateAgentPayloadBattleSide(createAgent.TeamIndex);
            if (payloadSide == BattleSideEnum.None)
                return false;

            List<RosterEntryState> heroCandidates = runtimeState.EntriesById.Values
                .Where(candidate =>
                    candidate != null &&
                    IsHeroEntryEligibleForExactPersonalPerks(candidate) &&
                    candidate.IsMounted &&
                    DoesClientVisualOverlayEntryMatchAgentSide(candidate, payloadSide) &&
                    DoesClientStrictExactHeroCreateAgentEntryMatchPayload(candidate, payloadCharacterId))
                .ToList();
            if (heroCandidates.Count == 0)
                return false;

            List<RosterEntryState> exactSupportedCandidates = heroCandidates
                .Where(candidate =>
                {
                    ExactEntryCompatibilityDiagnostic diagnostic = GetExactEntryCompatibilityDiagnostic(candidate);
                    return IsMaterializedExactEntryCharacterSupported(diagnostic);
                })
                .ToList();

            if (exactSupportedCandidates.Count == 1)
            {
                entryState = exactSupportedCandidates[0];
                resolutionSource = "unique-exact-supported-mounted-hero-payload-match";
            }
            else if (TryResolveLocalSelectedStrictExactHeroCreateAgentEntry(
                         heroCandidates,
                         exactSupportedCandidates,
                         out RosterEntryState localSelectedEntry))
            {
                entryState = localSelectedEntry;
                resolutionSource = "local-selected-mounted-hero-payload-match";
            }
            else if (heroCandidates.Count == 1)
            {
                entryState = heroCandidates[0];
                resolutionSource = "unique-mounted-hero-payload-match";
            }
            else
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: skipped strict client exact CreateAgent contract resolution because mounted remote hero payload was ambiguous. " +
                    "AgentIndex=" + createAgent.AgentIndex +
                    " TeamIndex=" + createAgent.TeamIndex +
                    " PayloadCharacterId=" + (payloadCharacterId ?? "null") +
                    " HeroCandidateCount=" + heroCandidates.Count +
                    " ExactSupportedCandidateCount=" + exactSupportedCandidates.Count);
                return false;
            }

            entryId = entryState.EntryId;
            contract = ExactTransferContractBuilder.Build(
                entryState,
                isPlayerControlledOrigin: false,
                teamIndex: createAgent.TeamIndex,
                formationIndex: createAgent.FormationIndex);
            validation = ExactTransferContractValidator.Validate(contract);
            ExactTransferContractRuntimeCache.RegisterClientObservedContract(
                contract,
                validation,
                createAgent.AgentIndex,
                createAgent.MountAgentIndex,
                "client strict CreateAgent contract resolve: " + (resolutionSource ?? "unknown"));

            ModLogger.Info(
                "CoopMissionSpawnLogic: resolved strict client exact CreateAgent contract. " +
                "AgentIndex=" + createAgent.AgentIndex +
                " MountAgentIndex=" + createAgent.MountAgentIndex +
                " EntryId=" + (entryId ?? "null") +
                " PayloadCharacterId=" + (payloadCharacterId ?? "null") +
                " ResolutionSource=" + (resolutionSource ?? "null") +
                " " + ExactTransferContractRuntimeCache.BuildContractSummary(entryId) +
                " " + ExactTransferContractRuntimeCache.BuildValidationSummary(entryId) +
                " " + ExactTransferContractRuntimeCache.BuildRuntimeStateSummary(entryId));
            return true;
        }

        private static void EnsureAllowedControlEntryIdsRegistered(
            BattleSideEnum side,
            BattleRosterEntryProjectionState entryProjection,
            string spawnTemplateId)
        {
            if (entryProjection == null || string.IsNullOrWhiteSpace(entryProjection.EntryId))
                return;

            if (!AllowedControlEntryIdsBySide.TryGetValue(side, out List<string> sideEntryIds))
            {
                sideEntryIds = new List<string>();
                AllowedControlEntryIdsBySide[side] = sideEntryIds;
            }

            if (!AllowedControlEntriesBySide.TryGetValue(side, out List<BattleRosterEntryProjectionState> sideEntries))
            {
                sideEntries = new List<BattleRosterEntryProjectionState>();
                AllowedControlEntriesBySide[side] = sideEntries;
            }

            if (!AllowedControlEntryIds.Contains(entryProjection.EntryId))
                AllowedControlEntryIds.Add(entryProjection.EntryId);
            if (!sideEntryIds.Contains(entryProjection.EntryId))
                sideEntryIds.Add(entryProjection.EntryId);
            if (!sideEntries.Any(entry => string.Equals(entry?.EntryId, entryProjection.EntryId, StringComparison.Ordinal)))
                sideEntries.Add(entryProjection);

            if (string.IsNullOrWhiteSpace(spawnTemplateId))
                return;

            if (!AllowedControlTroopIds.Contains(spawnTemplateId))
                AllowedControlTroopIds.Add(spawnTemplateId);

            if (!AllowedControlTroopIdsBySide.TryGetValue(side, out List<string> sideTroopIds))
            {
                sideTroopIds = new List<string>();
                AllowedControlTroopIdsBySide[side] = sideTroopIds;
            }

            if (!sideTroopIds.Contains(spawnTemplateId))
                sideTroopIds.Add(spawnTemplateId);
        }

        private static bool TryResolveClientStrictExactHeroCreateAgentEntryFromPayloadDiagnostics(
            CreateAgent createAgent,
            string payloadCharacterId,
            out RosterEntryState entryState,
            out string resolutionSource)
        {
            entryState = null;
            resolutionSource = null;

            if (createAgent == null || createAgent.MountAgentIndex < 0)
                return false;

            if (!ExactCreateAgentCorridorDiagnostics.TryResolveClientCreateAgentPayloadEntryId(
                    createAgent,
                    out string candidateEntryId,
                    out string resolutionState,
                    out string _))
            {
                return false;
            }

            if (string.IsNullOrWhiteSpace(candidateEntryId))
                return false;

            RosterEntryState candidateEntryState = BattleSnapshotRuntimeState.GetEntryState(candidateEntryId);
            if (candidateEntryState == null ||
                !IsHeroEntryEligibleForExactPersonalPerks(candidateEntryState) ||
                !candidateEntryState.IsMounted)
            {
                return false;
            }

            if (!DoesClientStrictExactHeroCreateAgentEntryMatchPayload(candidateEntryState, payloadCharacterId))
                return false;

            entryState = candidateEntryState;
            resolutionSource = "payload-diagnostics-" + (resolutionState ?? "resolved");
            return true;
        }

        private static bool TryResolveLocalSelectedStrictExactHeroCreateAgentEntry(
            IReadOnlyCollection<RosterEntryState> heroCandidates,
            IReadOnlyCollection<RosterEntryState> exactSupportedCandidates,
            out RosterEntryState entryState)
        {
            entryState = null;
            if ((heroCandidates == null || heroCandidates.Count == 0) &&
                (exactSupportedCandidates == null || exactSupportedCandidates.Count == 0))
            {
                return false;
            }

            if (!TryResolveLocalSelectedEntryIdForStrictCreateAgent(out string selectedEntryId))
                return false;

            entryState = exactSupportedCandidates?.FirstOrDefault(candidate =>
                candidate != null &&
                string.Equals(candidate.EntryId, selectedEntryId, StringComparison.Ordinal));
            if (entryState != null)
                return true;

            entryState = heroCandidates?.FirstOrDefault(candidate =>
                candidate != null &&
                string.Equals(candidate.EntryId, selectedEntryId, StringComparison.Ordinal));
            return entryState != null;
        }

        internal static bool TryResolveLocalSelectedEntryIdForBattleMapCommander(out string entryId)
        {
            return TryResolveLocalSelectedEntryIdForBattleMapCommander(out entryId, out _);
        }

        internal static bool TryResolveLocalSelectedEntryIdForBattleMapCommander(out string entryId, out string source)
        {
            return TryResolveLocalSelectedEntryIdForStrictCreateAgent(out entryId, out source);
        }

        private static bool TryResolveLocalSelectedEntryIdForStrictCreateAgent(out string entryId)
        {
            return TryResolveLocalSelectedEntryIdForStrictCreateAgent(out entryId, out _);
        }

        private static bool TryResolveLocalSelectedEntryIdForStrictCreateAgent(out string entryId, out string source)
        {
            entryId = null;
            source = null;

            MissionPeer localMissionPeer = GameNetwork.MyPeer?.GetComponent<MissionPeer>();
            if (localMissionPeer != null)
            {
                if (CoopBattleAuthorityState.TryGetExplicitSelectedEntryId(localMissionPeer, out string explicitEntryId) &&
                    TryResolveKnownEntryIdForClientVisualOverlay(explicitEntryId, out entryId))
                {
                    source = "authority-explicit-selected-entry";
                    return true;
                }

                if (TryResolveKnownEntryIdForClientVisualOverlay(
                        CoopBattleAuthorityState.GetSelectedEntryId(localMissionPeer),
                        out entryId))
                {
                    source = "authority-selected-entry";
                    return true;
                }
            }

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot status = CoopBattleEntryStatusBridgeFile.ReadStatus();
            if (TryResolveKnownEntryIdForClientVisualOverlay(status?.SpawnRequestEntryId, out entryId))
            {
                source = "status-spawn-request";
                return true;
            }

            if (TryResolveKnownEntryIdForClientVisualOverlay(status?.SelectionRequestEntryId, out entryId))
            {
                source = "status-selection-request";
                return true;
            }

            if (TryResolveKnownEntryIdForClientVisualOverlay(status?.SelectedEntryId, out entryId))
            {
                source = "status-selected-entry";
                return true;
            }

            if (TryResolveKnownEntryIdForClientVisualOverlay(status?.IntentTroopOrEntryId, out entryId))
            {
                source = "status-intent-entry";
                return true;
            }

            CoopBattleSelectionBridgeFile.SelectionBridgeSnapshot currentSelection =
                CoopBattleSelectionBridgeFile.ReadCurrentSelection();
            bool resolved = TryResolveKnownEntryIdForClientVisualOverlay(currentSelection?.TroopOrEntryId, out entryId);
            if (resolved)
                source = "selection-bridge";

            return resolved;
        }

        private static bool DoesClientStrictExactHeroCreateAgentEntryMatchPayload(
            RosterEntryState entryState,
            string payloadCharacterId)
        {
            if (entryState == null || string.IsNullOrWhiteSpace(payloadCharacterId))
                return false;

            foreach (string candidateCharacterId in EnumerateClientStrictExactHeroCreateAgentCandidateCharacterIds(entryState))
            {
                if (string.Equals(candidateCharacterId, payloadCharacterId, StringComparison.OrdinalIgnoreCase))
                    return true;
            }

            return false;
        }

        private static IEnumerable<string> EnumerateClientStrictExactHeroCreateAgentCandidateCharacterIds(RosterEntryState entryState)
        {
            if (entryState == null)
                yield break;

            var yielded = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
            foreach (string candidateCharacterId in new[]
                     {
                         BattleSnapshotRuntimeState.TryResolveCharacterObject(entryState.EntryId)?.StringId,
                         entryState.SpawnTemplateId,
                         entryState.CharacterId,
                         entryState.OriginalCharacterId,
                         entryState.HeroTemplateId
                     })
            {
                if (string.IsNullOrWhiteSpace(candidateCharacterId) || !yielded.Add(candidateCharacterId))
                    continue;

                yield return candidateCharacterId;
            }
        }

        private static BattleSideEnum ResolveCreateAgentPayloadBattleSide(int teamIndex)
        {
            Team missionTeam = Mission.MissionNetworkHelper.GetTeamFromTeamIndex(teamIndex);
            if (missionTeam != null && missionTeam.Side != BattleSideEnum.None)
                return missionTeam.Side;

            if (teamIndex == 0)
                return BattleSideEnum.Attacker;

            if (teamIndex == 1)
                return BattleSideEnum.Defender;

            return BattleSideEnum.None;
        }

        private static bool DoesClientVisualOverlayEntryMatchAgentSide(RosterEntryState entryState, BattleSideEnum teamSide)
        {
            if (entryState == null || teamSide == BattleSideEnum.None)
                return false;

            string sideId = entryState.SideId ?? string.Empty;
            if (teamSide == BattleSideEnum.Attacker)
                return string.Equals(sideId, "Attacker", StringComparison.OrdinalIgnoreCase);

            if (teamSide == BattleSideEnum.Defender)
                return string.Equals(sideId, "Defender", StringComparison.OrdinalIgnoreCase);

            return false;
        }

        private static bool TryResolveKnownEntryIdForClientVisualOverlay(string candidateEntryId, out string entryId)
        {
            entryId = null;
            if (string.IsNullOrWhiteSpace(candidateEntryId))
                return false;

            string normalizedEntryId = candidateEntryId.Trim();
            if (normalizedEntryId.IndexOf('|') < 0 || BattleSnapshotRuntimeState.GetEntryState(normalizedEntryId) == null)
                return false;

            entryId = normalizedEntryId;
            return true;
        }

        private static MissionPeer ResolveHostedLocalMissionPeer(Mission mission)
        {
            if (mission == null || GameNetwork.NetworkPeers == null)
                return null;

            if (!HostSelfJoinRedirectState.TryResolvePersistedHostedPeerUserName(out string hostedLocalUserName) ||
                string.IsNullOrWhiteSpace(hostedLocalUserName))
            {
                return null;
            }

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null ||
                    peer.IsServerPeer ||
                    !peer.IsConnectionActive ||
                    !peer.IsSynchronized ||
                    !string.Equals(peer.UserName, hostedLocalUserName, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer != null)
                    return missionPeer;
            }

            return null;
        }

        private static bool IsBattleStartAuthorityPeer(Mission mission, MissionPeer missionPeer)
        {
            if (mission == null || missionPeer == null)
                return false;

            MissionPeer hostedLocalPeer = ResolveHostedLocalMissionPeer(mission);
            return hostedLocalPeer != null && ReferenceEquals(hostedLocalPeer, missionPeer);
        }

        private static bool HasBootstrapReadySide(MissionPeer missionPeer, Mission mission, string source)
        {
            if (missionPeer == null || mission == null)
                return false;

            CoopBattleAuthorityState.PeerSelectionState selectionState =
                CoopBattleAuthorityState.GetSelectionState(missionPeer);
            BattleSideEnum authoritativeSide = selectionState.Side != BattleSideEnum.None
                ? selectionState.Side
                : selectionState.RequestedSide;
            if (authoritativeSide == BattleSideEnum.None)
                authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, source);

            return HasAllowedRosterForSide(authoritativeSide);
        }

        private static IReadOnlyList<string> ResolveSelectableEntryIdsForStatus(
            Mission mission,
            BattleSideEnum side,
            CoopBattlePhase currentPhase,
            MissionPeer viewingPeer,
            out string source)
        {
            source = "none";
            if (side == BattleSideEnum.None)
                return Array.Empty<string>();

            if (currentPhase < CoopBattlePhase.BattleActive)
            {
                bool useMaterializedPrebattleEntries =
                    currentPhase >= CoopBattlePhase.PreBattleHold &&
                    HasTrackedBattlefieldEntryStateForSide(mission, side);
                if (useMaterializedPrebattleEntries)
                {
                    IReadOnlyList<string> livePrebattleEntryIds = FilterClaimedSelectableEntryIdsForPeer(
                        GetLiveSelectableEntryIdsSnapshot(mission, side),
                        viewingPeer,
                        "live-prebattle-materialized",
                        out string liveSource);

                    IReadOnlyList<string> allowedPrebattleEntryIds = FilterClaimedSelectableEntryIdsForPeer(
                        GetAllowedSelectableEntryIdsForSide(side),
                        viewingPeer,
                        "allowed-prebattle-materialized",
                        out _);

                    if (livePrebattleEntryIds.Count > 0)
                    {
                        IReadOnlyList<string> mergedPrebattleEntryIds = MergeSelectableEntryIdsForPrebattle(
                            side,
                            livePrebattleEntryIds,
                            allowedPrebattleEntryIds);
                        source = mergedPrebattleEntryIds.Count > livePrebattleEntryIds.Count
                            ? "live-prebattle-materialized-allowed-merged"
                            : liveSource;
                        return mergedPrebattleEntryIds;
                    }

                    return FilterClaimedSelectableEntryIdsForPeer(
                        GetAllowedSelectableEntryIdsForSide(side),
                        viewingPeer,
                        "allowed-prebattle-live-empty-fallback",
                        out source);
                }

                return FilterClaimedSelectableEntryIdsForPeer(
                    GetAllowedSelectableEntryIdsForSide(side),
                    viewingPeer,
                    "allowed-prebattle",
                    out source);
            }

            List<string> liveSelectableEntryIds = GetLiveSelectableEntryIdsSnapshot(mission, side);
            if (liveSelectableEntryIds.Count > 0)
            {
                source = "live-eligible";
                return liveSelectableEntryIds;
            }

            if (currentPhase >= CoopBattlePhase.BattleActive || HasTrackedBattlefieldEntryStateForSide(mission, side))
            {
                source = "live-empty";
                return Array.Empty<string>();
            }

            return FilterClaimedSelectableEntryIdsForPeer(
                GetAllowedSelectableEntryIdsForSide(side),
                viewingPeer,
                "allowed-fallback",
                out source);
        }

        private static bool TryResolveBattleDataReadinessForPeer(
            Mission mission,
            MissionPeer missionPeer,
            CoopBattlePhase currentPhase,
            BattleSideEnum statusSide,
            out string readinessStage,
            out string readinessReason)
        {
            readinessStage = "Loading";
            readinessReason = "Loading battle data...";

            if (mission == null || missionPeer == null)
            {
                readinessReason = "Loading battle data...";
                return false;
            }

            if (currentPhase < CoopBattlePhase.PreBattleHold)
            {
                readinessReason = "Loading battle data...";
                return false;
            }

            if (currentPhase >= CoopBattlePhase.BattleEnded)
            {
                readinessStage = "BattleEnded";
                readinessReason = "Battle data unavailable.";
                return false;
            }

            if (!AreBattlefieldArmiesReadyForStart(mission, out _, out _, out _))
            {
                readinessReason = "Loading battle data...";
                return false;
            }

            if (!CoopMissionNetworkBridge.HasPeerAcknowledgedCurrentBattleSnapshot(
                    missionPeer,
                    out int expectedBattleSnapshotTransmissionId,
                    out int acknowledgedBattleSnapshotTransmissionId))
            {
                readinessReason = "Loading battle data...";
                TryLogBattleSnapshotAckReadinessBlock(
                    missionPeer,
                    currentPhase,
                    statusSide,
                    expectedBattleSnapshotTransmissionId,
                    acknowledgedBattleSnapshotTransmissionId);
                return false;
            }

            if (CoopBattlePeerReconnectState.TryGetActiveBattleReconnectFinalizeGateState(
                    missionPeer,
                    out CoopBattlePeerReconnectState.ActiveBattleReconnectFinalizeGateState reconnectFinalizeGateState) &&
                !reconnectFinalizeGateState.ReadyAcknowledged)
            {
                readinessStage = "ReconnectFinalize";
                readinessReason = "Finalizing reconnect to active battle...";
                TryLogReconnectFinalizeReadinessBlock(
                    missionPeer,
                    currentPhase,
                    statusSide,
                    reconnectFinalizeGateState);
                return false;
            }

            if (statusSide != BattleSideEnum.None)
            {
                if (!TryResolveSideBattleDataReadyForPeer(
                        mission,
                        missionPeer,
                        statusSide,
                        currentPhase,
                        out _,
                        out _,
                        out _))
                {
                    readinessStage = currentPhase < CoopBattlePhase.BattleActive
                        ? "Loading"
                        : "RespawnSelection";
                    readinessReason = "Loading battle data...";
                    return false;
                }

                readinessStage = currentPhase < CoopBattlePhase.BattleActive
                    ? "UnitSelection"
                    : "RespawnSelection";
                readinessReason = "Battle data ready.";
                return true;
            }

            bool hasReadySide = false;
            foreach (BattleSideEnum side in new[] { BattleSideEnum.Attacker, BattleSideEnum.Defender })
            {
                if (!HasAllowedRosterForSide(side))
                    continue;

                if (!TryResolveSideBattleDataReadyForPeer(
                        mission,
                        missionPeer,
                        side,
                        currentPhase,
                        out _,
                        out _,
                        out _))
                {
                    readinessReason = "Loading battle data...";
                    return false;
                }

                hasReadySide = true;
            }

            if (!hasReadySide)
            {
                readinessReason = "Loading battle data...";
                return false;
            }

            readinessStage = "SideSelection";
            readinessReason = "Battle data ready.";
            return true;
        }

        private static void TryLogBattleSnapshotAckReadinessBlock(
            MissionPeer missionPeer,
            CoopBattlePhase currentPhase,
            BattleSideEnum statusSide,
            int expectedTransmissionId,
            int acknowledgedTransmissionId)
        {
            NetworkCommunicator peer = missionPeer?.GetNetworkPeer();
            int peerIndex = peer?.Index ?? -1;
            string logKey =
                expectedTransmissionId + "|" +
                acknowledgedTransmissionId + "|" +
                currentPhase + "|" +
                statusSide;
            if (_lastLoggedBattleSnapshotAckBlockStateByPeer.TryGetValue(peerIndex, out string previousLogKey) &&
                string.Equals(previousLogKey, logKey, StringComparison.Ordinal))
            {
                return;
            }

            _lastLoggedBattleSnapshotAckBlockStateByPeer[peerIndex] = logKey;
            ModLogger.Info(
                "CoopMissionSpawnLogic: battle data readiness blocked until peer acknowledges battle snapshot. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " ExpectedTransmissionId=" + expectedTransmissionId +
                " AcknowledgedTransmissionId=" + acknowledgedTransmissionId +
                " Phase=" + currentPhase +
                " StatusSide=" + statusSide);
        }

        private static void TryLogReconnectFinalizeReadinessBlock(
            MissionPeer missionPeer,
            CoopBattlePhase currentPhase,
            BattleSideEnum statusSide,
            CoopBattlePeerReconnectState.ActiveBattleReconnectFinalizeGateState reconnectFinalizeGateState)
        {
            NetworkCommunicator peer = missionPeer?.GetNetworkPeer();
            int peerIndex = peer?.Index ?? -1;
            string logKey =
                reconnectFinalizeGateState.TransmissionId + "|" +
                reconnectFinalizeGateState.ReadyAcknowledged + "|" +
                currentPhase + "|" +
                statusSide + "|" +
                (reconnectFinalizeGateState.Reason ?? string.Empty);
            if (_lastLoggedReconnectFinalizeBlockStateByPeer.TryGetValue(peerIndex, out string previousLogKey) &&
                string.Equals(previousLogKey, logKey, StringComparison.Ordinal))
            {
                return;
            }

            _lastLoggedReconnectFinalizeBlockStateByPeer[peerIndex] = logKey;
            ModLogger.Info(
                "CoopMissionSpawnLogic: battle data readiness blocked until reconnect finalize gate is acknowledged. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " TransmissionId=" + reconnectFinalizeGateState.TransmissionId +
                " ReadyAcknowledged=" + reconnectFinalizeGateState.ReadyAcknowledged +
                " Reason=" + (reconnectFinalizeGateState.Reason ?? "null") +
                " Phase=" + currentPhase +
                " StatusSide=" + statusSide +
                " ArmedUtc=" + reconnectFinalizeGateState.ArmedUtc.ToString("O"));
        }

        private static bool TryResolveSideBattleDataReadyForPeer(
            Mission mission,
            MissionPeer missionPeer,
            BattleSideEnum side,
            CoopBattlePhase currentPhase,
            out IReadOnlyList<string> selectableEntryIds,
            out string selectableSource,
            out string reason)
        {
            selectableEntryIds = Array.Empty<string>();
            selectableSource = "none";
            reason = string.Empty;

            if (mission == null || missionPeer == null || side == BattleSideEnum.None)
            {
                reason = "missing-side-context";
                return false;
            }

            selectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                side,
                currentPhase,
                missionPeer,
                out selectableSource);
            if (selectableEntryIds == null || selectableEntryIds.Count <= 0)
            {
                reason = "selectable-entries-empty";
                return false;
            }

            if (!IsExplicitSelectableSourceReady(currentPhase, selectableSource))
            {
                reason = "selectable-source-not-ready";
                return false;
            }

            reason = "ready";
            return true;
        }

        private static bool IsExplicitSelectableSourceReady(CoopBattlePhase currentPhase, string selectableSource)
        {
            if (string.IsNullOrWhiteSpace(selectableSource) ||
                currentPhase < CoopBattlePhase.PreBattleHold ||
                currentPhase >= CoopBattlePhase.BattleEnded)
            {
                return false;
            }

            if (selectableSource.StartsWith("live-prebattle-materialized", StringComparison.OrdinalIgnoreCase))
                return true;

            return currentPhase >= CoopBattlePhase.BattleActive &&
                selectableSource.StartsWith("live-eligible", StringComparison.OrdinalIgnoreCase);
        }

        private static IReadOnlyList<string> MergeSelectableEntryIdsForPrebattle(
            BattleSideEnum side,
            IReadOnlyList<string> primaryEntryIds,
            IReadOnlyList<string> fallbackEntryIds)
        {
            var mergedEntryIds = new HashSet<string>(StringComparer.Ordinal);
            if (primaryEntryIds != null)
            {
                foreach (string entryId in primaryEntryIds)
                {
                    if (!string.IsNullOrWhiteSpace(entryId))
                        mergedEntryIds.Add(entryId);
                }
            }

            if (fallbackEntryIds != null)
            {
                foreach (string entryId in fallbackEntryIds)
                {
                    if (!string.IsNullOrWhiteSpace(entryId))
                        mergedEntryIds.Add(entryId);
                }
            }

            if (mergedEntryIds.Count <= 0)
                return Array.Empty<string>();

            return OrderSelectableEntryIds(side, mergedEntryIds);
        }

        private static IReadOnlyList<string> GetAllowedSelectableEntryIdsForSide(BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return Array.Empty<string>();

            return CoopBattleAuthorityState.GetAllowedEntryIds(side)?
                       .Where(entryId => !string.IsNullOrWhiteSpace(entryId))
                       .Distinct(StringComparer.Ordinal)
                       .ToArray()
                   ?? Array.Empty<string>();
        }

        private static IReadOnlyList<string> FilterClaimedSelectableEntryIdsForPeer(
            IReadOnlyList<string> entryIds,
            MissionPeer viewingPeer,
            string baseSource,
            out string source)
        {
            source = baseSource ?? "none";
            if (entryIds == null || entryIds.Count <= 0 || viewingPeer == null)
                return entryIds ?? Array.Empty<string>();

            var filteredEntryIds = new List<string>(entryIds.Count);
            int filteredClaimedCount = 0;
            foreach (string entryId in entryIds)
            {
                if (string.IsNullOrWhiteSpace(entryId))
                    continue;

                if (IsEntryClaimedByAnotherPeer(entryId, viewingPeer))
                {
                    filteredClaimedCount++;
                    continue;
                }

                filteredEntryIds.Add(entryId);
            }

            if (filteredClaimedCount > 0)
                source = (baseSource ?? "none") + "-claim-filtered";

            return filteredEntryIds;
        }

        private static List<string> GetLiveSelectableEntryIdsSnapshot(Mission mission, BattleSideEnum side)
        {
            if (mission?.AllAgents == null || side == BattleSideEnum.None)
                return new List<string>();

            var liveEntryIds = new HashSet<string>(StringComparer.Ordinal);
            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent candidate = mission.AllAgents[i];
                if (!IsSelectableMaterializedArmyAgent(candidate, side, out string entryId))
                    continue;

                liveEntryIds.Add(entryId);
            }

            return OrderSelectableEntryIds(side, liveEntryIds);
        }

        private static bool IsSelectableMaterializedArmyAgent(Agent candidate, BattleSideEnum side, out string entryId)
        {
            entryId = null;
            if (candidate == null ||
                !candidate.IsActive() ||
                candidate.IsMount ||
                candidate.MissionPeer != null ||
                candidate.Controller == AgentControllerType.Player)
            {
                return false;
            }

            return DoesAgentMatchSelectableSide(candidate, side) &&
                   TryResolveSelectableEntryId(candidate, out entryId);
        }

        private static bool DoesAgentMatchSelectableSide(Agent agent, BattleSideEnum side)
        {
            if (agent == null || side == BattleSideEnum.None)
                return false;

            if (_materializedArmySideByAgentIndex.TryGetValue(agent.Index, out BattleSideEnum trackedSide) &&
                trackedSide == side)
            {
                return true;
            }

            if (ExactCampaignArmyBootstrap.TryGetSide(agent, out BattleSideEnum originSide) &&
                originSide == side)
            {
                return true;
            }

            return agent.Team?.Side == side;
        }

        internal static bool TryResolveAuthoritativeTrackedEntryId(Agent agent, out string entryId)
        {
            entryId = null;
            if (agent == null)
                return false;

            if (TryResolveClientAuthoritativeMaterializedEntryId(agent.Index, out string authoritativeEntryId))
            {
                _materializedArmyEntryIdByAgentIndex[agent.Index] = authoritativeEntryId;
                entryId = authoritativeEntryId;
                return true;
            }

            if (_materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out string trackedEntryId) &&
                !string.IsNullOrWhiteSpace(trackedEntryId))
            {
                RosterEntryState trackedEntryState = BattleSnapshotRuntimeState.GetEntryState(trackedEntryId);
                if (trackedEntryState != null &&
                    (DoesClientVisualOverlayEntryMatchAgentTroop(trackedEntryState, agent.Character?.StringId) ||
                     ShouldPreserveStrictExactHeroEntryMapping(agent.Index, trackedEntryId)))
                {
                    entryId = trackedEntryId;
                    return true;
                }

                ClearClientTrackedMaterializedAgentIdentityState(
                    agent.Index,
                    "TryResolveAuthoritativeTrackedEntryId",
                    "stale-authoritative-tracked-entry",
                    preserveCreateAgentRuntime: true,
                    logClear: true);
                ModLogger.Info(
                    "CoopMissionSpawnLogic: cleared stale authoritative tracked entry mapping. " +
                    "AgentIndex=" + agent.Index +
                    " TrackedEntryId=" + trackedEntryId +
                    " CurrentTroopId=" + (agent.Character?.StringId ?? "null"));
            }

            if (ExactCampaignArmyBootstrap.TryGetEntryId(agent, out string originEntryId) &&
                !string.IsNullOrWhiteSpace(originEntryId))
            {
                entryId = originEntryId;
                return true;
            }

            return false;
        }

        internal static bool TryResolveSelectableEntryId(Agent agent, out string entryId)
        {
            if (TryResolveAuthoritativeTrackedEntryId(agent, out entryId))
                return true;

            if (_exactNativeClientVisualOverlayEntryIdByAgentIndex.TryGetValue(agent.Index, out string clientOverlayEntryId) &&
                !string.IsNullOrWhiteSpace(clientOverlayEntryId))
            {
                RosterEntryState overlayEntryState = BattleSnapshotRuntimeState.GetEntryState(clientOverlayEntryId);
                if (overlayEntryState != null &&
                    (DoesClientVisualOverlayEntryMatchAgentTroop(overlayEntryState, agent?.Character?.StringId) ||
                     ShouldPreserveStrictExactHeroEntryMapping(agent?.Index ?? -1, clientOverlayEntryId)))
                {
                    entryId = clientOverlayEntryId;
                    return true;
                }

                ClearClientExactCampaignVisualOverlayAgentIndexState(
                    agent?.Index ?? -1,
                    "TryResolveSelectableEntryId",
                    logClear: true,
                    reason: "stale-selectable-overlay-entry",
                    preserveCreateAgentRuntime: true);
            }

            if (TryResolveQueuedClientExactCampaignVisualOverlayEntryId(agent, out string queuedEntryId))
            {
                _exactNativeClientVisualOverlayEntryIdByAgentIndex[agent.Index] = queuedEntryId;
                _materializedArmyEntryIdByAgentIndex[agent.Index] = queuedEntryId;
                entryId = queuedEntryId;
                return true;
            }

            if (TryResolveClientHeuristicCreateAgentEntryId(
                    agent.Index,
                    requireSettled: true,
                    out string heuristicEntryId,
                    out string heuristicResolutionState,
                    out string heuristicResolutionSource,
                    out _) &&
                BattleSnapshotRuntimeState.GetEntryState(heuristicEntryId) is RosterEntryState heuristicEntryState &&
                (DoesClientVisualOverlayEntryMatchAgentTroop(heuristicEntryState, agent?.Character?.StringId) ||
                 ShouldPreserveStrictExactHeroEntryMapping(agent?.Index ?? -1, heuristicEntryId)))
            {
                PromoteSettledClientHeuristicCreateAgentEntryId(
                    agent,
                    heuristicEntryId,
                    heuristicResolutionState,
                    heuristicResolutionSource,
                    "TryResolveSelectableEntryId");
                entryId = heuristicEntryId;
                return true;
            }

            entryId = null;
            return false;
        }

        private static bool ShouldPreserveStrictExactHeroEntryMapping(int riderAgentIndex, string entryId)
        {
            if (riderAgentIndex < 0 || string.IsNullOrWhiteSpace(entryId))
                return false;

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(riderAgentIndex, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                return false;
            }

            if (!string.Equals(state.EntryId, entryId, StringComparison.Ordinal) ||
                state.ExactVisualApplied ||
                state.Stage >= StrictExactHeroTransferStage.ExactVisualApplied)
            {
                return false;
            }

            return state.IsMountedHero ||
                   state.Stage >= StrictExactHeroTransferStage.CreateAgentPayloadObserved;
        }

        private static bool ShouldPreserveAppliedStrictExactHeroVisualOnTransientMountLinkLoss(
            int riderAgentIndex,
            string entryId)
        {
            if (riderAgentIndex < 0 || string.IsNullOrWhiteSpace(entryId))
                return false;

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(riderAgentIndex, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                return false;
            }

            if (!string.Equals(state.EntryId, entryId, StringComparison.Ordinal) ||
                !state.IsMountedHero ||
                state.DeathObserved ||
                state.ExpectedMountAgentIndex < 0)
            {
                return false;
            }

            if (!state.EquipmentSynchronized ||
                !state.ExactVisualApplied ||
                !state.IncludesWeaponsApplied ||
                state.Stage < StrictExactHeroTransferStage.ExactVisualApplied)
            {
                return false;
            }

            return true;
        }

        internal static bool ShouldSuppressStrictExactHeroOnSpawnWield(
            Agent agent,
            out string entryId,
            out string suppressReason)
        {
            entryId = null;
            suppressReason = "strict-exact-hero-contract-missing";

            if (GameNetwork.IsServer || agent == null || agent.IsMount || agent.Index < 0)
                return false;

            if (!ExactTransferContractRuntimeCache.TryGetEntryIdByRiderAgentIndex(agent.Index, out entryId) ||
                string.IsNullOrWhiteSpace(entryId))
            {
                entryId = null;
                return false;
            }

            if (!ExactTransferContractRuntimeCache.TryGetContract(entryId, out ExactTransferSpawnContract contract) ||
                contract?.SpawnPolicy == null ||
                !contract.SpawnPolicy.UseStrictExactHeroPath ||
                !contract.SpawnPolicy.ForbidSurrogatePrimaryMaterialization)
            {
                suppressReason = "strict-exact-hero-contract-not-applicable";
                return false;
            }

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
            {
                suppressReason = "strict-exact-hero-entry-not-eligible";
                return false;
            }

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(agent.Index, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                suppressReason = "strict-exact-hero-stale-onspawn-wield-contract-cache";
                return true;
            }

            if (!string.IsNullOrWhiteSpace(state.EntryId) &&
                !string.Equals(state.EntryId, entryId, StringComparison.Ordinal))
            {
                suppressReason = "strict-exact-hero-entry-mismatch";
                return false;
            }

            if (state.DeathObserved)
            {
                suppressReason = "strict-exact-hero-death-observed";
                return false;
            }

            if (state.Stage < StrictExactHeroTransferStage.CreateAgentPayloadObserved)
            {
                suppressReason = "strict-exact-hero-payload-stage-pending";
                return false;
            }

            suppressReason =
                state.ExactVisualApplied || state.Stage >= StrictExactHeroTransferStage.ExactVisualApplied
                    ? "strict-exact-hero-stale-onspawn-wield-after-visual-applied"
                    : "strict-exact-hero-stale-onspawn-wield";
            return true;
        }

        internal static bool HasStrictExactHeroLocalInitialWieldBeenApplied(
            Agent agent,
            string entryId,
            out string currentVersionKey,
            out string versionStateSummary)
        {
            currentVersionKey = string.Empty;
            versionStateSummary = "strict-exact-hero-local-initial-wield-state-missing";

            if (GameNetwork.IsServer || agent == null || agent.IsMount || agent.Index < 0 || string.IsNullOrWhiteSpace(entryId))
                return false;

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(agent.Index, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                return false;
            }

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
            {
                versionStateSummary = "strict-exact-hero-local-initial-wield-entry-unresolved";
                return false;
            }

            RefreshStrictExactHeroVersionState(
                state,
                entryId,
                entryState,
                "strict exact hero local initial wield query");

            currentVersionKey = BuildStrictExactHeroLocalInitialWieldVersionKey(state);
            versionStateSummary =
                "BattleId=" + (state.BattleId ?? "null") +
                " LifecycleGeneration=" + state.LifecycleGeneration +
                " Applied=" + !string.IsNullOrWhiteSpace(state.LocalInitialWieldAppliedVersionKey);
            return
                !string.IsNullOrWhiteSpace(currentVersionKey) &&
                string.Equals(state.LocalInitialWieldAppliedVersionKey, currentVersionKey, StringComparison.Ordinal);
        }

        internal static bool ShouldAllowVanillaOnSpawnWieldFallbackForStrictHero(
            Agent agent,
            string entryId,
            out string reason)
        {
            reason = "strict-exact-hero-vanilla-onspawn-wield-fallback-unresolved";

            if (GameNetwork.IsServer || agent == null || agent.IsMount || agent.Index < 0 || string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
            {
                reason = "strict-exact-hero-entry-unresolved";
                return false;
            }

            ExactEntryCompatibilityDiagnostic diagnostic = GetExactEntryCompatibilityDiagnostic(entryState);
            if (diagnostic == null)
            {
                reason = "strict-exact-hero-entry-diagnostic-missing";
                return false;
            }

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(agent.Index, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                reason = "strict-exact-hero-transfer-state-missing";
                return false;
            }

            EquipmentIndex currentMainHandIndex = agent.GetPrimaryWieldedItemIndex();
            EquipmentIndex currentOffHandIndex = agent.GetOffhandWieldedItemIndex();
            bool hasUsableLiveWieldState =
                currentMainHandIndex != EquipmentIndex.None ||
                currentOffHandIndex != EquipmentIndex.None;
            bool degradedWeaponFallback =
                !IsExactWeaponContractSupported(diagnostic) ||
                !diagnostic.CurrentRuntimePreSpawnIncludesWeapons;

            if (state.ExactVisualApplied || state.Stage >= StrictExactHeroTransferStage.ExactVisualApplied)
            {
                if (!hasUsableLiveWieldState)
                {
                    reason =
                        "strict-exact-hero-local-wield-unusable-after-exact-visual" +
                        "{Status=" + (diagnostic.Status ?? "unknown") +
                        ",WeaponContractSupported=" + IsExactWeaponContractSupported(diagnostic) +
                        ",CurrentPreSpawnWeapons=" + diagnostic.CurrentRuntimePreSpawnIncludesWeapons +
                        ",Weapon2Risk=" + diagnostic.HasWeapon2WieldReplicationRisk +
                        ",Stage=" + state.Stage +
                        ",Main=" + currentMainHandIndex +
                        ",Off=" + currentOffHandIndex + "}";
                    return true;
                }

                reason = "strict-exact-hero-exact-visual-already-applied";
                return false;
            }

            if (degradedWeaponFallback)
            {
                reason =
                    "strict-exact-hero-degraded-weapon-fallback" +
                    "{Status=" + (diagnostic.Status ?? "unknown") +
                    ",WeaponContractSupported=" + IsExactWeaponContractSupported(diagnostic) +
                    ",CurrentPreSpawnWeapons=" + diagnostic.CurrentRuntimePreSpawnIncludesWeapons +
                    ",Weapon2Risk=" + diagnostic.HasWeapon2WieldReplicationRisk +
                    ",Stage=" + state.Stage +
                    ",Main=" + currentMainHandIndex +
                    ",Off=" + currentOffHandIndex + "}";
                return true;
            }

            if (!hasUsableLiveWieldState)
            {
                reason =
                    "strict-exact-hero-local-wield-unusable-before-exact-visual" +
                    "{Status=" + (diagnostic.Status ?? "unknown") +
                    ",WeaponContractSupported=" + IsExactWeaponContractSupported(diagnostic) +
                    ",CurrentPreSpawnWeapons=" + diagnostic.CurrentRuntimePreSpawnIncludesWeapons +
                    ",Weapon2Risk=" + diagnostic.HasWeapon2WieldReplicationRisk +
                    ",Stage=" + state.Stage +
                    ",Main=" + currentMainHandIndex +
                    ",Off=" + currentOffHandIndex + "}";
                return true;
            }

            reason = "strict-exact-hero-exact-weapon-contract-supported";
            return false;
        }

        internal static void InvalidateStrictExactHeroLocalInitialWieldAppliedMarker(
            Agent agent,
            string entryId,
            string source,
            string reason)
        {
            if (GameNetwork.IsServer || agent == null || agent.IsMount || agent.Index < 0)
                return;

            if (!_strictExactHeroTransferStateByRiderAgentIndex.TryGetValue(agent.Index, out StrictExactHeroTransferRuntimeState state) ||
                state == null)
            {
                return;
            }

            RosterEntryState entryState = !string.IsNullOrWhiteSpace(entryId)
                ? BattleSnapshotRuntimeState.GetEntryState(entryId)
                : null;
            if (entryState != null)
            {
                RefreshStrictExactHeroVersionState(
                    state,
                    entryId,
                    entryState,
                    source ?? "strict exact hero local initial wield invalidate");
            }

            InvalidateStrictExactHeroLocalInitialWieldAppliedState(
                state,
                source ?? "strict exact hero local initial wield invalidate",
                reason ?? "manual-invalidate",
                bumpLifecycleGeneration: false);
        }

        private static void RecordStrictExactHeroLocalInitialWieldApplied(
            Agent agent,
            string entryId,
            string source)
        {
            if (GameNetwork.IsServer || agent == null || agent.IsMount || agent.Index < 0 || string.IsNullOrWhiteSpace(entryId))
                return;

            StrictExactHeroTransferRuntimeState state = EnsureStrictExactHeroTransferState(agent.Index);
            if (state == null)
                return;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
                return;

            RefreshStrictExactHeroVersionState(
                state,
                entryId,
                entryState,
                source ?? "strict exact hero local initial wield applied");

            string versionKey = BuildStrictExactHeroLocalInitialWieldVersionKey(state);
            if (string.IsNullOrWhiteSpace(versionKey))
                return;

            state.LocalInitialWieldAppliedVersionKey = versionKey;
            state.LocalInitialWieldAppliedUtc = DateTime.UtcNow;
            state.LastSource = source ?? "unknown";
            state.LastUpdatedUtc = DateTime.UtcNow;
        }

        internal static bool TryApplyStrictExactHeroLocalInitialWield(
            Agent agent,
            string entryId,
            string source,
            out string appliedWieldRefresh,
            out string wieldRefreshIssue)
        {
            appliedWieldRefresh = "(none)";
            wieldRefreshIssue = "(none)";

            if (GameNetwork.IsServer || agent == null || agent.IsMount || string.IsNullOrWhiteSpace(entryId))
            {
                wieldRefreshIssue = "strict-exact-hero-local-initial-wield-invalid-input";
                return false;
            }

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            if (!IsHeroEntryEligibleForExactPersonalPerks(entryState))
            {
                wieldRefreshIssue = "strict-exact-hero-local-initial-wield-entry-unresolved";
                return false;
            }

            Equipment overlaySpawnEquipment = null;
            if (ExactTransferContractRuntimeCache.TryGetContract(entryId, out ExactTransferSpawnContract contract))
                overlaySpawnEquipment = contract?.Equipment?.SpawnEquipment?.Clone(false);

            if (overlaySpawnEquipment == null)
            {
                overlaySpawnEquipment = BuildSnapshotEquipmentForExactRuntime(
                    entryState,
                    includeWeapons: true,
                    honorExactVisualContracts: false,
                    includeArmorVisuals: false,
                    includeMountVisuals: false);
            }
            if (overlaySpawnEquipment == null)
            {
                wieldRefreshIssue = "strict-exact-hero-local-initial-wield-equipment-unresolved";
                return false;
            }

            if (ExactTransferContractBuilder.TryNormalizeStrictHeroWeaponLayoutInPlace(
                    overlaySpawnEquipment,
                    entryState,
                    out bool normalizedStrictHeroWieldLayout,
                    out string normalizedStrictHeroWieldLayoutSummary) &&
                normalizedStrictHeroWieldLayout)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: normalized strict hero local initial wield layout before live refresh. " +
                    "AgentIndex=" + agent.Index +
                    " EntryId=" + entryId +
                    " Summary=" + (normalizedStrictHeroWieldLayoutSummary ?? "(none)") +
                    " Source=" + (source ?? "unknown"));
            }

            if (TryRefreshClientOverlayLiveWeaponWieldState(
                    agent,
                    overlaySpawnEquipment,
                    entryId,
                    source,
                    out appliedWieldRefresh,
                    out wieldRefreshIssue))
            {
                RecordStrictExactHeroLocalInitialWieldApplied(
                    agent,
                    entryId,
                    source ?? "strict exact hero local initial wield live refresh");
                return true;
            }

            try
            {
                EquipmentIndex preMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex preOffHandIndex = agent.GetOffhandWieldedItemIndex();
                agent.WieldInitialWeapons(
                    Agent.WeaponWieldActionType.Instant,
                    Equipment.InitialWeaponEquipPreference.Any);
                EquipmentIndex postMainHandIndex = agent.GetPrimaryWieldedItemIndex();
                EquipmentIndex postOffHandIndex = agent.GetOffhandWieldedItemIndex();
                bool success = postMainHandIndex != EquipmentIndex.None || postOffHandIndex != EquipmentIndex.None;
                appliedWieldRefresh =
                    "strict-exact-hero-wield-initial-weapons" +
                    "{AgentIndex=" + agent.Index +
                    ",EntryId=" + entryId +
                    ",PreMain=" + FormatAgentWieldedEquipmentIndex(agent, preMainHandIndex) +
                    ",PreOff=" + FormatAgentWieldedEquipmentIndex(agent, preOffHandIndex) +
                    ",PostMain=" + FormatAgentWieldedEquipmentIndex(agent, postMainHandIndex) +
                    ",PostOff=" + FormatAgentWieldedEquipmentIndex(agent, postOffHandIndex) +
                    ",PostWieldedItem=" + (agent.WieldedWeapon.Item?.StringId ?? "none") +
                    ",PostOffhandItem=" + (agent.WieldedOffhandWeapon.Item?.StringId ?? "none") +
                    ",Source=" + (source ?? "unknown") + "}";
                if (!success)
                    wieldRefreshIssue = "strict-exact-hero-local-initial-wield-post-none";
                if (success)
                {
                    RecordStrictExactHeroLocalInitialWieldApplied(
                        agent,
                        entryId,
                        source ?? "strict exact hero local initial wield initial-weapons");
                }
                return success;
            }
            catch (Exception ex)
            {
                wieldRefreshIssue = "strict-exact-hero-local-initial-wield-failed:" + ex.GetType().Name;
                return false;
            }
        }

        public static bool TryResolveExactDisplayNameForAgent(Agent agent, out string entryId, out TextObject exactName)
        {
            entryId = null;
            exactName = null;
            if (agent == null)
                return false;

            if (!TryResolveSelectableEntryId(agent, out entryId) || string.IsNullOrWhiteSpace(entryId))
                return false;

            RosterEntryState entryState = BattleSnapshotRuntimeState.GetEntryState(entryId);
            string resolvedDisplayName = BattleSnapshotRuntimeState.ResolveEntryDisplayName(entryState, entryId);
            if (string.IsNullOrWhiteSpace(resolvedDisplayName) ||
                string.Equals(resolvedDisplayName, "Unknown Unit", StringComparison.Ordinal))
            {
                return false;
            }

            exactName = new TextObject(resolvedDisplayName);
            return true;
        }

        private static bool HasTrackedBattlefieldEntryStateForSide(Mission mission, BattleSideEnum side)
        {
            if (side == BattleSideEnum.None)
                return false;

            string sideId = side.ToString();
            foreach (MaterializedBattleResultEntryRuntimeState runtimeState in _materializedBattleResultEntriesByEntryId.Values)
            {
                if (runtimeState == null ||
                    runtimeState.MaterializedSpawnCount <= 0 ||
                    !string.Equals(runtimeState.SideId, sideId, StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                return true;
            }

            if (mission?.AllAgents == null)
                return false;

            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent candidate = mission.AllAgents[i];
                if (candidate == null || candidate.IsMount || !DoesAgentMatchSelectableSide(candidate, side))
                    continue;

                if (TryResolveSelectableEntryId(candidate, out _))
                    return true;
            }

            return false;
        }

        private static List<string> OrderSelectableEntryIds(BattleSideEnum side, IEnumerable<string> entryIds)
        {
            var pendingEntryIds = new HashSet<string>(
                (entryIds ?? Enumerable.Empty<string>())
                .Where(entryId => !string.IsNullOrWhiteSpace(entryId)),
                StringComparer.Ordinal);
            var orderedEntryIds = new List<string>(pendingEntryIds.Count);
            if (pendingEntryIds.Count <= 0)
                return orderedEntryIds;

            BattleSideState sideState = BattleSnapshotRuntimeState.GetSideState(side.ToString());
            if (sideState?.MissionReadyEntryOrder != null)
            {
                foreach (string missionReadyEntryId in sideState.MissionReadyEntryOrder)
                {
                    if (!pendingEntryIds.Remove(missionReadyEntryId))
                        continue;

                    orderedEntryIds.Add(missionReadyEntryId);
                }
            }

            foreach (RosterEntryState entryState in GetAllowedControlEntryStatesSnapshot(side))
            {
                string entryId = entryState?.EntryId;
                if (string.IsNullOrWhiteSpace(entryId) || !pendingEntryIds.Remove(entryId))
                    continue;

                orderedEntryIds.Add(entryId);
            }

            orderedEntryIds.AddRange(pendingEntryIds.OrderBy(entryId => entryId, StringComparer.Ordinal));
            return orderedEntryIds;
        }

        private static void TryLogSelectableEntryUniverse(
            Mission mission,
            CoopBattlePhase currentPhase,
            string attackerSource,
            IReadOnlyList<string> attackerEntryIds,
            string defenderSource,
            IReadOnlyList<string> defenderEntryIds,
            BattleSideEnum currentSide,
            string currentSource,
            IReadOnlyList<string> currentEntryIds)
        {
            string logKey =
                (mission?.SceneName ?? "null") + "|" +
                currentPhase + "|" +
                (attackerSource ?? "unknown") + "|" +
                string.Join(",", attackerEntryIds ?? Array.Empty<string>()) + "|" +
                (defenderSource ?? "unknown") + "|" +
                string.Join(",", defenderEntryIds ?? Array.Empty<string>()) + "|" +
                currentSide + "|" +
                (currentSource ?? "unknown") + "|" +
                string.Join(",", currentEntryIds ?? Array.Empty<string>());
            if (string.Equals(_lastLoggedSelectableEntryUniverseKey, logKey, StringComparison.Ordinal))
                return;

            _lastLoggedSelectableEntryUniverseKey = logKey;
            ModLogger.Info(
                "CoopMissionSpawnLogic: selectable entry universe updated. " +
                "Mission=" + (mission?.SceneName ?? "null") +
                " Phase=" + currentPhase +
                " AttackerSource=" + (attackerSource ?? "unknown") +
                " AttackerCount=" + (attackerEntryIds?.Count ?? 0) +
                " AttackerSample=[" + BuildSelectableEntrySample(attackerEntryIds) + "]" +
                " DefenderSource=" + (defenderSource ?? "unknown") +
                " DefenderCount=" + (defenderEntryIds?.Count ?? 0) +
                " DefenderSample=[" + BuildSelectableEntrySample(defenderEntryIds) + "]" +
                " CurrentSide=" + currentSide +
                " CurrentSource=" + (currentSource ?? "unknown") +
                " CurrentCount=" + (currentEntryIds?.Count ?? 0) +
                " CurrentSample=[" + BuildSelectableEntrySample(currentEntryIds) + "]");
        }

        private static string BuildSelectableEntrySample(IReadOnlyList<string> entryIds)
        {
            if (entryIds == null || entryIds.Count <= 0)
                return string.Empty;

            return string.Join(", ", entryIds.Where(entryId => !string.IsNullOrWhiteSpace(entryId)).Take(6));
        }

        private static bool TryResolveAuthoritativeCompatibilityEntryIdForPeerStatus(
            CoopBattlePeerSessionSnapshot sessionSnapshot,
            CoopBattleAuthorityState.PeerSelectionState selectionState,
            out string entryId,
            out string source)
        {
            if (!string.IsNullOrWhiteSpace(sessionSnapshot?.EffectiveEntryId))
            {
                entryId = sessionSnapshot.EffectiveEntryId;
                source = "session-effective-entry";
                return true;
            }

            if (!string.IsNullOrWhiteSpace(sessionSnapshot?.SpawnRequestEntryId))
            {
                entryId = sessionSnapshot.SpawnRequestEntryId;
                source = "session-spawn-request-entry";
                return true;
            }

            if (!string.IsNullOrWhiteSpace(sessionSnapshot?.SelectionRequestEntryId))
            {
                entryId = sessionSnapshot.SelectionRequestEntryId;
                source = "session-selection-request-entry";
                return true;
            }

            if (!string.IsNullOrWhiteSpace(selectionState.EntryId))
            {
                entryId = selectionState.EntryId;
                source = "selection-state-entry";
                return true;
            }

            entryId = null;
            source = null;
            return false;
        }

        private static void PopulateAuthoritativeCompatibilityStatusForPeerSnapshot(
            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot snapshot,
            CoopBattlePeerSessionSnapshot sessionSnapshot,
            CoopBattleAuthorityState.PeerSelectionState selectionState)
        {
            if (snapshot == null)
                return;

            snapshot.AuthoritativeCompatibilityEntryId = string.Empty;
            snapshot.AuthoritativeCompatibilityEntrySource = string.Empty;
            snapshot.AuthoritativeCompatibilityStatus = string.Empty;
            snapshot.AuthoritativeWeaponContractSupported = false;
            snapshot.AuthoritativeVisualContractSupported = false;
            snapshot.AuthoritativeCompatibilitySummary = string.Empty;

            if (!TryResolveAuthoritativeCompatibilityEntryIdForPeerStatus(
                    sessionSnapshot,
                    selectionState,
                    out string compatibilityEntryId,
                    out string compatibilityEntrySource))
            {
                return;
            }

            snapshot.AuthoritativeCompatibilityEntryId = compatibilityEntryId ?? string.Empty;
            snapshot.AuthoritativeCompatibilityEntrySource = compatibilityEntrySource ?? string.Empty;

            BattleRuntimeState runtimeState = BattleSnapshotRuntimeState.GetState();
            if (runtimeState?.EntriesById == null ||
                string.IsNullOrWhiteSpace(compatibilityEntryId) ||
                !runtimeState.EntriesById.TryGetValue(compatibilityEntryId, out RosterEntryState entryState) ||
                entryState == null)
            {
                snapshot.AuthoritativeCompatibilityStatus = "entry-unresolved";
                snapshot.AuthoritativeCompatibilitySummary =
                    "EntryId=" + (compatibilityEntryId ?? "null") +
                    " Diagnostic=entry-unresolved";
                return;
            }

            ExactEntryCompatibilityDiagnostic diagnostic = GetExactEntryCompatibilityDiagnostic(entryState);
            snapshot.AuthoritativeCompatibilityStatus = diagnostic?.Status ?? "unknown";
            snapshot.AuthoritativeWeaponContractSupported = IsExactWeaponContractSupported(diagnostic);
            snapshot.AuthoritativeVisualContractSupported = IsExactVisualContractSupported(diagnostic);
            snapshot.AuthoritativeCompatibilitySummary = BuildExactEntryCompatibilityDebugSummary(compatibilityEntryId);
        }

        internal static CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot BuildEntryStatusSnapshotForPeer(
            Mission mission,
            MissionPeer missionPeer,
            string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return null;

            CoopBattlePhaseStateSnapshot phaseSnapshot = CoopBattlePhaseRuntimeState.GetCurrent();
            CoopBattlePhase currentPhase = phaseSnapshot?.Phase ?? CoopBattlePhase.None;
            bool canStartBattle = IsBattleStartReady(mission, out _, out _) &&
                currentPhase >= CoopBattlePhase.PreBattleHold &&
                currentPhase < CoopBattlePhase.BattleActive;
            bool canStartBattleForPeer = canStartBattle && IsBattleStartAuthorityPeer(mission, missionPeer);
            IReadOnlyList<string> attackerSelectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                BattleSideEnum.Attacker,
                currentPhase,
                missionPeer,
                out string attackerSelectableSource);
            IReadOnlyList<string> defenderSelectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                BattleSideEnum.Defender,
                currentPhase,
                missionPeer,
                out string defenderSelectableSource);
            CoopBattlePeerSessionState.TryBuild(
                mission,
                missionPeer,
                source,
                out CoopBattlePeerSessionSnapshot sessionSnapshot);
            CoopBattlePeerSessionState.LogTransition(sessionSnapshot, source);
            CoopBattleAuthorityState.PeerSelectionState selectionState =
                missionPeer != null
                    ? CoopBattleAuthorityState.GetSelectionState(missionPeer)
                    : default(CoopBattleAuthorityState.PeerSelectionState);
            BattleSideEnum statusSide = sessionSnapshot?.EffectiveSide ?? (
                selectionState.Side != BattleSideEnum.None
                    ? selectionState.Side
                    : selectionState.RequestedSide);
            bool battleDataReady = TryResolveBattleDataReadinessForPeer(
                mission,
                missionPeer,
                currentPhase,
                statusSide,
                out string battleDataReadinessStage,
                out string battleDataReadinessReason);
            Dictionary<int, string> authoritativeMaterializedAgentEntries = BuildAuthoritativeMaterializedAgentEntryMapSnapshot(mission);

            var snapshot = new CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot
            {
                MissionName = mission.SceneName ?? string.Empty,
                Source = source,
                BattlePhase = currentPhase.ToString(),
                BattlePhaseSource = phaseSnapshot?.Source ?? string.Empty,
                WinnerSide = ResolveBattleResultWinnerSide(mission),
                BattleCompletionReason = _authoritativeBattleCompletionReason ?? string.Empty,
                PeerName = sessionSnapshot?.PeerName ?? missionPeer?.Name?.ToString() ?? missionPeer?.GetNetworkPeer()?.UserName ?? string.Empty,
                PeerIndex = sessionSnapshot?.PeerIndex ?? missionPeer?.GetNetworkPeer()?.Index ?? -1,
                HasPeer = missionPeer != null,
                HasAgent = sessionSnapshot?.HasActiveControlledAgent ?? (missionPeer?.ControlledAgent != null && missionPeer.ControlledAgent.IsActive()),
                BattleDataReady = battleDataReady,
                BattleDataReadinessStage = battleDataReadinessStage,
                BattleDataReadinessReason = battleDataReadinessReason,
                CanRespawn = false,
                CanStartBattle = canStartBattleForPeer,
                LifecycleState = "NoPeer",
                LifecycleSource = sessionSnapshot?.LifecycleSource ?? source,
                DeathCount = 0,
                IntentSide = (sessionSnapshot?.RequestedSide ?? selectionState.RequestedSide) == BattleSideEnum.None ? string.Empty : (sessionSnapshot?.RequestedSide ?? selectionState.RequestedSide).ToString(),
                IntentTroopOrEntryId = sessionSnapshot?.EffectiveEntryId ?? sessionSnapshot?.EffectiveTroopId ?? selectionState.EntryId ?? selectionState.TroopId,
                AuthoritativeCompatibilityEntryId = string.Empty,
                AuthoritativeCompatibilityEntrySource = string.Empty,
                AuthoritativeCompatibilityStatus = string.Empty,
                AuthoritativeWeaponContractSupported = false,
                AuthoritativeVisualContractSupported = false,
                AuthoritativeCompatibilitySummary = string.Empty,
                AuthoritativeMaterializedAgentEntryCount = authoritativeMaterializedAgentEntries.Count,
                AuthoritativeMaterializedAgentEntries = CoopBattleEntryStatusBridgeFile.SerializeAgentEntryMap(authoritativeMaterializedAgentEntries),
                AttackerAllowedTroopIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(CoopBattleAuthorityState.GetAllowedTroopIds(BattleSideEnum.Attacker) ?? Array.Empty<string>()),
                AttackerAllowedEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(CoopBattleAuthorityState.GetAllowedEntryIds(BattleSideEnum.Attacker) ?? Array.Empty<string>()),
                AttackerSelectableEntryCount = attackerSelectableEntryIds?.Count ?? 0,
                AttackerSelectableEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(attackerSelectableEntryIds),
                AttackerSelectableEntrySource = attackerSelectableSource,
                DefenderAllowedTroopIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(CoopBattleAuthorityState.GetAllowedTroopIds(BattleSideEnum.Defender) ?? Array.Empty<string>()),
                DefenderAllowedEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(CoopBattleAuthorityState.GetAllowedEntryIds(BattleSideEnum.Defender) ?? Array.Empty<string>()),
                DefenderSelectableEntryCount = defenderSelectableEntryIds?.Count ?? 0,
                DefenderSelectableEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(defenderSelectableEntryIds),
                DefenderSelectableEntrySource = defenderSelectableSource,
                UpdatedUtc = DateTime.UtcNow
            };

            if (missionPeer != null)
            {
                BattleSideEnum requestedSide = sessionSnapshot?.RequestedSide ?? selectionState.RequestedSide;
                BattleSideEnum assignedSide = sessionSnapshot?.AssignedSide ?? selectionState.Side;
                snapshot.RequestedSide = requestedSide == BattleSideEnum.None ? string.Empty : requestedSide.ToString();
                snapshot.AssignedSide = assignedSide == BattleSideEnum.None ? string.Empty : assignedSide.ToString();
                snapshot.SelectedTroopId = sessionSnapshot?.EffectiveTroopId ?? selectionState.TroopId;
                snapshot.SelectedEntryId = sessionSnapshot?.EffectiveEntryId ?? selectionState.EntryId;
                snapshot.AllowedTroopIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(CoopBattleAuthorityState.GetAllowedTroopIds(statusSide) ?? Array.Empty<string>());
                snapshot.AllowedEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(CoopBattleAuthorityState.GetAllowedEntryIds(statusSide) ?? Array.Empty<string>());
                snapshot.SelectionRequestSide = (sessionSnapshot?.SelectionRequestSide ?? BattleSideEnum.None) == BattleSideEnum.None ? string.Empty : sessionSnapshot.SelectionRequestSide.ToString();
                snapshot.SelectionRequestTroopId = sessionSnapshot?.SelectionRequestTroopId ?? string.Empty;
                snapshot.SelectionRequestEntryId = sessionSnapshot?.SelectionRequestEntryId ?? string.Empty;
                snapshot.SpawnRequestSide = (sessionSnapshot?.SpawnRequestSide ?? BattleSideEnum.None) == BattleSideEnum.None ? string.Empty : sessionSnapshot.SpawnRequestSide.ToString();
                snapshot.SpawnRequestTroopId = sessionSnapshot?.SpawnRequestTroopId ?? string.Empty;
                snapshot.SpawnRequestEntryId = sessionSnapshot?.SpawnRequestEntryId ?? string.Empty;
                snapshot.SpawnStatus = sessionSnapshot != null && sessionSnapshot.SpawnStatus != CoopBattleSpawnStatus.None
                    ? sessionSnapshot.SpawnStatus.ToString()
                    : string.Empty;
                snapshot.SpawnReason = sessionSnapshot?.SpawnStatusReason ?? string.Empty;
                snapshot.LifecycleSource = sessionSnapshot?.LifecycleSource ?? snapshot.LifecycleSource;
                snapshot.DeathCount = sessionSnapshot?.DeathCount ?? 0;

                snapshot.CanRespawn = battleDataReady && CanPeerRespawn(mission, missionPeer);
                snapshot.LifecycleState = ResolveEntryLifecycleState(mission, missionPeer, sessionSnapshot, snapshot.CanRespawn);
                PopulateAuthoritativeCompatibilityStatusForPeerSnapshot(snapshot, sessionSnapshot, selectionState);
            }

            if (statusSide != BattleSideEnum.None)
            {
                snapshot.AllowedTroopIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(
                    CoopBattleAuthorityState.GetAllowedTroopIds(statusSide) ?? Array.Empty<string>());
                snapshot.AllowedEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(
                    CoopBattleAuthorityState.GetAllowedEntryIds(statusSide) ?? Array.Empty<string>());
                IReadOnlyList<string> currentSelectableEntryIds = ResolveSelectableEntryIdsForStatus(
                    mission,
                    statusSide,
                    currentPhase,
                    missionPeer,
                    out string currentSelectableSource);
                snapshot.SelectableEntryIds = CoopBattleEntryStatusBridgeFile.SerializeIdList(currentSelectableEntryIds);
                snapshot.SelectableEntrySource = currentSelectableSource;
            }
            else
            {
                snapshot.SelectableEntryIds = string.Empty;
                snapshot.SelectableEntrySource = string.Empty;
            }

            return snapshot;
        }

        internal static CoopBattleEntryStatusBridgeFile.AuthoritativeMaterializedAgentEntrySnapshot
            BuildAuthoritativeMaterializedAgentEntrySnapshot(
                Mission mission,
                string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return null;

            Dictionary<int, string> authoritativeMaterializedAgentEntries =
                BuildAuthoritativeMaterializedAgentEntryMapSnapshot(mission);
            return new CoopBattleEntryStatusBridgeFile.AuthoritativeMaterializedAgentEntrySnapshot
            {
                BattleId = BattleSnapshotRuntimeState.GetCurrent()?.BattleId ?? string.Empty,
                MissionName = mission.SceneName ?? string.Empty,
                Source = source ?? string.Empty,
                UseStringIdExactEquipmentPath = UseDedicatedSafeStringIdExactEquipmentPathOnServer(),
                EntryCount = authoritativeMaterializedAgentEntries.Count,
                AgentEntries = CoopBattleEntryStatusBridgeFile.SerializeAgentEntryMap(authoritativeMaterializedAgentEntries),
                UpdatedUtc = DateTime.UtcNow
            };
        }

        private static Dictionary<int, string> BuildAuthoritativeMaterializedAgentEntryMapSnapshot(Mission mission)
        {
            var mappings = new Dictionary<int, string>();
            if (mission?.AllAgents == null || _materializedArmyEntryIdByAgentIndex.Count == 0)
                return mappings;

            for (int i = 0; i < mission.AllAgents.Count; i++)
            {
                Agent agent = mission.AllAgents[i];
                if (agent == null ||
                    !agent.IsActive() ||
                    agent.IsMount ||
                    !agent.IsHuman ||
                    agent.Team == null ||
                    agent.Team.Side == BattleSideEnum.None)
                {
                    continue;
                }

                if (_materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out string entryId) &&
                    !string.IsNullOrWhiteSpace(entryId))
                {
                    mappings[agent.Index] = entryId;
                }
            }

            return mappings;
        }

        private static void TryWriteEntryStatusSnapshot(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            MissionPeer missionPeer = ResolvePrimaryControllablePeer(mission);
            CoopBattlePhaseStateSnapshot phaseSnapshot = CoopBattlePhaseRuntimeState.GetCurrent();
            CoopBattlePhase currentPhase = phaseSnapshot?.Phase ?? CoopBattlePhase.None;
            bool canStartBattle = IsBattleStartReady(mission, out int assignedPeerCount, out int controlledPeerCount) &&
                currentPhase >= CoopBattlePhase.PreBattleHold &&
                currentPhase < CoopBattlePhase.BattleActive;
            IReadOnlyList<string> attackerSelectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                BattleSideEnum.Attacker,
                currentPhase,
                missionPeer,
                out string attackerSelectableSource);
            IReadOnlyList<string> defenderSelectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                BattleSideEnum.Defender,
                currentPhase,
                missionPeer,
                out string defenderSelectableSource);

            CoopBattleEntryStatusBridgeFile.EntryStatusSnapshot snapshot =
                BuildEntryStatusSnapshotForPeer(mission, missionPeer, source);
            if (snapshot == null)
                return;

            BattleSideEnum statusSide = BattleSideEnum.None;
            if (Enum.TryParse(snapshot.AssignedSide, out BattleSideEnum assignedSide) && assignedSide != BattleSideEnum.None)
                statusSide = assignedSide;
            else if (Enum.TryParse(snapshot.RequestedSide, out BattleSideEnum requestedSide) && requestedSide != BattleSideEnum.None)
                statusSide = requestedSide;

            if (statusSide != BattleSideEnum.None)
            {
                IReadOnlyList<string> currentSelectableEntryIds = CoopBattleEntryStatusBridgeFile.DeserializeIdList(snapshot.SelectableEntryIds);
                TryLogSelectableEntryUniverse(
                    mission,
                    currentPhase,
                    attackerSelectableSource,
                    attackerSelectableEntryIds,
                    defenderSelectableSource,
                    defenderSelectableEntryIds,
                    statusSide,
                    snapshot.SelectableEntrySource,
                    currentSelectableEntryIds);
            }
            else
            {
                TryLogSelectableEntryUniverse(
                    mission,
                    currentPhase,
                    attackerSelectableSource,
                    attackerSelectableEntryIds,
                    defenderSelectableSource,
                    defenderSelectableEntryIds,
                    BattleSideEnum.None,
                    "none",
                    Array.Empty<string>());
            }

            TryLogBattleStartReadinessAudit(
                mission,
                currentPhase,
                canStartBattle,
                assignedPeerCount,
                controlledPeerCount,
                source);
            CoopBattleEntryStatusBridgeFile.WriteStatus(snapshot);
        }

        private static void TryLogBattleStartReadinessAudit(
            Mission mission,
            CoopBattlePhase currentPhase,
            bool canStartBattle,
            int assignedPeerCount,
            int controlledPeerCount,
            string source)
        {
            if (mission == null || currentPhase < CoopBattlePhase.PreBattleHold || currentPhase >= CoopBattlePhase.BattleActive)
                return;

            bool armiesReady = AreBattlefieldArmiesReadyForStart(
                mission,
                out string readinessSource,
                out int attackerActive,
                out int defenderActive);
            string logKey =
                currentPhase + "|" +
                canStartBattle + "|" +
                assignedPeerCount + "|" +
                controlledPeerCount + "|" +
                armiesReady + "|" +
                attackerActive + "|" +
                defenderActive + "|" +
                readinessSource;
            if (string.Equals(_lastLoggedBattleStartReadinessAuditKey, logKey, StringComparison.Ordinal))
                return;

            _lastLoggedBattleStartReadinessAuditKey = logKey;
            ModLogger.Info(
                "CoopMissionSpawnLogic: battle start readiness audit. " +
                "Phase=" + currentPhase +
                " CanStartBattle=" + canStartBattle +
                " AssignedPeers=" + assignedPeerCount +
                " ControlledPeers=" + controlledPeerCount +
                " ArmiesReady=" + armiesReady +
                " ArmiesReadySource=" + readinessSource +
                " AttackerActive=" + attackerActive +
                " DefenderActive=" + defenderActive +
                " MaterializedArmiesFlag=" + _hasMaterializedBattlefieldArmies +
                " ExactBootstrapActive=" + IsUsingNativeExactCampaignArmyBootstrap(mission) +
                " Source=" + (source ?? "unknown"));
        }

        private static string ResolveEntryLifecycleState(
            Mission mission,
            MissionPeer missionPeer,
            CoopBattlePeerSessionSnapshot sessionSnapshot,
            bool canRespawn)
        {
            if (missionPeer == null)
                return "NoPeer";

            if (sessionSnapshot != null)
            {
                if (sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.Alive || sessionSnapshot.HasActiveControlledAgent)
                    return "Alive";

                if (sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.NoSide || sessionSnapshot.SessionStage == CoopBattlePeerSessionStage.NoSide)
                    return "NoSide";

                if (sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.SpawnQueued || sessionSnapshot.SessionStage == CoopBattlePeerSessionStage.SpawnQueued)
                    return "SpawnQueued";

                if (sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.AwaitingSelection ||
                    sessionSnapshot.SessionStage == CoopBattlePeerSessionStage.SideAssigned)
                {
                    return "AwaitingSelection";
                }

                if (sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.DeadAwaitingRespawn ||
                    sessionSnapshot.SessionStage == CoopBattlePeerSessionStage.DeadAwaitingRespawn)
                {
                    return canRespawn ? "Respawnable" : "DeadAwaitingRespawn";
                }

                if (sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.Respawnable)
                    return "Respawnable";

                if (sessionSnapshot.SessionStage == CoopBattlePeerSessionStage.EntrySelected)
                    return canRespawn ? "Respawnable" : "Waiting";

                if (sessionSnapshot.SessionStage == CoopBattlePeerSessionStage.BattleEnded)
                    return "Waiting";
            }

            BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, "entry-status lifecycle");
            if (authoritativeSide == BattleSideEnum.None)
                return "NoSide";

            CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
            bool hasSelection =
                !string.IsNullOrWhiteSpace(selectionState.EntryId) ||
                !string.IsNullOrWhiteSpace(selectionState.TroopId);
            if (!hasSelection)
                return "AwaitingSelection";

            if (CoopBattleSpawnRequestState.HasPendingRequest(missionPeer))
                return "SpawnQueued";

            return canRespawn ? "Respawnable" : "Waiting";
        }

        private static bool CanPeerRespawn(Mission mission, MissionPeer missionPeer)
        {
            return CanPeerRespawnFromCoopRuntime(mission, missionPeer, out _);
        }

        private static bool CanPeerRespawnFromCoopRuntime(Mission mission, MissionPeer missionPeer, out string reason)
        {
            reason = string.Empty;
            if (mission == null || missionPeer == null)
            {
                reason = "mission or peer missing";
                return false;
            }

            CoopBattlePeerSessionState.TryBuild(mission, missionPeer, "entry-status can-respawn", out CoopBattlePeerSessionSnapshot sessionSnapshot);
            if (sessionSnapshot != null && sessionSnapshot.HasActiveControlledAgent)
            {
                reason = "peer still controls active agent";
                return false;
            }

            if (sessionSnapshot != null && sessionSnapshot.OccupiesActiveCoopLife)
            {
                reason = "peer still marked alive in coop runtime";
                return false;
            }

            CoopBattlePhase currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            if (currentPhase >= CoopBattlePhase.BattleEnded)
            {
                reason = "battle already ended";
                return false;
            }

            BattleSideEnum authoritativeSide =
                sessionSnapshot != null && sessionSnapshot.CommittedSide != BattleSideEnum.None
                    ? sessionSnapshot.CommittedSide
                    : ResolveAuthoritativeSide(missionPeer, mission, "entry-status can-respawn");
            if (authoritativeSide == BattleSideEnum.None)
            {
                reason = "peer side not assigned";
                return false;
            }

            bool hasSelection = sessionSnapshot?.HasEffectiveSelection ?? false;
            if (sessionSnapshot == null)
            {
                CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
                hasSelection =
                    !string.IsNullOrWhiteSpace(selectionState.EntryId) ||
                    !string.IsNullOrWhiteSpace(selectionState.TroopId);
            }
            if (!hasSelection)
            {
                reason = "peer selection missing";
                return false;
            }

            if (sessionSnapshot != null ? sessionSnapshot.HasQueuedSpawnRuntime : IsPeerHoldingQueuedSpawnInCoopRuntime(missionPeer))
            {
                reason = "peer already has queued spawn runtime";
                return false;
            }

            if ((sessionSnapshot != null && sessionSnapshot.LifecycleStatus == CoopBattlePeerLifecycleStatus.NoSide) ||
                (sessionSnapshot == null &&
                 CoopBattlePeerLifecycleRuntimeState.TryGetState(missionPeer, out PeerLifecycleRuntimeState lifecycleState) &&
                 lifecycleState.Status == CoopBattlePeerLifecycleStatus.NoSide))
            {
                reason = "peer lifecycle still no-side";
                return false;
            }

            if (!TryResolvePeerSpawnAvailability(
                    mission,
                    missionPeer,
                    authoritativeSide,
                    out CoopBattlePhase _,
                    out IReadOnlyList<string> _,
                    out string _,
                    out string _,
                    out int _,
                    out int _,
                    out string availabilityReason))
            {
                reason = availabilityReason;
                return false;
            }

            return true;
        }

        private static bool TryResolvePeerSpawnAvailability(
            Mission mission,
            MissionPeer missionPeer,
            BattleSideEnum authoritativeSide,
            out CoopBattlePhase currentPhase,
            out IReadOnlyList<string> selectableEntryIds,
            out string selectableSource,
            out string readinessSource,
            out int attackerActive,
            out int defenderActive,
            out string reason)
        {
            currentPhase = CoopBattlePhaseRuntimeState.GetPhase();
            selectableEntryIds = Array.Empty<string>();
            selectableSource = "none";
            readinessSource = string.Empty;
            attackerActive = 0;
            defenderActive = 0;
            reason = string.Empty;

            if (mission == null || missionPeer == null)
            {
                reason = "mission or peer missing";
                return false;
            }

            if (authoritativeSide == BattleSideEnum.None)
            {
                reason = "peer side not assigned";
                return false;
            }

            selectableEntryIds = ResolveSelectableEntryIdsForStatus(
                mission,
                authoritativeSide,
                currentPhase,
                missionPeer,
                out selectableSource);
            if (selectableEntryIds.Count == 0)
            {
                reason =
                    "no selectable entries available" +
                    " | selectableSource=" + selectableSource +
                    " | phase=" + currentPhase;
                return false;
            }

            if (!IsExplicitSelectableSourceReady(currentPhase, selectableSource))
            {
                reason =
                    "battle data still loading" +
                    " | selectableSource=" + selectableSource +
                    " | phase=" + currentPhase;
                return false;
            }

            if (!AreBattlefieldArmiesReadyForStart(mission, out readinessSource, out attackerActive, out defenderActive))
            {
                reason =
                    "battlefield armies not ready" +
                    " | readinessSource=" + readinessSource +
                    " | phase=" + currentPhase +
                    " | attackerActive=" + attackerActive +
                    " | defenderActive=" + defenderActive;
                return false;
            }

            return true;
        }

        private static bool TryParseBattleSide(string requestedSideRaw, out BattleSideEnum requestedSide)
        {
            requestedSide = BattleSideEnum.None;
            if (string.IsNullOrWhiteSpace(requestedSideRaw))
                return false;

            string normalized = requestedSideRaw.Trim().ToLowerInvariant();
            if (normalized == "attacker" || normalized == "attackers" || normalized == "1")
            {
                requestedSide = BattleSideEnum.Attacker;
                return true;
            }

            if (normalized == "defender" || normalized == "defenders" || normalized == "2")
            {
                requestedSide = BattleSideEnum.Defender;
                return true;
            }

            return false;
        }

        private static bool LooksLikeEntryId(string value)
        {
            return !string.IsNullOrWhiteSpace(value) &&
                   value.IndexOf('|') >= 0;
        }

        private static bool TryResolveAuthoritativeCharacterForPeer(
            MissionPeer missionPeer,
            out BasicCharacterObject selectedCharacter,
            out string selectedTroopId,
            out string selectedEntryId,
            out string reason)
        {
            selectedCharacter = null;
            selectedTroopId = null;
            selectedEntryId = null;
            reason = string.Empty;

            if (missionPeer == null)
            {
                reason = "mission peer missing";
                return false;
            }

            CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
            RosterEntryState preferredEntry = ResolvePreferredAllowedEntryStateForPeer(missionPeer, selectionState);
            if (!CoopBattleSpawnRequestState.TryGetPendingRequest(missionPeer, out CoopBattleSpawnRequestState.PeerSpawnRequestState pendingRequest))
            {
                reason = "pending spawn request missing";
                return false;
            }

            CoopBattleSpawnRuntimeState.MarkValidating(missionPeer, "TryResolveAuthoritativeCharacterForPeer pending-request");
            selectedEntryId = pendingRequest.EntryId;
            string requestedTroopId = pendingRequest.TroopId;
            if (string.IsNullOrWhiteSpace(requestedTroopId))
            {
                reason = "pending spawn request troop missing";
                return false;
            }

            bool requiresEntryMatch = !string.IsNullOrWhiteSpace(selectedEntryId) || !string.IsNullOrWhiteSpace(selectionState.EntryId);
            if (preferredEntry == null && requiresEntryMatch)
            {
                reason = "pending spawn request entry not allowed";
                return false;
            }

            if (preferredEntry != null &&
                !string.IsNullOrWhiteSpace(selectedEntryId) &&
                !string.Equals(preferredEntry.EntryId, selectedEntryId, StringComparison.Ordinal))
            {
                reason = "pending spawn request entry mismatched current allowed entry";
                return false;
            }

            bool hasExplicitEntrySelection =
                !string.IsNullOrWhiteSpace(pendingRequest.EntryId) ||
                !string.IsNullOrWhiteSpace(selectionState.EntryId);

            selectedEntryId = hasExplicitEntrySelection
                ? preferredEntry?.EntryId
                : null;
            selectedTroopId = requestedTroopId;

            ExactEntryCompatibilityDiagnostic exactEntryDiagnostic =
                hasExplicitEntrySelection
                    ? GetExactEntryCompatibilityDiagnostic(preferredEntry)
                    : null;
            if (hasExplicitEntrySelection)
            {
                if (exactEntryDiagnostic == null)
                {
                    reason = "exact entry contract missing (entry='" + (selectedEntryId ?? "null") + "')";
                    return false;
                }

                if (!IsExactWeaponContractSupported(exactEntryDiagnostic))
                {
                    LogExactEntryCompatibilityDiagnostic(exactEntryDiagnostic, "authoritative-peer-reject");
                    reason = BuildExactWeaponContractRejectionReason(exactEntryDiagnostic);
                    return false;
                }

                LogExactEntryCompatibilityDiagnostic(exactEntryDiagnostic, "authoritative-peer");
                selectedCharacter = exactEntryDiagnostic.ResolvedCharacter;
            }
            else
            {
                selectedCharacter = ResolveAllowedCharacter(selectedTroopId);
            }

            if (!hasExplicitEntrySelection && selectedCharacter == null)
            {
                string cultureFallbackTroopId = ResolveCultureSpecificTargetTroopId(requestedTroopId, missionPeer.Culture);
                if (!string.IsNullOrWhiteSpace(cultureFallbackTroopId) &&
                    !string.Equals(cultureFallbackTroopId, requestedTroopId, StringComparison.Ordinal))
                {
                    BasicCharacterObject cultureFallbackCharacter = ResolveAllowedCharacter(cultureFallbackTroopId);
                    if (cultureFallbackCharacter != null)
                    {
                        ModLogger.Info(
                            "CoopMissionSpawnLogic: authoritative troop direct lookup failed, using peer-culture fallback. " +
                            "RequestedTroopId=" + requestedTroopId +
                            " FallbackTroopId=" + cultureFallbackTroopId +
                            " PeerCulture=" + (missionPeer.Culture?.StringId ?? "null"));
                        selectedTroopId = cultureFallbackTroopId;
                        selectedCharacter = cultureFallbackCharacter;
                    }
                }
            }

            if (!hasExplicitEntrySelection && !string.IsNullOrWhiteSpace(preferredEntry?.EntryId))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: skipped snapshot entry character resolution for troop-only spawn request. " +
                    "RequestedTroopId=" + requestedTroopId +
                    " PreferredEntryId=" + preferredEntry.EntryId);
            }
            if (selectedCharacter == null)
            {
                reason = "pending troop/entry not resolved (troop='" + selectedTroopId + "', entry='" + (selectedEntryId ?? "null") + "')";
                return false;
            }

            CoopBattleSpawnRuntimeState.MarkValidated(
                missionPeer,
                selectedTroopId,
                selectedEntryId,
                "TryResolveAuthoritativeCharacterForPeer pending-request",
                exactEntryDiagnostic?.Status ?? "validated");
            return true;
        }

        private static void AdvanceLifecycleAfterSpawnWaitOrReject(Mission mission, MissionPeer missionPeer, string reason, string source)
        {
            if (missionPeer == null)
                return;

            bool preferSpawnQueued =
                string.Equals(reason, "spawn timer not ready", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(reason, "team perk info not ready", StringComparison.OrdinalIgnoreCase) ||
                string.Equals(reason, "authoritative mission team not ready", StringComparison.OrdinalIgnoreCase);
            ApplyDerivedPeerLifecycleState(
                mission,
                missionPeer,
                preferSpawnQueued,
                preserveDeadAwaitingRespawn: true,
                preferSpawnQueued ? source + " queued" : source + " derived");
        }

        private static Team ResolveAuthoritativeMissionTeam(
            Mission mission,
            MissionPeer missionPeer,
            BattleSideEnum authoritativeSide)
        {
            if (mission == null || authoritativeSide == BattleSideEnum.None)
                return null;

            Team currentTeam = missionPeer?.Team;
            if (currentTeam != null &&
                !ReferenceEquals(currentTeam, mission.SpectatorTeam) &&
                currentTeam.Side == authoritativeSide)
            {
                return currentTeam;
            }

            if (authoritativeSide == BattleSideEnum.Attacker)
                return mission.AttackerTeam ?? mission.Teams?.Attacker;

            if (authoritativeSide == BattleSideEnum.Defender)
                return mission.DefenderTeam ?? mission.Teams?.Defender;

            return null;
        }

        private static bool TryRemovePendingAgentVisuals(Mission mission, MissionPeer missionPeer)
        {
            if (mission == null || missionPeer == null || mission.MissionBehaviors == null)
                return false;

            foreach (MissionBehavior behavior in mission.MissionBehaviors)
            {
                if (behavior == null)
                    continue;

                Type behaviorType = behavior.GetType();
                if (behaviorType.Name.IndexOf("MissionAgentVisualSpawnComponent", StringComparison.OrdinalIgnoreCase) < 0)
                    continue;

                try
                {
                    MethodInfo removeMethod = behaviorType.GetMethod(
                        "RemoveAgentVisuals",
                        BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic,
                        null,
                        new[] { typeof(MissionPeer), typeof(bool) },
                        null);
                    if (removeMethod != null)
                    {
                        removeMethod.Invoke(behavior, new object[] { missionPeer, true });
                        return true;
                    }

                    removeMethod = behaviorType.GetMethod(
                        "RemoveAgentVisuals",
                        BindingFlags.Instance | BindingFlags.Public | BindingFlags.NonPublic,
                        null,
                        new[] { typeof(MissionPeer) },
                        null);
                    if (removeMethod != null)
                    {
                        removeMethod.Invoke(behavior, new object[] { missionPeer });
                        return true;
                    }
                }
                catch (Exception ex)
                {
                    ModLogger.Info("CoopMissionSpawnLogic: removing pending agent visuals failed: " + ex.Message);
                    return false;
                }
            }

            return false;
        }

        private static void GetDirectSpawnFrame(Mission mission, Team team, out Vec3 spawnPosition, out Vec2 spawnDirection)
        {
            spawnPosition = team.Side == BattleSideEnum.Attacker
                ? new Vec3(-4f, 0f, 0f)
                : new Vec3(4f, 0f, 0f);
            spawnDirection = team.Side == BattleSideEnum.Attacker
                ? new Vec2(1f, 0f)
                : new Vec2(-1f, 0f);

            try
            {
                FFASpawnFrameBehavior spawnFrameBehavior = new FFASpawnFrameBehavior();
                spawnFrameBehavior.Initialize();
                MatrixFrame spawnFrame = spawnFrameBehavior.GetSpawnFrame(team, hasMount: false, isInitialSpawn: true);
                if (spawnFrame.origin != Vec3.Zero)
                {
                    spawnPosition = spawnFrame.origin;
                    spawnDirection = spawnFrame.rotation.f.AsVec2.Normalized();
                    if (spawnDirection.LengthSquared > 0.001f)
                        return;
                }
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: FFASpawnFrameBehavior failed: " + ex.Message);
            }

            if (team.ActiveAgents == null || team.ActiveAgents.Count == 0)
            {
                if (string.Equals(mission?.SceneName, "mp_tdm_map_001", StringComparison.OrdinalIgnoreCase))
                {
                    // Temporary safe fallback for the fixed bootstrap scene until we switch to proper
                    // scene-derived spawn points. The origin-based fallback was outside the arena.
                    spawnPosition = team.Side == BattleSideEnum.Attacker
                        ? new Vec3(312f, 320f, 140f)
                        : new Vec3(336f, 320f, 140f);
                }
                return;
            }

            Agent anchorAgent = team.ActiveAgents.FirstOrDefault(agent => agent != null && agent.IsActive());
            if (anchorAgent == null)
                return;

            float lateralOffset = team.Side == BattleSideEnum.Attacker ? -1.5f : 1.5f;
            spawnPosition = anchorAgent.Position + new Vec3(lateralOffset, 0f, 0f);

            Agent targetEnemy = mission.GetClosestEnemyAgent(team, spawnPosition, 200f);
            Vec3 lookAt = targetEnemy != null
                ? targetEnemy.Position
                : anchorAgent.Position + new Vec3(team.Side == BattleSideEnum.Attacker ? 6f : -6f, 0f, 0f);

            Vec3 toEnemy3 = lookAt - spawnPosition;
            spawnDirection = new Vec2(toEnemy3.x, toEnemy3.y);
            if (spawnDirection.LengthSquared < 0.001f)
                spawnDirection = team.Side == BattleSideEnum.Attacker ? new Vec2(1f, 0f) : new Vec2(-1f, 0f);
            spawnDirection.Normalize();
        }

        public static bool TryResolvePreferredHeroClassForPeer(
            MissionPeer missionPeer,
            MultiplayerClassDivisions.MPHeroClass vanillaClass,
            out MultiplayerClassDivisions.MPHeroClass preferredClass,
            out int preferredTroopIndex,
            out string debugReason)
        {
            return TryResolvePreferredHeroClassForPeer(
                missionPeer,
                vanillaClass,
                true,
                out preferredClass,
                out preferredTroopIndex,
                out debugReason);
        }

        private static bool TryResolvePreferredHeroClassForPeer(
            MissionPeer missionPeer,
            MultiplayerClassDivisions.MPHeroClass vanillaClass,
            bool requireSpawnTimerReady,
            out MultiplayerClassDivisions.MPHeroClass preferredClass,
            out int preferredTroopIndex,
            out string debugReason)
        {
            if (!TryResolveAuthoritativeCompatibilityHeroClassForPeer(
                    missionPeer,
                    requireSpawnTimerReady,
                    out preferredClass,
                    out preferredTroopIndex,
                    out debugReason))
            {
                return false;
            }

            return !ReferenceEquals(preferredClass, vanillaClass) || missionPeer.SelectedTroopIndex != preferredTroopIndex;
        }

        private static bool TryResolveAuthoritativeCompatibilityHeroClassForPeer(
            MissionPeer missionPeer,
            bool requireSpawnTimerReady,
            out MultiplayerClassDivisions.MPHeroClass preferredClass,
            out int preferredTroopIndex,
            out string debugReason)
        {
            preferredClass = null;
            preferredTroopIndex = -1;
            debugReason = string.Empty;

            if (!GameNetwork.IsServer)
            {
                debugReason = "not server";
                return false;
            }

            if (missionPeer == null)
            {
                debugReason = "missionPeer is null";
                return false;
            }

            if (missionPeer.Team == null || missionPeer.Culture == null)
            {
                debugReason = "peer team/culture not ready";
                return false;
            }

            if (missionPeer.ControlledAgent != null)
            {
                debugReason = "peer already has controlled agent";
                return false;
            }

            if (!CoopBattleSpawnRequestState.HasPendingRequest(missionPeer))
            {
                debugReason = "no pending spawn request";
                return false;
            }

            if (requireSpawnTimerReady && !IsSpawnTimerReady(missionPeer))
            {
                debugReason = "spawn timer not ready";
                return false;
            }

            string targetTroopId = GetPreferredTargetTroopIdForPeerCulture(missionPeer);
            if (string.IsNullOrWhiteSpace(targetTroopId))
            {
                debugReason = "no selected allowed troop";
                return false;
            }

            List<MultiplayerClassDivisions.MPHeroClass> cultureClasses = MultiplayerClassDivisions
                .GetMPHeroClasses(missionPeer.Culture)
                ?.Where(heroClass => heroClass?.HeroCharacter != null)
                .ToList();

            if (cultureClasses == null || cultureClasses.Count == 0)
            {
                debugReason = "peer culture has no MP classes";
                return false;
            }

            CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
            RosterEntryState preferredAllowedEntry = ResolvePreferredAllowedEntryStateForPeer(missionPeer, selectionState);
            bool preservePendingExactEntryAuthority =
                CoopBattleSpawnRequestState.TryGetPendingRequest(missionPeer, out CoopBattleSpawnRequestState.PeerSpawnRequestState pendingRequestForBridge) &&
                !string.IsNullOrWhiteSpace(pendingRequestForBridge.EntryId);

            int exactIndex = cultureClasses.FindIndex(heroClass =>
                MatchesPreferredHeroClass(heroClass, targetTroopId));
            if (exactIndex >= 0)
            {
                RosterEntryState exactMatchEntry = ResolveMatchedAllowedEntryState(cultureClasses[exactIndex], missionPeer, selectionState, preferredAllowedEntry);
                if (preservePendingExactEntryAuthority)
                {
                    preferredClass = cultureClasses[exactIndex];
                    preferredTroopIndex = exactIndex;
                    debugReason =
                        "exact troop id bridge for explicit exact-entry pending spawn '" +
                        targetTroopId +
                        "' entry='" +
                        pendingRequestForBridge.EntryId +
                        "'";
                    return true;
                }

                if (TryRejectPendingExactEntrySpawnDrift(
                        missionPeer,
                        exactMatchEntry,
                        targetTroopId,
                        "exact troop id match",
                        out string pendingEntryDriftReason))
                {
                    debugReason = pendingEntryDriftReason;
                    return false;
                }

                ApplyAuthoritativePreferredSelection(missionPeer, exactMatchEntry, targetTroopId, "exact troop id match");
                preferredClass = cultureClasses[exactIndex];
                preferredTroopIndex = exactIndex;
                debugReason = "exact troop id match for '" + targetTroopId + "' entry='" + (exactMatchEntry?.EntryId ?? selectionState.EntryId ?? "null") + "'";
                return true;
            }

            int bestIndex = FindBestPeerCultureHeroClassIndex(cultureClasses, targetTroopId);
            if (bestIndex < 0 || bestIndex >= cultureClasses.Count)
            {
                debugReason = "no suitable class in peer culture";
                return false;
            }

            RosterEntryState surrogateEntry = ResolveMatchedAllowedEntryState(cultureClasses[bestIndex], missionPeer, selectionState, preferredAllowedEntry);
            if (preservePendingExactEntryAuthority)
            {
                preferredClass = cultureClasses[bestIndex];
                preferredTroopIndex = bestIndex;
                debugReason =
                    "peer-culture surrogate bridge for explicit exact-entry pending spawn '" +
                    targetTroopId +
                    "' entry='" +
                    pendingRequestForBridge.EntryId +
                    "'";
                return true;
            }

            if (TryRejectPendingExactEntrySpawnDrift(
                    missionPeer,
                    surrogateEntry,
                    targetTroopId,
                    "peer-culture surrogate",
                    out string surrogatePendingEntryDriftReason))
            {
                debugReason = surrogatePendingEntryDriftReason;
                return false;
            }

            ApplyAuthoritativePreferredSelection(missionPeer, surrogateEntry, targetTroopId, "peer-culture surrogate");
            preferredClass = cultureClasses[bestIndex];
            preferredTroopIndex = bestIndex;
            debugReason = "peer-culture surrogate for '" + targetTroopId + "' entry='" + (surrogateEntry?.EntryId ?? selectionState.EntryId ?? "null") + "'";
            return true;
        }

        private static RosterEntryState ResolvePreferredAllowedEntryStateForPeer(
            MissionPeer missionPeer,
            CoopBattleAuthorityState.PeerSelectionState selectionState)
        {
            if (missionPeer == null)
                return null;

            IReadOnlyList<RosterEntryState> allowedEntries = CoopMissionSpawnLogic.GetAllowedControlEntryStatesSnapshot(selectionState.Side);
            if (allowedEntries.Count == 0)
                return null;

            if (!string.IsNullOrWhiteSpace(selectionState.EntryId))
            {
                RosterEntryState selectedEntry = allowedEntries.FirstOrDefault(entry =>
                    string.Equals(entry?.EntryId, selectionState.EntryId, StringComparison.Ordinal));
                if (selectedEntry != null)
                    return selectedEntry;
            }

            if (!string.IsNullOrWhiteSpace(selectionState.TroopId))
            {
                RosterEntryState selectedByTroop = ResolveHighestPriorityAllowedEntry(
                    missionPeer,
                    selectionState.Side,
                    allowedEntries.Where(entry =>
                        string.Equals(entry?.CharacterId, selectionState.TroopId, StringComparison.OrdinalIgnoreCase)));
                if (selectedByTroop != null)
                    return selectedByTroop;
            }

            return ResolveHighestPriorityAllowedEntry(missionPeer, selectionState.Side, allowedEntries);
        }

        private static RosterEntryState ResolveMatchedAllowedEntryState(
            MultiplayerClassDivisions.MPHeroClass heroClass,
            MissionPeer missionPeer,
            CoopBattleAuthorityState.PeerSelectionState selectionState,
            RosterEntryState preferredAllowedEntry)
        {
            if (heroClass?.HeroCharacter == null || missionPeer == null)
                return null;

            if (!string.IsNullOrWhiteSpace(selectionState.EntryId) &&
                MatchesPreferredHeroClass(heroClass, selectionState.TroopId))
            {
                RosterEntryState selectedEntry = CoopMissionSpawnLogic.GetAllowedControlEntryStatesSnapshot(selectionState.Side)
                    .FirstOrDefault(entry => string.Equals(entry?.EntryId, selectionState.EntryId, StringComparison.Ordinal));
                if (selectedEntry != null)
                    return selectedEntry;
            }

            if (preferredAllowedEntry != null && MatchesPreferredHeroClass(heroClass, preferredAllowedEntry.CharacterId))
                return preferredAllowedEntry;

            return ResolveHighestPriorityAllowedEntry(
                missionPeer,
                selectionState.Side,
                CoopMissionSpawnLogic.GetAllowedControlEntryStatesSnapshot(selectionState.Side)
                    .Where(entry =>
                        entry != null &&
                        MatchesPreferredHeroClass(heroClass, entry.CharacterId)));
        }

        private static RosterEntryState ResolveHighestPriorityAllowedEntry(
            MissionPeer missionPeer,
            BattleSideEnum side,
            IEnumerable<RosterEntryState> entries)
        {
            if (entries == null)
                return null;

            List<RosterEntryState> candidateEntries = entries
                .Where(entry => entry != null)
                .ToList();
            if (candidateEntries.Count <= 0)
                return null;

            RosterEntryState commanderEntry = ResolveCommanderPreferredAllowedEntry(missionPeer, side, candidateEntries);
            if (commanderEntry != null)
                return commanderEntry;

            return candidateEntries
                .Where(entry => !IsEntryClaimedByAnotherPeer(entry?.EntryId, missionPeer))
                .OrderBy(GetAllowedEntrySelectionPriority)
                .ThenByDescending(entry => entry.IsHero)
                .ThenByDescending(entry => entry.HeroLevel)
                .ThenByDescending(entry => entry.Tier)
                .ThenBy(entry => entry.EntryId, StringComparer.Ordinal)
                .FirstOrDefault();
        }

        private static RosterEntryState ResolveCommanderPreferredAllowedEntry(
            MissionPeer missionPeer,
            BattleSideEnum side,
            IReadOnlyCollection<RosterEntryState> candidateEntries)
        {
            if (candidateEntries == null || candidateEntries.Count <= 0 || side == BattleSideEnum.None)
                return null;

            RosterEntryState commanderEntry = BattleCommanderResolver.ResolveCommanderEntry(
                BattleSnapshotRuntimeState.GetState(),
                side,
                candidateEntries);
            if (commanderEntry == null || string.IsNullOrWhiteSpace(commanderEntry.EntryId))
                return null;

            return IsEntryClaimedByAnotherPeer(commanderEntry.EntryId, missionPeer)
                ? null
                : commanderEntry;
        }

        private static bool IsEntryClaimedByAnotherPeer(string entryId, MissionPeer currentPeer)
        {
            if (string.IsNullOrWhiteSpace(entryId))
                return false;

            if (GameNetwork.NetworkPeers == null)
                return false;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive)
                    continue;

                MissionPeer otherPeer = peer.GetComponent<MissionPeer>();
                if (otherPeer == null || ReferenceEquals(otherPeer, currentPeer))
                    continue;

                if (DoesPeerClaimEntryId(otherPeer, entryId))
                    return true;
            }

            return false;
        }

        private static bool DoesPeerClaimEntryId(MissionPeer missionPeer, string entryId)
        {
            if (missionPeer == null || string.IsNullOrWhiteSpace(entryId))
                return false;

            if (CoopBattlePeerSessionState.TryBuild(null, missionPeer, "entry-claim-check", out CoopBattlePeerSessionSnapshot sessionSnapshot))
                return sessionSnapshot.ClaimsEntryId(entryId);

            return DoesAgentMatchAuthoritativeEntryId(missionPeer.ControlledAgent, entryId);
        }

        private static bool DoesAgentMatchAuthoritativeEntryId(Agent agent, string entryId)
        {
            if (agent == null || string.IsNullOrWhiteSpace(entryId))
                return false;

            return (_materializedArmyEntryIdByAgentIndex.TryGetValue(agent.Index, out string candidateEntryId) &&
                    string.Equals(candidateEntryId, entryId, StringComparison.Ordinal)) ||
                   (ExactCampaignArmyBootstrap.TryGetEntryId(agent, out string originEntryId) &&
                    string.Equals(originEntryId, entryId, StringComparison.Ordinal));
        }

        private static int GetAllowedEntrySelectionPriority(RosterEntryState entry)
        {
            if (entry == null)
                return int.MaxValue;

            if (IsHeroRoleEntry(entry, "player"))
                return 0;

            if (IsHeroRoleEntry(entry, "companion", "wanderer"))
                return 1;

            if (IsHeroRoleEntry(entry, "lord"))
                return 2;

            if (entry.IsHero)
                return 3;

            return 10;
        }

        private static bool IsHeroRoleEntry(RosterEntryState entry, params string[] roles)
        {
            if (entry == null)
                return false;

            if (roles == null || roles.Length == 0)
                return entry.IsHero && !string.IsNullOrWhiteSpace(entry.HeroRole);

            string heroRole = entry.HeroRole ?? string.Empty;
            foreach (string role in roles)
            {
                if (string.Equals(heroRole, role, StringComparison.OrdinalIgnoreCase))
                    return true;
            }

            return false;
        }

        private static string ResolveMatchedAllowedEntryId(MultiplayerClassDivisions.MPHeroClass heroClass, MissionPeer missionPeer)
        {
            if (heroClass?.HeroCharacter == null || missionPeer == null)
                return null;

            CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
            RosterEntryState preferredAllowedEntry = ResolvePreferredAllowedEntryStateForPeer(missionPeer, selectionState);
            return ResolveMatchedAllowedEntryState(heroClass, missionPeer, selectionState, preferredAllowedEntry)?.EntryId;
        }

        private static void ApplyAuthoritativePreferredSelection(
            MissionPeer missionPeer,
            RosterEntryState preferredEntry,
            string preferredTroopId,
            string source)
        {
            if (missionPeer == null)
                return;

            bool hadPendingSpawnRequest = CoopBattleSpawnRequestState.HasPendingRequest(missionPeer);

            if (preferredEntry != null && !string.IsNullOrWhiteSpace(preferredEntry.EntryId))
            {
                if (CoopBattleAuthorityState.TrySetSelectedEntryId(missionPeer, preferredEntry.EntryId, source + " entry"))
                {
                    CoopBattleSelectionRequestState.TryQueueFromAuthoritySelection(missionPeer, source + " selection-request");
                    if (hadPendingSpawnRequest)
                        CoopBattleSpawnRequestState.TryQueueFromSelection(missionPeer, source + " pending-request-refresh");
                    return;
                }
            }

            if (!string.IsNullOrWhiteSpace(preferredTroopId))
            {
                CoopBattleAuthorityState.TrySetSelectedTroopId(missionPeer, preferredTroopId, source + " troop");
                CoopBattleSelectionRequestState.TryQueueFromAuthoritySelection(missionPeer, source + " selection-request");
                if (hadPendingSpawnRequest)
                    CoopBattleSpawnRequestState.TryQueueFromSelection(missionPeer, source + " pending-request-refresh");
            }
        }

        private static bool TryRejectPendingExactEntrySpawnDrift(
            MissionPeer missionPeer,
            RosterEntryState preferredEntry,
            string preferredTroopId,
            string source,
            out string reason)
        {
            reason = string.Empty;
            if (missionPeer == null ||
                !CoopBattleSpawnRequestState.TryGetPendingRequest(missionPeer, out CoopBattleSpawnRequestState.PeerSpawnRequestState pendingRequest) ||
                string.IsNullOrWhiteSpace(pendingRequest.EntryId))
            {
                return false;
            }

            string nextEntryId = preferredEntry?.EntryId;
            if (string.Equals(pendingRequest.EntryId, nextEntryId, StringComparison.Ordinal))
                return false;

            reason =
                "exact selected entry no longer spawnable; canceled pending spawn before '" +
                (source ?? "unknown") +
                "' fallback";

            string rejectSource = (source ?? "unknown") + " exact-entry-missing";
            CoopBattleSelectionRequestState.Clear(missionPeer, rejectSource);
            CoopBattleSpawnRequestState.Clear(missionPeer, rejectSource);
            CoopBattleSpawnRuntimeState.MarkRejected(missionPeer, rejectSource, "exact selected entry no longer spawnable");
            AdvanceLifecycleAfterSpawnWaitOrReject(Mission.Current, missionPeer, "exact selected entry no longer spawnable", rejectSource);

            NetworkCommunicator peer = missionPeer.GetNetworkPeer();
            ModLogger.Info(
                "CoopMissionSpawnLogic: canceled pending exact-entry spawn instead of mutating to fallback selection. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " PendingEntryId=" + pendingRequest.EntryId +
                " PendingTroopId=" + (pendingRequest.TroopId ?? "null") +
                " PreferredEntryId=" + (nextEntryId ?? "null") +
                " PreferredTroopId=" + (preferredTroopId ?? "null") +
                " Source=" + (source ?? "unknown"));
            return true;
        }

        private static void TryForcePreferredHeroClassForPeer(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || GameNetwork.NetworkPeers == null || GameNetwork.NetworkPeers.Count == 0)
                return;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null || missionPeer.ControlledAgent != null)
                    continue;

                if (missionPeer.Team == null || ReferenceEquals(missionPeer.Team, mission.SpectatorTeam) || missionPeer.Culture == null)
                    continue;

                if (!RequiresListedShellNativeSpawnCompatibility(mission, missionPeer))
                {
                    ClearSelectedTroopIndexBridgeCompatibilityState(missionPeer);
                    continue;
                }

                int currentTroopIndex = missionPeer.SelectedTroopIndex;
                MultiplayerClassDivisions.MPHeroClass currentClass = null;
                List<MultiplayerClassDivisions.MPHeroClass> cultureClasses = MultiplayerClassDivisions
                    .GetMPHeroClasses(missionPeer.Culture)
                    ?.Where(heroClass => heroClass?.HeroCharacter != null)
                    .ToList();
                if (cultureClasses != null && currentTroopIndex >= 0 && currentTroopIndex < cultureClasses.Count)
                    currentClass = cultureClasses[currentTroopIndex];

                if (!TryResolvePreferredHeroClassForPeer(
                        missionPeer,
                        currentClass,
                        false,
                        out MultiplayerClassDivisions.MPHeroClass preferredClass,
                        out int preferredTroopIndex,
                        out string debugReason))
                {
                    continue;
                }

                if (preferredTroopIndex < 0)
                    continue;

                if (currentClass != null && missionPeer.SelectedTroopIndex == preferredTroopIndex)
                    continue;

                ApplySelectedTroopIndexBridge(missionPeer, peer, preferredTroopIndex);

                string classId = preferredClass?.HeroCharacter?.StringId ?? "null";
                string peerName = peer.UserName ?? peer.Index.ToString();
                string logKey = peer.Index + "|compat-selected-index|" + preferredTroopIndex + "|" + classId;
                if (_loggedForcedPreferredClassKeys.Add(logKey))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: synchronized native compatibility troop index from authoritative coop selection (" + source + "). " +
                        "Peer=" + peerName +
                        " Culture=" + (missionPeer.Culture?.StringId ?? "null") +
                        " TroopIndex=" + preferredTroopIndex +
                        " HeroClass=" + classId +
                        " Reason=" + debugReason);
                }
            }

            TrySyncCoopClassRestrictions(mission, source);
        }

        private static void TryBridgeListedShellInitialPerkInfoReadiness(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || GameNetwork.NetworkPeers == null || GameNetwork.NetworkPeers.Count == 0)
                return;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null || missionPeer.ControlledAgent != null)
                    continue;

                if (!RequiresListedShellNativeSpawnCompatibility(mission, missionPeer))
                    continue;

                if (missionPeer.TeamInitialPerkInfoReady)
                    continue;

                if (!TryResolveAuthoritativeCompatibilityHeroClassForPeer(
                        missionPeer,
                        false,
                        out MultiplayerClassDivisions.MPHeroClass preferredClass,
                        out int preferredTroopIndex,
                        out string debugReason))
                {
                    continue;
                }

                if (preferredTroopIndex < 0)
                    continue;

                ApplySelectedTroopIndexBridge(missionPeer, peer, preferredTroopIndex);
                if (!TryApplyListedShellInitialPerkInfoReadinessBridge(missionPeer))
                    continue;

                string peerName = peer.UserName ?? peer.Index.ToString();
                string cultureId = missionPeer.Culture?.StringId ?? "null";
                string classId = preferredClass?.HeroCharacter?.StringId ?? "null";
                string logKey = peer.Index + "|compat-team-perk-ready|" + cultureId + "|" + preferredTroopIndex + "|" + classId;
                if (_loggedForcedInitialPerkInfoReadyKeys.Add(logKey))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: bridged listed-shell native TeamInitialPerkInfoReady from authoritative coop selection (" + source + "). " +
                        "Peer=" + peerName +
                        " Culture=" + cultureId +
                        " TroopIndex=" + preferredTroopIndex +
                        " HeroClass=" + classId +
                        " Reason=" + debugReason);
                }
            }
        }

        internal static bool RequiresListedShellNativeSpawnCompatibility(Mission mission, MissionPeer missionPeer)
        {
            if (mission == null || missionPeer == null)
                return false;

            if (mission.GetMissionBehavior<MissionMultiplayerCoopBattle>() != null ||
                mission.GetMissionBehavior<MissionMultiplayerCoopBattleClient>() != null)
            {
                return false;
            }

            if (!CoopBattleSpawnRequestState.HasPendingRequest(missionPeer))
                return false;

            if (missionPeer.ControlledAgent != null)
                return false;

            if (missionPeer.Team == null || ReferenceEquals(missionPeer.Team, mission.SpectatorTeam))
                return false;

            return true;
        }

        private static void TryArmListedShellNativeSpawnCompatibilityState(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || GameNetwork.NetworkPeers == null || GameNetwork.NetworkPeers.Count == 0)
                return;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                TryArmListedShellNativeSpawnCompatibilityState(
                    mission,
                    missionPeer,
                    peer,
                    source + " listed-shell-bootstrap");
            }
        }

        internal static bool TryArmListedShellNativeSpawnCompatibilityState(
            Mission mission,
            MissionPeer missionPeer,
            NetworkCommunicator peer,
            string source)
        {
            if (!RequiresListedShellNativeSpawnCompatibility(mission, missionPeer))
                return false;

            if (!TryResolveAuthoritativeCompatibilityHeroClassForPeer(
                    missionPeer,
                    false,
                    out MultiplayerClassDivisions.MPHeroClass preferredClass,
                    out int preferredTroopIndex,
                    out string debugReason))
            {
                return false;
            }

            if (preferredTroopIndex < 0)
                return false;

            ApplySelectedTroopIndexBridge(missionPeer, peer, preferredTroopIndex);
            if (!missionPeer.TeamInitialPerkInfoReady &&
                !TryApplyListedShellInitialPerkInfoReadinessBridge(missionPeer))
            {
                return false;
            }

            bool removedPendingVisuals = false;
            if (missionPeer.HasSpawnedAgentVisuals || !missionPeer.EquipmentUpdatingExpired)
                removedPendingVisuals = TryRemovePendingAgentVisuals(mission, missionPeer);

            missionPeer.HasSpawnedAgentVisuals = true;
            missionPeer.EquipmentUpdatingExpired = true;

            string peerName = peer?.UserName ?? peer?.Index.ToString() ?? "none";
            string classId = preferredClass?.HeroCharacter?.StringId ?? "null";
            string logKey =
                (peer?.Index.ToString() ?? peerName) +
                "|listed-shell-native-spawn-armed|" +
                preferredTroopIndex +
                "|" +
                classId;
            if (_loggedArmedListedShellNativeSpawnCompatibilityKeys.Add(logKey))
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: armed listed-shell native spawn compatibility state from authoritative coop selection. " +
                    "Peer=" + peerName +
                    " TroopIndex=" + preferredTroopIndex +
                    " HeroClass=" + classId +
                    " TeamInitialPerkInfoReady=" + missionPeer.TeamInitialPerkInfoReady +
                    " RemovedPendingVisuals=" + removedPendingVisuals +
                    " Reason=" + debugReason +
                    " Source=" + (source ?? "unknown"));
            }

            return true;
        }

        internal static void FinalizeListedShellDirectSpawnCompatibilityState(
            Mission mission,
            MissionPeer missionPeer,
            string source)
        {
            if (mission == null || missionPeer == null)
                return;

            bool removedPendingVisuals = ClearMissionPeerPendingNativeSpawnVisualCompatibility(mission, missionPeer);
            if (!removedPendingVisuals)
                return;

            NetworkCommunicator peer = missionPeer.GetNetworkPeer();
            ModLogger.Info(
                "CoopMissionSpawnLogic: cleared stale listed-shell native visual compatibility after direct authoritative spawn. " +
                "Peer=" + (peer?.UserName ?? peer?.Index.ToString() ?? "none") +
                " Source=" + (source ?? "unknown"));
        }

        private static void ApplySelectedTroopIndexBridge(MissionPeer missionPeer, NetworkCommunicator peer, int preferredTroopIndex)
        {
            if (missionPeer == null || peer == null || preferredTroopIndex < 0)
                return;

            if (missionPeer.SelectedTroopIndex == preferredTroopIndex &&
                _lastBridgedSelectedTroopIndexByPeer.TryGetValue(peer.Index, out int lastBridgedTroopIndex) &&
                lastBridgedTroopIndex == preferredTroopIndex)
            {
                return;
            }

            missionPeer.SelectedTroopIndex = preferredTroopIndex;
            _lastBridgedSelectedTroopIndexByPeer[peer.Index] = preferredTroopIndex;

            TryBroadcastSelectedTroopIndexBridge(
                peer,
                preferredTroopIndex,
                "CoopMissionSpawnLogic.ApplySelectedTroopIndexBridge");
        }

        private static bool TryApplyListedShellInitialPerkInfoReadinessBridge(MissionPeer missionPeer)
        {
            if (missionPeer == null)
                return false;

            try
            {
                missionPeer.OnTeamInitialPerkInfoReceived(_listedShellDefaultInitialPerkIndices);
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: listed-shell TeamInitialPerkInfoReady bridge failed open: " + ex.Message);
                return false;
            }

            if (missionPeer.TeamInitialPerkInfoReady)
                return true;

            SetServerMemberValue(missionPeer, "TeamInitialPerkInfoReady", true);
            return missionPeer.TeamInitialPerkInfoReady;
        }

        public static bool IsVanillaSelectedTroopIndexNetworkCompatible(int selectedTroopIndex)
        {
            return selectedTroopIndex >= -1 && selectedTroopIndex <= 15;
        }

        public static bool TryBroadcastSelectedTroopIndexBridge(
            NetworkCommunicator peer,
            int selectedTroopIndex,
            string source,
            string heroClassId = null)
        {
            if (peer == null)
                return false;

            if (!IsVanillaSelectedTroopIndexNetworkCompatible(selectedTroopIndex))
            {
                string logKey = (peer.UserName ?? peer.Index.ToString()) +
                    "|" + selectedTroopIndex +
                    "|" + (heroClassId ?? "null") +
                    "|" + (source ?? "unknown");
                if (_loggedSuppressedVanillaSelectedTroopIndexBridgeKeys.Add(logKey))
                {
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: kept local preferred troop index without vanilla UpdateSelectedTroopIndex because it exceeds native compression range. " +
                        "Peer=" + (peer.UserName ?? peer.Index.ToString()) +
                        " TroopIndex=" + selectedTroopIndex +
                        " NativeMin=-1" +
                        " NativeMax=15" +
                        " HeroClass=" + (heroClassId ?? "null") +
                        " Source=" + (source ?? "unknown"));
                }

                return false;
            }

            GameNetwork.BeginBroadcastModuleEvent();
            GameNetwork.WriteMessage(new NetworkMessages.FromServer.UpdateSelectedTroopIndex(peer, selectedTroopIndex));
            GameNetwork.EndBroadcastModuleEvent(GameNetwork.EventBroadcastFlags.None);
            return true;
        }

        private static void TrySyncCoopClassRestrictions(Mission mission, string source)
        {
            if (!EnableCoopClassRestrictionSyncExperiment)
                return;

            if (mission == null || !GameNetwork.IsServer)
                return;

            MissionLobbyComponent lobbyComponent = mission.GetMissionBehavior<MissionLobbyComponent>();
            if (lobbyComponent == null)
                return;

            HashSet<FormationClass> allowedClasses = ResolveAllowedFormationClassesForMission(mission);
            if (allowedClasses.Count == 0)
                return;

            foreach (FormationClass formationClass in RestrictableFormationClasses)
            {
                bool desiredAvailability = allowedClasses.Contains(formationClass);
                if (_appliedCoopClassAvailabilityStates.TryGetValue(formationClass, out bool appliedAvailability) &&
                    appliedAvailability == desiredAvailability)
                {
                    continue;
                }

                bool finalAvailability = ApplyCoopClassRestriction(lobbyComponent, formationClass, desiredAvailability);
                _appliedCoopClassAvailabilityStates[formationClass] = finalAvailability;

                ModLogger.Info(
                    "CoopMissionSpawnLogic: synced class restriction (" + source + "). " +
                    "FormationClass=" + formationClass +
                    " DesiredAvailability=" + desiredAvailability +
                    " FinalAvailability=" + finalAvailability);
            }
        }

        private static HashSet<FormationClass> ResolveAllowedFormationClassesForMission(Mission mission)
        {
            HashSet<FormationClass> allowedClasses = new HashSet<FormationClass>();
            if (mission == null || GameNetwork.NetworkPeers == null)
                return allowedClasses;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null || missionPeer.Team == null || ReferenceEquals(missionPeer.Team, mission.SpectatorTeam))
                    continue;

                BattleSideEnum authoritativeSide = ResolveAuthoritativeSide(missionPeer, mission, "class-restriction-sync");
                if (authoritativeSide == BattleSideEnum.None)
                    continue;

                BasicCharacterObject controlledCharacter = missionPeer.ControlledAgent?.Character as BasicCharacterObject;
                if (controlledCharacter != null)
                {
                    allowedClasses.Add(controlledCharacter.DefaultFormationClass);
                    continue;
                }

                foreach (BasicCharacterObject allowedCharacter in ResolveAllowedCharactersForPeerCulture(missionPeer))
                {
                    if (allowedCharacter != null)
                        allowedClasses.Add(allowedCharacter.DefaultFormationClass);
                }
            }

            if (allowedClasses.Count == 0)
            {
                foreach (string allowedTroopId in GetAllowedControlTroopIdsSnapshot())
                {
                    BasicCharacterObject fallbackCharacter = ResolveAllowedCharacter(allowedTroopId);
                    if (fallbackCharacter != null)
                        allowedClasses.Add(fallbackCharacter.DefaultFormationClass);
                }
            }

            return allowedClasses;
        }

        private static bool ApplyCoopClassRestriction(
            MissionLobbyComponent lobbyComponent,
            FormationClass formationClass,
            bool desiredAvailability)
        {
            bool finalAvailability = desiredAvailability;
            bool broadcastValue = !desiredAvailability;

            try
            {
                lobbyComponent.ChangeClassRestriction(formationClass, broadcastValue);
                finalAvailability = lobbyComponent.IsClassAvailable(formationClass);
                if (finalAvailability != desiredAvailability)
                {
                    broadcastValue = desiredAvailability;
                    lobbyComponent.ChangeClassRestriction(formationClass, broadcastValue);
                    finalAvailability = lobbyComponent.IsClassAvailable(formationClass);
                }

                GameNetwork.BeginBroadcastModuleEvent();
                GameNetwork.WriteMessage(new NetworkMessages.FromServer.ChangeClassRestrictions(formationClass, broadcastValue));
                GameNetwork.EndBroadcastModuleEvent(GameNetwork.EventBroadcastFlags.None);
            }
            catch (Exception ex)
            {
                ModLogger.Info(
                    "CoopMissionSpawnLogic: class restriction sync failed. " +
                    "FormationClass=" + formationClass +
                    " DesiredAvailability=" + desiredAvailability +
                    " Error=" + ex.Message);
            }

            return finalAvailability;
        }

        private static string GetPreferredTargetTroopIdForPeerCulture(MissionPeer missionPeer)
        {
            CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
            RosterEntryState preferredEntry = ResolvePreferredAllowedEntryStateForPeer(missionPeer, selectionState);
            bool hasExplicitSelection = CoopBattleAuthorityState.HasExplicitSelection(missionPeer);
            string authoritativeBaseTroopId = hasExplicitSelection
                ? (!string.IsNullOrWhiteSpace(selectionState.TroopId)
                    ? selectionState.TroopId
                    : preferredEntry?.CharacterId)
                : (preferredEntry?.CharacterId ?? selectionState.TroopId);
            if (string.IsNullOrWhiteSpace(authoritativeBaseTroopId))
                return ResolveAllowedTargetTroopIdsForPeerCulture(missionPeer).FirstOrDefault();

            if (ShouldPreserveExactHeroRuntimeTarget(preferredEntry, authoritativeBaseTroopId))
                return authoritativeBaseTroopId;

            string cultureSpecificTargetTroopId = ResolveCultureSpecificTargetTroopId(authoritativeBaseTroopId, missionPeer?.Culture);
            return string.IsNullOrWhiteSpace(cultureSpecificTargetTroopId)
                ? authoritativeBaseTroopId
                : cultureSpecificTargetTroopId;
        }

        private static List<RosterEntryState> ResolveOrderedAllowedEntriesForPeer(MissionPeer missionPeer)
        {
            List<RosterEntryState> orderedEntries = new List<RosterEntryState>();
            if (missionPeer == null)
                return orderedEntries;

            CoopBattleAuthorityState.PeerSelectionState selectionState = CoopBattleAuthorityState.GetSelectionState(missionPeer);
            IReadOnlyList<RosterEntryState> allowedEntries = GetAllowedControlEntryStatesSnapshot(selectionState.Side);
            if (allowedEntries.Count == 0)
                return orderedEntries;

            RosterEntryState preferredEntry = ResolvePreferredAllowedEntryStateForPeer(missionPeer, selectionState);
            if (preferredEntry != null)
                orderedEntries.Add(preferredEntry);

            foreach (RosterEntryState entry in allowedEntries)
            {
                if (entry == null)
                    continue;

                if (orderedEntries.Any(candidate => string.Equals(candidate.EntryId, entry.EntryId, StringComparison.Ordinal)))
                    continue;

                orderedEntries.Add(entry);
            }

            return orderedEntries;
        }

        private static List<string> ResolveAllowedTargetTroopIdsForPeerCulture(MissionPeer missionPeer)
        {
            List<string> targetTroopIds = new List<string>();
            List<RosterEntryState> orderedEntries = ResolveOrderedAllowedEntriesForPeer(missionPeer);
            IReadOnlyList<string> allowedBaseTroopIds = orderedEntries.Count > 0
                ? orderedEntries
                    .Select(entry => entry?.CharacterId)
                    .Where(characterId => !string.IsNullOrWhiteSpace(characterId))
                    .Distinct(StringComparer.Ordinal)
                    .ToArray()
                : GetAllowedControlTroopIdsSnapshot(CoopBattleAuthorityState.GetSelectionState(missionPeer).Side);
            if (allowedBaseTroopIds.Count == 0)
                return targetTroopIds;

            string cultureToken = ExtractCultureToken(missionPeer?.Culture);
            HashSet<string> seenTroopIds = new HashSet<string>(StringComparer.Ordinal);

            foreach (string baseTargetTroopId in allowedBaseTroopIds)
            {
                string preferredTroopId = baseTargetTroopId;
                RosterEntryState matchingEntry = orderedEntries.FirstOrDefault(entry =>
                    entry != null &&
                    string.Equals(entry.CharacterId, baseTargetTroopId, StringComparison.Ordinal));
                if (!ShouldPreserveExactHeroRuntimeTarget(matchingEntry, baseTargetTroopId) &&
                    !string.IsNullOrWhiteSpace(cultureToken))
                {
                    string cultureSpecificCoopTroopId = TryBuildCultureSpecificCoopTroopId(baseTargetTroopId, cultureToken);
                    if (!string.IsNullOrWhiteSpace(cultureSpecificCoopTroopId))
                    {
                        BasicCharacterObject cultureSpecificCharacter = ResolveAllowedCharacter(cultureSpecificCoopTroopId);
                        if (cultureSpecificCharacter != null)
                            preferredTroopId = cultureSpecificCoopTroopId;
                    }
                }

                if (string.IsNullOrWhiteSpace(preferredTroopId) || !seenTroopIds.Add(preferredTroopId))
                    continue;

                targetTroopIds.Add(preferredTroopId);
            }

            return targetTroopIds;
        }

        private static string ResolveCultureSpecificTargetTroopId(string baseTargetTroopId, BasicCultureObject culture)
        {
            if (string.IsNullOrWhiteSpace(baseTargetTroopId))
                return null;

            string cultureToken = ExtractCultureToken(culture);
            if (string.IsNullOrWhiteSpace(cultureToken))
                return baseTargetTroopId;

            string cultureSpecificCoopTroopId = TryBuildCultureSpecificCoopTroopId(baseTargetTroopId, cultureToken);
            if (string.IsNullOrWhiteSpace(cultureSpecificCoopTroopId))
                return baseTargetTroopId;

            return ResolveAllowedCharacter(cultureSpecificCoopTroopId) != null
                ? cultureSpecificCoopTroopId
                : baseTargetTroopId;
        }

        private static IEnumerable<BasicCharacterObject> ResolveAllowedCharactersForPeerCulture(MissionPeer missionPeer)
        {
            List<RosterEntryState> orderedEntries = ResolveOrderedAllowedEntriesForPeer(missionPeer);
            if (orderedEntries.Count > 0)
            {
                HashSet<string> yieldedTroopIds = new HashSet<string>(StringComparer.Ordinal);
                string cultureToken = ExtractCultureToken(missionPeer?.Culture);
                foreach (RosterEntryState entry in orderedEntries)
                {
                    string baseTroopId = entry?.CharacterId;
                    if (string.IsNullOrWhiteSpace(baseTroopId))
                        continue;

                    string resolvedTroopId = baseTroopId;
                    if (!ShouldPreserveExactHeroRuntimeTarget(entry, baseTroopId) &&
                        !string.IsNullOrWhiteSpace(cultureToken))
                    {
                        string cultureSpecificTroopId = TryBuildCultureSpecificCoopTroopId(baseTroopId, cultureToken);
                        if (!string.IsNullOrWhiteSpace(cultureSpecificTroopId) && ResolveAllowedCharacter(cultureSpecificTroopId) != null)
                            resolvedTroopId = cultureSpecificTroopId;
                    }

                    if (!yieldedTroopIds.Add(resolvedTroopId))
                        continue;

                    BasicCharacterObject allowedCharacter = ResolveAllowedCharacter(resolvedTroopId);
                    if (allowedCharacter != null)
                        yield return allowedCharacter;
                }

                yield break;
            }

            foreach (string targetTroopId in ResolveAllowedTargetTroopIdsForPeerCulture(missionPeer))
            {
                BasicCharacterObject allowedCharacter = ResolveAllowedCharacter(targetTroopId);
                if (allowedCharacter != null)
                    yield return allowedCharacter;
            }
        }

        private static bool ShouldPreserveExactHeroRuntimeTarget(RosterEntryState entry, string troopId)
        {
            if (entry == null || string.IsNullOrWhiteSpace(troopId))
                return false;

            if (!string.Equals(entry.CharacterId, troopId, StringComparison.Ordinal))
                return false;

            return IsHeroRoleEntry(entry, "player", "companion", "wanderer", "lord");
        }

        private static string TryBuildCultureSpecificCoopTroopId(string targetTroopId, string cultureToken)
        {
            if (string.IsNullOrWhiteSpace(targetTroopId) ||
                string.IsNullOrWhiteSpace(cultureToken) ||
                !targetTroopId.StartsWith("mp_coop_", StringComparison.Ordinal))
            {
                return null;
            }

            string normalizedTarget = targetTroopId.Trim().ToLowerInvariant();
            string role = GetTroopRole(normalizedTarget);
            if (string.IsNullOrWhiteSpace(role))
                return null;

            string weight = GetTroopWeight(normalizedTarget);
            string prefix = string.IsNullOrWhiteSpace(weight)
                ? "mp_coop_" + role + "_"
                : "mp_coop_" + weight + "_" + role + "_";

            return prefix + cultureToken + "_troop";
        }

        private static string ExtractCultureToken(BasicCultureObject culture)
        {
            string cultureId = culture?.StringId;
            if (string.IsNullOrWhiteSpace(cultureId))
                return null;

            int dotIndex = cultureId.LastIndexOf('.');
            if (dotIndex >= 0 && dotIndex < cultureId.Length - 1)
                return cultureId.Substring(dotIndex + 1).Trim().ToLowerInvariant();

            return cultureId.Trim().ToLowerInvariant();
        }

        private static bool IsSpawnTimerReady(MissionPeer missionPeer)
        {
            if (missionPeer?.SpawnTimer == null || Mission.Current == null)
                return false;

            try
            {
                float elapsed = Mission.Current.CurrentTime - missionPeer.SpawnTimer.StartTime;
                return elapsed >= missionPeer.SpawnTimer.Duration;
            }
            catch
            {
                return false;
            }
        }

        private static int FindBestPeerCultureHeroClassIndex(List<MultiplayerClassDivisions.MPHeroClass> cultureClasses, string targetTroopId)
        {
            if (cultureClasses == null || cultureClasses.Count == 0 || string.IsNullOrWhiteSpace(targetTroopId))
                return -1;

            string normalizedTarget = targetTroopId.Trim().ToLowerInvariant();
            string targetRole = GetTroopRole(normalizedTarget);
            string targetWeight = GetTroopWeight(normalizedTarget);
            bool targetMounted = normalizedTarget.Contains("_cavalry_");
            bool targetRanged = normalizedTarget.Contains("_ranged_") || normalizedTarget.Contains("_archer_");

            int bestIndex = -1;
            int bestScore = int.MinValue;

            for (int i = 0; i < cultureClasses.Count; i++)
            {
                string candidateId = cultureClasses[i]?.HeroCharacter?.StringId;
                if (string.IsNullOrWhiteSpace(candidateId))
                    continue;

                string normalizedCandidate = candidateId.Trim().ToLowerInvariant();
                int score = 0;

                if (string.Equals(normalizedCandidate, normalizedTarget, StringComparison.Ordinal))
                    score += 1000;

                string candidateRole = GetTroopRole(normalizedCandidate);
                if (!string.IsNullOrEmpty(targetRole) && string.Equals(candidateRole, targetRole, StringComparison.Ordinal))
                    score += 200;

                string candidateWeight = GetTroopWeight(normalizedCandidate);
                if (!string.IsNullOrEmpty(targetWeight) && string.Equals(candidateWeight, targetWeight, StringComparison.Ordinal))
                    score += 50;

                bool candidateMounted = normalizedCandidate.Contains("_cavalry_");
                if (candidateMounted == targetMounted)
                    score += 25;

                bool candidateRanged = normalizedCandidate.Contains("_ranged_") || normalizedCandidate.Contains("_archer_");
                if (candidateRanged == targetRanged)
                    score += 15;

                if (normalizedCandidate.Contains("_troop"))
                    score += 5;

                if (score > bestScore)
                {
                    bestScore = score;
                    bestIndex = i;
                }
            }

            return bestIndex;
        }

        private static bool MatchesPreferredHeroClass(MultiplayerClassDivisions.MPHeroClass heroClass, string targetTroopId)
        {
            string heroId = heroClass?.HeroCharacter?.StringId;
            if (string.IsNullOrWhiteSpace(heroId) || string.IsNullOrWhiteSpace(targetTroopId))
                return false;

            if (string.Equals(heroId, targetTroopId, StringComparison.Ordinal))
                return true;

            string normalizedTarget = targetTroopId.Trim();
            string canonicalTarget = NormalizeTroopIdForHeroClassMatch(normalizedTarget);
            string canonicalHeroId = NormalizeTroopIdForHeroClassMatch(heroId);
            if (!string.IsNullOrWhiteSpace(canonicalTarget) &&
                !string.IsNullOrWhiteSpace(canonicalHeroId) &&
                string.Equals(canonicalHeroId, canonicalTarget, StringComparison.Ordinal))
            {
                return true;
            }

            if (normalizedTarget.EndsWith("_troop", StringComparison.Ordinal))
            {
                string expectedHeroId = normalizedTarget.Substring(0, normalizedTarget.Length - "_troop".Length) + "_hero";
                if (string.Equals(heroId, expectedHeroId, StringComparison.Ordinal))
                    return true;

                string canonicalExpectedHeroId = NormalizeTroopIdForHeroClassMatch(expectedHeroId);
                if (!string.IsNullOrWhiteSpace(canonicalExpectedHeroId) &&
                    !string.IsNullOrWhiteSpace(canonicalHeroId) &&
                    string.Equals(canonicalHeroId, canonicalExpectedHeroId, StringComparison.Ordinal))
                {
                    return true;
                }
            }

            if (normalizedTarget.EndsWith("_hero", StringComparison.Ordinal))
            {
                string expectedTroopId = normalizedTarget.Substring(0, normalizedTarget.Length - "_hero".Length) + "_troop";
                if (string.Equals(heroId, expectedTroopId, StringComparison.Ordinal))
                    return true;

                string canonicalExpectedTroopId = NormalizeTroopIdForHeroClassMatch(expectedTroopId);
                if (!string.IsNullOrWhiteSpace(canonicalExpectedTroopId) &&
                    !string.IsNullOrWhiteSpace(canonicalHeroId) &&
                    string.Equals(canonicalHeroId, canonicalExpectedTroopId, StringComparison.Ordinal))
                {
                    return true;
                }
            }

            return false;
        }

        private static string NormalizeTroopIdForHeroClassMatch(string troopId)
        {
            if (string.IsNullOrWhiteSpace(troopId))
                return null;

            string normalized = troopId.Trim();
            if (normalized.StartsWith("mp_coop_", StringComparison.Ordinal))
                normalized = "mp_" + normalized.Substring("mp_coop_".Length);

            return normalized;
        }

        private static string GetTroopRole(string troopId)
        {
            if (string.IsNullOrWhiteSpace(troopId))
                return string.Empty;

            if (troopId.Contains("_cavalry_"))
                return "cavalry";
            if (troopId.Contains("_ranged_") || troopId.Contains("_archer_"))
                return "ranged";
            if (troopId.Contains("_infantry_"))
                return "infantry";
            return string.Empty;
        }

        private static string GetTroopWeight(string troopId)
        {
            if (string.IsNullOrWhiteSpace(troopId))
                return string.Empty;

            if (troopId.Contains("_heavy_"))
                return "heavy";
            if (troopId.Contains("_light_"))
                return "light";
            if (troopId.Contains("_medium_"))
                return "medium";
            return string.Empty;
        }

        private static void TrySpawnSelectedAllowedCharacterForDiagnostics(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer)
                return;

            if (_hasSpawnedDiagnosticAllowedAgent && ReferenceEquals(_lastDiagnosticSpawnMission, mission))
                return;

            if (SelectedAllowedCharacter == null)
                return;

            Team spawnTeam = mission.AttackerTeam ?? mission.DefenderTeam;
            if (spawnTeam == null)
            {
                ModLogger.Info("CoopMissionSpawnLogic: diagnostic spawn skipped (" + source + ") because no vanilla TDM team is available yet.");
                return;
            }

            Agent anchorAgent = null;
            try
            {
                if (spawnTeam.ActiveAgents != null && spawnTeam.ActiveAgents.Count > 0)
                    anchorAgent = spawnTeam.ActiveAgents[0];
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: diagnostic spawn could not inspect team agents (" + source + "): " + ex.Message);
            }

            if (anchorAgent == null)
            {
                ModLogger.Info("CoopMissionSpawnLogic: diagnostic spawn skipped (" + source + ") because team " + spawnTeam.TeamIndex + " has no active anchor agent yet.");
                return;
            }

            Agent spawnedAgent = SpawnDiagnosticAiAgent(mission, spawnTeam, SelectedAllowedCharacter, anchorAgent);
            if (spawnedAgent == null)
            {
                ModLogger.Info("CoopMissionSpawnLogic: diagnostic spawn failed (" + source + ") for troop id '" + SelectedAllowedCharacter.StringId + "'.");
                return;
            }

            _lastDiagnosticSpawnMission = mission;
            _hasSpawnedDiagnosticAllowedAgent = true;
            _diagnosticAllowedAgent = spawnedAgent;

            string spawnedName = spawnedAgent.Name?.ToString() ?? spawnedAgent.Index.ToString();
            ModLogger.Info(
                "CoopMissionSpawnLogic: diagnostic allowed agent spawned (" + source + "). " +
                "TroopId=" + SelectedAllowedCharacter.StringId +
                " TeamIndex=" + (spawnedAgent.Team?.TeamIndex ?? -1) +
                " Side=" + (spawnedAgent.Team?.Side ?? BattleSideEnum.None) +
                " Agent=" + spawnedName +
                " Position=" + spawnedAgent.Position);
        }

        private static Agent SpawnDiagnosticAiAgent(Mission mission, Team team, BasicCharacterObject troop, Agent anchorAgent)
        {
            if (mission == null || team == null || troop == null || anchorAgent == null)
                return null;

            try
            {
                float lateralOffset = team.Side == BattleSideEnum.Attacker ? -1.5f : 1.5f;
                Vec3 spawnPosition = anchorAgent.Position + new Vec3(lateralOffset, 0f, 0f);
                Agent targetEnemy = mission.GetClosestEnemyAgent(team, spawnPosition, 200f);
                Vec3 lookAt = targetEnemy != null
                    ? targetEnemy.Position
                    : anchorAgent.Position + new Vec3(team.Side == BattleSideEnum.Attacker ? 6f : -6f, 0f, 0f);

                var origin = new BasicBattleAgentOrigin(troop);
                Vec3 toEnemy3 = lookAt - spawnPosition;
                Vec2 toEnemy2 = new Vec2(toEnemy3.x, toEnemy3.y);
                if (toEnemy2.LengthSquared < 0.001f)
                    toEnemy2 = new Vec2(1f, 0f);
                toEnemy2.Normalize();

                AgentBuildData buildData = new AgentBuildData(troop);
                buildData.Team(team);
                buildData.Controller(AgentControllerType.AI);
                buildData.TroopOrigin(origin);
                buildData.InitialPosition(in spawnPosition);
                buildData.InitialDirection(in toEnemy2);
                buildData.SpawnsIntoOwnFormation(false);
                buildData.SpawnsUsingOwnTroopClass(false);

                Agent agent = mission.SpawnAgent(buildData, spawnFromAgentVisuals: false);
                if (agent != null)
                {
                    agent.SetAutomaticTargetSelection(true);
                    agent.SetFiringOrder(FiringOrder.RangedWeaponUsageOrderEnum.FireAtWill);
                }

                return agent;
            }
            catch (Exception ex)
            {
                ModLogger.Info("CoopMissionSpawnLogic: SpawnDiagnosticAiAgent failed: " + ex.Message);
                return null;
            }
        }

        private static void TryTransferDiagnosticAllowedAgentToPeer(Mission mission, string source)
        {
            if (mission == null || !GameNetwork.IsServer || _diagnosticAllowedAgent == null)
                return;

            if (_hasTransferredDiagnosticAllowedAgentToPeer && ReferenceEquals(_lastDiagnosticOwnershipMission, mission))
                return;

            if (GameNetwork.NetworkPeers == null || GameNetwork.NetworkPeers.Count == 0)
                return;

            foreach (NetworkCommunicator peer in GameNetwork.NetworkPeers)
            {
                if (peer == null || peer.IsServerPeer || !peer.IsConnectionActive || !peer.IsSynchronized)
                    continue;

                MissionPeer missionPeer = peer.GetComponent<MissionPeer>();
                if (missionPeer == null)
                    continue;

                Agent currentlyControlledAgent = missionPeer.ControlledAgent;
                if (currentlyControlledAgent == null)
                    continue;

                if (ReferenceEquals(currentlyControlledAgent, _diagnosticAllowedAgent))
                {
                    _hasTransferredDiagnosticAllowedAgentToPeer = true;
                    _lastDiagnosticOwnershipMission = mission;
                    return;
                }

                try
                {
                    Team peerTeam = missionPeer.Team ?? currentlyControlledAgent.Team ?? _diagnosticAllowedAgent.Team;
                    if (peerTeam != null && !ReferenceEquals(_diagnosticAllowedAgent.Team, peerTeam))
                    {
                        _diagnosticAllowedAgent.SetTeam(peerTeam, false);
                        _diagnosticAllowedAgent.ForceUpdateCachedAndFormationValues(true, false);
                    }

                    currentlyControlledAgent.MissionPeer = null;
                    currentlyControlledAgent.Controller = AgentControllerType.AI;

                    _diagnosticAllowedAgent.Controller = AgentControllerType.Player;
                    _diagnosticAllowedAgent.MissionPeer = missionPeer;

                    missionPeer.ControlledAgent = _diagnosticAllowedAgent;
                    missionPeer.FollowedAgent = _diagnosticAllowedAgent;
                    peer.ControlledAgent = _diagnosticAllowedAgent;

                    mission.TakeControlOfAgent(_diagnosticAllowedAgent);
                    _diagnosticAllowedAgent.UpdateSpawnEquipmentAndRefreshVisuals(_diagnosticAllowedAgent.SpawnEquipment);
                    _diagnosticAllowedAgent.WieldInitialWeapons(
                        Agent.WeaponWieldActionType.Instant,
                        Equipment.InitialWeaponEquipPreference.Any);

                    GameNetwork.BeginModuleEventAsServer(peer.VirtualPlayer);
                    GameNetwork.WriteMessage(new NetworkMessages.FromServer.SetAgentOwningMissionPeer(_diagnosticAllowedAgent.Index, peer.VirtualPlayer));
                    GameNetwork.EndModuleEventAsServer();

                    _hasTransferredDiagnosticAllowedAgentToPeer = true;
                    _lastDiagnosticOwnershipMission = mission;

                    string previousName = currentlyControlledAgent.Name?.ToString() ?? currentlyControlledAgent.Index.ToString();
                    string newName = _diagnosticAllowedAgent.Name?.ToString() ?? _diagnosticAllowedAgent.Index.ToString();
                    ModLogger.Info(
                        "CoopMissionSpawnLogic: transferred control to diagnostic allowed agent (" + source + "). " +
                        "Peer=" + (peer.UserName ?? peer.Index.ToString()) +
                        " PreviousAgent=" + previousName +
                        " NewAgent=" + newName +
                        " TeamIndex=" + (_diagnosticAllowedAgent.Team?.TeamIndex ?? -1) +
                        " Side=" + (_diagnosticAllowedAgent.Team?.Side ?? BattleSideEnum.None) +
                        " Mount=" + _diagnosticAllowedAgent.HasMount);
                    return;
                }
                catch (Exception ex)
                {
                    ModLogger.Info("CoopMissionSpawnLogic: diagnostic control transfer failed (" + source + "): " + ex.Message);
                    return;
                }
            }
        }

    }
}
